# ── Windowed .exe stdout/stderr patch ────────────────────────────────────────
# In a PyInstaller windowed exe (console=False), sys.stdout and sys.stderr are
# None. music21 calls warn() which writes to sys.stderr, causing:
#   AttributeError: 'NoneType' object has no attribute 'write'
# Redirect to devnull so music21 can load silently without crashing.
if getattr(sys, 'frozen', False):
    import io
    if sys.stdout is None:
        sys.stdout = io.StringIO()
    if sys.stderr is None:
        sys.stderr = io.StringIO()
    # Also give music21 a writable home directory
    _m21_dir = os.path.join(os.path.dirname(sys.executable), 'music21_data')
    os.makedirs(_m21_dir, exist_ok=True)
    os.environ.setdefault('MUSIC21_USERCORPUS', _m21_dir)
    os.environ.setdefault('HOME', _m21_dir)
    os.environ.setdefault('USERPROFILE', _m21_dir)

