CONFIG_PATH     = os.path.join(os.path.expanduser("~"), ".songmaker_config.json")
CONFIG_BAK_PATH = CONFIG_PATH + ".bak"

# YouTube → FLAC "Downloaded Songs" library (v4.4.61-1). Standalone registry +
# art cache, deliberately separate from the main config so a corrupt/huge
# library file can never take the app config down with it. The registry is
# written atomically (tmp + fsync + os.replace + .bak mirror) — same discipline
# as save_config — so a mid-write process kill cannot wipe the user's library.
YT_LIBRARY_PATH     = os.path.join(os.path.expanduser("~"), ".parakit_yt_library.json")
YT_LIBRARY_BAK_PATH = YT_LIBRARY_PATH + ".bak"
YT_ART_CACHE_DIR    = os.path.join(os.path.expanduser("~"), ".parakit_yt_art_cache")
# Pre-search album-art backups so a right-click "Undo album art search" can revert
# to the cover a song had before the last "Search for missing album art" (one
# backup per song, keyed by sha1(normcase(abspath)); survives restarts).
YT_ART_UNDO_DIR     = os.path.join(os.path.expanduser("~"), ".parakit_yt_art_undo")
# Serializes registry read-modify-write across the Tk thread (download add) and
# the two background workers (file backfill + art backfill) so concurrent
# load->modify->save cycles can't clobber each other's rows. Slow work (duration
# probe, art extraction) is done OUTSIDE this lock; only the fast reload-merge-
# save span holds it, so the Tk thread never blocks on slow I/O.
import threading as _threading
YT_LIBRARY_LOCK     = _threading.Lock()
# Serializes save_config's load→merge→replace so concurrent writers cannot
# silently resurrect-over each other's keys. Residual: external RMW shapes
# like load_config(); …; save_config({key:…}) still have a same-key lost-update
# window (main-thread UI handlers in practice). A mutator helper is the full fix.
_CONFIG_LOCK        = _threading.Lock()

# v4.4.65 — library Play/Pause chip colours (owner): filled chip, white text.
# Purple "▶ Play" matches the app's purple buttons (#7c3aed); pink "⏸ Pause"
# matches the magenta in the ParaKit logo wordmark (sampled #bd02c1).
YT_PLAY_CHIP_BG  = "#7c3aed"   # ▶ Play  — app purple
YT_PAUSE_CHIP_BG = "#bd02c1"   # ⏸ Pause — logo magenta/pink

# v4.5.6.2 — pygame mixer output-buffer size (samples), shared by EVERY
# pygame.mixer.init() call in this file so the singleton mixer can't inherit a
# smaller buffer from whichever tab initialised it last. pygame's default (512 ≈
# 11 ms @ 44.1 kHz) is notoriously underrun-prone: a brief main-thread CPU spike
# (e.g. the MIDI-Editor's periodic auto-scroll piano-roll rebuild, or a Python GC
# pause) can starve SDL's audio callback and produce a ~1-2 s burst of crunchy
# static + a playback stutter. 8192 (~186 ms) gives the audio thread enough slack
# to ride through those spikes (the library preview also decodes to RAM up front,
# so playback never streams from disk). The added output latency is fully compensated:
# _me_estimate_audio_latency() derives the MIDI-Editor playhead-sync offset from
# THIS constant, so the playhead stays aligned with what you hear.
PARAKIT_MIXER_BUFFER = 8192


def _read_config_file(path):
    """Return a parsed dict from `path`, or None if missing / unreadable / not a dict.

    Treating a missing file the same as a corrupt one is intentional — load_config
    layers a .bak fallback on top so the caller never has to distinguish.
    """
    try:
        with open(path, "r", encoding="utf-8") as f:
            data = json.load(f)
        if isinstance(data, dict):
            return data
    except Exception:
        pass
    return None


def load_config():
    """Read the live config, falling back to the .bak sibling if the primary
    file is missing, corrupt, or temporarily locked.

    The legacy implementation returned `{}` whenever the read failed for any
    reason. Combined with the merge-on-save flow, that meant a single read
    glitch (AV scan, partial write, transient lock) silently reset the config
    on the next `save_config` — wiping recent_* lists across every tab.
    """
    primary = _read_config_file(CONFIG_PATH)
    if primary is not None:
        return primary
    backup = _read_config_file(CONFIG_BAK_PATH)
    if backup is not None:
        return backup
    return {}


def save_config(data):
    """Merge `data` into the live config; never overwrites unrelated keys.

    The write goes through a sibling `.tmp` file + fsync + `os.replace` so a
    process kill or filesystem interruption mid-write can no longer leave a
    partial JSON on disk. After the live file is replaced, it is mirrored to
    `.bak` so a future read failure has a known-good fallback.

    Serialized under ``_CONFIG_LOCK`` so concurrent load→merge→replace writers
    cannot silently resurrect-over each other's keys.

    Returns True on success, False on failure. On failure the prior live file
    is left intact, the sibling ``.tmp`` is removed when present, and the
    exception is logged with path + operation. Callers that ignore the return
    value remain compatible.
    """
    tmp_path = CONFIG_PATH + ".tmp"
    try:
        with _CONFIG_LOCK:
            cfg = load_config()
            cfg.update(data)
            with open(tmp_path, "w", encoding="utf-8") as f:
                # ensure_ascii stays default-True: values can carry unpaired
                # surrogates from os.listdir on NTFS, which ensure_ascii=False
                # + utf-8 REFUSES to encode — one such key would then brick
                # every future save (the merge re-includes it). Escaped ASCII
                # output also keeps older builds' locale readers compatible.
                json.dump(cfg, f, indent=2)
                try:
                    f.flush()
                    os.fsync(f.fileno())
                except Exception:
                    pass
            os.replace(tmp_path, CONFIG_PATH)
            # Mirror the successful write to .bak so the next launch has a
            # fallback if the primary file becomes unreadable.
            try:
                shutil.copyfile(CONFIG_PATH, CONFIG_BAK_PATH)
            except Exception:
                pass
        return True
    except Exception as e:
        try:
            # Re-acquire the lock for cleanup (the `with` above has already
            # released it on exception): otherwise this could delete a
            # CONCURRENT writer's freshly-staged .tmp in its close->replace
            # window, failing that healthy save spuriously.
            with _CONFIG_LOCK:
                if os.path.isfile(tmp_path):
                    os.remove(tmp_path)
        except Exception:
            pass
        print(
            f"[config] save_config failed path={CONFIG_PATH} op=write: {e}")
        return False


