def select_initial_tempo_us(mid):
    """Return the intended initial tempo (µs/beat) of a loaded MidiFile.

    Type-1 files can carry set_tempo events on any track; the intended
    initial tempo is the one in effect at the LOWEST absolute tick across
    the whole file, not the last track visited. Among several events at
    that same tick, the LAST one in file order wins — matching SMF
    semantics, mido merged playback, and parse_midi's own tempo map
    (later same-tick entries override earlier ones), so this BPM agrees
    with the timeline the notes are actually placed on. Defaults to
    500000 (120 BPM) when the file has no tempo event.
    """
    best_tick = None
    best_tempo = None
    for track in mid.tracks:
        abs_tick = 0
        for msg in track:
            abs_tick += msg.time
            if best_tick is not None and abs_tick > best_tick:
                # abs_tick is monotonic within a track — nothing at or
                # before the current best tick can follow in this track.
                break
            if msg.type == 'set_tempo':
                if best_tick is None or abs_tick < best_tick:
                    best_tick, best_tempo = abs_tick, msg.tempo
                elif abs_tick == best_tick:
                    best_tempo = msg.tempo  # last-at-tick wins (SMF)
    return best_tempo if best_tempo is not None else 500000


def parse_midi(midi_path):
    mid = mido.MidiFile(midi_path)
    ticks_per_beat = mid.ticks_per_beat

    # Build a tempo map — external MIDIs may have multiple tempo changes
    tempo_map = []  # list of (abs_tick, tempo_us)
    for track in mid.tracks:
        abs_tick = 0
        for msg in track:
            abs_tick += msg.time
            if msg.type == 'set_tempo':
                tempo_map.append((abs_tick, msg.tempo))
    if not tempo_map:
        tempo_map = [(0, 500000)]  # default 120 BPM
    tempo_map.sort(key=lambda x: x[0])

    def ticks_to_seconds(abs_tick):
        """Convert absolute ticks to seconds using the tempo map."""
        time_sec = 0.0
        prev_tick = 0
        prev_tempo = 500000
        for change_tick, tempo in tempo_map:
            if change_tick >= abs_tick:
                break
            time_sec += (change_tick - prev_tick) * prev_tempo / ticks_per_beat / 1_000_000
            prev_tick = change_tick
            prev_tempo = tempo
        time_sec += (abs_tick - prev_tick) * prev_tempo / ticks_per_beat / 1_000_000
        return time_sec

    notes = []
    for track in mid.tracks:
        abs_tick = 0
        for msg in track:
            abs_tick += msg.time
            if msg.type == 'note_on' and msg.velocity > 0:
                # Store (abs_tick, note, velocity, time_in_seconds)
                notes.append((abs_tick, msg.note, msg.velocity,
                              ticks_to_seconds(abs_tick)))
    notes.sort(key=lambda x: x[0])
    return mid, notes, ticks_per_beat


def detect_bpm_and_offset(audio_path, midi_notes, ticks_per_beat, log_fn=print):
    import librosa
    import numpy as np

    log_fn("Analyzing audio for BPM detection...")
    y, sr = librosa.load(audio_path, sr=None)
    duration = len(y) / sr
    log_fn(f"  Audio duration: {duration:.1f}s, sample rate: {sr}")

    onset_frames = librosa.onset.onset_detect(y=y, sr=sr, units='frames', backtrack=True)
    audio_onsets = librosa.frames_to_time(onset_frames, sr=sr)
    log_fn(f"  Audio onsets detected: {len(audio_onsets)}")

    if len(audio_onsets) < 10:
        log_fn("  WARNING: Too few onsets. Falling back to 120 BPM.")
        return 120.0, 0.0, audio_onsets

    log_fn("  Searching for best BPM + offset alignment...")
    log_fn("  (This may take 30-60 seconds...)")

    best_bpm, best_offset, best_score = 120.0, 0.0, float('inf')
    num_check = min(100, len(midi_notes))

    for bpm_10x in range(800, 2000, 5):
        test_bpm = bpm_10x / 10.0
        test_tempo = int(60_000_000 / test_bpm)
        # F6 Option A (owner-approved 2026-07-07): times must DEPEND on the
        # tested BPM or the search is a no-op. parse_midi always emits 4-tuples,
        # so the old `n[3] if len(n)==4` shortcut made every BPM score identical
        # and the first candidate (~79.5) always won. Tick-based times restore
        # the fit (validated: tools/bpm_fix_validation.py).
        test_times = [mido.tick2second(n[0], ticks_per_beat, test_tempo) for n in midi_notes[:num_check]]

        for offset_ms in range(-3000, 3000, 25):
            offset = offset_ms / 1000.0
            shifted = [t + offset for t in test_times]
            total_dist = sum(np.min(np.abs(audio_onsets - mt)) for mt in shifted)
            avg_dist = total_dist / num_check
            if avg_dist < best_score:
                best_score = avg_dist
                best_bpm = test_bpm
                best_offset = offset

    # Refine
    for bpm_100x in range(int(best_bpm * 100) - 50, int(best_bpm * 100) + 51, 1):
        test_bpm = bpm_100x / 100.0
        test_tempo = int(60_000_000 / test_bpm)
        # F6 Option A: tick-based times (see the coarse loop's note above).
        test_times = [mido.tick2second(n[0], ticks_per_beat, test_tempo) for n in midi_notes[:num_check]]
        for offset_ms in range(int(best_offset * 1000) - 100, int(best_offset * 1000) + 101, 5):
            offset = offset_ms / 1000.0
            shifted = [t + offset for t in test_times]
            total_dist = sum(np.min(np.abs(audio_onsets - mt)) for mt in shifted)
            avg_dist = total_dist / num_check
            if avg_dist < best_score:
                best_score = avg_dist
                best_bpm = test_bpm
                best_offset = offset

    # Offset re-fit on the PLACEMENT timeline (owner-approved 2026-07-12):
    # the F6 search above scores candidate BPMs on tick-derived times, but
    # export places notes at n[3] (embedded-tempo-map seconds) + offset — see
    # build_rlrr ("BPM doesn't move notes — offset does"). Whenever the
    # embedded tempo != best_bpm, an offset fitted on the tick timeline
    # desyncs the chart progressively. Re-fit ONLY the offset against the
    # placement times, holding best_bpm fixed (it still feeds bpmEvents /
    # difficulty reduction / SyncTrack). Same grids + aggregation as the
    # search; identical output when embedded tempo == best_bpm.
    _refit_tempo = int(60_000_000 / best_bpm)
    _place_times = [(n[3] if len(n) == 4 else
                     mido.tick2second(n[0], ticks_per_beat, _refit_tempo))
                    for n in midi_notes[:num_check]]
    _refit_offset, _refit_score = best_offset, float('inf')
    for offset_ms in range(-3000, 3000, 25):
        offset = offset_ms / 1000.0
        shifted = [t + offset for t in _place_times]
        total_dist = sum(np.min(np.abs(audio_onsets - mt)) for mt in shifted)
        avg_dist = total_dist / num_check
        if avg_dist < _refit_score:
            _refit_score = avg_dist
            _refit_offset = offset
    for offset_ms in range(int(_refit_offset * 1000) - 100, int(_refit_offset * 1000) + 101, 5):
        offset = offset_ms / 1000.0
        shifted = [t + offset for t in _place_times]
        total_dist = sum(np.min(np.abs(audio_onsets - mt)) for mt in shifted)
        avg_dist = total_dist / num_check
        if avg_dist < _refit_score:
            _refit_score = avg_dist
            _refit_offset = offset
    best_offset, best_score = _refit_offset, _refit_score

    log_fn(f"  Best match: {best_bpm:.2f} BPM with offset {best_offset:+.3f}s")
    log_fn(f"  Average note-to-onset distance: {best_score:.3f}s")

    final_tempo = int(60_000_000 / best_bpm)
    all_times = [(n[3] if len(n)==4 else mido.tick2second(n[0], ticks_per_beat, final_tempo)) + best_offset for n in midi_notes]
    for label, idx in [("start", 0), ("25%", len(all_times)//4),
                       ("50%", len(all_times)//2), ("75%", 3*len(all_times)//4),
                       ("end", len(all_times)-1)]:
        mt = all_times[idx]
        closest = audio_onsets[np.argmin(np.abs(audio_onsets - mt))]
        log_fn(f"  Alignment at {label:5s}: MIDI {mt:.3f}s -> Audio {closest:.3f}s (diff: {closest-mt:+.3f}s)")

    return best_bpm, best_offset, audio_onsets


def validate_alignment(event_times, audio_onsets, audio_duration, log_fn=print):
    """
    Check alignment quality across the full song. Returns True if OK, False if problems found.
    Warns about:
      - Section-by-section drift (notes going out of sync partway through)
      - Structural mismatches (MIDI gaps don't match audio gaps)
      - Notes landing past the end of the audio
      - Overall poor alignment score
    """
    import numpy as np

    warnings = []
    log_fn("\n--- Sync Quality Check ---")

    if len(event_times) == 0 or len(audio_onsets) == 0:
        log_fn("  Cannot validate: no events or no audio onsets.")
        return True

    et = np.array(event_times, dtype=float)

    # 1. Section-by-section alignment (20-second windows)
    section_drifts = []
    log_fn("  Section alignment:")
    for start in range(0, int(et[-1]) + 1, 20):
        end = start + 20
        mask = (et >= start) & (et < end)
        section = et[mask]
        if len(section) >= 3:
            diffs = [audio_onsets[np.argmin(np.abs(audio_onsets - t))] - t for t in section]
            avg_diff = np.mean(diffs)
            section_drifts.append((start, end, avg_diff, len(section)))
            status = "OK" if abs(avg_diff) < 0.3 else "DRIFT" if abs(avg_diff) < 1.0 else "BAD"
            symbol = "  " if status == "OK" else " !" if status == "DRIFT" else "!!"
            log_fn(f"  {symbol} {start:3d}s-{end:3d}s: avg drift {avg_diff:+.3f}s ({len(section)} notes) [{status}]")

    # 2. Check for progressive drift (does it get worse over time?)
    if len(section_drifts) >= 4:
        first_quarter = [d for s, e, d, n in section_drifts[:len(section_drifts)//4]]
        last_quarter = [d for s, e, d, n in section_drifts[-(len(section_drifts)//4):]]
        if first_quarter and last_quarter:
            early_drift = abs(np.mean(first_quarter))
            late_drift = abs(np.mean(last_quarter))
            if late_drift > 0.5 and late_drift > early_drift * 3:
                msg = (f"Progressive drift detected: early avg {np.mean(first_quarter):+.3f}s "
                       f"vs late avg {np.mean(last_quarter):+.3f}s. "
                       f"The MIDI may have been authored at a slightly wrong tempo.")
                warnings.append(msg)
                log_fn(f"\n  ⚠ WARNING: {msg}")

    # 3. Check for structural mismatch (compare gap patterns)
    midi_gaps = np.diff(et)
    audio_gap_times = np.diff(audio_onsets)

    big_midi_gaps = [(et[i], et[i+1], g) for i, g in enumerate(midi_gaps) if g > 5.0]
    big_audio_gaps = [(audio_onsets[i], audio_onsets[i+1], g)
                      for i, g in enumerate(audio_gap_times) if g > 5.0]

    if big_midi_gaps:
        log_fn(f"\n  MIDI gaps > 5s:")
        for start, end, gap in big_midi_gaps:
            log_fn(f"    {start:.1f}s to {end:.1f}s ({gap:.1f}s gap)")
    if big_audio_gaps:
        log_fn(f"  Audio gaps > 5s:")
        for start, end, gap in big_audio_gaps:
            log_fn(f"    {start:.1f}s to {end:.1f}s ({gap:.1f}s gap)")

    # Check if big gaps are mismatched
    if big_midi_gaps and big_audio_gaps:
        for m_start, m_end, m_gap in big_midi_gaps:
            matched = False
            for a_start, a_end, a_gap in big_audio_gaps:
                # Check if this MIDI gap roughly corresponds to an audio gap
                if abs(m_start - a_start) < 10 and abs(m_gap - a_gap) > 5:
                    msg = (f"Structural mismatch: MIDI has a {m_gap:.1f}s gap at {m_start:.0f}s "
                           f"but audio has a {a_gap:.1f}s gap at {a_start:.0f}s. "
                           f"The MIDI may be for a different version/edit of this song.")
                    warnings.append(msg)
                    log_fn(f"\n  ⚠ WARNING: {msg}")
                    matched = True
                    break
            if not matched:
                # MIDI gap with no corresponding audio gap nearby
                nearest_audio_gap = None
                for a_start, a_end, a_gap in big_audio_gaps:
                    if nearest_audio_gap is None or abs(m_start - a_start) < abs(m_start - nearest_audio_gap[0]):
                        nearest_audio_gap = (a_start, a_end, a_gap)
                if nearest_audio_gap and abs(m_start - nearest_audio_gap[0]) > 15:
                    msg = (f"MIDI has a {m_gap:.1f}s gap at {m_start:.0f}s with no matching "
                           f"audio gap nearby. The MIDI may not match this audio.")
                    warnings.append(msg)
                    log_fn(f"\n  ⚠ WARNING: {msg}")

    elif big_midi_gaps and not big_audio_gaps:
        msg = (f"MIDI has {len(big_midi_gaps)} gap(s) > 5s but audio has none. "
               f"The MIDI may not match this audio.")
        warnings.append(msg)
        log_fn(f"\n  ⚠ WARNING: {msg}")

    # 4. Check for notes past end of audio
    notes_past_end = sum(1 for t in et if t > audio_duration)
    if notes_past_end > 0:
        msg = (f"{notes_past_end} notes land after the audio ends ({audio_duration:.1f}s). "
               f"The MIDI may be too long or at the wrong tempo.")
        warnings.append(msg)
        log_fn(f"\n  ⚠ WARNING: {msg}")

    # 5. Check for notes way before audio starts
    if len(audio_onsets) > 0:
        audio_start = audio_onsets[0]
        early_notes = sum(1 for t in et if t < audio_start - 2.0)
        if early_notes > 2:
            msg = (f"{early_notes} notes land more than 2s before the first audio onset "
                   f"({audio_start:.1f}s). These may be stray notes in the MIDI.")
            warnings.append(msg)
            log_fn(f"\n  ⚠ WARNING: {msg}")

    # 6. Overall quality score
    all_diffs = [abs(audio_onsets[np.argmin(np.abs(audio_onsets - t))] - t) for t in et]
    pct_good = sum(1 for d in all_diffs if d < 0.15) / len(all_diffs) * 100
    pct_ok = sum(1 for d in all_diffs if d < 0.5) / len(all_diffs) * 100
    avg_all = np.mean(all_diffs)

    log_fn(f"\n  Overall quality:")
    log_fn(f"    {pct_good:.0f}% of notes within 150ms of an audio hit")
    log_fn(f"    {pct_ok:.0f}% of notes within 500ms of an audio hit")
    log_fn(f"    Average distance: {avg_all:.3f}s")

    if pct_good >= 80 and not warnings:
        log_fn(f"    Rating: EXCELLENT - should play great!")
    elif pct_good >= 60 and not warnings:
        log_fn(f"    Rating: GOOD - should be playable with minor drift")
    elif pct_ok >= 70 and not warnings:
        log_fn(f"    Rating: FAIR - noticeable sync issues in some sections")
    elif warnings:
        log_fn(f"    Rating: POOR - sync problems detected (see warnings above)")
    else:
        log_fn(f"    Rating: POOR - significant sync problems likely")
        warnings.append("Overall alignment quality is poor. "
                        "The MIDI may not match this audio file.")

    # Summary
    if warnings:
        log_fn(f"\n  === {len(warnings)} WARNING(S) FOUND ===")
        log_fn(f"  The output file was still created, but may not sync well.")
        log_fn(f"  Consider finding a different MIDI that matches your audio.")
    else:
        log_fn(f"\n  No warnings - alignment looks good!")

    return len(warnings) == 0


# ---------------------------------------------------------------------------
# Pre-flight validator (Phase 1 of v4.3.0 roadmap)
#
# Surfaces structural / semantic export-blocking issues *before* the user hits
# Convert. Pure function — no Tkinter, no logging side-effects. Runs read-only
# on the same input data structures `build_rlrr` consumes; `build_rlrr` itself
# is untouched.
#
# Scope is deliberately structural-only in v1: bug-or-not checks that cannot
# be argued with. Ergonomic playability (third-arm, crossover physics, BPM-vs-
# density reachability) is out of scope here — those are taste calls and
# belong to editor-time lint, not export-time validation.
# ---------------------------------------------------------------------------
PFV_HUGE_GAP_SECONDS              = 30.0
PFV_AUDIO_DURATION_TOLERANCE_S    = 1.0
PFV_OVERLAP_SAME_LANE_MS          = 20
PFV_FIRST_NOTE_TOO_EARLY_S        = 0.5
# Standard GM percussion range — notes outside this range are not "lane
# unmapped" candidates, they're just non-drum data we ignore quietly.
PFV_DRUM_NOTE_RANGE               = (35, 81)


@dataclass
class ValidationIssue:
    """One pre-flight finding. Pure data — no UI dependencies."""
    severity: str                          # "error" | "warn" | "info"
    code: str                              # e.g. "PFV_AUDIO_MISSING"
    message: str                           # human-readable, plain English
    fix_hint: str = ""                     # actionable next step
    time_s: Optional[float] = None         # for click-to-jump in the modal
    note_idx: Optional[int] = None         # index into midi_notes if relevant


def _pfv_audio_duration(audio_path):
    """Return audio duration in seconds, or None if unreadable."""
    if not audio_path or not os.path.exists(audio_path):
        return None
    try:
        import soundfile as sf
        return float(sf.info(audio_path).duration)
    except Exception:
        try:
            import librosa
            y, sr = librosa.load(audio_path, sr=None, mono=True)
            return float(len(y)) / float(sr) if sr else None
        except Exception:
            return None


def validate_chart(midi_notes, audio_path, song_meta, mapping,
                   ticks_per_beat=480, bpm=None, offset=0.0,
                   difficulties=None, reduce_fn=None):
    """
    Run all v1 structural pre-flight checks.

    Parameters
    ----------
    midi_notes : list of (tick, note, velocity[, precomputed_sec])
        Same shape `build_rlrr` consumes. Read-only.
    audio_path : str
        Path to the song audio file (the one that will ship with the chart).
    song_meta : dict
        Free-form metadata. Recognized keys: title, artist, bpm, offset.
        Anything else is ignored.
    mapping : dict
        MIDI-note-number -> Paradiddle instrument-class string. Pass
        `MIDI_MAP` for the default mapping.
    ticks_per_beat, bpm, offset : float
        Used to compute per-note seconds when notes are 3-tuples. Ignored
        for 4-tuples (precomputed_sec is used).
    difficulties : list of str or None
        Difficulties enabled for export. If None, no per-difficulty checks
        run. If provided, `reduce_fn` should be `reduce_notes_for_difficulty`
        so the validator can confirm each difficulty has notes after
        reduction.
    reduce_fn : callable or None
        Injected to avoid forward-reference. Pass `reduce_notes_for_difficulty`.

    Returns
    -------
    list[ValidationIssue]
        All findings. Caller decides how to surface them and whether to
        block on `severity == "error"`.
    """
    issues: List[ValidationIssue] = []

    # --- Resolve metadata -------------------------------------------------
    sm = song_meta or {}
    sm_title  = (sm.get("title")  or "").strip()
    sm_artist = (sm.get("artist") or "").strip()
    sm_bpm    = sm.get("bpm",    bpm)
    sm_offset = sm.get("offset", offset)

    # PFV_BPM_OFFSET_UNSET — BPM = 0 / None or offset is None. ERROR.
    bpm_unset    = (sm_bpm is None) or (isinstance(sm_bpm, (int, float)) and sm_bpm <= 0)
    offset_unset = (sm_offset is None)
    if bpm_unset or offset_unset:
        bits = []
        if bpm_unset:    bits.append("BPM is not set (0 or empty)")
        if offset_unset: bits.append("offset is not set")
        issues.append(ValidationIssue(
            severity="error", code="PFV_BPM_OFFSET_UNSET",
            message="; ".join(bits) + ".",
            fix_hint="Run BPM detection or enter a manual BPM/offset before exporting."))

    # PFV_METADATA_MISSING — title or artist empty. WARN.
    if not sm_title or not sm_artist:
        missing = []
        if not sm_title:  missing.append("title")
        if not sm_artist: missing.append("artist")
        issues.append(ValidationIssue(
            severity="warn", code="PFV_METADATA_MISSING",
            message=f"Missing metadata: {', '.join(missing)}.",
            fix_hint="Fill in Title and Artist in the Song Creator tab."))

    # --- Audio file checks ------------------------------------------------
    audio_duration = None
    if not audio_path:
        issues.append(ValidationIssue(
            severity="error", code="PFV_AUDIO_MISSING",
            message="No audio file selected.",
            fix_hint="Pick a song audio file in the Audio field."))
    elif not os.path.exists(audio_path):
        issues.append(ValidationIssue(
            severity="error", code="PFV_AUDIO_MISSING",
            message=f"Audio file does not exist: {audio_path}",
            fix_hint="Re-select the audio file or verify it has not been moved/deleted."))
    else:
        audio_duration = _pfv_audio_duration(audio_path)
        if audio_duration is None:
            issues.append(ValidationIssue(
                severity="error", code="PFV_AUDIO_MISSING",
                message=f"Audio file is unreadable: {audio_path}",
                fix_hint="Verify the file is a valid mp3/wav/flac/ogg and is not corrupt."))

    # --- Notes: build a (time_s, midi_note, velocity, idx) table ----------
    # Mirror `build_rlrr`'s tick-to-second handling so timing reports match
    # what users will see in the exported chart.
    safe_bpm = sm_bpm if (isinstance(sm_bpm, (int, float)) and sm_bpm > 0) else 120.0
    tempo_us = int(60_000_000 / safe_bpm)
    safe_offset = sm_offset if isinstance(sm_offset, (int, float)) else 0.0

    rows = []  # (time_s, midi_note, velocity, idx)
    for idx, note_data in enumerate(midi_notes or []):
        if len(note_data) >= 4:
            tick, note, velocity, precomputed_sec = note_data[:4]
            time_sec = float(precomputed_sec) + safe_offset
        else:
            tick, note, velocity = note_data[:3]
            time_sec = mido.tick2second(tick, ticks_per_beat, tempo_us) + safe_offset
        rows.append((time_sec, int(note), int(velocity), idx))

    # PFV_VEL_OUT_OF_RANGE — velocity outside 1..127. ERROR per note (capped).
    vel_bad = [r for r in rows if not (1 <= r[2] <= 127)]
    if vel_bad:
        # Cap at 5 distinct error rows so the modal stays readable; summarize the rest.
        for r in vel_bad[:5]:
            time_s, midi_note, velocity, idx = r
            issues.append(ValidationIssue(
                severity="error", code="PFV_VEL_OUT_OF_RANGE",
                message=f"Note {idx} at {time_s:.3f}s has velocity {velocity} (must be 1-127).",
                fix_hint="Re-run detection or fix the velocity in the MIDI Editor.",
                time_s=time_s, note_idx=idx))
        if len(vel_bad) > 5:
            issues.append(ValidationIssue(
                severity="error", code="PFV_VEL_OUT_OF_RANGE",
                message=f"... and {len(vel_bad) - 5} more notes with out-of-range velocity.",
                fix_hint="Open the MIDI Editor and run Vel Filter to clamp velocities."))

    # PFV_LANE_UNMAPPED — note in standard drum range but not in mapping.
    # Notes outside 35-81 are silently ignored (non-drum data). Notes inside
    # the drum range that are not in MIDI_MAP would be silently dropped by
    # `build_rlrr`, so we surface them as ERRORs here.
    mapping_keys = set(mapping.keys()) if mapping else set()
    lane_unmapped = [r for r in rows
                     if PFV_DRUM_NOTE_RANGE[0] <= r[1] <= PFV_DRUM_NOTE_RANGE[1]
                     and r[1] not in mapping_keys]
    if lane_unmapped:
        bad_notes = sorted(set(r[1] for r in lane_unmapped))
        # One issue per *distinct* MIDI note number, not per occurrence.
        for bad_note in bad_notes[:8]:
            first = next(r for r in lane_unmapped if r[1] == bad_note)
            count = sum(1 for r in lane_unmapped if r[1] == bad_note)
            issues.append(ValidationIssue(
                severity="error", code="PFV_LANE_UNMAPPED",
                message=f"MIDI note {bad_note} ({count} hit{'s' if count != 1 else ''}) "
                        f"is in the drum range but has no Paradiddle lane mapping.",
                fix_hint="Use the MIDI Editor to reassign these hits to a mapped lane "
                         "(35/36 kick, 38/40 snare, 42/46 hi-hat, 41/43 floor tom, "
                         "45/47 tom 2, 48/50 tom 1, 49/55/57 crash, 51/53/59 ride).",
                time_s=first[0], note_idx=first[3]))
        if len(bad_notes) > 8:
            issues.append(ValidationIssue(
                severity="error", code="PFV_LANE_UNMAPPED",
                message=f"... and {len(bad_notes) - 8} more unmapped MIDI note numbers.",
                fix_hint="Bulk-reclassify in the MIDI Editor."))

    # Notes that *will* end up in the chart (mapped, non-negative time).
    # Negative-time notes are dropped silently by `build_rlrr`; mirror that here.
    playable = [r for r in rows
                if r[1] in mapping_keys and r[0] >= 0
                and 1 <= r[2] <= 127]

    # PFV_NO_NOTES — zero playable notes. ERROR.
    if not playable:
        issues.append(ValidationIssue(
            severity="error", code="PFV_NO_NOTES",
            message="Chart contains zero playable notes after filtering.",
            fix_hint="Re-run Audio→MIDI detection on the drums-only stem, "
                     "or open the MIDI Editor to verify notes exist."))

    # --- Time-domain checks (need playable notes) -------------------------
    if playable:
        playable_sorted = sorted(playable, key=lambda r: r[0])
        first_time = playable_sorted[0][0]
        last_time  = playable_sorted[-1][0]

        # PFV_AUDIO_DURATION_MISMATCH — last note > audio_duration + 1s. ERROR.
        if audio_duration is not None and last_time > audio_duration + PFV_AUDIO_DURATION_TOLERANCE_S:
            issues.append(ValidationIssue(
                severity="error", code="PFV_AUDIO_DURATION_MISMATCH",
                message=f"Last note at {last_time:.2f}s extends past audio end "
                        f"({audio_duration:.2f}s) by {last_time - audio_duration:.2f}s.",
                fix_hint="Check BPM/offset, or trim trailing notes in the MIDI Editor.",
                time_s=last_time))

        # PFV_FIRST_NOTE_TOO_EARLY — first note < 0.5s from audio start. WARN.
        if first_time < PFV_FIRST_NOTE_TOO_EARLY_S:
            issues.append(ValidationIssue(
                severity="warn", code="PFV_FIRST_NOTE_TOO_EARLY",
                message=f"First note at {first_time:.3f}s — Paradiddle expects "
                        f"at least {PFV_FIRST_NOTE_TOO_EARLY_S:.1f}s of lead-in.",
                fix_hint="Increase the audio offset or pad silence at the start of the audio.",
                time_s=first_time))

        # PFV_KICK_ONLY — chart contains only kick notes. WARN (likely detection failure).
        kick_classes = {"BP_Kick_C"}
        classes_present = {mapping.get(r[1]) for r in playable}
        non_kick = classes_present - kick_classes - {None}
        if not non_kick:
            issues.append(ValidationIssue(
                severity="warn", code="PFV_KICK_ONLY",
                message=f"Chart contains only kick notes ({len(playable)} hits).",
                fix_hint="Detection probably failed for hand drums. Re-run on a "
                         "drums-only stem with the ML or Hybrid engine."))

        # PFV_OVERLAP_SAME_LANE — two notes on same lane within 20 ms. WARN.
        # Group by mapped class, then walk consecutive pairs.
        by_class = {}
        for r in playable_sorted:
            cls = mapping.get(r[1])
            by_class.setdefault(cls, []).append(r)
        overlap_count = 0
        first_overlap_time = None
        threshold_s = PFV_OVERLAP_SAME_LANE_MS / 1000.0
        for cls, group in by_class.items():
            for a, b in zip(group, group[1:]):
                if (b[0] - a[0]) < threshold_s:
                    overlap_count += 1
                    if first_overlap_time is None:
                        first_overlap_time = a[0]
        if overlap_count:
            issues.append(ValidationIssue(
                severity="warn", code="PFV_OVERLAP_SAME_LANE",
                message=f"{overlap_count} pair(s) of notes on the same lane within "
                        f"{PFV_OVERLAP_SAME_LANE_MS} ms — Paradiddle drops the second hit.",
                fix_hint="Run Dedup in the MIDI Editor to merge or remove the duplicates.",
                time_s=first_overlap_time))

        # PFV_HUGE_GAP — > 30s of silence inside the chart. INFO.
        biggest_gap = 0.0
        biggest_gap_time = None
        for a, b in zip(playable_sorted, playable_sorted[1:]):
            gap = b[0] - a[0]
            if gap > biggest_gap:
                biggest_gap = gap
                biggest_gap_time = a[0]
        if biggest_gap > PFV_HUGE_GAP_SECONDS:
            issues.append(ValidationIssue(
                severity="info", code="PFV_HUGE_GAP",
                message=f"{biggest_gap:.1f}s gap between notes "
                        f"(starts at {biggest_gap_time:.2f}s).",
                fix_hint="Probably a detection drop on a quiet section. "
                         "Open the MIDI Editor and verify the gap is intentional.",
                time_s=biggest_gap_time))

    # --- PFV_DIFFICULTY_EMPTY — per-difficulty reduction check ------------
    if difficulties and reduce_fn and playable:
        # Build a minimal events list matching `build_rlrr` output schema so
        # `reduce_notes_for_difficulty` can chew on it. Use the same fields
        # it reads (`name`, `vel`, `time`).
        rough_events = []
        for time_s, midi_note, velocity, _idx in playable:
            cls = mapping.get(midi_note)
            inst_name = CLASS_TO_NAME.get(cls) if cls else None
            if inst_name is None:
                continue
            rough_events.append({
                "name": inst_name,
                "vel":  velocity,
                "loc":  0,
                "time": "%.4f" % time_s,
            })
        for diff in difficulties:
            if diff == "Expert":
                # No reduction applied — Expert is always non-empty if playable is.
                continue
            try:
                reduced = reduce_fn(list(rough_events), safe_bpm, diff)
            except Exception:
                # Reduction itself blew up — surface as ERROR but don't crash
                # the validator.
                issues.append(ValidationIssue(
                    severity="error", code="PFV_DIFFICULTY_EMPTY",
                    message=f"Difficulty reduction for '{diff}' raised an exception.",
                    fix_hint="Open an issue — this should never happen on valid input."))
                continue
            if not reduced:
                issues.append(ValidationIssue(
                    severity="error", code="PFV_DIFFICULTY_EMPTY",
                    message=f"Difficulty '{diff}' has zero notes after reduction.",
                    fix_hint="Disable this difficulty for export, or use a denser source chart."))

    return issues


# Severity → display order / blocking semantics
PFV_SEVERITY_ORDER    = {"error": 0, "warn": 1, "info": 2}
PFV_BLOCKING_SEVERITY = "error"


# ── Phase 2 (v4.3.0 roadmap) — Batch / Template mode helpers ─────────────────
# Module-level pure functions, no Tk. Mirror the validator pattern from Phase 1.

# Pinned template schema — see PLAN_v4.3.0_roadmap.md Phase 2 step 3.
BATCH_TEMPLATE_SCHEMA_VERSION = 1

# Strings the template's `detection.genre` field is allowed to take. Must match
# the keys the active `_a2m_genre_params` switch already accepts; re-grep at
# implementation time. (Source of truth: ParaKit v4.0.py `_a2m_genre_params`.)
BATCH_TEMPLATE_VALID_GENRES = {"auto", "raw", "pop_rock", "metal", "punk", "funk"}

# `mapping.name` — only `rhythm_game` is wired up today. The plan keeps this
# field for forward compatibility; reject anything else loud per plan step 3.
BATCH_TEMPLATE_VALID_MAPPINGS = {"rhythm_game"}

# Difficulty labels accepted by `reduce_notes_for_difficulty` in this file.
BATCH_TEMPLATE_VALID_DIFFICULTIES = {"Easy", "Medium", "Hard", "Expert"}

# Overwrite policies for already-existing output folders.
BATCH_TEMPLATE_VALID_OVERWRITE = {"skip", "overwrite", "rename"}

# Audio extensions the folder scanner picks up. Match Single Song Creator's
# accept list so a song that imports there imports here too.
BATCH_AUDIO_EXTS = (".mp3", ".wav", ".flac", ".ogg", ".m4a")


def batch_template_default():
    """Return a fresh copy of the built-in default template dict.

    Used when the user runs Folder mode without picking a template file.
    Values mirror `templates/default.json`; the on-disk file is the
    user-editable copy and this in-code dict is the safety net.

    NOTE on schema: the on-disk schema (v1) ships flatter than the verbose
    block sketched in PLAN_v4.3.0_roadmap.md Phase 2 step 3 — detection
    settings are intentionally NOT template-driven in v1, they come from the
    user's existing app config (Audio→MIDI tab settings persist there).
    The plan's `detection`/`mapping` blocks are reserved for a future schema
    bump; v1 only ships chart-level (difficulty/complexity/metadata/output)
    knobs because those are the only ones the existing single-song export
    codepath actually consumes per-call. Documented as a deviation from the
    plan in PARAKIT_CODEX_README.md.
    """
    return {
        "schema_version": BATCH_TEMPLATE_SCHEMA_VERSION,
        "name": "default",
        "chart": {
            "difficulty": "Expert",
            "complexity": 3,
            "creator": "ParaKit",
        },
        "difficulty_reduction": {
            "enabled": False,
            "difficulty": "Expert",
        },
        "metadata_defaults": {
            "artist": "",
            "album": "",
            "year": None,
            "genre": "",
        },
        "output": {
            "folder_pattern": "{title}",
            "overwrite_policy": "skip",
        },
    }


def batch_template_load(path):
    """Read a template JSON from disk. Returns the parsed dict, or raises."""
    with open(path, "r", encoding="utf-8") as f:
        return json.load(f)


def batch_template_validate(template):
    """Validate a template against the pinned schema.

    Returns a list[ValidationIssue]. Errors carry code `PFV_TEMPLATE_INVALID`
    (Phase-1 ERROR severity) so they surface through the same modal the rest
    of the validator uses. An empty list means the template is OK to run.
    """
    issues = []

    def err(msg, hint=""):
        issues.append(ValidationIssue(
            severity="error", code="PFV_TEMPLATE_INVALID",
            message=msg, fix_hint=hint))

    if not isinstance(template, dict):
        err("Template root is not a JSON object.",
            "Open the template in a text editor and confirm the outer braces are present.")
        return issues

    sv = template.get("schema_version")
    if sv != BATCH_TEMPLATE_SCHEMA_VERSION:
        err(f"Unsupported template schema_version: {sv!r}.",
            f"Set \"schema_version\": {BATCH_TEMPLATE_SCHEMA_VERSION} or pick a newer ParaKit build.")

    chart = template.get("chart") or {}
    if not isinstance(chart, dict):
        err("Template `chart` block is missing or not an object.",
            "Add a `chart` block — see templates/default.json.")
    else:
        d = chart.get("difficulty", "Expert")
        if d not in BATCH_TEMPLATE_VALID_DIFFICULTIES:
            err(f"Unknown chart.difficulty: {d!r}.",
                f"Valid values: {sorted(BATCH_TEMPLATE_VALID_DIFFICULTIES)}.")
        raw_cplx = chart.get("complexity", 3)
        if isinstance(raw_cplx, bool):
            err("chart.complexity must be an integer, not a boolean.",
                "Use an integer between 1 and 5.")
        else:
            try:
                c = int(raw_cplx)
                if c < 1 or c > 5:
                    err(f"chart.complexity out of range: {c}.",
                        "Pick a value between 1 and 5.")
            except (TypeError, ValueError):
                err("chart.complexity is not an integer.",
                    "Use an integer between 1 and 5.")
        creator = chart.get("creator", "")
        if creator is not None and not isinstance(creator, str):
            err("chart.creator must be a string.",
                "Quote the value in the JSON.")

    redux = template.get("difficulty_reduction") or {}
    if redux and not isinstance(redux, dict):
        err("Template `difficulty_reduction` must be an object if present.",
            "See templates/default.json.")
    elif isinstance(redux, dict):
        if "enabled" in redux and not isinstance(redux["enabled"], bool):
            err("difficulty_reduction.enabled must be true or false.",
                "Boolean only — no quotes.")
        rd = redux.get("difficulty", "Expert")
        if rd not in BATCH_TEMPLATE_VALID_DIFFICULTIES:
            err(f"Unknown difficulty_reduction.difficulty: {rd!r}.",
                f"Valid values: {sorted(BATCH_TEMPLATE_VALID_DIFFICULTIES)}.")

    out = template.get("output") or {}
    if not isinstance(out, dict):
        err("Template `output` block is missing or not an object.",
            "Add an `output` block — see templates/default.json.")
    else:
        op = out.get("overwrite_policy", "skip")
        if op not in BATCH_TEMPLATE_VALID_OVERWRITE:
            err(f"Unknown output.overwrite_policy: {op!r}.",
                f"Valid values: {sorted(BATCH_TEMPLATE_VALID_OVERWRITE)}.")
        fp = out.get("folder_pattern", "{artist} - {title}")
        if not isinstance(fp, str) or "{" not in fp:
            err(f"output.folder_pattern looks wrong: {fp!r}.",
                "Use a Python format string with at least one of "
                "{title}, {artist}, {album}, {filename}.")

    md = template.get("metadata_defaults", {})
    if md and not isinstance(md, dict):
        err("Template `metadata_defaults` must be an object if present.",
            "See templates/default.json.")

    return issues


def batch_audio_metadata_lookup(audio_path):
    """Pre-fill {title, artist, album, year} from an audio file's tags.

    Uses mutagen (already a project dependency for cover-art extraction).
    Returns a dict with whichever keys could be read; missing tags are simply
    absent so the caller can fall back to template defaults.
    """
    tags = {}
    if not audio_path or not os.path.exists(audio_path):
        return tags
    ext = os.path.splitext(audio_path)[1].lower()
    try:
        if ext == ".flac":
            from mutagen.flac import FLAC
            f = FLAC(audio_path)
            for key, dst in (("title", "title"), ("artist", "artist"),
                             ("album", "album"), ("date", "year")):
                v = f.get(key)
                if v:
                    tags[dst] = v[0] if isinstance(v, list) else str(v)
        elif ext == ".mp3":
            from mutagen.id3 import ID3, ID3NoHeaderError
            try:
                t = ID3(audio_path)
            except ID3NoHeaderError:
                return tags
            mapping = {"TIT2": "title", "TPE1": "artist", "TALB": "album", "TDRC": "year"}
            for fid, dst in mapping.items():
                if fid in t:
                    tags[dst] = str(t[fid].text[0]) if getattr(t[fid], "text", None) else str(t[fid])
        elif ext == ".ogg":
            from mutagen.oggvorbis import OggVorbis
            f = OggVorbis(audio_path)
            for key, dst in (("title", "title"), ("artist", "artist"),
                             ("album", "album"), ("date", "year")):
                v = f.get(key)
                if v:
                    tags[dst] = v[0] if isinstance(v, list) else str(v)
        elif ext in (".m4a", ".mp4"):
            from mutagen.mp4 import MP4
            f = MP4(audio_path)
            mp4_keys = {"\xa9nam": "title", "\xa9ART": "artist",
                        "\xa9alb": "album", "\xa9day": "year"}
            for k, dst in mp4_keys.items():
                v = f.tags.get(k) if f.tags else None
                if v:
                    tags[dst] = v[0] if isinstance(v, list) else str(v)
        # WAV: no standard tag block — leave empty.
    except Exception:
        # Tag read failures are non-fatal — fall back to template defaults.
        return tags
    # Strip whitespace + drop empties.
    return {k: v.strip() for k, v in tags.items() if v and str(v).strip()}


class _BatchFolderSlotShim:
    """Duck-typed slot for the Folder Batch path.

    `_batch_convert_one_slot` reads `slot["xxx_var"].get()` on every field
    plus `slot.get("_overwrite_policy")`. The slot-based UI uses real Tk
    StringVars; the folder path doesn't need Tk vars at all because the
    helper only ever reads them. This shim wraps each value in a tiny
    `.get()`-returning object and supports dict-style `.get(...)` for the
    optional `_overwrite_policy` flag.
    """
    class _V:
        __slots__ = ("_v",)
        def __init__(self, v): self._v = v
        def get(self): return self._v

    def __init__(self, midi, audio, title, artist, diff, complexity,
                 bpm, offset, reduce_enabled, overwrite_policy):
        V = _BatchFolderSlotShim._V
        self._fields = {
            "midi_var":     V(midi),
            "audio_var":    V(audio),
            "drum_var":     V(""),       # No drum-stem split in folder mode v1.
            "cover_var":    V(""),       # Per-file cover art is a Phase 2.5 item.
            "title_var":    V(title),
            "artist_var":   V(artist),
            "diff_var":     V(diff),
            "comp_var":     V(int(complexity)),
            "auto_bpm_var": V(False),    # We pre-detected BPM up the stack.
            "bpm_var":      V(str(bpm)),
            "offset_var":   V(str(offset)),
            "reduce_var":   V(bool(reduce_enabled)),
            "enabled_var":  V(True),
        }
        self._overwrite_policy = overwrite_policy

    def __getitem__(self, key):
        return self._fields[key]

    def get(self, key, default=None):
        if key == "_overwrite_policy":
            return self._overwrite_policy
        if key in self._fields:
            return self._fields[key]
        return default


def batch_format_folder_name(pattern, ctx):
    """Apply a template folder_pattern with safe fallbacks.

    Unknown keys resolve to "" rather than raising. Slashes / control chars
    are stripped to keep the result safe to use as a directory name.
    """
    class _SafeDict(dict):
        def __missing__(self, key):
            return ""
    try:
        name = pattern.format_map(_SafeDict(ctx))
    except Exception:
        name = ctx.get("title", "Untitled")
    # Strip directory separators and unprintable control chars.
    bad = '<>:"/\\|?*\x00\r\n\t'
    cleaned = "".join("_" if c in bad else c for c in name).strip()
    return cleaned or "Untitled"


def sanitize_fs_component(name, fallback="Untitled"):
    """Make a single path component safe on Windows. Filesystem names ONLY —
    never applied to metadata (titles inside .rlrr / notes.chart / song.ini
    stay verbatim; Paradiddle and ParaDB read display names from inside the
    files, not from the filename). Same char set as batch_format_folder_name."""
    bad = '<>:"/\\|?*\x00\r\n\t'
    cleaned = "".join("_" if c in bad else c for c in str(name))
    cleaned = cleaned.strip().rstrip(". ")           # Win32 strips trailing dots/spaces
    root = cleaned.split(".")[0].upper()
    if root in {"CON", "PRN", "AUX", "NUL",
                *(f"COM{i}" for i in range(1, 10)),
                *(f"LPT{i}" for i in range(1, 10))}:
        cleaned = "_" + cleaned                       # reserved device names
    return cleaned or fallback


def build_rlrr(midi_notes, ticks_per_beat, bpm, offset, title, artist, creator,
               song_tracks, drum_tracks, cover_image, complexity, difficulty,
               description=""):
    tempo_us = int(60_000_000 / bpm)
    midi_to_name = {n: CLASS_TO_NAME[c] for n, c in MIDI_MAP.items() if c in CLASS_TO_NAME}

    events = []
    for note_data in midi_notes:
        # Support both old 3-tuple (tick, note, vel) and new 4-tuple with pre-computed seconds
        if len(note_data) == 4:
            tick, note, velocity, precomputed_sec = note_data
            # Pre-computed tempo-map seconds + offset. NO BPM scaling happens
            # here (an older comment claimed it did — it never existed): bpm
            # only feeds tempo_us (3-tuple fallback) and the bpmEvents metadata.
            # "BPM doesn't move notes — offset does."
            time_sec = precomputed_sec + offset
        else:
            tick, note, velocity = note_data
            time_sec = mido.tick2second(tick, ticks_per_beat, tempo_us) + offset

        if note in midi_to_name and time_sec >= 0:
            events.append({
                "name": midi_to_name[note],
                "vel": velocity,
                "loc": 0,
                "time": "%.4f" % time_sec
            })

    events.sort(key=lambda e: float(e["time"]))
    last_time = float(events[-1]["time"]) if events else 0

    return {
        "version": 0.7,
        "recordingMetadata": {
            "title": title, "description": description or "", "coverImagePath": cover_image,
            "artist": artist, "creator": creator, "length": last_time + 5.0,
            "complexity": complexity
        },
        "audioFileData": {
            "songTracks": song_tracks, "drumTracks": drum_tracks, "calibrationOffset": 0
        },
        "instruments": DEFAULT_INSTRUMENTS,
        "events": events,
        "bpmEvents": [{"bpm": bpm, "time": 0.0}]
    }


# ---------------------------------------------------------------------------
# Difficulty-based note reduction (per-lane retention; see reduce_notes_for_difficulty)
# ---------------------------------------------------------------------------
# LEGACY v1 instrument-name sets (exact-suffix). The rebuilt reducer matches lanes
# by family PREFIX and no longer reads these; kept for reference only.
KICK_INSTRUMENTS    = {"BP_Kick_C_1"}
SNARE_INSTRUMENTS   = {"BP_Snare_C_1"}
HIHAT_INSTRUMENTS   = {"BP_HiHat_C_1"}
CRASH_INSTRUMENTS   = {"BP_Crash15_C_1", "BP_Crash17_C_1"}
RIDE_INSTRUMENTS    = {"BP_Ride17_C_1", "BP_Ride20_C_1"}
TOM_INSTRUMENTS     = {"BP_Tom1_C_1", "BP_Tom2_C_2", "BP_FloorTom_C_1"}

# All instruments that are always kept (crashes/rides stay on all difficulties)
ALWAYS_KEEP = CRASH_INSTRUMENTS | RIDE_INSTRUMENTS


# Per-(tier, lane) retention targets for reduce_notes_for_difficulty (v4.5.x
# rebuild 2026-06-22). Fractions of Expert notes to KEEP per lane, seeded from
# the human ParaDB tier profile (tools/detection_harness/results/
# human_tier_profile.json) and harness-validated (eval_difficulty_reduction.py).
_DIFFICULTY_RETENTION = {
    "Hard":   {"kick": 0.92, "snare": 0.95, "hihat": 1.00, "crash": 1.00,
               "ride": 0.95, "tom_mid": 0.92, "floor_tom": 0.85},
    "Medium": {"kick": 0.42, "snare": 0.73, "hihat": 0.73, "crash": 1.00,
               "ride": 0.55, "tom_mid": 0.46, "floor_tom": 0.42},
    "Easy":   {"kick": 0.18, "snare": 0.70, "hihat": 0.52, "crash": 1.00,
               "ride": 0.40, "tom_mid": 0.34, "floor_tom": 0.30},
}


def reduce_notes_for_difficulty(events, bpm, difficulty):
    """
    Difficulty reduction by PER-LANE RETENTION (v4.5.x rebuild, 2026-06-22).

    Each lane is KEPT but THINNED to the fraction of notes humans keep at the
    target tier (measured from the human ParaDB Easy/Medium/Hard charts), by
    selecting the metrically-strongest notes (downbeat > beat > 8th > 16th >
    off-grid). This REPLACES the v1 instrument on/off layering, which (a) dropped
    kick + toms entirely on Easy/Medium although humans keep thinned versions,
    (b) had a tempo-broken ghost-note test that was a no-op above ~100 BPM (so
    Hard collapsed into Expert), and (c) silently dropped instrument-name
    variants. Lanes are matched by family PREFIX, so variants (BP_Kick_C_0/_C_69,
    alt snares/toms, second crash/ride sizes) are no longer dropped; china/splash
    map to the crash lane. tambourine/cowbell/unknown have no lane and are dropped.

    Validated on tools/detection_harness/eval_difficulty_reduction.py vs the human
    ParaDB tiers (±50 ms, 98 tracks): macro-F Hard 0.85 / Medium 0.67 / Easy 0.53
    (v1 was 0.85 / 0.55 / 0.47). Expert is returned unchanged (no reduction).

    'complexity' (recording metadata) does NOT reach this function; the signature
    is (events, bpm, difficulty). Returns a new filtered + time-sorted list.
    """
    if difficulty == "Expert" or difficulty not in _DIFFICULTY_RETENTION:
        return events
    if not events:
        return []
    if not bpm or float(bpm) <= 0:
        return events   # degenerate tempo -> return unchanged rather than divide-by-zero
    beat = 60.0 / float(bpm)

    def _lane_of(name):
        if name.startswith("BP_Kick"):     return "kick"
        if name.startswith("BP_Snare"):    return "snare"
        if name.startswith("BP_HiHat"):    return "hihat"
        if name.startswith("BP_Crash") or name.startswith("BP_China") or name.startswith("BP_Splash"):
            return "crash"
        if name.startswith("BP_Ride"):     return "ride"
        if name.startswith("BP_FloorTom"): return "floor_tom"
        if name.startswith("BP_Tom"):      return "tom_mid"
        return None

    # Robust grid anchor: mode phase of the kick+snare backbone (vs v1's fragile
    # first-hit anchor, which a pickup/grace note could shift for the whole song).
    BINS = 24
    offs = [float(e["time"]) % beat for e in events if _lane_of(e["name"]) in ("kick", "snare")]
    if not offs:
        offs = [float(e["time"]) % beat for e in events]
    if offs:
        counts = [0] * BINS
        for o in offs:
            counts[int((o / beat) * BINS) % BINS] += 1
        anchor = (counts.index(max(counts)) + 0.5) / BINS * beat
    else:
        anchor = 0.0

    def _metric_keep(evts, keep):
        """Keep the `keep` metrically-strongest notes from a single lane."""
        if keep >= len(evts):
            return list(evts)
        if keep <= 0:
            return []
        TOL = 0.12  # fraction of a beat
        scored = []
        for e in evts:
            t = float(e["time"])
            p = ((t - anchor) % beat) / beat
            d_beat = min(p, 1.0 - p)
            d_8 = abs(p - 0.5)
            d_16 = min(abs(p - 0.25), abs(p - 0.75))
            if d_beat < TOL:
                s = 4.0
            elif d_8 < TOL:
                s = 3.0
            elif d_16 < TOL:
                s = 2.0
            else:
                s = 1.0
            if round((t - anchor) / beat) % 4 == 0:   # bar downbeat (assume 4/4)
                s += 0.5
            scored.append((s, t, e))
        scored.sort(key=lambda x: (-x[0], x[1]))       # strongest first, then time-ordered
        return [e for (_s, _t, e) in scored[:keep]]

    by = {}
    for e in events:
        lane = _lane_of(e["name"])
        if lane is None:
            continue
        by.setdefault(lane, []).append(e)

    tgt = _DIFFICULTY_RETENTION[difficulty]
    filtered = []
    for lane, evs in by.items():
        r = tgt.get(lane, 1.0)
        if r >= 1.0:
            filtered.extend(evs)
        else:
            keep = max(1, round(len(evs) * r))   # a present lane keeps >=1 (never a wholesale drop)
            filtered.extend(_metric_keep(evs, keep))
    filtered.sort(key=lambda e: float(e["time"]))
    return filtered


# ---------------------------------------------------------------------------
# Clone Hero export helpers
# ---------------------------------------------------------------------------

# Standard MIDI note -> (CH pad note, cymbal flag or None)
# Cymbal flag: 66=yellow cymbal, 67=blue cymbal, 68=green cymbal
# No flag = tom pad hit. Layout follows the 4-lane Pro convention (verified
# against the .chart spec + real human charts, 2026-07-10): Yellow=hi-hat,
# Blue=ride, Green=crash. Keeping the three cymbal families on THREE distinct
# lanes means no cymbal-vs-cymbal same-tick collapse (Sol #7 fix: crash used
# to share Yellow with hi-hat, so a simultaneous hat+crash lost the crash).
_CH_NOTE_MAP = {
    35: (0, None), 36: (0, None),                 # Kick
    37: (1, None), 38: (1, None), 40: (1, None),  # Snare  -> red
    42: (2, 66),   44: (2, 66),   46: (2, 66),   # Hi-Hat -> yellow cymbal
    26: (2, 66),   21: (2, 66),   22: (2, 66),   23: (2, 66),   # Hi-Hat alt/extended-kit notes -> yellow cymbal
    49: (4, 68),   55: (4, 68),   57: (4, 68),   # Crash  -> green cymbal
    51: (3, 67),   53: (3, 67),   59: (3, 67),   # Ride   -> blue cymbal
    48: (2, None), 50: (2, None),                 # Tom 1  -> yellow pad
    45: (3, None), 47: (3, None),                 # Tom 2  -> blue pad
    41: (4, None), 43: (4, None),                 # Floor Tom -> green pad
}


def midi_notes_to_ch(midi_notes, ticks_per_beat, bpm, offset, resolution=192):
    """Convert parsed MIDI note list to Clone Hero tick-based events.

    Accepts both 3-tuple (tick, note, vel) and 4-tuple
    (tick, note, vel, precomputed_sec). Returns sorted list of
    (ch_tick, ch_note, cymbal_flag_or_None).
    """
    import mido
    tempo_us = int(60_000_000 / bpm)
    ch_events = []
    for note_data in midi_notes:
        if len(note_data) == 4:
            tick, note, velocity, precomputed_sec = note_data
            time_sec = precomputed_sec + offset
        else:
            tick, note, velocity = note_data
            time_sec = mido.tick2second(tick, ticks_per_beat, tempo_us) + offset
        if note not in _CH_NOTE_MAP or time_sec < 0:
            continue
        ch_note, cymbal_flag = _CH_NOTE_MAP[note]
        ch_tick = int(round(time_sec * bpm / 60.0 * resolution))
        ch_events.append((ch_tick, ch_note, cymbal_flag))
    return _ch_dedupe_same_pad(ch_events)


def _ch_escape(value):
    """Escape a value for notes.chart quoted song metadata."""
    return str(value).replace("\\", "\\\\").replace("\"", "\\\"")


def build_chart(ch_events, bpm, title, artist, album="", year="",
                charter="ParaKit", resolution=192, music_stream="song.ogg"):
    """Build a Clone Hero notes.chart file as a string."""
    bpm_int = int(round(bpm * 1000))
    lines = [
        "[Song]", "{",
        f'  Name = "{_ch_escape(title)}"',
        f'  Artist = "{_ch_escape(artist)}"',
    ]
    if album:
        lines.append(f'  Album = "{_ch_escape(album)}"')
    if year:
        lines.append(f'  Year = ", {_ch_escape(year)}"')
    lines += [
        f'  Charter = "{_ch_escape(charter)}"',
        f"  Resolution = {resolution}",
        "  Offset = 0",
        "  Player2 = bass",
        "  Difficulty = 0",
        "  PreviewStart = 0",
        "  PreviewEnd = 0",
        '  Genre = "rock"',
        '  MediaType = "cd"',
        f'  MusicStream = "{music_stream}"',
        "}", "",
        "[SyncTrack]", "{",
        "  0 = TS 4",
        f"  0 = B {bpm_int}",
        "}", "",
        "[Events]", "{", "}", "",
        "[ExpertDrums]", "{",
    ]
    for ch_tick, ch_note, cymbal_flag in ch_events:
        lines.append(f"  {ch_tick} = N {ch_note} 0")
        if cymbal_flag is not None:
            lines.append(f"  {ch_tick} = N {cymbal_flag} 0")
    lines += ["}", ""]
    return "\n".join(lines)


def write_song_ini(title, artist, album="", year="", charter="ParaKit",
                   song_length_ms=0, diff_drums=3):
    """Build a Clone Hero song.ini file as a string.

    diff_drums: 1=Easy 2=Medium 3=Hard 4=Expert
    """
    lines = ["[song]", f"name = {title}", f"artist = {artist}"]
    if album:
        lines.append(f"album = {album}")
    if year:
        lines.append(f"year = {year}")
    lines += [
        f"charter = {charter}",
        f"diff_drums = {diff_drums}",
        f"diff_drums_real = {diff_drums}",
        "pro_drums = True",
        "diff_guitar = -1",
        "diff_bass = -1",
        "diff_keys = -1",
        "diff_guitarghl = -1",
        "diff_bassghl = -1",
        f"song_length = {song_length_ms}",
        "preview_start_time = 0",
        "icon = ",
    ]
    return "\n".join(lines)


# ---------------------------------------------------------------------------
# v4.4.57.96-10 Patch 7+8 (re-applies v4.4.57.86-8 + .87-8 + .88-8 from the
# rolled-back UI-overhaul cycle): Paradiddle → Clone Hero Batch Converter
# module-level helpers + class + MidiToRlrrApp instance methods. Pure
# additive feature (no edits to existing CH-export path at T1/T3). Tools-
# menu wiring lives in the menu-build section further down.
# ---------------------------------------------------------------------------

import re as _pd_to_ch_re


def _paradiddle_difficulty_from_filename(filename):
    """Parse Paradiddle .rlrr filename convention. Returns the canonical
    Title-cased difficulty name ("Easy" / "Medium" / "Hard" / "Expert") or
    None if filename doesn't match `<song>_<difficulty>.rlrr` pattern.

    Examples:
        'Beggin_Easy.rlrr'    → 'Easy'
        'My Song_Expert.rlrr' → 'Expert'
        'unknown.rlrr'        → None
    """
    if not filename:
        return None
    base = filename.rsplit(".", 1)[0]  # strip extension
    m = _pd_to_ch_re.search(r"_(Easy|Medium|Hard|Expert)$",
                             base, _pd_to_ch_re.IGNORECASE)
    if not m:
        return None
    return m.group(1).capitalize()


# Audio role detection — filename substring match, case-insensitive.
# Order matters: 'drums' / 'bass' / 'guitar' etc. checked BEFORE 'song' so
# 'drums_song.ogg' isn't misclassified as the main mix.
_PD_TO_CH_AUDIO_ROLE_PATTERNS = [
    ("drums",  ("drum",)),
    ("bass",   ("bass",)),
    ("guitar", ("guitar", "gtr")),
    ("vocals", ("vocal",)),
    ("keys",   ("key", "synth", "piano")),
    ("rhythm", ("rhythm",)),
    ("song",   ("song", "mix", "master", "full")),
]
_PD_TO_CH_AUDIO_EXTS = {".ogg", ".mp3", ".wav", ".m4a", ".flac"}
_PD_TO_CH_IMAGE_EXTS = {".png", ".jpg", ".jpeg"}
_PD_TO_CH_IMAGE_HINTS = ("cover", "album", "art", "thumbnail")


def _paradiddle_detect_audio_files(folder_path, rlrr_audio_filename=None):
    """Scan a Paradiddle song folder for audio + image files and classify
    each by intended Clone Hero role. Returns dict (schema in PdToCh
    converter dispatch §3.7): keys song / drums / bass / guitar / vocals /
    keys / rhythm / album_art / unmapped."""
    result = {"unmapped": []}
    if not folder_path or not os.path.isdir(folder_path):
        return result

    rlrr_mix_lower = (rlrr_audio_filename or "").lower()

    for entry in sorted(os.listdir(folder_path)):
        full = os.path.join(folder_path, entry)
        if not os.path.isfile(full):
            continue
        ext = os.path.splitext(entry)[1].lower()
        name_lower = entry.lower()

        # Audio classification
        if ext in _PD_TO_CH_AUDIO_EXTS:
            if rlrr_mix_lower and entry.lower() == rlrr_mix_lower:
                result.setdefault("song", full)
                continue
            matched = False
            for role, patterns in _PD_TO_CH_AUDIO_ROLE_PATTERNS:
                if any(p in name_lower for p in patterns):
                    if role not in result:
                        result[role] = full
                    matched = True
                    break
            if not matched:
                result["unmapped"].append(full)

        # Image classification
        elif ext in _PD_TO_CH_IMAGE_EXTS:
            if "album_art" not in result and any(
                    h in name_lower for h in _PD_TO_CH_IMAGE_HINTS):
                result["album_art"] = full

    return result


# Ghost / accent velocity thresholds. _load_rlrr_as_me_notes normalizes
# velocity to 0-127 int in note['vel'].
_CH_VELOCITY_ACCENT_THRESHOLD = 100   # vel > 100 → accent
_CH_VELOCITY_GHOST_THRESHOLD = 50     # vel < 50  → ghost
# .chart accent/ghost modifiers are PER-LANE (verified against the .chart spec
# 2026-07-10): accents 34/35/36/37 and ghosts 40/41/42/43 for Red/Yellow/Blue/
# Green. Kick (pad 0) has no accent/ghost modifier. The pre-2026-07-10 code
# emitted a fixed accent=33 (not a valid modifier at all) and ghost=34 (which
# the spec defines as RED ACCENT) regardless of lane — so every ghost note was
# written as a red accent and every accent silently dropped. This maps them
# correctly by pad.
_CH_ACCENT_BY_PAD = {1: 34, 2: 35, 3: 36, 4: 37}
_CH_GHOST_BY_PAD = {1: 40, 2: 41, 3: 42, 4: 43}


def _ch_velocity_flag(vel_int_0_127, ch_pad, emit_ghost=True, emit_accent=True):
    """Return the CH per-lane accent/ghost modifier note number for the given
    velocity + pad, or None if velocity is in the normal band or the pad is the
    kick (which has no accent/ghost modifier).

    emit_ghost / emit_accent let the two be requested INDEPENDENTLY — enabling
    only accents must not also emit ghosts, and vice versa (audit 2026-07-10:
    the callers used a single 'emit velocity flags' bool, so ticking one box
    silently emitted the other kind too)."""
    try:
        v = int(vel_int_0_127)
    except (TypeError, ValueError):
        return None
    if ch_pad == 0:
        return None
    if emit_accent and v > _CH_VELOCITY_ACCENT_THRESHOLD:
        return _CH_ACCENT_BY_PAD.get(ch_pad)
    if emit_ghost and v < _CH_VELOCITY_GHOST_THRESHOLD:
        return _CH_GHOST_BY_PAD.get(ch_pad)
    return None


def _ch_dedupe_same_pad(events):
    """Collapse events that fall on the same (tick, CH pad) and return the list
    re-sorted. The .chart format cannot represent a cymbal and a tom of the same
    colour on one tick (spec: 4-Lane Note Mechanics), and ParaKit collapses
    several distinct Paradiddle articulations onto one CH pad (e.g. closed/open
    hats -> yellow cymbal), so two source hits can land on the same (tick, pad).
    Policy: a cymbal beats a tom on the same lane; otherwise keep the first hit.
    Accepts 3-tuples (tick, pad, cymbal_flag) and 4-tuples (+ vel_flag)."""
    best = {}
    for ev in events:
        key = (ev[0], ev[1])
        has_cymbal = len(ev) > 2 and ev[2] is not None
        cur = best.get(key)
        if cur is None:
            best[key] = ev
        elif has_cymbal and not (len(cur) > 2 and cur[2] is not None):
            best[key] = ev  # cymbal wins over a same-lane tom
    out = list(best.values())
    out.sort(key=lambda e: (e[0], e[1]))
    return out


def _paradiddle_rlrr_to_ch_events(rlrr_notes_list, bpm,
                                   emit_velocity_flags=False,
                                   resolution=192,
                                   emit_ghost=None, emit_accent=None):
    """Sibling to `midi_notes_to_ch` that preserves per-event velocity for
    ghost/accent flags. Returns 3-tuples (tick, note, cymbal_flag) when no
    velocity flags are requested; 4-tuples (tick, note, cymbal_flag, vel_flag)
    otherwise. `build_chart_multi_difficulty` accepts both shapes.

    emit_ghost / emit_accent can be requested independently; when either is
    None it falls back to `emit_velocity_flags` (back-compat for the single-
    checkbox callers: Pd→CH converter, folder-batch)."""
    eg = emit_velocity_flags if emit_ghost is None else emit_ghost
    ea = emit_velocity_flags if emit_accent is None else emit_accent
    want_flags = bool(eg or ea)
    events = []
    for n in rlrr_notes_list:
        try:
            midi_note = int(n.get("note"))
            time_sec = float(n.get("time", 0.0))
        except (TypeError, ValueError):
            continue
        if midi_note not in _CH_NOTE_MAP or time_sec < 0:
            continue
        ch_pad, cymbal_flag = _CH_NOTE_MAP[midi_note]
        ch_tick = int(round(time_sec * bpm / 60.0 * resolution))
        if want_flags:
            vel_flag = _ch_velocity_flag(n.get("vel", 80), ch_pad,
                                         emit_ghost=eg, emit_accent=ea)
            events.append((ch_tick, ch_pad, cymbal_flag, vel_flag))
        else:
            events.append((ch_tick, ch_pad, cymbal_flag))
    return _ch_dedupe_same_pad(events)


def build_chart_multi_difficulty(events_by_difficulty, bpm, title, artist,
                                  album="", year="", charter="ParaKit",
                                  resolution=192, music_stream="song.ogg"):
    """Sibling to `build_chart` that emits MULTIPLE difficulty sections
    in one notes.chart. events_by_difficulty: dict keyed Expert/Hard/
    Medium/Easy. Accepts 3-tuple or 4-tuple event shapes (4th is CH
    accent/ghost flag note number)."""
    bpm_int = int(round(bpm * 1000))
    lines = [
        "[Song]", "{",
        f'  Name = "{_ch_escape(title)}"',
        f'  Artist = "{_ch_escape(artist)}"',
    ]
    if album:
        lines.append(f'  Album = "{_ch_escape(album)}"')
    if year:
        lines.append(f'  Year = ", {_ch_escape(year)}"')
    lines += [
        f'  Charter = "{_ch_escape(charter)}"',
        f"  Resolution = {resolution}",
        "  Offset = 0",
        "  Player2 = bass",
        "  Difficulty = 0",
        "  PreviewStart = 0",
        "  PreviewEnd = 0",
        '  Genre = "rock"',
        '  MediaType = "cd"',
        f'  MusicStream = "{music_stream}"',
        "}", "",
        "[SyncTrack]", "{",
        "  0 = TS 4",
        f"  0 = B {bpm_int}",
        "}", "",
        "[Events]", "{", "}", "",
    ]

    section_order = [
        ("Expert", "[ExpertDrums]"),
        ("Hard",   "[HardDrums]"),
        ("Medium", "[MediumDrums]"),
        ("Easy",   "[EasyDrums]"),
    ]
    for diff_key, section_header in section_order:
        events = events_by_difficulty.get(diff_key)
        if not events:
            continue
        lines += [section_header, "{"]
        for ev in events:
            if len(ev) >= 4:
                ch_tick, ch_note, cymbal_flag, vel_flag = ev[0], ev[1], ev[2], ev[3]
            else:
                ch_tick, ch_note, cymbal_flag = ev
                vel_flag = None
            lines.append(f"  {ch_tick} = N {ch_note} 0")
            if cymbal_flag is not None:
                lines.append(f"  {ch_tick} = N {cymbal_flag} 0")
            if vel_flag is not None:
                lines.append(f"  {ch_tick} = N {vel_flag} 0")
        lines += ["}", ""]

    return "\n".join(lines)


# Audit E2 (2026-07-10): reverse of build_rlrr's midi_to_name — one canonical
# MIDI note per Paradiddle instrument name, for deriving Clone Hero events
# from FINAL .rlrr events. CH collapses in-lane variants to the same pad, so
# the canonical note per class is lossless for .chart purposes.
_RLRR_NAME_TO_NOTE = {
    "BP_Kick_C_1": 35,  "BP_Snare_C_1": 38,   "BP_HiHat_C_1": 42,
    "BP_FloorTom_C_1": 41, "BP_Tom2_C_2": 45, "BP_Tom1_C_1": 48,
    "BP_Crash15_C_1": 49,  "BP_Crash17_C_1": 57,
    "BP_Ride17_C_1": 51,   "BP_Ride20_C_1": 59,
}


def rlrr_events_to_ch_events(events, bpm, emit_velocity_flags=False,
                             resolution=192, emit_ghost=None, emit_accent=None):
    """Derive Clone Hero events from the FINAL .rlrr event list — i.e. AFTER
    difficulty reduction — so .rlrr and .chart always represent the SAME hit
    set (audit E2: reduction used to apply only to the .rlrr while the .chart
    was built from the unreduced note list). Velocity survives via the event
    "vel" field, so ghost/accent flags can be emitted (audit E5). Event "time"
    strings already include the export offset — no further shifting."""
    dicts = []
    for ev in events:
        note = _RLRR_NAME_TO_NOTE.get(ev.get("name"))
        if note is None:
            continue
        dicts.append({"note": note, "vel": ev.get("vel", 80),
                      "time": ev.get("time", 0.0)})
    return _paradiddle_rlrr_to_ch_events(
        dicts, bpm, emit_velocity_flags=emit_velocity_flags,
        resolution=resolution, emit_ghost=emit_ghost, emit_accent=emit_accent)


def _itunes_fetch_album_art(title, artist, user_agent_version=""):
    """Query iTunes Search API for album art matching title + artist.
    Returns (art_bytes, mime, source_url) or None. Substitutes 600x600 for
    the 100x100 default. First caller is `_PdToChConverterWindow`. Asset
    Manager inlines its own iTunes lookup — kept byte-identical here per
    protected-anti-edit list."""
    if not title and not artist:
        return None
    try:
        import urllib.request as _ur, urllib.parse as _up, json as _json
        query = " ".join(filter(None, [artist, title])).strip()
        if not query:
            return None
        url = ("https://itunes.apple.com/search?"
               f"term={_up.quote(query)}&media=music&limit=1")
        ua = "ParaKit/" + (user_agent_version or "unknown") + " (parakit-app)"
        req = _ur.Request(url, headers={"User-Agent": ua})
        with _ur.urlopen(req, timeout=10) as r:
            data = _json.loads(r.read().decode())
        results = data.get("results", []) or []
        if not results:
            return None
        art_url = (results[0].get("artworkUrl100", "")
                   .replace("100x100", "600x600"))
        if not art_url:
            return None
        with _ur.urlopen(art_url, timeout=10) as r:
            art_bytes = r.read()
        mime = "image/jpeg"
        return (art_bytes, mime, art_url)
    except Exception:
        return None


# ---------------------------------------------------------------------------
# Paradiddle → Clone Hero Batch Converter — popup window (v4.4.57.86-8)
#
# Two-tab Notebook popup invoked from Tools menu. Single Folder tab does one
# Paradiddle source folder; Batch Folder tab iterates a parent folder's
# immediate subfolders. Convert button (shared footer) dispatches per-tab
# to the matching MidiToRlrrApp orchestration method (`_pd_to_ch_convert_*`).
#
# Threading: Convert kicks off a daemon thread; UI updates from the worker
# go through `self.app.root.after(0, lambda: ...)` per Tk threading rules.
# ---------------------------------------------------------------------------
class _PdToChConverterWindow(tk.Toplevel):
    """Tools-menu popup: Paradiddle → Clone Hero batch converter."""

    _DIFF_ORDER = ("Expert", "Hard", "Medium", "Easy")
    _DIFF_TO_RATING = {"Easy": 1, "Medium": 2, "Hard": 3, "Expert": 4}

    def __init__(self, parent_root, app):
        super().__init__(parent_root)
        self.app = app
        self.title("Paradiddle → Clone Hero Batch Converter")
        try:
            self.geometry("960x760")
            self.minsize(820, 640)
        except Exception:
            pass
        self.protocol("WM_DELETE_WINDOW", self._on_close)

        # State -- Single-folder tab
        self._single_source_var = tk.StringVar(value="")
        self._single_scan_result = None
        self._single_rlrr_rows = []
        self._meta_title_var = tk.StringVar()
        self._meta_artist_var = tk.StringVar()
        self._meta_album_var = tk.StringVar()
        self._meta_year_var = tk.StringVar()
        self._meta_genre_var = tk.StringVar()
        self._meta_charter_locked_var = tk.StringVar()
        self._meta_additional_creator_var = tk.StringVar()
        self._art_status_var = tk.StringVar(value="No source folder loaded.")
        self._fetched_art_bytes = None
        self._fetched_art_thumb = None
        # State -- Batch tab
        self._batch_parent_var = tk.StringVar(value="")
        self._batch_scan_results = []
        self._batch_row_widgets = []
        self._batch_apply_all_var = tk.BooleanVar(value=True)
        self._batch_autofetch_art_var = tk.BooleanVar(value=False)
        # State -- Shared footer
        _ch_out_default = ""
        try:
            _ch_out_default = (load_config().get("ch_output_folder", "") or "")
        except Exception:
            pass
        self._output_folder_var = tk.StringVar(value=_ch_out_default)
        _folder_template_default = "artist_title"
        try:
            _folder_template_default = (
                load_config().get("ch_folder_name_template", "artist_title")
                or "artist_title")
        except Exception:
            pass
        self._folder_name_template_var = tk.StringVar(
            value=_folder_template_default)
        _emit_velocity_flags_default = True
        try:
            _emit_velocity_flags_default = bool(
                load_config().get("ch_emit_ghost_accent", True))
        except Exception:
            pass
        self._emit_velocity_flags_var = tk.BooleanVar(
            value=_emit_velocity_flags_default)
        self._convert_thread = None
        self._cancel_requested = False

        # Layout
        outer = ttk.Frame(self, padding=10)
        outer.pack(fill=tk.BOTH, expand=True)
        self._nb = ttk.Notebook(outer)
        self._nb.pack(fill=tk.BOTH, expand=True)
        self._tab_single = ttk.Frame(self._nb, padding=10)
        self._tab_batch = ttk.Frame(self._nb, padding=10)
        self._nb.add(self._tab_single, text="  Single Folder  ")
        self._nb.add(self._tab_batch, text="  Batch Folder  ")
        self._build_single_tab(self._tab_single)
        self._build_batch_tab(self._tab_batch)
        self._build_shared_footer(outer)
        self._refresh_convert_enabled()

