def _neon_resource_path(*parts):
    base = getattr(sys, "_MEIPASS",
                   os.path.dirname(os.path.abspath(__file__)))
    return os.path.join(base, *parts)


def load_changelog_entries(max_entries=None):
    """Parse CHANGELOG.txt -> a newest-first list of (header, body) version entries
    for the in-app "What's New" (the SINGLE SOURCE OF TRUTH for version history,
    owner 2026-06-30 -- the entries used to be ~2,200 inline lines in this file).

    CHANGELOG.txt ships next to this script (source) / is bundled via the .spec
    (frozen .exe), resolved through _neon_resource_path. An entry is a version line
    (``vX.Y.Z ...``) sandwiched between two dashed separators; its body is the lines
    up to the next separator. Returns [] on ANY error (missing/unreadable/parse
    fail) so the Help tab degrades gracefully instead of crashing."""
    try:
        with open(_neon_resource_path("CHANGELOG.txt"), "r", encoding="utf-8") as f:
            lines = f.read().split("\n")
    except Exception:
        return []
    return parse_changelog_lines(lines, max_entries)


def parse_changelog_lines(lines, max_entries=None):
    """Core CHANGELOG.txt parser: a list of text *lines* -> newest-first
    [(header, body)]. Split out from load_changelog_entries so the same format
    can be parsed from a remote string (the update popup fetches the repo's
    CHANGELOG.txt to preview what a not-yet-installed version changes)."""
    def _is_sep(s):
        t = s.strip()
        return t.startswith("---") and len(t) >= 10

    entries = []
    i, n = 0, len(lines)
    while i < n:
        # a version header sits BETWEEN two dashed separators: ---- / "vX..." / ----
        if (_is_sep(lines[i]) and i + 2 < n and _is_sep(lines[i + 2])
                and lines[i + 1].strip()[:1].lower() == "v"):
            header = lines[i + 1].strip()
            j = i + 3
            body = []
            while j < n and not _is_sep(lines[j]):
                t = lines[j].strip()
                if t.startswith("===") or t.startswith("PART "):
                    break
                body.append(lines[j])
                j += 1
            while body and not body[-1].strip():   # trim trailing blanks
                body.pop()
            entries.append((header, "\n".join(body)))
            i = j
        else:
            i += 1
        if max_entries and len(entries) >= max_entries:
            break
    return entries


def _tick_strip(parent, length, tick_px=10, bg=APP_BG):
    """Pack a faint tick-mark canvas below a slider inside *parent*.

    Call immediately after the Scale is packed inside *parent* (which should
    be a small wrapper Frame containing only the scale + this canvas).
    """
    c = tk.Canvas(parent, width=length, height=6,
                  bg=bg, highlightthickness=0, bd=0)
    c.pack(side=tk.TOP, anchor="w")
    n = max(2, length // tick_px)
    for i in range(n + 1):
        x = int(round(i * (length - 1) / n))
        c.create_line(x, 0, x, 4, fill="#554477", width=1)
    return c


