_TROUGH_FILL = (18, 10, 28, 255)
_TROUGH_STROKE = (174, 76, 214, 220)
_TROUGH_GLOW = (205, 100, 235, 105)

_NEON_TROUGH_CACHE = {}


def _neon_render_trough(width, height, glow_radius=6):
    """Procedural rounded-trough renderer.

    Returns an RGBA PIL.Image at exactly (width, height). No horizontal
    sprite stretch. Three-layer composite: blurred outer glow, magenta
    stroke, dark fill.
    """
    from PIL import Image, ImageDraw, ImageFilter
    width = max(int(width), 8)
    height = max(int(height), 8)
    pad = max(glow_radius, 2)

    canvas = Image.new("RGBA", (width + pad * 2, height + pad * 2), (0, 0, 0, 0))
    glow_layer = Image.new("RGBA", canvas.size, (0, 0, 0, 0))
    stroke_layer = Image.new("RGBA", canvas.size, (0, 0, 0, 0))
    fill_layer = Image.new("RGBA", canvas.size, (0, 0, 0, 0))

    radius = height // 2
    rect = (pad, pad, pad + width - 1, pad + height - 1)

    ImageDraw.Draw(glow_layer).rounded_rectangle(
        rect, radius=radius, fill=_TROUGH_GLOW)
    glow_layer = glow_layer.filter(ImageFilter.GaussianBlur(glow_radius))

    stroke_draw = ImageDraw.Draw(stroke_layer)
    stroke_draw.rounded_rectangle(
        rect, radius=radius, outline=_TROUGH_STROKE, width=2)

    ImageDraw.Draw(fill_layer).rounded_rectangle(
        (rect[0] + 1, rect[1] + 1, rect[2] - 1, rect[3] - 1),
        radius=max(radius - 1, 1), fill=_TROUGH_FILL)

    out = Image.alpha_composite(canvas, glow_layer)
    out = Image.alpha_composite(out, fill_layer)
    out = Image.alpha_composite(out, stroke_layer)
    return out.crop((pad, pad, pad + width, pad + height))


def _neon_cached_trough(width, height):
    key = (int(width), int(height))
    img = _NEON_TROUGH_CACHE.get(key)
    if img is None:
        img = _neon_render_trough(*key)
        _NEON_TROUGH_CACHE[key] = img
    return img


# ---------------------------------------------------------------------------
# v4.4.57.97-10 Patch 14: G8.5_alt Option A — Snare Node Line progress bar
# (drum-themed). Owner-restored 2026-05-23 from
# `design_review/ui_icon_pass/G8.5_alt/option_a_snare_node_line/`. Drop-in
# compatible with NeonDotProgressBar's public surface (start/stop/set/step/
# configure) — additive; existing NeonDotProgressBar call sites unchanged.
# ---------------------------------------------------------------------------

_SNARE_BAR_ASSET_DIR = _neon_resource_path(
    "assets", "ui", "progress_bars", "snare_node_line")
_SNARE_BAR_LINE_COLOR = "#5b3aa8"      # connecting line — purple (idle/running)
_SNARE_BAR_COMPLETE_LINE = "#39d36f"   # connecting line — green at 100 %
_SNARE_BAR_BG = "#0c0712"              # dark navy background
_SNARE_BAR_COMET_LEN = 4               # how many snares are "lit" in running mode


class _G85AltSnareProgressBar(tk.Canvas):
    """Drum-themed snare-node-line progress bar.

    Renders evenly-spaced snare sprites along a connecting line. Per-mode
    sprite size: 24 px when ``height < 30`` (compact), 32 px otherwise.
    Hit sprites alternate left/right for a drumming feel in indeterminate
    mode. Determinate mode lights snares up to ``value / maximum``; reaching
    100 % turns the connecting line green.

    Public surface mirrors NeonDotProgressBar so this widget can drop in
    to existing call sites without changes:

        .start(interval=12) / .stop()                        indeterminate mode
        .configure(value=, length=, width=, height=, mode=)  ttk-style options
        .step(amount=None)                                   determinate increment
        .set(percent_0_to_1)                                 convenience setter
    """

    _SPRITE_CACHE: dict = {}  # (size, kind) -> PhotoImage

    def __init__(self, parent,
                 width=400, height=30,
                 mode="indeterminate", value=0.0, maximum=100.0,
                 num_snares=None, **kwargs):
        kwargs.setdefault("bg", _SNARE_BAR_BG)
        kwargs.setdefault("highlightthickness", 0)
        kwargs.setdefault("bd", 0)
        super().__init__(parent, width=width, height=height, **kwargs)

        self._mode = mode
        self._value = float(value)
        self._maximum = float(maximum) if maximum else 100.0
        self._width = int(width)
        self._height = int(height)
        self._explicit_num = num_snares

        # Per-mode sprite size: 24 px compact, 32 px roomy.
        self._sprite_size = 24 if self._height < 30 else 32

        self._after_id = None
        self._is_running = True
        self._comet_pos = 0
        self._frame = 0  # toggles 0/1 each tick for stick-hand alternation
        self._tick_interval = 220
        self._snare_items: list = []
        self._line_item = None
        self._suppress_configure = False
        self._positions: list = []

        try:
            self._rebuild()
        except Exception:
            # If sprites are missing, the widget still renders an empty
            # canvas rather than crashing the host frame.
            self.delete("all")
        self.bind("<Destroy>", self._snare_on_destroy)
        self.bind("<Configure>", self._snare_on_configure)

    # -- sprite loading -----------------------------------------------------

    def _snare_load_sprite(self, kind):
        key = (self._sprite_size, kind)
        cache = type(self)._SPRITE_CACHE
        img = cache.get(key)
        if img is None:
            from PIL import Image, ImageTk
            filename = f"{kind}_{self._sprite_size}.png"
            path = os.path.join(_SNARE_BAR_ASSET_DIR, filename)
            pil = Image.open(path).convert("RGBA")
            if pil.size != (self._sprite_size, self._sprite_size):
                pil = pil.resize(
                    (self._sprite_size, self._sprite_size), Image.LANCZOS)
            img = ImageTk.PhotoImage(pil)
            cache[key] = img
        return img

    def _snare_compute_num(self):
        if self._explicit_num is not None:
            return max(2, int(self._explicit_num))
        # 10 snares at 560 px matches the design contact sheet; scale for
        # narrower call sites so spacing stays drum-readable.
        target_spacing = self._sprite_size + 18
        side_pad = max(12, self._sprite_size // 2 + 4)
        usable = max(self._width - side_pad * 2, target_spacing)
        n = max(2, usable // target_spacing + 1)
        return int(min(14, n))

    # -- rendering ----------------------------------------------------------

    def _rebuild(self):
        self._idle_img = self._snare_load_sprite("snare_idle")
        self._hit_left_img = self._snare_load_sprite("snare_hit_left")
        self._hit_right_img = self._snare_load_sprite("snare_hit_right")
        self._num = self._snare_compute_num()

        self._suppress_configure = True
        try:
            self.config(width=self._width, height=self._height)
        finally:
            self._suppress_configure = False
        self.delete("all")
        self._snare_items = []
        self._line_item = None

        side_pad = max(12, self._sprite_size // 2 + 4)
        cy = self._height // 2
        if self._num == 1:
            positions = [self._width // 2]
        else:
            inner = self._width - side_pad * 2
            step = inner / float(self._num - 1)
            positions = [int(side_pad + i * step) for i in range(self._num)]
        self._positions = positions

        # Connecting line drawn first so snares overlay it.
        self._line_item = self.create_line(
            positions[0], cy, positions[-1], cy,
            fill=_SNARE_BAR_LINE_COLOR, width=2, capstyle="round")

        for cx in positions:
            item = self.create_image(cx, cy, image=self._idle_img,
                                     anchor="center")
            self._snare_items.append(item)

        self._snare_refresh_visual()

    def _snare_refresh_visual(self):
        if self._mode == "indeterminate" and self._is_running:
            self._snare_paint_running()
        elif self._mode == "indeterminate":
            self._snare_paint_idle()
        else:
            self._snare_paint_determinate()

    def _snare_paint_idle(self):
        if self._line_item:
            self.itemconfigure(self._line_item, fill=_SNARE_BAR_LINE_COLOR)
        for item in self._snare_items:
            self.itemconfigure(item, image=self._idle_img)

    def _snare_paint_determinate(self):
        pct = self._value / self._maximum if self._maximum else 0.0
        pct = max(0.0, min(1.0, pct))
        lit_count = self._num if pct >= 1.0 else int(pct * self._num)
        complete = lit_count >= self._num

        if self._line_item:
            self.itemconfigure(
                self._line_item,
                fill=_SNARE_BAR_COMPLETE_LINE if complete
                else _SNARE_BAR_LINE_COLOR)

        for i, item in enumerate(self._snare_items):
            if i < lit_count:
                img = (self._hit_left_img if (i % 2 == 0)
                       else self._hit_right_img)
            else:
                img = self._idle_img
            self.itemconfigure(item, image=img)

    def _snare_paint_running(self):
        head = self._comet_pos
        comet_len = _SNARE_BAR_COMET_LEN
        if self._line_item:
            self.itemconfigure(self._line_item, fill=_SNARE_BAR_LINE_COLOR)
        for i, item in enumerate(self._snare_items):
            dist = (i - head) % self._num
            if dist < comet_len:
                parity = (i + self._frame) % 2
                img = (self._hit_left_img if parity == 0
                       else self._hit_right_img)
            else:
                img = self._idle_img
            self.itemconfigure(item, image=img)

    # -- public API (mirrors NeonDotProgressBar) ----------------------------

    def set(self, percent):
        self._mode = "determinate"
        self._value = max(0.0, min(1.0, float(percent))) * self._maximum
        self._snare_refresh_visual()

    def start(self, interval=12):
        self._mode = "indeterminate"
        self._is_running = True
        if self._after_id is not None:
            return
        # interval=12 ms is ttk.Progressbar's frame-tick units; the snare
        # animation reads at a drum-tempo (~220 ms) instead.
        self._tick_interval = max(120, int(interval) * 18)
        self._snare_tick()

    def stop(self):
        self._is_running = False
        if self._after_id is not None:
            try:
                self.after_cancel(self._after_id)
            except Exception:
                pass
            self._after_id = None
        if self._mode != "indeterminate":
            return
        try:
            self._snare_paint_idle()
        except tk.TclError:
            pass

    def step(self, amount=None):
        if amount is None:
            amount = 1.0
        self._mode = "determinate"
        self._value = (self._value + float(amount)) % (self._maximum + 1e-9)
        self._snare_refresh_visual()

    def configure(self, **kwargs):
        rebuild = False
        if "value" in kwargs:
            self._value = float(kwargs.pop("value"))
        if "maximum" in kwargs:
            self._maximum = float(kwargs.pop("maximum")) or 100.0
        if "mode" in kwargs:
            new_mode = kwargs.pop("mode")
            if new_mode != self._mode:
                self.stop()
                self._mode = new_mode
        if "length" in kwargs or "width" in kwargs:
            new_w = int(kwargs.pop("length", kwargs.pop("width", self._width)))
            if new_w != self._width:
                self._width = new_w
                rebuild = True
        if "height" in kwargs:
            new_h = int(kwargs.pop("height"))
            if new_h != self._height:
                self._height = new_h
                new_size = 24 if self._height < 30 else 32
                if new_size != self._sprite_size:
                    self._sprite_size = new_size
                rebuild = True
        if kwargs:
            super().configure(**kwargs)
        if rebuild:
            self._rebuild()
        else:
            self._snare_refresh_visual()

    config = configure

    # -- animation tick -----------------------------------------------------

    def _snare_tick(self):
        if not self._snare_items:
            self._after_id = None
            return
        self._comet_pos = (self._comet_pos + 1) % self._num
        self._frame = (self._frame + 1) % 2
        try:
            self._snare_paint_running()
        except tk.TclError:
            self._after_id = None
            return
        self._after_id = self.after(self._tick_interval, self._snare_tick)

    def _snare_on_configure(self, event):
        if self._suppress_configure:
            return
        new_w = int(event.width)
        if abs(new_w - self._width) < 2:
            return
        self._width = max(40, new_w)
        try:
            self._rebuild()
        except Exception:
            self.delete("all")

    def _snare_on_destroy(self, _event=None):
        self.stop()


class NeonDotProgressBar(tk.Canvas):
    """ttk.Progressbar-compatible neon dot bar.

    Public surface mirrors enough of ttk.Progressbar to drop in for the
    existing call sites:
        .start(interval=12) / .stop()                        indeterminate mode
        .configure(value=, length=, width=, height=, mode=)  ttk-style options
        .step(amount=None)                                   determinate increment
        .set(percent_0_to_1)                                 convenience setter
    """

    def __init__(self, parent,
                 width=400, height=30,
                 mode="indeterminate", value=0.0, maximum=100.0,
                 lit=_NEON_VISUAL["lit"], unlit=_NEON_VISUAL["unlit"],
                 trail=_NEON_VISUAL["trail"],
                 dot_size=_NEON_VISUAL["dot_size"],
                 dot_spacing=_NEON_VISUAL["dot_spacing"],
                 side_padding=_NEON_VISUAL["side_padding"],
                 num_dots=None, comet_size=_NEON_VISUAL["comet_size"],
                 **kwargs):
        kwargs.setdefault("bg", _NEON_DEFAULT_BG)
        kwargs.setdefault("highlightthickness", 0)
        kwargs.setdefault("bd", 0)
        super().__init__(parent, width=width, height=height, **kwargs)

        self._mode = mode
        self._value = float(value)
        self._maximum = float(maximum) if maximum else 100.0
        self._dot_size = dot_size
        self._dot_spacing = dot_spacing
        self._side_padding = side_padding
        self._comet_size = comet_size
        self._width = int(width)
        self._height = int(height)
        self._explicit_num_dots = num_dots

        self._lit_filename = lit
        self._unlit_filename = unlit
        self._trail_filename = trail

        self._after_id = None
        self._is_running = bool(_NEON_VISUAL["starts_visible"])
        self._comet_pos = 0.0
        self._comet_delay = 36
        self._comet_step = _NEON_VISUAL["comet_step"]
        self._dot_items = []
        self._suppress_configure = False

        self._rebuild()
        self.bind("<Destroy>", self._neon_on_destroy)
        self.bind("<Configure>", self._neon_on_configure)

    def _neon_compute_num_dots(self):
        if self._explicit_num_dots is not None:
            return max(1, int(self._explicit_num_dots))
        usable = self._width - self._side_padding * 2 - self._dot_size
        if usable <= 0:
            return 1
        return max(1, usable // self._dot_spacing + 1)

    def _neon_load_dot(self, filename):
        from PIL import Image, ImageTk
        path = os.path.join(_NEON_ASSET_DIR, filename)
        img = Image.open(path).convert("RGBA")
        if img.size != (self._dot_size, self._dot_size):
            img = img.resize((self._dot_size, self._dot_size), Image.LANCZOS)
        return ImageTk.PhotoImage(img)

    def _rebuild(self):
        from PIL import ImageTk
        self._num_dots = self._neon_compute_num_dots()
        self._lit_img = self._neon_load_dot(self._lit_filename)
        self._unlit_img = self._neon_load_dot(self._unlit_filename)
        self._trail_img = self._neon_load_dot(self._trail_filename)
        self._trough_img = ImageTk.PhotoImage(
            _neon_cached_trough(self._width, self._height))

        self._suppress_configure = True
        try:
            self.config(width=self._width, height=self._height)
        finally:
            self._suppress_configure = False
        self.delete("all")
        self._dot_items = []

        self.create_image(0, 0, image=self._trough_img, anchor="nw")

        cy = self._height // 2
        for i in range(self._num_dots):
            cx = self._side_padding + i * self._dot_spacing + self._dot_size // 2
            item = self.create_image(cx, cy, image=self._unlit_img,
                                     anchor="center")
            self._dot_items.append(item)

        self._neon_refresh_visual()

    def _neon_refresh_visual(self):
        if _neon_should_show_comet(self._mode, self._is_running):
            self._neon_paint_comet()
        elif self._mode == "indeterminate":
            self._neon_paint_idle()
        else:
            self._neon_paint_determinate()

    def _neon_paint_idle(self):
        for item in self._dot_items:
            self.itemconfigure(item, image=self._unlit_img)

    def _neon_paint_determinate(self):
        pct = self._value / self._maximum if self._maximum else 0.0
        pct = max(0.0, min(1.0, pct))
        if pct >= 1.0:
            lit_count = self._num_dots
        else:
            lit_count = int(pct * self._num_dots)
        for i, item in enumerate(self._dot_items):
            self.itemconfigure(item,
                               image=self._lit_img if i < lit_count
                               else self._unlit_img)

    def _neon_paint_comet(self):
        head = self._comet_pos
        for i, item in enumerate(self._dot_items):
            dist = (i - head) % self._num_dots
            if dist < 0:
                dist += self._num_dots
            if dist == 0:
                img = self._lit_img
            elif dist <= self._comet_size - 2:
                img = self._lit_img
            elif dist <= self._comet_size - 1:
                img = self._trail_img
            else:
                img = self._unlit_img
            self.itemconfigure(item, image=img)

    def set(self, percent):
        self._mode = "determinate"
        self._value = max(0.0, min(1.0, float(percent))) * self._maximum
        self._neon_refresh_visual()

    def start(self, interval=12):
        self._mode = "indeterminate"
        self._is_running = True
        if self._after_id is not None:
            return
        self._comet_delay = max(30, int(interval) * 3)
        self._neon_tick()

    def stop(self):
        self._is_running = False
        if self._after_id is not None:
            try:
                self.after_cancel(self._after_id)
            except Exception:
                pass
            self._after_id = None
        if self._mode != "indeterminate":
            return
        try:
            self._neon_paint_idle()
        except tk.TclError:
            pass

    def step(self, amount=None):
        if amount is None:
            amount = 1.0
        self._mode = "determinate"
        self._value = (self._value + float(amount)) % (self._maximum + 1e-9)
        self._neon_refresh_visual()

    def configure(self, **kwargs):
        rebuild = False
        if "value" in kwargs:
            self._value = float(kwargs.pop("value"))
        if "maximum" in kwargs:
            self._maximum = float(kwargs.pop("maximum")) or 100.0
        if "mode" in kwargs:
            new_mode = kwargs.pop("mode")
            if new_mode != self._mode:
                self.stop()
                self._mode = new_mode
        if "length" in kwargs or "width" in kwargs:
            new_w = int(kwargs.pop("length", kwargs.pop("width", self._width)))
            if new_w != self._width:
                self._width = new_w
                rebuild = True
        if "height" in kwargs:
            new_h = int(kwargs.pop("height"))
            if new_h != self._height:
                self._height = new_h
                rebuild = True
        if kwargs:
            super().configure(**kwargs)
        if rebuild:
            self._rebuild()
        else:
            self._neon_refresh_visual()

    config = configure

    def _neon_tick(self):
        self._comet_pos = (self._comet_pos + self._comet_step) % self._num_dots
        try:
            self._neon_paint_comet()
        except tk.TclError:
            self._after_id = None
            return
        self._after_id = self.after(self._comet_delay, self._neon_tick)

    def _neon_on_configure(self, event):
        if self._suppress_configure:
            return
        new_w = int(event.width)
        if abs(new_w - self._width) < 2:
            return
        self._width = max(40, new_w)
        self._rebuild()

    def _neon_on_destroy(self, _event=None):
        self.stop()


# ---------------------------------------------------------------------------
# MIDI Extractor (RLRR -> MIDI) — inline panel
# ---------------------------------------------------------------------------

import sys as _sys
# v4.4.53.2 fix: previously only added `<exe_dir>/Extractor Mini App/` to
# sys.path, which broke `rlrr_parse` import for users with the intact
# Requirements/ folder layout (Extractor Mini App lives at
# `Requirements/Extractor Mini App/` in that case). Now adds BOTH candidate
# locations via `_external_search_dirs()` so Python finds rlrr_parse
# wherever the folder happens to be.
for _rlrr_base in _external_search_dirs():
    _rlrr_dir = os.path.join(_rlrr_base, "Extractor Mini App")
    if _rlrr_dir not in _sys.path:
        _sys.path.insert(0, _rlrr_dir)

try:
    from rlrr_parse import (
        CLASS_TO_MIDI,
        LANE_NAMES,
        extract_notes_from_rlrr,
        write_ground_truth_mid,
        write_mid_with_metadata,
    )
    _RLRR_AVAILABLE = True
except ImportError:
    _RLRR_AVAILABLE = False

# rlrr_parse's CLASS_TO_MIDI collapses the cymbal variants onto one note per
# lane (its 8-lane ground-truth design). The editor must keep the variant —
# MIDI_MAP exports 57/59 to the distinct Paradiddle instruments.
_RLRR_EDITOR_VARIANT_NOTE = {"BP_Crash17_C": 57, "BP_Ride20_C": 59}

_MIDI_EXT_DIFFS = ["Easy", "Medium", "Hard", "Expert", "Expert+"]


def _me_safe_stem(s: str) -> str:
    import re
    return re.sub(r'[\\/:*?"<>|]+', "_", s).strip() or "output"


class MidiExtractorPanel:
    """Builds the RLRR->MIDI extractor UI into a given parent frame (inline panel).

    Call MidiExtractorPanel(parent_frame) once when the reveal frame is
    created. All state lives in this instance; no Toplevel or singleton needed.
    """

    def __init__(self, parent, on_send_to_editor=None):
        self._frame = parent
        self._stop_event = threading.Event()
        self._running = False
        self._output_dir: Optional[Path] = None
        self._on_send_to_editor = on_send_to_editor
        self._send_to_editor_after = False

        self._single_path: Optional[Path] = None
        self._single_notes: list = []

        self._meta_title   = tk.StringVar()
        self._meta_artist  = tk.StringVar()
        self._meta_creator = tk.StringVar()

        self._folder_path: Optional[Path] = None
        self._diff_vars = {d: tk.BooleanVar(value=True) for d in _MIDI_EXT_DIFFS}

        self._build_ui()

    # ── UI construction ───────────────────────────────────────────────────────

    def _mk_btn(self, parent, text, cmd, width=None):
        kw = dict(text=text, command=cmd)
        if width:
            kw["width"] = width
        btn = ttk.Button(parent, **kw)
        return btn

    def _build_ui(self):
        # Wrap everything in a padded inner frame — no explicit bg needed;
        # ttk widgets inherit the theme background.
        body = ttk.Frame(self._frame, padding=16)
        body.pack(fill="x")

        if not _RLRR_AVAILABLE:
            ttk.Label(body,
                      text="MIDI Extractor unavailable — could not import rlrr_parse.\n"
                           "Make sure the 'Extractor Mini App' folder is alongside ParaKit.exe.",
                      foreground="#ff6b81").pack(anchor="w")
            return

        ttk.Label(body,
                  text="Convert a Paradiddle chart file (.rlrr) directly to MIDI — "
                       "no re-recording needed. Pick a single file to preview its note count "
                       "and edit metadata before extracting, or pick a folder to batch-convert "
                       "an entire library. Use this to bring an existing chart into the MIDI "
                       "Editor for tweaking or difficulty editing.",
                  foreground="#b388ff", wraplength=580, justify=tk.LEFT,
                  anchor="w").pack(fill="x", pady=(0, 8))

        nb = ttk.Notebook(body)
        nb.pack(fill="x", pady=(0, 4))
        self._nb = nb   # kept so load_file() can flip to the Single File subtab

        self._tab_single = ttk.Frame(nb)
        self._tab_batch  = ttk.Frame(nb)
        nb.add(self._tab_single, text="  Single File  ")
        nb.add(self._tab_batch,  text="  Batch Folder  ")

        self._build_single_tab()
        self._build_batch_tab()

        ttk.Separator(body, orient="horizontal").pack(fill="x", pady=4)

        # Output dir row
        _saved_outdir = load_config().get("me_extractor_output_dir", "")
        if _saved_outdir and os.path.isdir(_saved_outdir):
            self._output_dir = Path(_saved_outdir)
        f_out = ttk.Frame(body)
        f_out.pack(fill="x", pady=2)
        ttk.Label(f_out, text="Output dir:", width=11, anchor="w").pack(side=tk.LEFT)
        self._outdir_var = tk.StringVar(
            value=str(self._output_dir) if self._output_dir else "Same as source")
        ttk.Label(f_out, textvariable=self._outdir_var,
                  anchor="w").pack(side=tk.LEFT, fill="x", expand=True, padx=(4, 0))
        self._mk_btn(f_out, "Clear",        self._clear_output_dir).pack(side=tk.RIGHT, padx=(2, 0))
        self._mk_btn(f_out, "Browse…",      self._pick_output_dir).pack(side=tk.RIGHT, padx=(2, 0))
        self._mk_btn(f_out, "📂 Open",       self._open_output_dir).pack(side=tk.RIGHT)

        # Action row
        f_act = ttk.Frame(body)
        f_act.pack(pady=2)
        self._extract_btn = self._mk_btn(f_act, "Extract MIDI", self._start_extract, width=14)
        self._extract_btn.pack(side=tk.LEFT, padx=(0, 4))
        self._extract_btn.configure(state="disabled")
        self._send_btn = self._mk_btn(f_act, "Extract MIDI & Send to Editor",
                                      self._start_extract_and_send)
        self._send_btn.pack(side=tk.LEFT, padx=(0, 8))
        self._send_btn.configure(state="disabled")
        self._stop_btn = self._mk_btn(f_act, "Stop", self._request_stop, width=8)
        self._stop_btn.pack(side=tk.LEFT)
        self._stop_btn.configure(state="disabled")
        self._status_var = tk.StringVar()
        ttk.Label(f_act, textvariable=self._status_var).pack(side=tk.LEFT, padx=(12, 0))

        # Progress
        self._progress = _G85AltSnareProgressBar(body, mode="determinate",
                                            width=400, height=30)
        self._progress.pack(fill="x", pady=(2, 0))
        self._prog_var = tk.StringVar()
        ttk.Label(body, textvariable=self._prog_var,
                  anchor="e").pack(fill="x")

        # Log
        ttk.Label(body, text="Log", foreground="#b388ff",
                  anchor="w").pack(fill="x")
        log_frame = ttk.Frame(body)
        log_frame.pack(fill="both", expand=True, pady=(0, 4))
        self._log = tk.Text(log_frame, height=9, state="disabled", wrap="word",
                            bg="#0d1117", fg="#58a6ff",
                            insertbackground="#e0e0e0",
                            selectbackground="#2a1235",
                            relief="flat", bd=0, padx=6, pady=4)
        _sb = ttk.Scrollbar(log_frame, orient="vertical", command=self._log.yview)
        self._log.configure(yscrollcommand=_sb.set)
        _sb.pack(side=tk.RIGHT, fill="y")
        self._log.pack(side=tk.LEFT, fill="both", expand=True)
        self._log.tag_config("ok",   foreground="#00d4d4")
        self._log.tag_config("err",  foreground="#ff6b81")
        self._log.tag_config("warn", foreground="#ffb347")
        self._log.tag_config("info", foreground="#58a6ff")

    def _build_single_tab(self):
        f = ttk.Frame(self._tab_single)
        f.pack(fill="x", padx=8, pady=4)
        self._mk_btn(f, "Select .rlrr…", self._pick_file).pack(side=tk.LEFT)
        self._single_var = tk.StringVar(value="No file selected")
        ttk.Label(f, textvariable=self._single_var,
                  anchor="w").pack(side=tk.LEFT, fill="x", expand=True, padx=(8, 0))

        self._preview_var = tk.StringVar()
        ttk.Label(self._tab_single, textvariable=self._preview_var,
                  foreground="#b388ff", anchor="w",
                  justify=tk.LEFT, wraplength=580).pack(fill="x", padx=8, pady=(0, 4))

        meta_frame = ttk.LabelFrame(self._tab_single, text=" Metadata ", padding=4)
        meta_frame.pack(fill="x", padx=8, pady=(0, 6))
        for lbl_text, var in [("Title",   self._meta_title),
                               ("Artist",  self._meta_artist),
                               ("Creator", self._meta_creator)]:
            row = ttk.Frame(meta_frame)
            row.pack(fill="x", pady=1)
            ttk.Label(row, text=f"{lbl_text}:", width=8, anchor="w").pack(side=tk.LEFT)
            ttk.Entry(row, textvariable=var).pack(side=tk.LEFT, fill="x",
                                                   expand=True, padx=(4, 8))

    def _build_batch_tab(self):
        f = ttk.Frame(self._tab_batch)
        f.pack(fill="x", padx=8, pady=4)
        self._mk_btn(f, "Select folder…", self._pick_folder).pack(side=tk.LEFT)
        self._folder_var = tk.StringVar(value="No folder selected")
        ttk.Label(f, textvariable=self._folder_var,
                  anchor="w").pack(side=tk.LEFT, fill="x", expand=True, padx=(8, 0))

        diff_frame = ttk.LabelFrame(self._tab_batch, text=" Difficulty filter ", padding=4)
        diff_frame.pack(fill="x", padx=8, pady=(0, 6))
        inner = ttk.Frame(diff_frame)
        inner.pack(anchor="w", padx=4, pady=2)
        for d in _MIDI_EXT_DIFFS:
            ttk.Checkbutton(inner, text=d,
                            variable=self._diff_vars[d]).pack(side=tk.LEFT, padx=(0, 12))

        self._batch_count_var = tk.StringVar()
        ttk.Label(self._tab_batch, textvariable=self._batch_count_var,
                  anchor="w").pack(fill="x", padx=8)

    # ── Pickers ───────────────────────────────────────────────────────────────

    def _pick_file(self):
        path = filedialog.askopenfilename(
            title="Select a .rlrr file",
            filetypes=[("Paradiddle chart", "*.rlrr"), ("All files", "*.*")])
        if not path:
            return
        self._single_path = Path(path)
        self._single_var.set(self._single_path.name)
        self._log_clear()
        self._load_preview(self._single_path)
        self._extract_btn.configure(state="normal")
        self._send_btn.configure(state="normal")
        self._reset_progress()

    def load_file(self, path):
        """Programmatic _pick_file — used by the Song Creator library's
        Extract → chip. Loads the given .rlrr into the Single File subtab
        exactly as if the user had browsed to it."""
        self._single_path = Path(path)
        self._single_var.set(self._single_path.name)
        self._log_clear()
        self._load_preview(self._single_path)
        self._extract_btn.configure(state="normal")
        self._send_btn.configure(state="normal")
        self._reset_progress()
        try:
            self._nb.select(self._tab_single)
        except Exception:
            pass

    def _pick_folder(self):
        path = filedialog.askdirectory(title="Select folder of .rlrr files")
        if not path:
            return
        self._folder_path = Path(path)
        self._folder_var.set(str(self._folder_path))
        self._refresh_batch_count()
        self._extract_btn.configure(state="normal")
        self._log_clear()
        self._reset_progress()

    def _pick_output_dir(self):
        path = filedialog.askdirectory(title="Select output directory")
        if not path:
            return
        self._output_dir = Path(path)
        self._outdir_var.set(str(self._output_dir))
        save_config({"me_extractor_output_dir": str(self._output_dir)})

    def _clear_output_dir(self):
        self._output_dir = None
        self._outdir_var.set("Same as source")
        save_config({"me_extractor_output_dir": ""})

    def _open_output_dir(self):
        folder = str(self._output_dir) if self._output_dir else None
        if not folder or not os.path.isdir(folder):
            messagebox.showinfo("No Output Folder", "No output folder is set or folder does not exist.")
            return
        import subprocess, platform
        try:
            if platform.system() == "Windows":
                os.startfile(folder)
            elif platform.system() == "Darwin":
                subprocess.Popen(["open", folder])
            else:
                subprocess.Popen(["xdg-open", folder])
        except Exception as e:
            messagebox.showerror("Error", f"Could not open folder:\n{e}")

    # ── Preview ───────────────────────────────────────────────────────────────

    def _load_preview(self, rlrr_path: Path):
        self._preview_var.set("Parsing…")
        self._meta_title.set("")
        self._meta_artist.set("")
        self._meta_creator.set("")
        self._single_notes = []
        self._frame.update_idletasks()

        notes, meta, err = extract_notes_from_rlrr(rlrr_path)
        if err:
            self._preview_var.set(f"Preview error: {err}")
            return

        self._single_notes = notes
        self._meta_title.set(meta.get("title", ""))
        self._meta_artist.set(meta.get("artist", ""))
        self._meta_creator.set(meta.get("creator", ""))

        duration = meta.get("length", 0.0)
        mins, secs = divmod(int(duration), 60)
        from collections import Counter
        note_to_lane = {v[1]: v[2] for v in CLASS_TO_MIDI.values()}
        lane_counts = Counter(note_to_lane.get(note, "?") for _, note, _ in notes)
        lane_str = "  ".join(
            f"{ln}:{lane_counts[ln]}" for ln in LANE_NAMES if lane_counts.get(ln))
        bpm = meta.get("bpm", "?")
        self._preview_var.set(
            f"{len(notes)} notes  |  {mins}:{secs:02d}  |  BPM ~{bpm}\n{lane_str}")

    def _refresh_batch_count(self):
        if not self._folder_path:
            return
        rlrrs = self._filtered_rlrrs()
        total = sum(1 for _ in self._folder_path.rglob("*.rlrr"))
        self._batch_count_var.set(
            f"{len(rlrrs)} of {total} .rlrr file(s) match current difficulty filter")

    def _filtered_rlrrs(self) -> list:
        if not self._folder_path:
            return []
        enabled = {d for d, v in self._diff_vars.items() if v.get()}
        out = []
        for p in sorted(self._folder_path.rglob("*.rlrr")):
            stem = p.stem
            matched = any(
                stem.endswith(f"_{d}") or stem.endswith(f"_{d.replace('+', 'Plus')}")
                for d in enabled)
            has_any = any(
                stem.endswith(f"_{d}") or stem.endswith(f"_{d.replace('+', 'Plus')}")
                for d in _MIDI_EXT_DIFFS)
            if matched or (not has_any and enabled == set(_MIDI_EXT_DIFFS)):
                out.append(p)
        return out

    # ── Extract ───────────────────────────────────────────────────────────────

    def _start_extract(self):
        if self._running:
            return
        self._log_clear()
        self._stop_event.clear()
        self._set_running(True)

        if self._single_path and not self._folder_path:
            t = threading.Thread(target=self._run_single, daemon=True)
        elif self._folder_path and not self._single_path:
            rlrrs = self._filtered_rlrrs()
            t = threading.Thread(target=self._run_batch, args=(rlrrs,), daemon=True)
        elif self._single_path:
            t = threading.Thread(target=self._run_single, daemon=True)
        else:
            self._set_running(False)
            return
        t.start()

    def _start_extract_and_send(self):
        self._send_to_editor_after = True
        self._start_extract()

    def _request_stop(self):
        self._stop_event.set()
        self._status_var.set("Stopping…")

    # ── Workers (daemon threads — no direct widget access) ────────────────────

    def _run_single(self):
        path = self._single_path
        self._frame.after(0, lambda: self._log_write(f"Extracting {path.name} …\n", "info"))
        self._frame.after(0, self._progress.start)

        title  = self._meta_title.get().strip()
        artist = self._meta_artist.get().strip()
        notes  = self._single_notes

        if not notes:
            notes, _, err = extract_notes_from_rlrr(path)
            if err:
                self._frame.after(0, lambda: self._log_write(f"ERR {err}\n", "err"))
                self._frame.after(0, self._on_done)
                return

        stem     = _me_safe_stem(title) if title else path.stem
        out_path = (self._output_dir or path.parent) / (stem + ".mid")

        try:
            tmp = out_path.with_suffix(".mid.tmp")
            write_mid_with_metadata(notes, tmp, title=title, artist=artist)
            tmp.replace(out_path)
        except Exception as exc:
            msg = f"Write failed: {exc}"
            self._frame.after(0, lambda: self._log_write(f"ERR {msg}\n", "err"))
            self._frame.after(0, self._on_done)
            return

        label = f"{title} - {artist}".strip(" -") if artist else (title or path.stem)
        self._frame.after(0, lambda: self._log_write(
            f"OK  {label} -> {out_path.name} ({len(notes)} notes)\n", "ok"))
        if self._send_to_editor_after and self._on_send_to_editor:
            _p = str(out_path)
            self._frame.after(0, lambda: self._on_send_to_editor(_p))
        self._frame.after(0, self._on_done)

    def _run_batch(self, rlrr_files: list):
        total = len(rlrr_files)
        self._frame.after(0, lambda: self._progress.configure(
            maximum=max(total, 1), value=0))
        ok_count = err_count = skip_count = 0

        for i, rlrr_path in enumerate(rlrr_files, 1):
            if self._stop_event.is_set():
                skip_count = total - (i - 1)
                self._frame.after(0, lambda s=i - 1: self._log_write(
                    f"Stopped after {s}/{total} files.\n", "warn"))
                break

            out_path = self._resolve_output(rlrr_path)
            ok, msg = self._extract_one_batch(rlrr_path, out_path)
            tag  = "ok" if ok else "err"
            line = f"{'OK ' if ok else 'ERR'} [{i}/{total}] {msg}\n"
            if ok:
                ok_count += 1
            else:
                err_count += 1

            self._frame.after(0, lambda l=line, t=tag, v=i: (
                self._log_write(l, t),
                self._progress.configure(value=v),
                self._prog_var.set(f"{v}/{total}"),
            ))

        self._frame.after(0, lambda: self._log_write(
            f"\nDone — {ok_count} OK, {err_count} error(s), {skip_count} skipped\n"))
        self._frame.after(0, self._on_done)

    # ── Core extraction (worker thread) ──────────────────────────────────────

    def _extract_one_batch(self, rlrr_path: Path, out_path: Path):
        notes, meta, err = extract_notes_from_rlrr(rlrr_path)
        if err:
            return False, f"{rlrr_path.name}: {err}"
        try:
            tmp = out_path.with_suffix(".mid.tmp")
            write_ground_truth_mid(notes, tmp)
            tmp.replace(out_path)
        except Exception as exc:
            return False, f"{rlrr_path.name}: write failed — {exc}"
        title  = meta.get("title", rlrr_path.stem)
        artist = meta.get("artist", "")
        label  = f"{title} - {artist}".strip(" -") if artist else title
        return True, f"{label} -> {out_path.name} ({len(notes)} notes)"

    def _resolve_output(self, rlrr_path: Path) -> Path:
        dest_dir = self._output_dir if self._output_dir else rlrr_path.parent
        return dest_dir / rlrr_path.with_suffix(".mid").name

    # ── State helpers (main thread only) ─────────────────────────────────────

    def _set_running(self, running: bool):
        self._running = running
        s_main = "disabled" if running else "normal"
        s_stop = "normal"   if running else "disabled"
        self._extract_btn.configure(state=s_main)
        self._send_btn.configure(state=s_main)
        self._stop_btn.configure(state=s_stop)
        self._status_var.set("Running…" if running else "")

    def _on_done(self):
        self._send_to_editor_after = False
        self._progress.stop()
        self._set_running(False)
        self._status_var.set("")

    def _reset_progress(self):
        self._progress.configure(value=0, maximum=100)
        self._prog_var.set("")

    # ── Log helpers (main thread only) ────────────────────────────────────────

    def _log_clear(self):
        self._log.configure(state="normal")
        self._log.delete("1.0", "end")
        self._log.configure(state="disabled")

    def _log_write(self, text: str, tag=None):
        self._log.configure(state="normal")
        self._log.insert("end", text, tag or "")
        self._log.see("end")
        self._log.configure(state="disabled")


# ---------------------------------------------------------------------------
# GUI
# ---------------------------------------------------------------------------
class MidiToRlrrApp:

    VERSION = "4.7.8.5"
    # Default song description prefilled in the Single Song Creator until the user
    # edits it (embedded into the .rlrr's recordingMetadata.description on save).
    DEFAULT_SONG_DESCRIPTION = "Song charted using ParaKit"
    REACTIVE_NOTE_WINDOW_S = 0.050   # trailing-only: note flashes white from the moment the playhead reaches it until this many seconds after it has passed (no pre-trigger). Loosened 40ms→50ms in v4.3.22 to give the flash more visible time after worst-case tick-alignment latency at 40 FPS playback.

    ME_DEFAULT_STATUS = (
        "Left-click: add note   Right-click: delete   Drag note: move   "
        "Reclassify toggle: drag to change lane   "
        "Shift+drag: rubber-band select   Ctrl+click: toggle select   "
        "Delete key: remove selected   P: play/pause   S: stop   "
        "T: tap to mark offset   B: tap BPM for last tempo entry   D: place marker"
    )

    def __init__(self, root):
        self.root = root
        self.root.title(f"ParaKit  v{self.VERSION}")
        self.root.resizable(True, True)
        self.root.minsize(640, 760)

        # Theme mode (owner 2026-07-09): "dark" = purple, "light" = original gray.
        # Load the saved choice and point the ACTIVE globals APP_BG / LOG_BG at
        # that palette BEFORE any widget is built, so the whole UI is created in
        # the right colours. The header toggle flips this live (_toggle_theme).
        global APP_BG, LOG_BG
        try:
            _tm = load_config().get("theme_mode", "dark")
        except Exception:
            _tm = "dark"
        self._theme_mode = _tm if _tm in THEME_PALETTES else "dark"
        APP_BG = THEME_PALETTES[self._theme_mode]["app_bg"]
        LOG_BG = THEME_PALETTES[self._theme_mode]["log_bg"]

        # MIDI input (Phase 1): RtMidi callback thread -> queue -> Tk main thread.
        self.midi_queue = queue.Queue()
        self._midi_port = None
        self._midi_hh_pedal_pos = 64
        self._midi_hh_mode = "auto"
        self._midi_first_cc4_seen_at = None
        self._midi_device_name = None
        self._midi_active_profile = None
        self._midi_last_messages = []
        self._midi_test_text = None
        # v4.4.53.6 — Learn-mode infrastructure for the new MIDI Controls
        # dialog. `_midi_user_lane_overrides` maps lane_name -> list of MIDI
        # note numbers, OVERRIDING the class-level `VIZ_LANES_MIDI_IN`
        # defaults when present. Populated by the dialog's "Learn" buttons
        # (each captured note replaces the override list for that lane).
        # Persisted across sessions via config key `midi_input.lane_overrides`.
        # `_midi_learn_target_lane` is set to a lane-name when the user has
        # pressed "Learn" and the dialog is waiting for the next MIDI note
        # to capture; None otherwise.
        try:
            _saved_overrides = load_config().get(
                "midi_input.lane_overrides", {}) or {}
            if not isinstance(_saved_overrides, dict):
                _saved_overrides = {}
        except Exception:
            _saved_overrides = {}
        self._midi_user_lane_overrides = _saved_overrides
        self._midi_learn_target_lane = None
        # `_midi_dialog_lane_indicators` maps lane_name -> tk.Canvas widget
        # (the per-lane hit indicator rectangle in the new dialog). Used by
        # `_handle_midi_message` to pulse the indicator when a matching note
        # arrives. None when dialog isn't open.
        self._midi_dialog_lane_indicators = None
        self._midi_dialog_learn_status_vars = None

        # MIDI input Phase 2: live recording in the MIDI Editor.
        self._midi_record_state = "IDLE"  # IDLE / COUNTIN / RECORDING / STOPPING
        self._midi_record_buffer = []  # (time_secs, editor_lane_idx, velocity)
        self._midi_record_start_time = None
        self._midi_record_song_start = None
        self._midi_record_countin_after_ids = []
        self._midi_count_in_enabled = tk.BooleanVar(value=True)
        self._midi_count_in_clicks_remaining = 0
        self._midi_metronome_sound = tk.StringVar(value="Wood block")
        self._midi_input_offset_ms = tk.DoubleVar(value=0.0)
        self._midi_metronome_cache = {}

        # ── Restore window size/position ──────────────────────────────────────
        cfg = load_config()
        geom = cfg.get("window_geometry")
        if geom:
            try:
                self.root.geometry(geom)
            except Exception:
                self.root.geometry("1100x800")
        else:
            self.root.geometry("1100x800")

        try:
            self.root.update_idletasks()
        except Exception:
            pass

        # 1080p-class monitors need tighter chrome so fixed toolbar/header
        # rows do not squeeze the editor canvases.
        self._compact_layout = self._should_use_compact_layout()

        # Save geometry on close
        self.root.protocol("WM_DELETE_WINDOW", self._on_close)

        # Always dark mode
        self._dark_mode = True

        try:
            self.root.configure(bg=APP_BG)
        except Exception:
            pass

        # Set window icon from bundled .ico (works both as .py and .exe)
        try:
            if getattr(sys, 'frozen', False):
                base = os.path.dirname(sys.executable)
            else:
                base = os.path.dirname(os.path.abspath(__file__))
            ico_path = os.path.join(base, 'parakit.ico')
            if not os.path.exists(ico_path):
                ico_path = os.path.join(base, 'drum_icon_final.ico')
            if os.path.exists(ico_path):
                self.root.iconbitmap(ico_path)
        except Exception:
            pass

        if TTKBS_AVAILABLE:
            ttk_bs.Style(theme="darkly")
        else:
            style = ttk.Style()
            style.theme_use("clam")

        # Force ttkbootstrap's focus/highlight colors to match background
        self.root.option_add("*Label.Background",        APP_BG)
        self.root.option_add("*Label.Foreground",        "#e0e0e0")
        self.root.option_add("*Label.highlightColor",    APP_BG)
        self.root.option_add("*Label.highlightBackground", APP_BG)
        self.root.option_add("*highlightColor",          APP_BG)
        self.root.option_add("*highlightBackground",     APP_BG)

        self._apply_theme()

        # Re-assert the theme once after the first paint settles. ttkbootstrap
        # can leave some widgets (and the root/header background) with its
        # default light styling on the very first paint, before our overrides
        # fully take — that was the "header comes up light until you click the
        # Dark/Light toggle" bug. after_idle fires once the initial layout is
        # done, running the same normalisation the toggle does. (owner 2026-07-10)
        try:
            self.root.after_idle(self._normalize_theme_on_startup)
        except Exception:
            pass

        BG     = APP_BG
        PURPLE = "#b388ff"
        compact = getattr(self, "_compact_layout", False)

        # ── Global header (above tabs) ───────────────────────────────────────
        # v4.4.45 — compact-mode header tightened further: padx 8 (was 10),
        # pady 2 (was 4) so the header consumes less vertical space on
        # 1080p displays where the MIDI Editor canvas gets squeezed.
        header_frame = tk.Frame(root, bg=BG,
                                padx=(8 if compact else 20),
                                pady=(2 if compact else 14))
        header_frame.pack(fill=tk.X)

        # Check for Updates button — top right, always visible above tabs
        update_btn_frame = ttk.Frame(header_frame)
        update_btn_frame.pack(side=tk.RIGHT, anchor="n", pady=(0, 0))
        self._update_status_lbl = ttk.Label(update_btn_frame, text="",
                                             style="Sub.TLabel", foreground="#888")
        self._update_status_lbl.pack(side=tk.RIGHT, padx=(0, 8), anchor="center")
        update_btn = ttk.Button(update_btn_frame, text="🔄  Check for Updates",
                                command=self._check_for_update_manual)
        update_btn.pack(side=tk.RIGHT)
        # Dark / Light theme toggle — sits just left of Check for Updates.
        # "Dark" = the purple theme; "Light" = the app's original gray.
        self._theme_toggle_btn = ttk.Button(
            update_btn_frame,
            text=("🌙  Dark" if self._theme_mode == "dark" else "☀  Light"),
            command=self._toggle_theme)
        self._theme_toggle_btn.pack(side=tk.RIGHT, padx=(0, 10))

        brand_frame = tk.Frame(header_frame, bg=BG)
        brand_frame.pack(anchor="w", fill=tk.X,
                         pady=(0, 0 if compact else 8))

        self.header_logo_img = None
        try:
            if getattr(sys, 'frozen', False):
                logo_base = os.path.dirname(sys.executable)
            else:
                logo_base = os.path.dirname(os.path.abspath(__file__))
            logo_path = os.path.join(logo_base, 'parakit_logo_FINAL.png')
            if os.path.exists(logo_path):
                try:
                    from PIL import Image, ImageTk
                    _pil = Image.open(logo_path).convert("RGBA")
                    # v4.4.45 — compact logo target_h 40 (was 54). 90 stays
                    # for roomy. Smaller logo + tighter logo-to-text padding
                    # buys ~15px of vertical space on 1080p.
                    _target_h = 40 if compact else 90
                    _target_w = int(_pil.width * _target_h / _pil.height)
                    _pil = _pil.resize((_target_w, _target_h), Image.LANCZOS)
                    self.header_logo_img = ImageTk.PhotoImage(_pil)
                except Exception:
                    # PIL unavailable — fall back to integer subsample
                    _logo_img = tk.PhotoImage(file=logo_path)
                    _scale = max(1, round(_logo_img.height() / (40 if compact else 90)))
                    self.header_logo_img = _logo_img.subsample(_scale, _scale)
                tk.Label(brand_frame, image=self.header_logo_img, bg=BG, bd=0,
                         highlightthickness=0).pack(
                             side=tk.LEFT, anchor="center",
                             padx=(0, 8 if compact else 22))
        except Exception:
            self.header_logo_img = None

        brand_text = tk.Frame(brand_frame, bg=BG)
        brand_text.pack(side=tk.LEFT, anchor="n", fill=tk.X, expand=True)

        self.header_wordmark_img = None
        try:
            wordmark_candidates = []
            if getattr(sys, 'frozen', False):
                wordmark_candidates.append(
                    os.path.join(os.path.dirname(sys.executable), 'Parakit_header_logo.png'))
                wordmark_candidates.append(
                    os.path.join(getattr(sys, "_MEIPASS", ""), 'Parakit_header_logo.png'))
            else:
                wordmark_candidates.append(
                    os.path.join(os.path.dirname(os.path.abspath(__file__)), 'Parakit_header_logo.png'))
            wordmark_path = next((p for p in wordmark_candidates if p and os.path.exists(p)), None)
            if wordmark_path and os.path.exists(wordmark_path):
                from PIL import Image, ImageTk
                _wm = Image.open(wordmark_path).convert("RGBA")
                # The source wordmark may carry a near-black/navy rectangle
                # behind the letters. Key that out before resizing so it sits
                # cleanly on ParaKit's dark header background.
                _px = _wm.load()
                for _y in range(_wm.height):
                    for _x in range(_wm.width):
                        _r, _g, _b, _a = _px[_x, _y]
                        if _a and _r < 34 and _g < 26 and _b < 54:
                            _px[_x, _y] = (_r, _g, _b, 0)
                _bbox = _wm.getbbox()
                if _bbox:
                    _wm = _wm.crop(_bbox)
                # Keep the wordmark below the 90px icon height so the header
                # and notebook tabs stay at their existing vertical positions.
                # v4.4.45 — compact wordmark target_h 18 (was 22) for more
                # vertical reclaim on 1080p.
                _target_h = 18 if compact else 34
                _target_w = int(_wm.width * _target_h / _wm.height)
                _wm = _wm.resize((_target_w, _target_h), Image.LANCZOS)
                self.header_wordmark_img = ImageTk.PhotoImage(_wm)
        except Exception:
            self.header_wordmark_img = None

        if self.header_wordmark_img:
            self.songmaker_lbl = tk.Label(brand_text, image=self.header_wordmark_img,
                  bg=BG, bd=0, highlightthickness=0)
