        # v4.4.38 — also re-apply theme on every tab switch. ttkbootstrap
        # applies its own styles during widget creation and on tab activation,
        # which can override our base-TRadiobutton foreground=PURPLE setting
        # for tabs not visible at the 50ms post-init reapply moment. Calling
        # `_apply_theme` again on tab change ensures the just-activated tab's
        # widgets pick up our latest style settings consistently.
        self.notebook.bind("<<NotebookTabChanged>>",
                           lambda e: self._apply_theme(), add="+")

        # Re-apply theme after all tabs are built — ttkbootstrap re-applies
        # its own styles during widget creation which can override our tab colors
        # v4.4.38 — staggered re-applies at 50ms, 200ms, 500ms, 1000ms catch
        # any later ttkbootstrap reapplication passes that might override our
        # base styles on non-currently-visible tabs.
        self.root.after(50,   self._apply_theme)
        self.root.after(200,  self._apply_theme)
        self.root.after(500,  self._apply_theme)
        self.root.after(1000, self._apply_theme)
        # v4.4.62-1 — reinstated automatic update check: a few seconds after
        # startup, silently ask GitHub whether a newer version is out (reads the
        # repo README's "Version in this release" line), so users who don't visit
        # GitHub or click the button still hear about updates. Quiet on failure
        # and when up-to-date; only prompts when a newer version is available.
        self.root.after(3000, self._check_for_update)
        # v4.5.5.1 — one-time notice: the pre-4.5.5.1 in-app updater pulled only
        # the main .py, so anyone who updated in-app may have stale supporting
        # files. Explain it once + offer a one-click in-place resync. Shown once
        # (config-flagged); source installs only.
        self.root.after(1500, self._maybe_show_dep_sync_notice)
        # v4.5.7.x audit fix — sweep stale A2M temp artifacts from PREVIOUS
        # sessions (alt-detector request dirs, Neural-Isolation stem WAV dirs,
        # orphaned larsnet runtime YAMLs). Age-guarded 24h so a concurrently
        # running instance (or this session's own separator workdir, which the
        # MIDI-Editor source-audio hand-off still references) is never touched.
        threading.Thread(target=self._sweep_stale_a2m_temp, daemon=True).start()

