    def _build_menu_bar(self):
        """Build a guarded desktop-style menu bar as alternate access to existing UI."""
        self._menu_guards = []
        self._tab_indexes = {
            "single": 0, "batch": 1, "ogg": 2, "stem": 3,
            "a2m": 4, "midi": 5, "sheet": 6, "youtube": 7,
            "asset": 8, "tester": 9, "preview": 10, "help": 11,
        }

        menubar = tk.Menu(self.root, tearoff=False)
        self.root.config(menu=menubar)

        def add(menu, label, command, guard=None, accelerator=None):
            kwargs = {"label": label, "command": command}
            if accelerator:
                kwargs["accelerator"] = accelerator
            menu.add_command(**kwargs)
            idx = menu.index("end")
            if guard:
                self._menu_guards.append((menu, idx, guard))

        file_menu = tk.Menu(menubar, tearoff=False, postcommand=self._update_menu_state)
        menubar.add_cascade(label="File", menu=file_menu)
