    def _menu_go(self, tab_key, then=None):
        """Switch to a tab, then optionally run an existing UI command."""
        try:
            self.notebook.select(self._tab_indexes[tab_key])
        except Exception:
            pass
        self._update_menu_state()
        if then:
            then()

    def _menu_is_tab(self, tab_key):
        try:
            return self.notebook.index("current") == self._tab_indexes[tab_key]
        except Exception:
            return False

    def _menu_safe_call(self, tab_key, predicate, fn, message):
        """Run a menu command only when its tab/context is safe."""
        if tab_key and not self._menu_is_tab(tab_key):
            self._menu_go(tab_key)
            if not predicate():
                messagebox.showinfo("Menu Command", message)
                return
        elif predicate and not predicate():
            messagebox.showinfo("Menu Command", message)
            return
        fn()
        self._update_menu_state()

    def _update_menu_state(self):
        for menu, idx, guard in getattr(self, "_menu_guards", []):
            try:
                menu.entryconfig(idx, state=("normal" if guard() else "disabled"))
            except Exception:
                pass

    def _menu_me_has_notes(self):
        return bool(getattr(self, "me_notes", []))

    def _menu_me_has_selection(self):
        return bool(getattr(self, "_me_selected_notes", set()))

    def _menu_me_has_clipboard(self):
        return bool(getattr(self, "_me_clipboard", []))

    def _menu_me_has_undo(self):
        return bool(getattr(self, "me_undo_stack", []))

    def _menu_me_has_redo(self):
        return bool(getattr(self, "me_redo_stack", []))

    def _menu_a2m_ready(self):
        return bool(getattr(self, "a2m_input_var", tk.StringVar()).get().strip()
                    and getattr(self, "a2m_output_var", tk.StringVar()).get().strip())

    def _menu_has_last_a2m_midi(self):
        path = getattr(self, "_a2m_last_midi", "")
        return bool(path and os.path.exists(path))

    def _menu_open_midi_extractor(self):
        self._menu_go("a2m")
        if not getattr(self, "_midi_extractor_visible", False):
            fn = getattr(self, "_toggle_midi_extractor_fn", None)
            if fn:
                fn()

    # ────────────────────────────────────────────────────────────────────
    # Paradiddle → Clone Hero Batch Converter orchestration methods
    # (v4.4.57.96-10 Patch 7+8 — re-applies v4.4.57.86-8 + .87-8 + .88-8)
    #
    # These methods sit on MidiToRlrrApp and are invoked by the
    # `_PdToChConverterWindow` Toplevel popup (module-level class defined
    # alongside the Pd→CH helpers at L1933-3050). All additive — no edits
    # to existing CH export flow at T1 or T3 batch.
    # ────────────────────────────────────────────────────────────────────
    def _pd_to_ch_open_converter(self):
        """Tools menu callback. Lazy-instantiate the converter popup;
        bring to front if already open."""
        existing = getattr(self, "_pd_to_ch_window", None)
        if existing is not None:
            try:
                existing.deiconify()
                existing.lift()
                return
            except Exception:
                pass
        self._pd_to_ch_window = _PdToChConverterWindow(self.root, self)

    def _pd_to_ch_scan_folder(self, folder_path):
        """Scan a Paradiddle source folder for .rlrr files + audio + image
        + metadata. Returns dict consumed by the popup's per-tab render
        logic and the convert methods. Schema in dispatch §3.4."""
        import glob as _glob
        import json as _json

        result = {
            "folder": folder_path,
            "rlrr_files": [],
            "audio_files": {},
            "metadata": {},
            "rlrr_audio_filename": None,
            "errors": [],
        }
        if not folder_path or not os.path.isdir(folder_path):
            result["errors"].append(
                f"Folder not found or not accessible: {folder_path}")
            return result

        rlrr_paths = sorted(
            _glob.glob(os.path.join(folder_path, "*.rlrr")))
        if not rlrr_paths:
            result["errors"].append("No .rlrr files in this folder.")
            return result

        first_metadata = None
        first_audio_filename = None
        for rp in rlrr_paths:
            filename = os.path.basename(rp)
            difficulty = _paradiddle_difficulty_from_filename(filename)
            notes, bpm = self._load_rlrr_as_me_notes(rp)
            if notes is None:
                result["errors"].append(
                    f"Failed to parse RLRR: {filename}")
                continue
            result["rlrr_files"].append({
                "path": rp,
                "filename": filename,
                "difficulty": difficulty,
                "notes_count": len(notes),
                "bpm": float(bpm) if bpm else 120.0,
            })
            if first_metadata is None:
                try:
                    text = None
                    for enc in ("utf-8-sig", "utf-8", "utf-16", "cp1252"):
                        try:
                            with open(rp, "r", encoding=enc) as f:
                                text = f.read()
                            break
                        except (UnicodeDecodeError, LookupError):
                            continue
                    if text is not None:
                        data = _json.loads(text)
                        rec = data.get("recordingMetadata", {}) or {}
                        first_metadata = {
                            "title":   str(rec.get("title", "") or ""),
                            "artist":  str(rec.get("artist", "") or ""),
                            "album":   str(rec.get("album", "") or ""),
                            "year":    str(rec.get("year", "") or ""),
                            "genre":   str(rec.get("genre", "") or "")
                                       or "rock",
                            "charter": str(rec.get("creator",
                                                    rec.get("charter", ""))
                                            or "Unknown"),
                        }
                        first_audio_filename = (
                            data.get("audioFileName") or "")
                except Exception as e:
                    result["errors"].append(
                        f"Metadata parse failed for {filename}: {e}")

        result["metadata"] = first_metadata or {
            "title": "", "artist": "", "album": "", "year": "",
            "genre": "rock", "charter": "Unknown",
        }
        result["rlrr_audio_filename"] = first_audio_filename

        result["audio_files"] = _paradiddle_detect_audio_files(
            folder_path, first_audio_filename)
        return result

    def _pd_to_ch_convert_single(self, scan_result, options, log_callback):
        """Convert one scanned Paradiddle source folder into a CH song
        folder. Returns True on success, False on failure (errors logged
        via callback)."""
        def _log(msg):
            try:
                log_callback(msg)
            except Exception:
                pass

        try:
            if not scan_result or not scan_result.get("rlrr_files"):
                _log("ERROR: no .rlrr files in scan result.")
                return False

            selected_rlrrs = options.get("selected_rlrrs", []) or []
            difficulty_map = options.get("difficulty_map", {}) or {}
            if not selected_rlrrs:
                _log("ERROR: no .rlrr difficulties selected.")
                return False

            metadata = options.get("metadata", {}) or {}
            additional_creator = (options.get("additional_creator", "")
                                  or "").strip()
            parent_folder = (options.get("parent_folder", "") or "").strip()
            folder_name_template = options.get("folder_name_template",
                                                "artist_title")
            emit_velocity_flags = bool(options.get("emit_velocity_flags",
                                                    True))
            fetched_art_bytes = options.get("fetched_art_bytes")

            if not parent_folder or not os.path.isdir(parent_folder):
                _log(f"ERROR: output parent folder not found: "
                     f"{parent_folder}")
                return False

            title = metadata.get("title", "").strip() or "Untitled"
            artist = metadata.get("artist", "").strip() or "Unknown"
            album = metadata.get("album", "").strip()
            year = metadata.get("year", "").strip()
            genre = metadata.get("genre", "").strip() or "rock"

            original_charter = (scan_result.get("metadata", {})
                                .get("charter", "Unknown") or "Unknown")
            charter_str = original_charter
            if additional_creator:
                charter_str = f"{original_charter}, {additional_creator}"

            events_by_difficulty = {}
            highest_rating = 0
            # Audit E8 (2026-07-10): ONE reference BPM (the first usable
            # file's) converts EVERY difficulty's absolute note-times, and that
            # same BPM is written to the chart's single SyncTrack. Previously
            # each file converted under its own BPM but the LAST file's BPM
            # went to the SyncTrack — mixed-BPM selections decoded earlier
            # sections at the wrong wall-clock time. Note times are absolute
            # seconds, so converting under the reference keeps every section
            # wall-clock correct.
            bpm_used = 0.0
            for rp in selected_rlrrs:
                diff = difficulty_map.get(rp)
                if diff not in self._pd_to_ch_diff_order():
                    _log(f"  SKIP (no difficulty): "
                         f"{os.path.basename(rp)}")
                    continue
                notes, bpm = self._load_rlrr_as_me_notes(rp)
                if notes is None:
                    _log(f"  SKIP (parse failed): "
                         f"{os.path.basename(rp)}")
                    continue
                file_bpm = float(bpm) if bpm else 120.0
                if not bpm_used:
                    bpm_used = file_bpm
                elif abs(file_bpm - bpm_used) > 0.01:
                    _log(f"  NOTE: {os.path.basename(rp)} carries "
                         f"bpmEvents={file_bpm:.2f}, but the chart's single "
                         f"SyncTrack uses {bpm_used:.2f} — its notes are "
                         f"converted from absolute seconds under the SyncTrack "
                         f"BPM so timing stays correct.")
                ev_list = _paradiddle_rlrr_to_ch_events(
                    notes, bpm_used,
                    emit_velocity_flags=emit_velocity_flags,
                )
                if not ev_list:
                    _log(f"  WARNING: {os.path.basename(rp)} produced 0 CH "
                         f"events (no mappable MIDI notes).")
                    continue
                events_by_difficulty[diff] = ev_list
                rating = _PdToChConverterWindow._DIFF_TO_RATING.get(diff, 3)
                if rating > highest_rating:
                    highest_rating = rating
                _log(f"  {diff}: {len(ev_list)} events from "
                     f"{os.path.basename(rp)}")

            if not events_by_difficulty:
                _log("ERROR: no usable events from any selected .rlrr.")
                return False
            if highest_rating == 0:
                highest_rating = 3
            bpm_used = bpm_used or 120.0   # E8: never write a 0-BPM SyncTrack

            def _safe_name(s):
                illegal = '<>:"/\\|?*'
                out = "".join("_" if c in illegal else c for c in s)
                out = "".join(c for c in out
                              if ord(c) >= 32 and ord(c) != 0x7F)
                out = out.rstrip(". ").strip()
                if len(out) > 200:
                    out = out[:200].rstrip(". ").strip()
                return out or "Untitled"

            if folder_name_template == "title_only":
                subfolder_name = _safe_name(title)
            else:
                subfolder_name = _safe_name(f"{artist} - {title}")
            ch_dir = os.path.join(parent_folder, subfolder_name)

            audio_files = scan_result.get("audio_files", {}) or {}
            song_src = audio_files.get("song")
            if not song_src or not os.path.isfile(song_src):
                unmapped = audio_files.get("unmapped", []) or []
                if unmapped:
                    song_src = unmapped[0]
                    _log(f"  NOTE: no main 'song' audio detected; using "
                         f"first unmapped audio as main mix: "
                         f"{os.path.basename(song_src)}")
            if not song_src or not os.path.isfile(song_src):
                _log("ERROR: no main audio file found to use as song.<ext>.")
                return False

            song_ext = os.path.splitext(song_src)[1].lower() or ".ogg"
            music_stream_filename = f"song{song_ext}"

            chart_str = build_chart_multi_difficulty(
                events_by_difficulty=events_by_difficulty,
                bpm=bpm_used,
                title=title, artist=artist,
                album=album, year=year,
                charter=charter_str,
                music_stream=music_stream_filename,
            )

            song_len_ms = 0
            for diff_key in ("Expert", "Hard", "Medium", "Easy"):
                ev = events_by_difficulty.get(diff_key) or []
                if ev:
                    last_tick = ev[-1][0]
                    last_sec = last_tick / (bpm_used / 60.0 * 192) + 5.0
                    song_len_ms = int(last_sec * 1000)
                    break
            ini_str = write_song_ini(
                title=title, artist=artist,
                album=album, year=year,
                charter=charter_str,
                song_length_ms=song_len_ms,
                diff_drums=highest_rating,
            )

            os.makedirs(ch_dir, exist_ok=True)

            chart_path = os.path.join(ch_dir, "notes.chart")
            with open(chart_path, "w", encoding="utf-8",
                      newline="\n") as f:
                f.write(chart_str)
            _log(f"  Wrote: notes.chart  ({len(chart_str)} bytes, "
                 f"{len(events_by_difficulty)} difficulty section(s))")

            ini_path = os.path.join(ch_dir, "song.ini")
            with open(ini_path, "w", encoding="utf-8",
                      newline="\n") as f:
                f.write(ini_str)
            _log(f"  Wrote: song.ini  (diff_drums={highest_rating}, "
                 f"charter='{charter_str}')")

            shutil.copy2(song_src,
                          os.path.join(ch_dir, music_stream_filename))
            _log(f"  Copied audio: {os.path.basename(song_src)} → "
                 f"{music_stream_filename}")

            for role in ("drums", "bass", "guitar", "vocals", "keys",
                         "rhythm"):
                src = audio_files.get(role)
                if src and os.path.isfile(src):
                    ext = os.path.splitext(src)[1].lower() or ".ogg"
                    dest = os.path.join(ch_dir, f"{role}{ext}")
                    try:
                        shutil.copy2(src, dest)
                        _log(f"  Copied stem: {os.path.basename(src)} → "
                             f"{role}{ext}")
                    except Exception as e:
                        _log(f"  WARNING: failed to copy {role}: {e}")

            if audio_files.get("unmapped"):
                _log(f"  NOTE: {len(audio_files['unmapped'])} audio "
                     f"file(s) had no role match; not copied. "
                     f"User can manually move if needed.")

            if audio_files.get("album_art"):
                src_art = audio_files["album_art"]
                try:
                    shutil.copy2(src_art,
                                  os.path.join(ch_dir, "album.png"))
                    _log(f"  Copied album art: "
                         f"{os.path.basename(src_art)} → album.png")
                except Exception as e:
                    _log(f"  WARNING: failed to copy album art: {e}")
            elif fetched_art_bytes:
                try:
                    from PIL import Image as _PI
                    import io as _io
                    _img = _PI.open(_io.BytesIO(fetched_art_bytes))
                    _img.save(os.path.join(ch_dir, "album.png"),
                              format="PNG")
                    _log("  Wrote auto-fetched album art → album.png")
                except Exception as e:
                    _log(f"  WARNING: failed to save fetched art: {e}")

            try:
                save_config({
                    "ch_output_folder": parent_folder,
                    "ch_folder_name_template": folder_name_template,
                    "ch_emit_ghost_accent": bool(emit_velocity_flags),
                })
            except Exception:
                pass

            _log(f"\n  Output folder: {ch_dir}")
            return True
        except Exception as e:
            _log(f"\n✗  Convert error: {e}")
            try:
                import traceback
                _log(traceback.format_exc())
            except Exception:
                pass
            return False

    def _pd_to_ch_convert_batch(self, queued, options, log_callback):
        """Sequential iteration over queued scan_result dicts. Per-folder
        failures log but do not abort the batch.

        Per-song popups (v.87-8 Gap A + B closures):
          * batch_apply_all OFF → `_ask_user_for_metadata_edit` per song
          * batch_autofetch_art ON + source folder lacks art →
            `_ask_user_about_art` per song
          * Defaults (True, False) preserve v.86-8 behavior."""
        def _log(msg):
            try:
                log_callback(msg)
            except Exception:
                pass

        total = len(queued)
        if total == 0:
            _log("Batch: no songs queued.")
            return

        popup_window = getattr(self, "_pd_to_ch_window", None)
        batch_apply_all = bool(options.get("batch_apply_all", True))
        batch_autofetch_art = bool(options.get("batch_autofetch_art", False))

        _log(f"\n=== Batch convert: {total} song(s) ===")
        success_count = 0
        for idx, scan in enumerate(queued, start=1):
            folder = scan.get("folder", "")
            _log(f"\n[{idx}/{total}] {os.path.basename(folder)}")

            per_song_options = dict(options)
            per_song_options["metadata"] = dict(scan.get("metadata", {}))
            selected = []
            diff_map = {}
            for rf in scan.get("rlrr_files", []):
                d = rf.get("difficulty")
                if d in _PdToChConverterWindow._DIFF_ORDER:
                    selected.append(rf["path"])
                    diff_map[rf["path"]] = d
            if not selected:
                _log("  SKIP: no detectable-difficulty .rlrr files in "
                     "this folder. (Use Single tab to pick manually.)")
                continue
            per_song_options["selected_rlrrs"] = selected
            per_song_options["difficulty_map"] = diff_map

            if (not batch_apply_all) and popup_window is not None:
                edited = popup_window._ask_user_for_metadata_edit(scan)
                if edited is None:
                    _log("  SKIPPED (user pressed Skip in metadata popup).")
                    continue
                per_song_options["metadata"] = dict(edited["metadata"])
                per_song_options["additional_creator"] = (
                    edited.get("additional_creator", "") or "")

            per_song_options["fetched_art_bytes"] = None
            audio_map = scan.get("audio_files", {}) or {}
            song_lacks_art = not audio_map.get("album_art")
            if batch_autofetch_art and song_lacks_art and popup_window is not None:
                song_title = per_song_options["metadata"].get("title", "") or ""
                song_artist = per_song_options["metadata"].get("artist", "") or ""
                art_result = popup_window._ask_user_about_art(
                    song_title, song_artist)
                if art_result is not None:
                    per_song_options["fetched_art_bytes"] = art_result.get(
                        "art_bytes")
                    _log("  Album art accepted via iTunes fetch.")
                else:
                    _log("  Album art skipped by user (no album.png "
                         "will be written).")
            elif batch_autofetch_art and song_lacks_art and popup_window is None:
                _log("  NOTE: auto-fetch art = ON but converter window "
                     "is gone; skipping art for this song.")

            ok = self._pd_to_ch_convert_single(scan, per_song_options, _log)
            if ok:
                success_count += 1
            else:
                _log("  (continuing batch despite failure on this folder)")

        _log(f"\n=== Batch complete: {success_count}/{total} succeeded ===")

    def _pd_to_ch_diff_order(self):
        """Tuple of difficulty names accepted by the converter."""
        return _PdToChConverterWindow._DIFF_ORDER

    def _menu_tester_ready(self):
        return bool(getattr(self, "tester_midi_var", tk.StringVar()).get().strip()
                    and getattr(self, "tester_audio_var", tk.StringVar()).get().strip())

    def _menu_about(self):
        messagebox.showinfo(
            "About ParaKit",
            f"ParaKit v{self.VERSION}\n\n"
            "Created by Micah. P.G. / Sherifican\n\n"
            "Custom Song Creator for Paradiddle and Clone Hero.\n\n"
            "The menu bar is an alternate shortcut layer; the tab UI remains the main workflow.")

    def _set_global_status(self, msg, timeout_ms=0):
        """Show a lightweight app-wide status message at the bottom of the window."""
        try:
            self._global_status_var.set(msg)
            if timeout_ms:
                self.root.after(timeout_ms, lambda: self._global_status_var.set(
                    "Ready - choose a tab to start building or cleaning up a chart."))
        except Exception:
            pass

    def _setup_pretty_log_widget(self, widget, bg=None):
        """Apply ParaKit-themed colors and tags to a ScrolledText log widget."""
        if widget is None:
            return
        try:
            current_bg = bg or widget.cget("bg") or "#0d1117"
        except Exception:
            current_bg = bg or "#0d1117"
        try:
            widget.configure(
                bg=current_bg,
                fg=PRETTY_LOG_TEXT,
                insertbackground=PRETTY_LOG_TEXT,
            )
            widget.tag_configure("log_text", foreground=PRETTY_LOG_TEXT)
            widget.tag_configure("log_number", foreground=PRETTY_LOG_NUMBER)
            widget.tag_configure("log_flair", foreground=PRETTY_LOG_FLAIR)
            widget.tag_configure("log_error", foreground=PRETTY_LOG_ERROR)
            widget.tag_configure("log_warning", foreground=PRETTY_LOG_WARNING)
            widget.tag_configure("log_success", foreground=PRETTY_LOG_SUCCESS)
            widget.tag_configure("log_info", foreground=PRETTY_LOG_INFO)
        except Exception:
            pass

    def _pretty_log_insert(self, widget, text):
        """Insert themed log text into a Tk Text widget without changing state."""
        self._setup_pretty_log_widget(widget)
        for tag, chunk in _pretty_log_segments(text):
            widget.insert(tk.END, chunk, tag)

    def _pretty_log_replace(self, widget, text):
        """Replace a log widget's contents using themed token tags."""
        self._setup_pretty_log_widget(widget)
        widget.delete("1.0", tk.END)
        self._pretty_log_insert(widget, text)

    def _setup_global_scroll(self):
        """One global handler that scrolls whatever scrollable widget is under
        the cursor. Skips the MIDI editor tab entirely."""

        def _is_in_midi_editor(widget):
            """Walk up the widget tree to check if we're inside the MIDI editor."""
            w = widget
            while w:
                if w is getattr(self, 'me_canvas', None):
                    return True
                if w is getattr(self, 'me_label_canvas', None):
                    return True
                try:
                    w = w.master
                except Exception:
                    break
            return False

        def _on_mousewheel(event):
            # Block if event came from a popup window (Ghost overlay, Mixer, Markers)
            try:
                top = event.widget.winfo_toplevel()
                if top is not self.root:
                    return "break"
            except Exception:
                pass
            # Block root-level scroll if the event came from a Scale widget
            wclass = event.widget.winfo_class()
            if wclass == 'Scale':
                return "break"
            if _is_in_midi_editor(event.widget):
                return  # MIDI editor handles its own scrolling
            widget = event.widget
            while widget:
                # The neon-dot AND snare-node-line progress bars are Canvas
                # subclasses but are UI elements, not scrollable content — walk
                # past them to find the real scrollable container. (Without this
                # the wheel scrolls the bar's own canvas, sliding the bar graphic
                # out of view — the YouTube-tab progress-bar bug, owner 2026-06-16.)
                if isinstance(widget, (NeonDotProgressBar, _G85AltSnareProgressBar)):
                    try:
                        widget = widget.master
                    except Exception:
                        break
                    continue
                wclass = widget.winfo_class()
                if wclass in ('Canvas', 'Text'):
                    try:
                        widget.yview_scroll(int(-1 * (event.delta / 120)), "units")
                    except Exception:
                        pass
                    return
                try:
                    widget = widget.master
                except Exception:
                    break

        self.root.bind_all("<MouseWheel>", _on_mousewheel)
        self.root.bind_all("<Button-4>",
            lambda e: self._scroll_under_cursor(e, -1))
        self.root.bind_all("<Button-5>",
            lambda e: self._scroll_under_cursor(e,  1))

    def _scroll_under_cursor(self, event, direction):
        widget = event.widget
        while widget:
            if widget is getattr(self, 'me_canvas', None):
                return  # skip MIDI editor
            if widget is getattr(self, 'me_label_canvas', None):
                return
            if widget in {getattr(self, k, None) for k in (
                    'viz_canvas', 'viz_practice_canvas',
                    'viz_density', 'viz_legend', 'viz_practice_legend')}:
                return  # Practice Mini-Game — no scrolling
            # The neon-dot AND snare-node-line progress bars are Canvas
            # subclasses used as UI elements, not scrollable content — walk
            # past them (else the wheel slides the bar graphic out of view).
            if isinstance(widget, (NeonDotProgressBar, _G85AltSnareProgressBar)):
                try:
                    widget = widget.master
                except Exception:
                    break
                continue
            if widget.winfo_class() in ('Canvas', 'Text'):
                try:
                    widget.yview_scroll(direction, "units")
                except Exception:
                    pass
                return
            try:
                widget = widget.master
            except Exception:
                break

    # =========================================================================
    # Tab 1 — Single Song Creator
    # =========================================================================
    def _register_session_temp(self, path):
        """Track a temp file that must outlive its creator (another tab still
        references the path this session) but should not outlive the app.
        Deleted best-effort in _on_close. (Audit A4 — sheet-music conversions
        with 'Save file' off leaked one .mid per run, permanently.)"""
        try:
            self._session_temp_files = getattr(self, "_session_temp_files", [])
            self._session_temp_files.append(str(path))
        except Exception:
            pass

    def _on_close(self):
        """Save window geometry before closing. If the MIDI Editor has unsaved
        edits, prompt the user first (Save & Quit / Exit Without Saving / Cancel)."""
        if getattr(self, "me_edit_started", False) and getattr(self, "me_notes", None):
            choice = self._me_prompt_unsaved_on_quit()
            if choice == "cancel":
                return                       # abort the close — keep the session open
            if choice == "save":
                if not self._me_save(show_message=False):
                    return                   # user backed out of the save dialog → don't quit
            # choice == "discard" → fall through and quit without saving
        save_config({"window_geometry": self.root.geometry()})
        # Session temp files (sheet-music handoffs etc.) — best-effort removal.
        for _p in getattr(self, "_session_temp_files", []):
            try:
                os.remove(_p)
            except Exception:
                pass
        try:
            self._midi_close()
        except Exception:
            pass
        self.root.destroy()

    # ── Elapsed timer helpers ─────────────────────────────────────────────────
    def _timer_start(self, label_widget):
        """Start a live elapsed timer updating a label every second."""
        import time
        self._timer_start_time = time.time()
        self._timer_running    = True
        self._timer_label      = label_widget

        def _tick():
            if not self._timer_running:
                return
            elapsed = time.time() - self._timer_start_time
            m = int(elapsed // 60)
            s = int(elapsed % 60)
            try:
                self._timer_label.configure(
                    text=f"⏱  {m:02d}:{s:02d}",
                    foreground="#00d4d4")
            except Exception:
                return
            self._timer_after_id = self.root.after(1000, _tick)

        _tick()

    def _timer_stop(self, label_widget):
        """Stop the timer and freeze the final elapsed time on the label."""
        import time
        self._timer_running = False
        try:
            self.root.after_cancel(self._timer_after_id)
        except Exception:
            pass
        if hasattr(self, '_timer_start_time'):
            elapsed = time.time() - self._timer_start_time
            m = int(elapsed // 60)
            s = int(elapsed % 60)
            try:
                label_widget.configure(
                    text=f"⏱  {m:02d}:{s:02d}  (done)",
                    foreground="#00884a")
            except Exception:
                pass

    def _sweep_stale_a2m_temp(self, max_age_h=24):
        """Delete leftover A2M temp artifacts from PREVIOUS sessions:
        %TEMP%/parakit_alt_detector/<uuid>/ (request/response dirs — normally
        removed per-run, this is the crash/kill safety net),
        %TEMP%/parakit_sep_v4_4_*/ (Neural Stem Isolation mkdtemp dirs — 100+ MB
        of stem WAVs per run, never cleaned in-run), and
        %TEMP%/larsnet_runtime_*.yaml (orphaned when the alt-detector child is
        timeout-killed before its own finally runs).

        Age-guarded: only items older than max_age_h are removed, so a second
        running instance — or THIS session's separator workdir, which
        _a2m_source_file may still reference for the MIDI-Editor hand-off — is
        never raced. Runs on a daemon thread; touches no Tk objects."""
        import glob, time, tempfile
        cutoff = time.time() - max_age_h * 3600
        tmp = tempfile.gettempdir()
        pats = [os.path.join(tmp, "parakit_alt_detector", "*"),
                os.path.join(tmp, "parakit_sep_v4_4_*"),
                os.path.join(tmp, "larsnet_runtime_*.yaml")]
        for pat in pats:
            for p in glob.glob(pat):
                try:
                    if os.path.getmtime(p) >= cutoff:
                        continue
                    if os.path.isdir(p):
                        shutil.rmtree(p, ignore_errors=True)
                    else:
                        os.remove(p)
                except Exception:
                    pass

    def _bg_message(self, title, msg, kind="error"):
        """Show a messagebox on the Tk main thread from any worker thread.
        The message is materialized to a plain string HERE (the caller's scope),
        so a deferred ``except ... as e`` variable — which Python deletes when the
        except block ends, before this after() lambda runs — can't NameError.
        (Audit fix A1/B: replaces the leaky `after(0, lambda: showerror(..{e}..))`.)"""
        m = str(msg)
        fn = {"error": messagebox.showerror,
              "warning": messagebox.showwarning,
              "info": messagebox.showinfo}.get(kind, messagebox.showerror)
        try:
            self.root.after(0, lambda: fn(title, m))
        except Exception:
            pass

    def _check_for_update(self):
        """Check GitHub for a newer version and prompt user if available (silent on fail)."""
        threading.Thread(target=self._update_worker, daemon=True).start()

    def _check_for_update_manual(self):
        """Check for updates and always report result to the user."""
        try:
            self._update_status_lbl.configure(text="Checking...", foreground="#b388ff")
        except Exception:
            pass
        threading.Thread(target=lambda: self._update_worker(silent=False), daemon=True).start()

    # 2026-06-15 (v4.4.62-1) — Update-check repointed to GitHub (the website was
    # down). The raw README on the open-source repo's main branch carries the
    # line "Version in this release: X.Y.Z"; we read that and compare to
    # self.VERSION. If newer, the user can open GitHub to download just the one
    # file, and (running from source) let ParaKit download + replace that single
    # file in place. We deliberately do NOT git clone — that pulls the whole repo
    # for a one-file change. The compiled .exe download is maintained separately.
    # IMPORTANT: the README "Version in this release:" line is the source of
    # truth here — keep it in sync with the VERSION constant on every push.
    PARAKIT_RELEASE_URL = "https://github.com/sherifican/ParaKit-Open_Source"
    PARAKIT_RELEASE_FILE_URL = (
        "https://github.com/sherifican/ParaKit-Open_Source/blob/main/ParaKit%20v4.0.py")
    PARAKIT_README_RAW_URL = (
        "https://raw.githubusercontent.com/sherifican/ParaKit-Open_Source/main/README.md")
    PARAKIT_PY_RAW_URL = (
        "https://raw.githubusercontent.com/sherifican/ParaKit-Open_Source/main/ParaKit%20v4.0.py")
    # v4.5.5.1: base for pulling any dependency file, + the manifest that lists them.
    # The in-app updater syncs every runtime file a release needs (not just the main
    # .py), so a multi-file update installs correctly without re-cloning the repo.
    PARAKIT_RAW_BASE = (
        "https://raw.githubusercontent.com/sherifican/ParaKit-Open_Source/main/")
    PARAKIT_MANIFEST_RAW_URL = (
        "https://raw.githubusercontent.com/sherifican/ParaKit-Open_Source/main/update_manifest.json")
    # v4.5.5.1: the update-available popup keeps a short "your supporting files
    # may be stale" reminder up for a few versions (belt-and-suspenders for users
    # who skim the one-time notice), then auto-retires it at this version.
    DEP_SYNC_NOTICE_UNTIL = "4.5.7"

    def _update_worker(self, silent=True):
        """Background: read the open-source repo's README "Version in this
        release" line on GitHub and compare it to self.VERSION."""
        import urllib.request, re

        release_url = self.PARAKIT_RELEASE_URL

        def _ver(s):
            try:
                # Accept a 2-to-4-number core (defensive: handles the standard
                # 3-segment "4.5.0-1" AND any future two-segment "X.Y-N" release).
                m = re.match(r"^v?(\d+(?:\.\d+){1,3})(?:-(\d+))?$", str(s).strip())
                if not m:
                    return None
                core = tuple(int(x) for x in m.group(1).split("."))
                suffix = int(m.group(2) or 0)
                return core + (suffix,)
            except Exception:
                return None

        try:
            req = urllib.request.Request(
                self.PARAKIT_README_RAW_URL,
                headers={"User-Agent": "ParaKit-update-check",
                         "Accept": "text/plain,*/*;q=0.8"})
            with urllib.request.urlopen(req, timeout=8) as resp:
                text = resp.read().decode("utf-8", errors="ignore")

            # The README line: "> **Version in this release:** `X.Y[.Z[.W]]-N` • ..."
            # Accept a 2-to-4-number core (e.g. "4.5.0-1" as well as "4.4.69-1").
            # .*? is non-greedy + `.` doesn't cross newlines, so it grabs the
            # version right after the label (before "Python 3.x" further down).
            version_match = re.search(
                r'Version in this release:.*?(\d+\.\d+(?:\.\d+){0,2}(?:-\d+)?)', text)
            if not version_match:
                raise ValueError(
                    "No 'Version in this release' line found in the GitHub README")
            latest_version = version_match.group(1)

            if _ver(latest_version) is None:
                raise ValueError(
                    f"Could not parse extracted version: {latest_version!r}")

            if _ver(latest_version) <= _ver(self.VERSION):
                self.root.after(0, lambda: self._update_status_lbl.configure(
                    text="Up to date", foreground="#00c853"))
                if not silent:
                    self.root.after(0, lambda: messagebox.showinfo(
                        "Up to Date",
                        f"You are running the latest version of ParaKit  "
                        f"(v{self.VERSION})."))
                return

            # Newer version available.
            self.root.after(0, lambda: self._update_status_lbl.configure(
                text=f"v{latest_version} available", foreground="#e09a3a"))
            # Fetch the repo's CHANGELOG.txt (best-effort) so the popup can preview
            # exactly what this not-yet-installed version changes. Still on this
            # background thread; failure just omits the preview, never blocks.
            changelog = self._fetch_remote_changelog_since(
                self.VERSION, latest_version)
            self.root.after(0, lambda: self._prompt_update(
                latest_version, release_url, changelog))

        except Exception as e:
            if not silent:
                self.root.after(0, lambda: self._update_status_lbl.configure(
                    text="Check failed", foreground="#e63946"))
                self._bg_message(
                    "Update Check Failed",
                    f"Could not reach GitHub to check for updates.\n\n{e}\n\n"
                    f"Check your internet connection or visit the repo "
                    f"manually:\n{release_url}", "warning")

    def _fetch_remote_changelog_since(self, cur_ver, latest_ver, cap=8):
        """Best-effort: fetch the repo's CHANGELOG.txt and return the newest-first
        [(header, body)] entries for every version NEWER than the installed one
        (so a user who skipped several releases previews all the changes they'd
        get, not just the newest). Returns [] on any network/parse failure — the
        update popup then simply shows no preview."""
        import urllib.request, re

        def _ver(s):
            m = re.match(r"^v?(\d+(?:\.\d+){1,3})(?:-(\d+))?$", str(s).strip())
            if not m:
                return None
            return (tuple(int(x) for x in m.group(1).split("."))
                    + (int(m.group(2) or 0),))

        try:
            req = urllib.request.Request(
                self.PARAKIT_RAW_BASE + "CHANGELOG.txt",
                headers={"User-Agent": "ParaKit-update-check",
                         "Accept": "text/plain,*/*;q=0.8"})
            with urllib.request.urlopen(req, timeout=8) as resp:
                text = resp.read().decode("utf-8", errors="ignore")
            text = text.replace("\r\n", "\n").replace("\r", "\n")
        except Exception:
            return []

        cur = _ver(cur_ver)
        if cur is None:
            return []
        out = []
        # Entries are newest-first; a header like "v4.5.9.1 -- ...". Pull the
        # leading version token, keep it while it outranks the installed version,
        # and stop as soon as we drop to/below it (everything after is older).
        for header, body in parse_changelog_lines(text.split("\n")):
            m = re.match(r"v?(\d+\.\d+(?:\.\d+){0,2}(?:-\d+)?)", header.strip())
            if not m:
                continue
            hv = _ver(m.group(1))
            if hv is None:
                continue
            if hv <= cur:
                break
            out.append((header, body))
            if len(out) >= cap:
                break
        return out

    def _prompt_update(self, new_ver, repo_url, changelog_entries=None):
        """Update dialog: open GitHub to download just the one file, and (when
        running from source) a one-click single-file self-update. When
        *changelog_entries* is a non-empty [(header, body)] list, a scrollable
        'What's new in this update' preview is shown so the user can see what the
        update changes without opening GitHub or downloading first."""
        import webbrowser
        is_frozen = bool(getattr(sys, "frozen", False))
        # v4.5.5.1: keep the "supporting files may be stale" reminder up for a few
        # versions (source installs only), then auto-retire at DEP_SYNC_NOTICE_UNTIL.
        show_dep_note = (not is_frozen) and self._dep_note_active()

        has_changelog = bool(changelog_entries)
        dlg = tk.Toplevel(self.root)
        dlg.title("Update Available")
        dlg.configure(bg=APP_BG)
        # Resizable only when the changelog preview is shown, so users can enlarge
        # to read a long entry; the plain popup stays fixed as before.
        dlg.resizable(has_changelog, has_changelog)
        dlg.transient(self.root)
        dlg.grab_set()
        try:
            pw = 520 if has_changelog else 480
            ph = (320 if show_dep_note else 230) + (240 if has_changelog else 0)
            px = self.root.winfo_x() + (self.root.winfo_width() - pw) // 2
            py = self.root.winfo_y() + (self.root.winfo_height() - ph) // 2
            dlg.geometry(f"{pw}x{ph}+{px}+{py}")
        except Exception:
            pass

        frame = ttk.Frame(dlg, padding=18)
        frame.pack(fill=tk.BOTH, expand=True)
        ttk.Label(frame, text=f"ParaKit v{new_ver} is available!",
                  font=("Segoe UI", 12, "bold"),
                  foreground="#b388ff").pack(anchor="w")
        ttk.Label(frame, text=f"You have v{self.VERSION}.",
                  style="Sub.TLabel").pack(anchor="w", pady=(2, 8))
        if is_frozen:
            body = ("Download the latest ParaKit from GitHub. (The compiled .exe "
                    "download is maintained separately and may lag this source "
                    "version.)")
        else:
            body = ("Grab the latest ParaKit from GitHub — you don't need the whole "
                    "repo — or let ParaKit download and install the updated files "
                    "for you now (the main app plus any supporting files this "
                    "version needs), then restart.")
        ttk.Label(frame, text=body, style="TLabel",
                  wraplength=440, justify=tk.LEFT).pack(anchor="w")

        if show_dep_note:
            note = ("Heads-up: ParaKit versions before 4.5.5.1 only downloaded the "
                    "main app file when updating in-app, so some supporting files "
                    "could be left out of date. The “Download update now” "
                    "button below now refreshes all of them — or re-clone from "
                    "GitHub — to be sure your install is complete.")
            ttk.Label(frame, text=note, foreground="#e09a3a",
                      wraplength=440, justify=tk.LEFT).pack(anchor="w", pady=(10, 0))

        # "What's new in this update" preview — the repo's CHANGELOG.txt entries
        # for every version newer than the one running, so the user can see what
        # the update fixes/changes without opening GitHub or downloading first.
        if has_changelog:
            cl_wrap = ttk.Frame(frame)
            cl_wrap.pack(fill=tk.BOTH, expand=True, pady=(12, 0))
            ttk.Label(cl_wrap, text="What's new in this update:",
                      font=("Segoe UI", 9, "bold"),
                      foreground="#b388ff").pack(anchor="w", pady=(0, 4))
            txt_row = ttk.Frame(cl_wrap)
            txt_row.pack(fill=tk.BOTH, expand=True)
            cl_txt = tk.Text(txt_row, wrap="word", height=9,
                             bg="#1a1a1a", fg="#e6e6e6", bd=0, relief="flat",
                             font=("Segoe UI", 9), padx=8, pady=6,
                             highlightthickness=1, highlightbackground="#3a2a4a",
                             cursor="arrow")
            cl_sb = ttk.Scrollbar(txt_row, orient="vertical",
                                  command=cl_txt.yview)
            cl_txt.configure(yscrollcommand=cl_sb.set)
            cl_sb.pack(side=tk.RIGHT, fill=tk.Y)
            cl_txt.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
            cl_txt.tag_configure("hdr", font=("Segoe UI", 10, "bold"),
                                 foreground="#b388ff", spacing1=6, spacing3=3)
            cl_txt.tag_configure("bdy", foreground="#d6d6d6", spacing3=2)
            for _idx, (_hdr, _body) in enumerate(changelog_entries):
                if _idx:
                    cl_txt.insert("end", "\n")
                cl_txt.insert("end", _hdr + "\n", "hdr")
                if _body.strip():
                    cl_txt.insert("end", _body.strip() + "\n", "bdy")
            cl_txt.configure(state="disabled")

        btn_row = ttk.Frame(frame)
        btn_row.pack(anchor="e", pady=(16, 0))

        def _open_github():
            # Always open the repo's main page (not the raw .py blob view).
            target = repo_url
            try:
                webbrowser.open(target)
            except Exception as e:
                messagebox.showerror(
                    "Open Browser Failed",
                    f"Could not open your browser.\n\n{e}\n\nOpen manually:\n{target}")

        ttk.Button(btn_row, text="Close", command=dlg.destroy).pack(
            side=tk.LEFT, padx=(0, 8))
        ttk.Button(btn_row, text="Open GitHub", command=_open_github).pack(
            side=tk.LEFT, padx=(0, 8))
        if not is_frozen:
            dl_btn = ttk.Button(btn_row, text="Download update now",
                                style="Convert.TButton")

            def _start_self_update():
                # Disable first (on the Tk thread) so a double-click can't spawn
                # two concurrent updates before the worker thread starts.
                try:
                    dl_btn.configure(state=tk.DISABLED)
                except Exception:
                    pass
                self._self_update_files(new_ver, dlg)

            dl_btn.configure(command=_start_self_update)
            dl_btn.pack(side=tk.LEFT)
        dlg.protocol("WM_DELETE_WINDOW", dlg.destroy)

    def _locate_app_py(self):
        """Return the absolute path to the running 'ParaKit v4.0.py' (source
        installs), or None when frozen / it can't be located."""
        _argv0 = (sys.argv[0] if getattr(sys, "argv", None) else None)
        for cand in (_argv0, globals().get("__file__")):
            try:
                if cand and os.path.isfile(cand) and cand.lower().endswith(".py"):
                    return os.path.abspath(cand)
            except Exception:
                pass
        return None

    def _dep_note_active(self):
        """True while the running version is older than DEP_SYNC_NOTICE_UNTIL —
        keeps the 'supporting files may be stale' reminder on the update popup for
        a few versions after the v4.5.5.1 updater fix, then auto-retires it."""
        import re

        def _k(s):
            m = re.match(r"^v?(\d+(?:\.\d+){1,3})(?:-(\d+))?$", str(s).strip())
            if not m:
                return None
            return (tuple(int(x) for x in m.group(1).split("."))
                    + (int(m.group(2) or 0),))

        try:
            a, b = _k(self.VERSION), _k(self.DEP_SYNC_NOTICE_UNTIL)
            return a is not None and b is not None and a < b
        except Exception:
            return False

    def _sync_manifest_deps(self, app_dir, progress=None):
        """Fetch update_manifest.json and sync every dependency file it lists into
        app_dir. Each file is hash-checked (unchanged files are skipped — the big
        models aren't re-downloaded), path-sanitized (no traversal / absolute /
        drive paths, so a hostile manifest can never write outside app_dir),
        hash-verified after download, and backed up (*.prev) before an atomic
        replace. Does NOT touch the main 'ParaKit v4.0.py'. Synchronous, no UI —
        call from a worker thread. Returns (updated_list, skipped_count,
        failed_list); a repo with no manifest yields ([], 0, []).

        *progress*, if given, is called as progress(status, rel, done, total):
        once with status="start" (rel=None, done=0), then per file with
        status in {"skipped","updated","failed"}. Used to drive a live progress
        log; any exception it raises is swallowed so the sync never breaks on UI."""
        import urllib.request, urllib.parse, hashlib, json as _json

        def _fetch(url, timeout=120):
            req = urllib.request.Request(
                url, headers={"User-Agent": "ParaKit-update"})
            with urllib.request.urlopen(req, timeout=timeout) as resp:
                return resp.read()

        dep = []
        try:
            man = _json.loads(
                _fetch(self.PARAKIT_MANIFEST_RAW_URL, timeout=30).decode("utf-8"))
            if isinstance(man, dict):
                dep = man.get("files", []) or []
        except Exception:
            dep = []

        # HARD path sanitization: reject absolute paths and '..' traversal; the
        # resolved path MUST stay under app_dir, so a bad/hostile manifest can
        # never write outside it.
        def _safe(rel):
            if not isinstance(rel, str):   # a malformed manifest entry (None/int/
                return None                # list) must not become a junk filename
            p = rel.replace("\\", "/").strip()
            if (not p or p.startswith("/") or ".." in p.split("/")
                    or (len(p) > 1 and p[1] == ":")):
                return None
            full = os.path.normpath(os.path.join(app_dir, p))
            try:
                if os.path.commonpath([full, os.path.normpath(app_dir)]) \
                        != os.path.normpath(app_dir):
                    return None
            except Exception:
                return None
            return full

        total = len(dep)
        if progress:
            try:
                progress("start", None, 0, total)
            except Exception:
                pass

        updated, skipped, failed = [], 0, []
        for idx, ent in enumerate(dep):
            rel = ent.get("path") if isinstance(ent, dict) else ent
            want = ent.get("sha256") if isinstance(ent, dict) else None
            local = _safe(rel)

            def _emit(status):
                if progress:
                    try:
                        progress(status, rel, idx + 1, total)
                    except Exception:
                        pass

            if not local:
                failed.append(f"{rel} (unsafe path)")
                _emit("failed")
                continue
            if not want:
                # No hash in the manifest => refuse to install it. Every real
                # entry from gen_update_manifest.py carries a sha256; a hashless
                # entry can only come from a malformed/hostile manifest, and we
                # never write an unverified (potentially executable) file.
                failed.append(f"{rel} (no hash in manifest)")
                _emit("failed")
                continue
            try:
                if want and os.path.isfile(local):
                    with open(local, "rb") as _lf:
                        if hashlib.sha256(_lf.read()).hexdigest() == want:
                            skipped += 1
                            _emit("skipped")
                            continue   # already current — don't re-download
                blob = _fetch(self.PARAKIT_RAW_BASE
                              + urllib.parse.quote(str(rel), safe="/"))
                if want and hashlib.sha256(blob).hexdigest() != want:
                    failed.append(f"{rel} (hash mismatch)")
                    _emit("failed")
                    continue
                d = os.path.dirname(local)
                if d:
                    os.makedirs(d, exist_ok=True)
                if os.path.isfile(local):
                    try:
                        shutil.copyfile(local, local + ".prev")
                    except Exception:
                        pass
                tmp = local + ".dl.tmp"
                with open(tmp, "wb") as f:
                    f.write(blob)
                    f.flush()
                    try:
                        os.fsync(f.fileno())
                    except Exception:
                        pass
                os.replace(tmp, local)
                updated.append(rel)
                _emit("updated")
            except Exception as e:
                failed.append(f"{rel} ({e})")
                _emit("failed")

        return updated, skipped, failed

    def _sync_manifest_deps_transactional(self, app_dir, new_ver, progress=None):
        """Audit C (2026-07-10): TRANSACTIONAL dependency sync for the real
        self-updater. Unlike the best-effort _sync_manifest_deps (kept for the
        'refresh supporting files' dialog), this one refuses to leave a
        mismatched install:

          * missing / malformed manifest, or a manifest whose "version" doesn't
            match the release being installed  ->  FATAL, nothing touched
          * STAGE: every changed file downloads + hash-verifies to <file>.dl.tmp
            first; ANY failure  ->  all temps deleted, FATAL, nothing touched
          * COMMIT: *.prev backup then os.replace per file; a commit failure
            triggers rollback of the already-committed files from their .prev

        Returns (updated_list, skipped_count, fatal_message_or_None). The
        caller must NOT install the main .py when fatal is not None."""
        import urllib.request, urllib.parse, hashlib, json as _json

        def _fetch(url, timeout=120):
            req = urllib.request.Request(
                url, headers={"User-Agent": "ParaKit-update"})
            with urllib.request.urlopen(req, timeout=timeout) as resp:
                return resp.read()

        # 1) STRICT manifest fetch + version binding.
        try:
            man = _json.loads(
                _fetch(self.PARAKIT_MANIFEST_RAW_URL, timeout=30).decode("utf-8"))
        except Exception as e:
            return [], 0, f"could not fetch/parse update_manifest.json ({e})"
        if not isinstance(man, dict) or not isinstance(man.get("files"), list):
            return [], 0, "update_manifest.json is malformed (no files list)"
        man_ver = str(man.get("version", ""))
        if man_ver != str(new_ver):
            return [], 0, (f"manifest version {man_ver!r} doesn't match the "
                           f"release being installed ({new_ver}) — likely a "
                           f"release still publishing; try again in a minute")

        def _safe(rel):
            if not isinstance(rel, str):
                return None
            p = rel.replace("\\", "/").strip()
            if (not p or p.startswith("/") or ".." in p.split("/")
                    or (len(p) > 1 and p[1] == ":")):
                return None
            full = os.path.normpath(os.path.join(app_dir, p))
            try:
                if os.path.commonpath([full, os.path.normpath(app_dir)]) \
                        != os.path.normpath(app_dir):
                    return None
            except Exception:
                return None
            return full

        dep = man["files"]
        total = len(dep)
        if progress:
            try:
                progress("start", None, 0, total)
            except Exception:
                pass

        # 2) STAGE — download + verify everything BEFORE touching any live file.
        staged = []            # (rel, local, tmp)
        skipped = 0
        done = 0

        def _emit(status, rel):
            if progress:
                try:
                    progress(status, rel, done, total)
                except Exception:
                    pass

        try:
            for ent in dep:
                rel = ent.get("path") if isinstance(ent, dict) else ent
                want = ent.get("sha256") if isinstance(ent, dict) else None
                local = _safe(rel)
                if not local or not want:
                    raise RuntimeError(f"{rel} (unsafe path or missing hash "
                                       f"in manifest)")
                if os.path.isfile(local):
                    with open(local, "rb") as _lf:
                        if hashlib.sha256(_lf.read()).hexdigest() == want:
                            skipped += 1
                            done += 1
                            _emit("skipped", rel)
                            continue
                blob = _fetch(self.PARAKIT_RAW_BASE
                              + urllib.parse.quote(str(rel), safe="/"))
                if hashlib.sha256(blob).hexdigest() != want:
                    raise RuntimeError(f"{rel} (hash mismatch after download)")
                d = os.path.dirname(local)
                if d:
                    os.makedirs(d, exist_ok=True)
                tmp = local + ".dl.tmp"
                with open(tmp, "wb") as f:
                    f.write(blob)
                    f.flush()
                    try:
                        os.fsync(f.fileno())
                    except Exception:
                        pass
                staged.append((rel, local, tmp))
        except Exception as e:
            for _rel, _local, tmp in staged:
                try:
                    os.remove(tmp)
                except Exception:
                    pass
            return [], skipped, (f"staging failed — {e}. Nothing was changed; "
                                 f"your current install is untouched")

        # 3) COMMIT — backup + atomic replace; roll back on a mid-commit failure.
        updated = []
        committed = []         # (local,) with a .prev alongside
        try:
            for rel, local, tmp in staged:
                if os.path.isfile(local):
                    shutil.copyfile(local, local + ".prev")
                os.replace(tmp, local)
                committed.append(local)
                updated.append(rel)
                done += 1
                _emit("updated", rel)
        except Exception as e:
            rolled_back, stuck = 0, []
            for local in committed:
                try:
                    prev = local + ".prev"
                    if os.path.isfile(prev):
                        os.replace(prev, local)
                        rolled_back += 1
                    else:
                        stuck.append(os.path.basename(local))
                except Exception:
                    stuck.append(os.path.basename(local))
            for _rel, _local, tmp in staged:
                try:
                    os.remove(tmp)
                except Exception:
                    pass
            if stuck:
                return [], skipped, (f"commit failed ({e}) AND rollback could "
                                     f"not restore: {', '.join(stuck[:5])} — "
                                     f"re-run the updater or re-clone from "
                                     f"GitHub to repair")
            return [], skipped, (f"commit failed ({e}) — all "
                                 f"{rolled_back} replaced file(s) were rolled "
                                 f"back; your current install is intact")

        return updated, skipped, None

    def _self_update_files(self, new_ver, dlg=None):
        """Download the new 'ParaKit v4.0.py' AND every dependency file the new
        version needs (per update_manifest.json) from GitHub, replacing them in
        place (source installs only).

        v4.5.5.1 fix: the old updater pulled ONLY the main .py, so a release that
        also changed supporting files (parakit_cleanup/, parakit_separators/,
        models, CHANGELOG.txt, ...) left users with a mismatched install. This now
        syncs the whole runtime file set via _sync_manifest_deps (hash-checked,
        path-sanitized, backed up), writing the main .py LAST. Still NOT a git
        clone — only changed files are fetched. Runs off the UI thread so a large
        model download doesn't freeze the app."""
        import threading
        target = self._locate_app_py()
        if not target:
            messagebox.showwarning(
                "Update",
                "Couldn't locate the running ParaKit .py to update in place. "
                "Use 'Open GitHub' to download the new files manually.")
            return
        app_dir = os.path.dirname(target)

        # Close the little "Update Available" popup and open a live progress
        # window (scrolling log + progress bar), so the user sees exactly what is
        # being downloaded instead of a silent, seemingly-dead button.
        if dlg is not None:
            try:
                dlg.destroy()
            except Exception:
                pass

        prog = tk.Toplevel(self.root)
        prog.title("Updating ParaKit")
        prog.configure(bg=APP_BG)
        prog.transient(self.root)
        prog.grab_set()
        try:
            pw, ph = 600, 460
            px = self.root.winfo_x() + (self.root.winfo_width() - pw) // 2
            py = self.root.winfo_y() + (self.root.winfo_height() - ph) // 2
            prog.geometry(f"{pw}x{ph}+{px}+{py}")
        except Exception:
            pass

        pframe = ttk.Frame(prog, padding=16)
        pframe.pack(fill=tk.BOTH, expand=True)
        ttk.Label(pframe, text=f"Downloading ParaKit v{new_ver}…",
                  font=("Segoe UI", 12, "bold"),
                  foreground="#b388ff").pack(anchor="w")
        status_var = tk.StringVar(value="Starting…")
        ttk.Label(pframe, textvariable=status_var,
                  style="Sub.TLabel").pack(anchor="w", pady=(2, 8))
        pbar = ttk.Progressbar(pframe, mode="determinate", maximum=100, value=0)
        pbar.pack(fill=tk.X, pady=(0, 8))

        log_row = ttk.Frame(pframe)
        log_row.pack(fill=tk.BOTH, expand=True)
        log_txt = tk.Text(log_row, height=14, wrap="none", bg=LOG_BG,
                          fg="#c9d1d9", insertbackground="#c9d1d9", relief="flat",
                          bd=0, padx=8, pady=6, font=("Consolas", 9),
                          highlightthickness=1, highlightbackground="#2a2440")
        log_sb = ttk.Scrollbar(log_row, orient="vertical", command=log_txt.yview)
        log_txt.configure(yscrollcommand=log_sb.set)
        log_sb.pack(side=tk.RIGHT, fill=tk.Y)
        log_txt.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        log_txt.tag_configure("hdr", foreground="#b388ff")
        log_txt.tag_configure("ok", foreground="#00c853")
        log_txt.tag_configure("dl", foreground="#58a6ff")
        log_txt.tag_configure("err", foreground="#e63946")
        log_txt.tag_configure("dim", foreground="#8a8a8a")
        log_txt.configure(state="disabled")

        btn_row = ttk.Frame(pframe)
        btn_row.pack(anchor="e", pady=(12, 0))
        close_btn = ttk.Button(btn_row, text="Close", state=tk.DISABLED,
                               command=prog.destroy)
        close_btn.pack(side=tk.RIGHT)
        # Block the window's [X] while the worker is mid-update (files are being
        # replaced on disk); re-enabled with the Close button when done.
        prog.protocol("WM_DELETE_WINDOW", lambda: None)

        # --- thread-safe UI helpers: the worker calls these; they marshal onto
        #     the Tk main thread via root.after so widgets are only touched there.
        def _ui(fn):
            try:
                self.root.after(0, fn)
            except Exception:
                pass

        def log(line, tag="dim"):
            def _do():
                try:
                    log_txt.configure(state="normal")
                    log_txt.insert("end", line + "\n", (tag,))
                    log_txt.see("end")
                    log_txt.configure(state="disabled")
                except Exception:
                    pass
            _ui(_do)

        def set_status(s):
            _ui(lambda: status_var.set(s))

        def set_prog(done, total):
            def _do():
                try:
                    pbar.configure(maximum=max(1, total), value=done)
                except Exception:
                    pass
            _ui(_do)

        def finish(ok, summary):
            def _do():
                try:
                    status_var.set(summary)
                    pbar.configure(value=pbar.cget("maximum"))
                    close_btn.configure(state=tk.NORMAL)
                    prog.protocol("WM_DELETE_WINDOW", prog.destroy)
                except Exception:
                    pass
            _ui(_do)

        def dep_progress(status, rel, done, total):
            if status == "start":
                log(f"Checking {total} supporting file(s)…", "hdr")
                set_prog(0, total)
                return
            set_prog(done, total)
            if status == "updated":
                log(f"  ⬇  downloaded    {rel}", "dl")
            elif status == "skipped":
                log(f"  ✓  up to date    {rel}", "ok")
            elif status == "failed":
                log(f"  ✗  failed        {rel}", "err")
            set_status(f"Supporting files: {done}/{total}…")

        def _work():
            import urllib.request

            def _fetch(url, timeout=120):
                req = urllib.request.Request(
                    url, headers={"User-Agent": "ParaKit-update"})
                with urllib.request.urlopen(req, timeout=timeout) as resp:
                    return resp.read()

            # 1) main 'ParaKit v4.0.py' — download + version-validate BEFORE touching
            #    anything (so a README/.py mismatch on GitHub can't install a wrong file)
            set_status("Downloading the main app file…")
            log("Downloading the main app (ParaKit v4.0.py)…", "hdr")
            try:
                data = _fetch(self.PARAKIT_PY_RAW_URL)
                text = data.decode("utf-8", "replace")
            except Exception as e:
                log(f"✗ Download failed: {e}", "err")
                finish(False, f"Download failed — nothing was changed. ({e})")
                return
            if (len(data) < 200000 or "class MidiToRlrrApp" not in text
                    or f'VERSION = "{new_ver}"' not in text):
                log("✗ The downloaded file didn't look like a valid v"
                    f"{new_ver} build — aborting, nothing changed.", "err")
                finish(False, "Update aborted — the download didn't validate. "
                              "Use 'Open GitHub' to download it manually.")
                return
            log(f"✓ Main app downloaded and validated ({len(data)//1024} KB).", "ok")

            # 2) TRANSACTIONAL dependency sync (audit C): strict manifest fetch
            #    bound to this release's version, stage-all + hash-verify, then
            #    commit with rollback. Any fatal outcome ABORTS the update here
            #    — the main .py below is NOT installed, so the old
            #    main-file/supporting-file mismatch can no longer be created.
            set_status("Checking supporting files…")
            updated, skipped, fatal = self._sync_manifest_deps_transactional(
                app_dir, new_ver, progress=dep_progress)
            if fatal:
                log(f"✗ {fatal}", "err")
                finish(False, f"Update aborted — {fatal}.")
                return

            # 3) write the main .py LAST — so a half-failed dependency set is never
            #    left running under the new .py before the user restarts.
            set_status("Installing the main app file…")
            log("Installing the main app file…", "hdr")
            try:
                shutil.copyfile(target, target + ".prev")
                tmp = target + ".dl.tmp"
                with open(tmp, "wb") as f:
                    f.write(data)
                    f.flush()
                    try:
                        os.fsync(f.fileno())
                    except Exception:
                        pass
                os.replace(tmp, target)
            except Exception as e:
                log(f"✗ Could not replace the main file: {e}", "err")
                finish(False, f"Update failed — your current version is unchanged. ({e})")
                return

            log("", "dim")
            parts = [f"✓ Updated to v{new_ver}."]
            if updated:
                parts.append(f"{len(updated)} file(s) downloaded.")
            if skipped:
                parts.append(f"{skipped} already up to date.")
            summary = "  ".join(parts)
            log(summary, "ok")
            log("Done. Close and reopen ParaKit to run the new version.", "hdr")
            finish(True, summary + "  Close and reopen ParaKit to finish.")

        threading.Thread(target=_work, daemon=True).start()

    def _maybe_show_dep_sync_notice(self):
        """One-time first-run notice (v4.5.5.1). The pre-4.5.5.1 in-app updater
        pulled ONLY the main .py, so a user who updated in-app may be running with
        stale supporting files (detection models, cleanup code, changelog, ...).
        This explains it once and offers a one-click 'Update supporting files now'
        (runs the shared manifest sync in place) plus a re-clone pointer. Source
        installs only; shown once, then flagged in the config."""
        try:
            if bool(getattr(sys, "frozen", False)):
                return  # the .exe ships self-contained — no loose deps to sync
            if load_config().get("seen_dep_sync_notice_v4551"):
                return
        except Exception:
            return

        def _mark_seen():
            try:
                save_config({"seen_dep_sync_notice_v4551": True})
            except Exception:
                pass

        target = self._locate_app_py()
        app_dir = os.path.dirname(target) if target else None

        dlg = tk.Toplevel(self.root)
        dlg.title("One-time notice — check your supporting files")
        dlg.configure(bg=APP_BG)
        dlg.resizable(False, True)   # allow vertical grow so nothing clips at
        dlg.transient(self.root)     # high-DPI / large Windows text scaling
        try:
            dlg.grab_set()
        except Exception:
            pass
        try:
            pw, ph = 520, 384
            px = self.root.winfo_x() + (self.root.winfo_width() - pw) // 2
            py = self.root.winfo_y() + (self.root.winfo_height() - ph) // 2
            dlg.geometry(f"{pw}x{ph}+{px}+{py}")
        except Exception:
            pass

        frame = ttk.Frame(dlg, padding=18)
        frame.pack(fill=tk.BOTH, expand=True)
        ttk.Label(frame, text="Please check your supporting files",
                  font=("Segoe UI", 12, "bold"),
                  foreground="#b388ff").pack(anchor="w")
        explain = (
            "A bug in ParaKit's in-app updater (fixed in this version, 4.5.5.1) "
            "meant that when you updated from inside the app, only the main "
            "program file was downloaded — any supporting files a newer version "
            "needed (detection models, cleanup code, separators, ...) could be "
            "left out of date.\n\n"
            "First time running ParaKit, or just cloned / downloaded it from "
            "GitHub? This doesn't apply to you — a fresh copy already has every "
            "current file — so you can simply dismiss this.\n\n"
            "Otherwise, to make sure your install is complete, either update your "
            "supporting files now (recommended), or re-download / re-clone ParaKit "
            "from GitHub. Updates from here on keep every file in sync automatically.")
        ttk.Label(frame, text=explain, style="TLabel",
                  wraplength=484, justify=tk.LEFT).pack(anchor="w", pady=(6, 0))

        status = ttk.Label(frame, text="", foreground="#e09a3a", wraplength=484,
                           justify=tk.LEFT)
        status.pack(anchor="w", pady=(8, 0))

        btn_row = ttk.Frame(frame)
        btn_row.pack(anchor="e", pady=(14, 0), fill=tk.X)
        buttons = {}

        def _open_github():
            import webbrowser
            try:
                # Open the repo main page (not the raw .py blob view).
                webbrowser.open(self.PARAKIT_RELEASE_URL)
            except Exception:
                pass

        def _close():
            _mark_seen()
            try:
                dlg.destroy()
            except Exception:
                pass

        def _do_sync():
            if not app_dir:
                status.configure(
                    text="Couldn't locate your ParaKit folder — use Open GitHub instead.")
                return
            for b in buttons.values():
                try:
                    b.configure(state=tk.DISABLED)
                except Exception:
                    pass
            status.configure(
                text="Updating supporting files… (this can take a minute)")

            def _work():
                try:
                    updated, skipped, failed = self._sync_manifest_deps(app_dir)
                except Exception as e:
                    updated, skipped, failed = [], 0, [f"error ({e})"]

                def _finish():
                    _mark_seen()
                    try:
                        dlg.destroy()
                    except Exception:
                        pass
                    if not updated and not failed:
                        messagebox.showinfo(
                            "Supporting files",
                            "Your supporting files are already up to date"
                            + (f" ({skipped} checked)." if skipped else "."))
                        return
                    msg = ""
                    if updated:
                        shown = ", ".join(str(u) for u in updated[:8])
                        msg += (f"{len(updated)} supporting file(s) updated: {shown}"
                                + (f" (+{len(updated) - 8} more)"
                                   if len(updated) > 8 else "") + "\n")
                    if skipped:
                        msg += f"{skipped} already up to date.\n"
                    if failed:
                        msg += ("\n⚠ Could not update: " + ", ".join(failed[:6])
                                + ("  ..." if len(failed) > 6 else "")
                                + "\nGrab these from GitHub if the app misbehaves.\n")
                    msg += "\n(Backups saved as *.prev.)"
                    (messagebox.showwarning if failed else messagebox.showinfo)(
                        "Supporting files", msg.strip())

                try:
                    self.root.after(0, _finish)
                except Exception:
                    pass

            threading.Thread(target=_work, daemon=True).start()

        buttons["close"] = ttk.Button(btn_row, text="Close", command=_close)
        buttons["close"].pack(side=tk.LEFT, padx=(0, 8))
        buttons["github"] = ttk.Button(btn_row, text="Open GitHub",
                                       command=_open_github)
        buttons["github"].pack(side=tk.LEFT, padx=(0, 8))
        if app_dir:
            buttons["sync"] = ttk.Button(
                btn_row, text="Update supporting files now",
                style="Convert.TButton", command=_do_sync)
            buttons["sync"].pack(side=tk.LEFT)

        # Grow the window to the content's real height if the fixed 384 isn't
        # enough (large text scaling / high-DPI), so the button row never clips.
        try:
            dlg.update_idletasks()
            need = frame.winfo_reqheight()
            if need > 384:
                dlg.geometry(f"520x{need}")
        except Exception:
            pass

        dlg.protocol("WM_DELETE_WINDOW", _close)

    def _current_monitor_work_area(self):
        """Return the nearest monitor work-area size in pixels."""
        try:
            if os.name == "nt":
                import ctypes

                class RECT(ctypes.Structure):
                    _fields_ = [
                        ("left", ctypes.c_long),
                        ("top", ctypes.c_long),
                        ("right", ctypes.c_long),
                        ("bottom", ctypes.c_long),
                    ]

                class MONITORINFO(ctypes.Structure):
                    _fields_ = [
                        ("cbSize", ctypes.c_ulong),
                        ("rcMonitor", RECT),
                        ("rcWork", RECT),
                        ("dwFlags", ctypes.c_ulong),
                    ]

                user32 = ctypes.windll.user32
                user32.MonitorFromWindow.argtypes = [ctypes.c_void_p, ctypes.c_ulong]
                user32.MonitorFromWindow.restype = ctypes.c_void_p
                user32.GetMonitorInfoW.argtypes = [
                    ctypes.c_void_p, ctypes.POINTER(MONITORINFO)]
                user32.GetMonitorInfoW.restype = ctypes.c_bool

                monitor = user32.MonitorFromWindow(
                    ctypes.c_void_p(self.root.winfo_id()), 2)
                info = MONITORINFO()
                info.cbSize = ctypes.sizeof(MONITORINFO)
                if user32.GetMonitorInfoW(monitor, ctypes.byref(info)):
                    work = info.rcWork
                    return (work.right - work.left, work.bottom - work.top)
        except Exception:
            pass
        try:
            return (self.root.winfo_screenwidth(), self.root.winfo_screenheight())
        except Exception:
            return (1920, 1080)

    def _monitor_bounds_for_point(self, x, y):
        """Return (left, top, right, bottom) of the work area of the
        monitor containing screen-coords (x, y).

        v4.4.53.8 — added to fix multi-monitor popup positioning. The
        previous popup-clipping logic used `winfo_screenwidth/height`
        which on Windows returns the PRIMARY monitor's dimensions, not
        the dimensions of the monitor where the popup actually is.
        When ParaKit was on a secondary monitor, popups (recent-files
        dropdown, tooltips) got incorrectly clipped back onto the
        primary monitor.

        Uses Win32 `MonitorFromPoint` to find the right monitor based on
        the popup's intended screen coordinates. Falls back to the
        whole virtual-desktop bounds on non-Windows or on API failure
        — that preserves the old "use any screen position" behavior
        rather than silently picking the wrong monitor.

        Returns:
            (left, top, right, bottom) tuple of the WORK AREA (taskbar
            already excluded) of the monitor containing (x, y).
        """
        try:
            if os.name == "nt":
                import ctypes

                class POINT(ctypes.Structure):
                    _fields_ = [
                        ("x", ctypes.c_long),
                        ("y", ctypes.c_long),
                    ]

                class RECT(ctypes.Structure):
                    _fields_ = [
                        ("left", ctypes.c_long),
                        ("top", ctypes.c_long),
                        ("right", ctypes.c_long),
                        ("bottom", ctypes.c_long),
                    ]

                class MONITORINFO(ctypes.Structure):
                    _fields_ = [
                        ("cbSize", ctypes.c_ulong),
                        ("rcMonitor", RECT),
                        ("rcWork", RECT),
                        ("dwFlags", ctypes.c_ulong),
                    ]

                user32 = ctypes.windll.user32
                user32.MonitorFromPoint.argtypes = [POINT, ctypes.c_ulong]
                user32.MonitorFromPoint.restype = ctypes.c_void_p
                user32.GetMonitorInfoW.argtypes = [
                    ctypes.c_void_p, ctypes.POINTER(MONITORINFO)]
                user32.GetMonitorInfoW.restype = ctypes.c_bool

                pt = POINT(int(x), int(y))
                # MONITOR_DEFAULTTONEAREST = 2 — if the point is off all
                # monitors (shouldn't happen for a real anchor widget,
                # but defensive), return the nearest one instead of NULL.
                monitor = user32.MonitorFromPoint(pt, 2)
                info = MONITORINFO()
                info.cbSize = ctypes.sizeof(MONITORINFO)
                if user32.GetMonitorInfoW(monitor, ctypes.byref(info)):
                    work = info.rcWork
                    return (work.left, work.top, work.right, work.bottom)
        except Exception:
            pass
        # Fallback — use the whole virtual desktop bounds. On Tk this
        # is best approximated as (0, 0) to (winfo_screenwidth, height)
        # which IS just the primary monitor on Windows, but it's better
        # than nothing.
        try:
            sw = self.root.winfo_screenwidth()
            sh = self.root.winfo_screenheight()
            return (0, 0, sw, sh)
        except Exception:
            return (0, 0, 1920, 1080)

    def _should_use_compact_layout(self):
        """Use tighter chrome on 1920x1080-class work areas.

        v4.4.45 — honors user-saved override from config first:
          - `me_layout_mode = "compact"`  → force compact, ignore auto-detect.
          - `me_layout_mode = "roomy"`    → force roomy, ignore auto-detect.
          - `me_layout_mode = "auto"` (or missing) → auto-detect via
            `_current_monitor_work_area`. Threshold broadened from
            `work_h <= 1100` to `work_h <= 1200` so 1920x1080 + 1920x1200
            panels both fire. The auto-detect path can still fail on
            multi-monitor setups where `MonitorFromWindow` at startup
            returns the primary monitor (often 1440p) before the window
            has been positioned on the secondary 1080p monitor. The
            manual override exists for those cases.
        """
        try:
            cfg_mode = (load_config().get("me_layout_mode", "auto") or "auto").lower()
        except Exception:
            cfg_mode = "auto"
        if cfg_mode == "compact":
            return True
        if cfg_mode == "roomy":
            return False
        try:
            work_w, work_h = self._current_monitor_work_area()
            return work_w <= 1920 or work_h <= 1200
        except Exception:
            return False

    def _set_layout_mode(self, mode):
        """Save layout-mode override to config and show a restart hint.

        v4.4.45 — used by the Tools > Layout Mode submenu. Owner-facing
        manual override for compact/roomy that auto-detection can miss
        on multi-monitor setups.
        """
        mode = (mode or "auto").lower()
        if mode not in ("auto", "compact", "roomy"):
            mode = "auto"
        try:
            save_config({"me_layout_mode": mode})
        except Exception:
            pass
        try:
            messagebox.showinfo(
                "Layout mode saved",
                f"Layout mode set to: {mode.title()}\n\n"
                "Restart ParaKit for the new layout to take effect.")
        except Exception:
            pass

    def _make_scrollable_tab(self, parent, fill_height=False):
        """Wrap a tab in a vertically-scrollable canvas + scrollbar.

        fill_height=True stretches the inner frame to at least the visible
        canvas height, so short content fills the viewport (letting an
        expand=True child claim the empty space below) while taller content
        keeps its natural height and scrolls.

        v4.4.53.5 — added to fix the 1080p compact-mode bug where the
        Stem Splitter and YouTube → FLAC tab logs got crushed
        off-screen. Both tabs have content-heavy layouts that exceeded
        the available vertical space on 1920×1080 displays even with
        compact-mode chrome.

        Returns the inner ttk.Frame to which the tab's content can be
        packed/gridded as if it were the tab parent. The canvas auto-
        sizes its inner-window WIDTH to match the visible canvas width
        on every resize, so content using fill=tk.X still expands
        horizontally as expected. VERTICAL content scrolls when it
        exceeds the visible height.

        Mouse-wheel scroll only fires when the cursor is over the
        canvas (Enter/Leave binding) so it doesn't steal wheel events
        from sibling widgets that need them (the Practice canvas,
        for example, deliberately swallows wheel events).
        """
        BG = APP_BG
        container = ttk.Frame(parent)
        container.pack(fill=tk.BOTH, expand=True)

        canvas = tk.Canvas(container, bg=BG, highlightthickness=0)
        vsb = ttk.Scrollbar(container, orient="vertical", command=canvas.yview)
        inner = ttk.Frame(canvas)

        inner_window_id = canvas.create_window((0, 0), window=inner,
                                                anchor="nw")
        canvas.configure(yscrollcommand=vsb.set)

        canvas.pack(side="left", fill="both", expand=True)
        vsb.pack(side="right", fill="y")

        def _fit_fill():
            # Stretch the inner window to at least the visible canvas height so
            # short content fills the viewport; taller content keeps its natural
            # height and scrolls. Guarded so re-firing with the same target can't
            # feed back into an endless <Configure> loop.
            if not fill_height:
                return
            try:
                target = max(inner.winfo_reqheight(), canvas.winfo_height())
                if str(canvas.itemcget(inner_window_id, "height")) != str(target):
                    canvas.itemconfigure(inner_window_id, height=target)
            except Exception:
                pass

        def _on_inner_configure(_event):
            try:
                canvas.configure(scrollregion=canvas.bbox("all"))
            except Exception:
                pass
            _fit_fill()
        inner.bind("<Configure>", _on_inner_configure)

        def _on_canvas_configure(event):
            try:
                canvas.itemconfigure(inner_window_id, width=event.width)
            except Exception:
                pass
            _fit_fill()
        canvas.bind("<Configure>", _on_canvas_configure)

        # v4.4.53.7 — Mouse-wheel handling NOTE:
        #
        # The previous v4.4.53.5 implementation bound `<MouseWheel>` via
        # `canvas.bind_all` on `<Enter>` and `canvas.unbind_all` on
        # `<Leave>`. That had a subtle bug: `unbind_all` removes ALL
        # global `<MouseWheel>` handlers, including the app-level
        # `_on_mousewheel` defined at `__init__` time (line ~4492).
        #
        # User flow that broke things: visit Stem Splitter or
        # YouTube → FLAC tab (compact mode) → cursor enters scrollable
        # canvas → my handler attaches → cursor leaves → my handler
        # ALSO strips the global handler. Then any tab the user visits
        # next (Audio → MIDI, MIDI Editor, etc.) has no wheel scrolling
        # at all until they re-enter a scrollable canvas region.
        #
        # The fix: don't bind a custom wheel handler here at all. The
        # global `_on_mousewheel` walks up the widget tree from
        # `event.widget` until it finds a Canvas or Text and scrolls
        # that. Child widgets inside our `inner` frame have their
        # `master` chain ending at `canvas`, so the global handler
        # naturally scrolls our canvas when the cursor is over any of
        # our content. No `bind_all` needed — and crucially, no risk
        # of stripping the global handler.

        return inner

    def _normalize_theme_on_startup(self):
        """Re-assert the active theme after the first paint — the same work the
        Dark/Light toggle does, minus the mode flip. ttkbootstrap can leave the
        root/header (and any widget built with the other palette's colour) in a
        light state until a style pass runs post-settle; this closes the
        'header stuck on light until you click the toggle' bug. Idempotent and
        safe to call once at launch. (owner 2026-07-10)"""
        try:
            self.root.configure(bg=APP_BG)
        except Exception:
            pass
        try:
            self._apply_theme()
        except Exception:
            pass
        try:
            other = "light" if self._theme_mode == "dark" else "dark"
            self._recolor_tk_tree(
                self.root,
                THEME_PALETTES[other]["app_bg"], APP_BG,
                THEME_PALETTES[other]["log_bg"], LOG_BG)
        except Exception:
            pass

    def _toggle_theme(self):
        """Flip between the purple 'dark' theme and the original-gray 'light'
        theme, re-colouring the RUNNING UI in place (no restart) and persisting
        the choice. Reassigns the module globals APP_BG / LOG_BG so widgets built
        after the toggle also pick up the active palette."""
        global APP_BG, LOG_BG
        old_app, old_log = APP_BG, LOG_BG
        new_mode = "light" if self._theme_mode == "dark" else "dark"
        self._theme_mode = new_mode
        APP_BG = THEME_PALETTES[new_mode]["app_bg"]
        LOG_BG = THEME_PALETTES[new_mode]["log_bg"]

        # 1) ttk styles (frames, labels, checkbuttons, notebook, logs-loop) —
        #    _apply_theme reads the new APP_BG via _parakit_theme_tokens() and
        #    normalises every known log to the new LOG_BG.
        try:
            self._apply_theme()
        except Exception:
            pass
        # 2) classic tk widgets carry their bg literally from creation — walk the
        #    whole tree and swap the OLD palette colours for the NEW ones.
        try:
            self._recolor_tk_tree(self.root, old_app, APP_BG, old_log, LOG_BG)
        except Exception:
            pass
        # 3) refresh the option database so widgets built later default correctly.
        for _opt in ("*Label.Background", "*Label.highlightColor",
                     "*Label.highlightBackground", "*highlightColor",
                     "*highlightBackground"):
            try:
                self.root.option_add(_opt, APP_BG)
            except Exception:
                pass
        # 4) toggle-button label + persist the choice.
        try:
            self._theme_toggle_btn.configure(
                text=("🌙  Dark" if new_mode == "dark" else "☀  Light"))
        except Exception:
            pass
        try:
            if save_config({"theme_mode": new_mode}) is False:
                # Explicit user preference action — surface failure non-blockingly.
                try:
                    self.root.after(
                        0,
                        lambda: messagebox.showerror(
                            "Settings not saved",
                            "Could not save the theme preference to disk.\n"
                            "Your choice is active for this session only."))
                except Exception:
                    print("[config] theme_mode preference save failed")
        except Exception:
            pass

    def _recolor_tk_tree(self, widget, old_app, new_app, old_log, new_log):
        """Recursively swap tk-widget background colours for a live theme change.
        Only classic tk widgets carry a 'bg' we set; ttk widgets raise on
        cget('bg') and are skipped (handled by _apply_theme). A widget whose
        current bg matches the OLD app background moves to the NEW app bg; one
        matching the OLD log background moves to the NEW log bg; anything else
        (buttons, coloured note boxes, accents) is left untouched."""
        try:
            cur = str(widget.cget("bg"))
        except Exception:
            cur = None
        if cur is not None:
            try:
                if cur == old_app:
                    widget.configure(bg=new_app)
                elif cur == old_log:
                    widget.configure(bg=new_log)
            except Exception:
                pass
        try:
            kids = widget.winfo_children()
        except Exception:
            kids = []
        for child in kids:
            self._recolor_tk_tree(child, old_app, new_app, old_log, new_log)

    def _apply_theme(self):
        """Apply dark theme custom overrides on top of ttkbootstrap darkly."""
        style = ttk.Style()

        tokens   = _parakit_theme_tokens()
        BG       = tokens["bg"]
        ENTRY_BG = tokens["entry_bg"]
        LOG_FG   = tokens["log_fg"]
        ACCENT   = tokens["primary_bg"]
        PURPLE   = tokens["purple"]
        compact  = getattr(self, "_compact_layout", False)
        button_pad = [6, 1] if compact else [10, 5]
        convert_pad = [7, 2] if compact else [14, 7]
        tab_pad = [7, 3] if compact else [14, 6]
        base_font_size = 8 if compact else 9
        convert_font_size = 9 if compact else 12

        # Global buttons — dark purple treatment promoted from the MIDI
        # Editor visual test (v4.4.43) so all tabs share one button language.
        style.configure("TButton",
                        background="#7c3aed",
                        foreground="#ffffff",
                        bordercolor=PURPLE,
                        lightcolor="#8b5cf6",
                        darkcolor="#2a1235",
                        focuscolor=PURPLE,
                        focusthickness=1,
                        borderwidth=1,
                        relief="raised",
                        padding=button_pad,
                        font=("Segoe UI", base_font_size))
        style.map("TButton",
                  foreground=[("disabled", "#888888"),
                              ("active", "#ffffff"),
                              ("pressed", "#ffffff"),
                              ("!disabled", "#ffffff")],
                  background=[("disabled", "#2a2a30"),
                              ("pressed", "#5b21b6"),
                              ("active", "#8b5cf6"),
                              ("!disabled", "#7c3aed")],
                  bordercolor=[("disabled", "#444444"),
                               ("active", "#d4b3ff"),
                               ("pressed", "#ffffff"),
                               ("!disabled", PURPLE)],
                  relief=[("pressed", "sunken"),
                          ("!pressed", "raised")])

        style.configure("Convert.TButton",
                        background="#7c3aed",
                        foreground="#ffffff",
                        bordercolor=PURPLE,
                        lightcolor="#8b5cf6",
                        darkcolor="#2a1235",
                        focuscolor=PURPLE,
                        font=("Segoe UI", convert_font_size, "bold"),
                        padding=convert_pad,
                        borderwidth=1,
                        relief="raised")
        style.map("Convert.TButton",
                  foreground=[("disabled", "#888888"),
                              ("active", "#ffffff"),
                              ("pressed", "#ffffff"),
                              ("!active", "#ffffff")],
                  background=[("disabled", "#2a2a30"),
                              ("pressed", "#5b21b6"),
                              ("active", "#8b5cf6"),
                              ("!active", "#7c3aed")],
                  bordercolor=[("active", "#d4b3ff"),
                               ("pressed", "#ffffff"),
                               ("!active", PURPLE)],
                  relief=[("pressed", "sunken"),
                          ("!pressed", "raised")])

        # v4.4.62 follow-up — The MIDI Editor "Auto Fetch Audio" button keeps the
        # DEFAULT purple ttk button look (so it matches Play/Stop) and gets its
        # standout from a CYAN BORDER drawn by a tk.Frame wrapper around it (see
        # the MIDI Editor build). A custom cyan ttk style / tk.Button bg did not
        # render reliably under the ttkbootstrap theme, so no Fetch.TButton style.

        # Header/sub labels
        style.configure("TFrame", background=BG)
        style.configure("TLabelframe", background=BG)
        style.configure("TLabelframe.Label", background=BG)
        # Pin the base widget backgrounds too — otherwise plain ttk.Label /
        # Checkbutton / Radiobutton keep ttkbootstrap-darkly's own gray, which
        # used to blend with the old #222222 frames but now shows as gray patches
        # against APP_BG. (v4.5.9.x purple theming.)
        style.configure("TLabel", background=BG)
        style.configure("TCheckbutton", background=BG)
        style.configure("Header.TLabel",
                        background=BG, foreground=PURPLE,
                        font=("Segoe UI", 12 if compact else 16, "bold"))
        style.configure("Sub.TLabel",
                        background=BG, foreground="#888",
                        font=("Segoe UI", 8 if compact else 9))

        # Notebook tab colors — force override ttkbootstrap's darkly defaults
        # Must set background in configure() as the base (unselected) color,
        # then override selected/active states in map()
        style.configure("TNotebook", background=BG, borderwidth=0)
        style.configure("TNotebook.Tab",
                        background=PURPLE,
                        foreground="#ffffff",
                        font=("Segoe UI", 8 if compact else 10, "bold"),
                        padding=tab_pad,
                        bordercolor=tokens["button_focus"],
                        lightcolor=PURPLE,
                        darkcolor=tokens["button_bg"])
        style.map("TNotebook.Tab",
                  background=[("selected",  tokens["button_bg"]),
                               ("active",   tokens["button_hover_bg"]),
                               ("!selected", PURPLE)],
                  foreground=[("selected",  "#ffffff"),
                               ("active",   "#ffffff"),
                               ("!selected", "#ffffff")],
                  bordercolor=[("selected", tokens["button_border"]),
                               ("active",   tokens["button_focus"]),
                               ("!selected", tokens["button_focus"])],
                  expand=[("selected", [1, 1, 1, 0])])

        # Radiobutton indicator + foreground (text)
        # v4.4.36 — added `foreground=PURPLE` on base TRadiobutton style
        # (was previously default white/gray inheriting from ttkbootstrap
        # darkly). v4.4.35 attempted a scoped test using a derived
        # `MEPurple.TRadiobutton` style on only the MIDI Editor tab, but
        # ttkbootstrap's darkly theme overrides foreground on derived
        # TRadiobutton styles at render time, so the scoped approach
        # didn't render visibly. v4.4.36 modifies the base style instead
        # — applies the purple text app-wide as the actual visual test.
        # If owner finds the app-wide purple overly noisy, revert via
        # the v4.4.35 backup (which restores the pre-v4.4.36 white text).
        # v4.4.57.99-10 PC11: Radiobutton text recolored PURPLE → cyan per
        # owner direction 2026-05-23 (companion to green→cyan text sweep).
        _RADIO_CYAN = "#00d4d4"  # matches Label/Checkbutton cyan from same slice
        style.configure("TRadiobutton",
                        background=BG,
                        foreground=_RADIO_CYAN)
        style.map("TRadiobutton",
                  foreground=[("disabled", "#888888"),
                              ("active",   _RADIO_CYAN),
                              ("!active",  _RADIO_CYAN)],
                  indicatorcolor=[("selected", _RADIO_CYAN), ("pressed", _RADIO_CYAN)])

        # Scrollbars — match the app's purple slider/loading-bar accent.
        # v4.3.29: explicit layout override forces theme-agnostic rendering so
        # all scrollbars (including the MIDI Editor's horizontal one) honor the
        # purple/dark colors. Without the layout override, clam still drew arrow
        # buttons and decorations with default colors that masked the configure().
        style.layout("Horizontal.TScrollbar",
                     [('Horizontal.Scrollbar.trough',
                       {'children': [('Horizontal.Scrollbar.thumb',
                                      {'expand': 1, 'sticky': 'nswe'})],
                        'sticky': 'we'})])
        style.layout("Vertical.TScrollbar",
                     [('Vertical.Scrollbar.trough',
                       {'children': [('Vertical.Scrollbar.thumb',
                                      {'expand': 1, 'sticky': 'nswe'})],
                        'sticky': 'ns'})])
        for sb_style in ("TScrollbar", "Horizontal.TScrollbar", "Vertical.TScrollbar"):
            style.configure(sb_style,
                            background=PURPLE,
                            troughcolor=tokens["button_bg"],
                            bordercolor=tokens["button_border"],
                            arrowcolor=PURPLE,
                            lightcolor=PURPLE,
                            darkcolor=tokens["button_bg"],
                            relief="flat",
                            borderwidth=0)
            style.map(sb_style,
                      background=[("active", tokens["button_hover_bg"]),
                                  ("pressed", tokens["button_pressed_bg"]),
                                  ("!disabled", PURPLE)],
                      arrowcolor=[("active", "#ffffff"),
                                  ("pressed", "#ffffff"),
                                  ("!disabled", PURPLE)])

        # v4.4.57.94-10 Patch 16 (re-applies v4.4.57.23-8 entry/combo styling):
        # NON-UI-overhaul carve-out — owner explicitly wants this styling kept
        # from the parked alpha cycle. Dark-purple stroke + much-darker-gray
        # interior on TCombobox + TEntry so all the safe-tab dropdowns and
        # entry fields (difficulty, complexity, genre, engine, metronome,
        # MuseScore filter, MusicXML part, YouTube cookie browser, tester
        # difficulty, audio device, batch row template, BPM/offset/time-sig
        # narrow numeric fields, MidiExtractorPanel peer-class fields) read
        # as one visual family. The G6 PNG-wrapped Entries (file/folder path
        # drag-and-drop fields on Single/Batch/A2M/Stem/SM/YT tabs) override
        # bg/fg/insertbg internally and bypass these styles entirely; this
        # treatment is for the un-wrapped fallback widgets so unwired rows
        # don't look out of place. Visual: dark-purple outline (#5b3aa8 base,
        # #b388ff on focus) + #1d1a2e interior (much darker gray-purple than
        # default clam) + light-purple #e8e0ff caret/text.
        _COMBO_FIELD_BG   = "#1d1a2e"   # interior — much darker gray than clam default
        _COMBO_FG         = "#e8e0ff"
        _COMBO_BORDER     = "#5b3aa8"   # dark purple stroke
        _COMBO_BORDER_FOC = "#b388ff"   # brighter purple on focus
        style.configure("TCombobox",
                        fieldbackground=_COMBO_FIELD_BG,
                        background="#2a1235",
                        foreground=_COMBO_FG,
                        bordercolor=_COMBO_BORDER,
                        lightcolor=_COMBO_BORDER,
                        darkcolor=_COMBO_BORDER,
                        arrowcolor=PURPLE,
                        selectbackground="#5a3a8f",
                        selectforeground="#ffffff",
                        insertcolor=_COMBO_FG,
                        padding=4,
                        relief="flat",
                        borderwidth=1)
        style.map("TCombobox",
                  fieldbackground=[("readonly", _COMBO_FIELD_BG),
                                   ("disabled", "#23202e"),
                                   ("!disabled", _COMBO_FIELD_BG)],
                  foreground=[("disabled", "#666"),
                              ("!disabled", _COMBO_FG)],
                  bordercolor=[("focus", _COMBO_BORDER_FOC),
                               ("active", _COMBO_BORDER_FOC),
                               ("!disabled", _COMBO_BORDER)],
                  lightcolor=[("focus", _COMBO_BORDER_FOC),
                              ("!disabled", _COMBO_BORDER)],
                  darkcolor=[("focus", _COMBO_BORDER_FOC),
                             ("!disabled", _COMBO_BORDER)],
                  arrowcolor=[("active", "#ffffff"),
                              ("disabled", "#666"),
                              ("!disabled", PURPLE)])
        style.configure("TEntry",
                        fieldbackground=_COMBO_FIELD_BG,
                        foreground=_COMBO_FG,
                        bordercolor=_COMBO_BORDER,
                        lightcolor=_COMBO_BORDER,
                        darkcolor=_COMBO_BORDER,
                        insertcolor=_COMBO_FG,
                        padding=4,
                        relief="flat",
                        borderwidth=1)
        style.map("TEntry",
                  fieldbackground=[("disabled", "#23202e"),
                                   ("!disabled", _COMBO_FIELD_BG)],
                  foreground=[("disabled", "#666"),
                              ("!disabled", _COMBO_FG)],
                  bordercolor=[("focus", _COMBO_BORDER_FOC),
                               ("!disabled", _COMBO_BORDER)])

        # Root background
        try:
            self.root.configure(bg=BG)
        except Exception:
            pass

        # Log text widgets
        # FORCE every known log to the single active LOG_BG (not each widget's
        # own creation bg) — this is what fixes the old inconsistency where some
        # logs were #0d1117, one had no bg (rendered light gray), and yt_log was
        # #0d0d1a. It also drives the Dark/Light toggle: re-running _apply_theme
        # after flipping LOG_BG repaints them all. (owner 2026-07-09)
        for attr in ['log_text', 'a2m_log_text', 'stem_log_text',
                     'ogg_log_text', 'batch_log_text', 'tester_log',
                     'sm_log_text', 'yt_log', 'fix_log_text',
                     '_log_widget', '_log', '_batch_folder_log_text']:
            try:
                w = getattr(self, attr)
                self._setup_pretty_log_widget(w, bg=LOG_BG)
            except Exception:
                pass

        # Header label colors enforced via deferred _fix_header_labels call


    def _build_single_tab(self, parent):
        """Scrollable single-song converter UI."""
        canvas = tk.Canvas(parent, bg=APP_BG, highlightthickness=0)
        self._tab1_canvas = canvas
        sb     = ttk.Scrollbar(parent, orient="vertical", command=canvas.yview)
        canvas.configure(yscrollcommand=sb.set)
        sb.pack(side=tk.RIGHT, fill=tk.Y)
        canvas.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)

        main = ttk.Frame(canvas, padding=20)
        win  = canvas.create_window((0, 0), window=main, anchor="nw")

        main.bind("<Configure>",  lambda e: canvas.configure(
            scrollregion=(0, 0, *(canvas.bbox("all")[2:] or [800, 600]))))
        canvas.bind("<Configure>", lambda e: canvas.itemconfig(win, width=e.width))

        # ── Recent files dropdown ────────────────────────────────────────────
        recent_frame = ttk.LabelFrame(main, text=" Recent Songs ", padding=8)
        recent_frame.pack(fill=tk.X, pady=(0, 10))

        self.recent_var = tk.StringVar(value="— Select a recent song to reload —")
        self.recent_combo = ttk.Combobox(recent_frame, textvariable=self.recent_var,
                                         state="readonly", width=60)
        self.recent_combo.pack(side=tk.LEFT, fill=tk.X, expand=True, padx=(0, 8))
        ttk.Button(recent_frame, text="Load", command=self._load_recent).pack(side=tk.LEFT)

        self._refresh_recent_combo()

        # ── v4.6.3 — TOP CARD BAND (owner layout) ─────────────────────────────
        # The whole top half becomes ONE horizontal band of four columns so the
        # tab fits on screen with little/no scrolling (like the YouTube tab):
        #   col0 Files | col1 Song Info | col2 Output + Export Format
        #   | col3 Tools + BPM/Timing.
        # _sc_relayout_top (defined once every card exists) reflows to a 2×2
        # grid when the tab is narrow so no card overflows its column.
        sc_top_band = ttk.Frame(main)
        sc_top_band.pack(fill=tk.X, pady=(0, 8))
        mid_stack = ttk.Frame(sc_top_band)     # col2: Output over Export Format
        right_stack = ttk.Frame(sc_top_band)   # col3: Tools over BPM / Timing

        # ── Files (band col 0) ────────────────────────────────────────────────
        files_frame = ttk.LabelFrame(sc_top_band, text=" Files ", padding=10)

        self.midi_var       = tk.StringVar()
        self.audio_var      = tk.StringVar()
        self.drum_audio_var = tk.StringVar()
        self.cover_var      = tk.StringVar()

        self._file_row(files_frame, "MIDI File *",  self.midi_var,       0,
                       [("MIDI files", "*.mid *.midi"), ("All files", "*.*")],
                       config_key="recent_midi", entry_width=22)
        self._file_row(files_frame, "Song Audio *", self.audio_var,      1,
                       [("Audio files", "*.ogg *.mp3 *.wav *.flac"), ("All files", "*.*")],
                       config_key="recent_audio", entry_width=22)
        # ── Extra Stems ───────────────────────────────────────────────────────
        self._single_extra_stems = []
        _stems_outer = ttk.Frame(files_frame)
        _stems_outer.grid(row=2, column=0, columnspan=3, sticky="ew", pady=(0, 4))
        _stems_outer.columnconfigure(0, weight=1)

        def _single_update_add_btn():
            _single_add_btn.configure(
                state="normal" if len(self._single_extra_stems) < 4 else "disabled")

        def _single_add_stem():
            if len(self._single_extra_stems) >= 4:
                return
            idx = len(self._single_extra_stems) + 1
            var = tk.StringVar()
            is_song_var = tk.BooleanVar(value=False)
            is_drum_var = tk.BooleanVar(value=True)
            row_f = ttk.Frame(_stems_outer)
            row_f.pack(fill="x", pady=1)
            ttk.Label(row_f, text=f"Extra Stem {idx}:", width=14,
                      anchor="w").pack(side=tk.LEFT, padx=(0, 4))
            ent = ttk.Entry(row_f, textvariable=var, width=14)
            ent.pack(side=tk.LEFT, padx=(0, 4), fill="x", expand=True)
            ttk.Button(row_f, text="Browse…",
                       command=lambda v=var: self._browse_file(
                           v, [("Audio files", "*.ogg *.mp3 *.wav *.flac"),
                               ("All files", "*.*")], None)
                       ).pack(side=tk.LEFT, padx=(0, 4))
            # Short "Drums"/"Song" labels (not "Drum audio"/"Song audio") so the
            # second toggle + clear button aren't clipped in the narrow card.
            ttk.Checkbutton(row_f, text="Drums", variable=is_drum_var,
                            command=lambda isd=is_drum_var, iss=is_song_var: (
                                isd.set(True), iss.set(False))
                            ).pack(side=tk.LEFT, padx=(0, 2))
            ttk.Checkbutton(row_f, text="Song", variable=is_song_var,
                            command=lambda isd=is_drum_var, iss=is_song_var: (
                                isd.set(False), iss.set(True))
                            ).pack(side=tk.LEFT, padx=(0, 4))
            stem_dict = {"var": var, "is_song_var": is_song_var, "frame": row_f}
            self._single_extra_stems.append(stem_dict)

            def _single_remove(sd=stem_dict):
                sd["frame"].destroy()
                self._single_extra_stems.remove(sd)
                _single_update_add_btn()

            ttk.Button(row_f, text="✕", width=2,
                       command=_single_remove).pack(side=tk.LEFT)
            self._enable_drop(ent, var)
            _single_update_add_btn()

        _single_add_btn = ttk.Button(_stems_outer, text="➕  Add more stem options",
                                     command=_single_add_stem)
        _single_add_btn.pack(anchor="w", pady=(0, 2))
        self._file_row(files_frame, "Drum Audio",   self.drum_audio_var, 3,
                       [("Audio files", "*.ogg *.mp3 *.wav *.flac"), ("All files", "*.*")],
                       config_key="recent_drum_audio", entry_width=22)
        self._cover_widgets = self._file_row(
            files_frame, "Cover Image", self.cover_var, 5,
            [("Images", "*.jpg *.jpeg *.png"), ("All files", "*.*")],
            config_key="recent_cover", entry_width=22)
        # Auto-metadata art indicator — shows when Asset Manager found art.
        # (The label now lives inside the Album Art Preview block below.)
        self._am_auto_art_path = None
        self.am_art_indicator_var = tk.StringVar(value="")
        # When user manually browses cover, clear the auto-art flag
        self.cover_var.trace_add("write", lambda *_: self._on_cover_manual_change())

        # ── Album Art Preview (v4.5.4.1-1) ─────────────────────────────────────
        # Live thumbnail of whatever cover will actually be embedded — whether
        # browsed manually OR pulled from the audio file's metadata (both paths
        # set cover_var) — so the user can confirm it's the right image and see
        # how it's cropped (the dimensions caption flags non-square art) before
        # building. Read-only; no effect on the build pipeline. Placed directly
        # under the Cover Image row at the START of the entry column (sticky w)
        # so it stays visible no matter how long the file paths get.
        self._COVER_PREVIEW_PX = 120
        art_prev_frame = ttk.Frame(files_frame)
        art_prev_frame.grid(row=6, column=1, columnspan=3, sticky="nw",
                            pady=(2, 4))
        _art_box = tk.Frame(art_prev_frame, width=self._COVER_PREVIEW_PX,
                            height=self._COVER_PREVIEW_PX, bg="#17172d",
                            highlightbackground="#00d4d4",
                            highlightcolor="#00d4d4", highlightthickness=2)
        _art_box.pack(side=tk.LEFT)
        _art_box.pack_propagate(False)
        self._cover_preview_label = tk.Label(_art_box, bg="#17172d",
                                             fg="#666666", text="No art")
        self._cover_preview_label.pack(expand=True)
        self._cover_preview_imgref = None  # keep a ref so Tk doesn't GC the image
        _art_meta = ttk.Frame(art_prev_frame)
        _art_meta.pack(side=tk.LEFT, anchor="n", padx=(10, 0))
        ttk.Label(_art_meta, text="Album Art Preview",
                  style="Sub.TLabel", foreground="#888888").pack(anchor="w")
        self._cover_preview_caption_var = tk.StringVar(value="No art selected")
        ttk.Label(_art_meta, textvariable=self._cover_preview_caption_var,
                  style="Sub.TLabel", foreground="#666666").pack(anchor="w", pady=(2, 0))
        # The Asset-Manager "found art" indicator now sits next to the preview.
        ttk.Label(_art_meta, textvariable=self.am_art_indicator_var,
                  style="Sub.TLabel", foreground="#b388ff",
                  wraplength=300, justify=tk.LEFT).pack(anchor="w", pady=(2, 0))
        # Refresh on any cover change (manual Browse OR metadata-extracted), and
        # once now in case a recent song restored a cover before this widget existed.
        self.cover_var.trace_add("write", lambda *_: self._update_cover_preview())
        self.root.after(60, self._update_cover_preview)

        # ── "Use album art from audio metadata" toggle ─────────────────────────
        # When ON: locks the Cover Image row, extracts embedded art (FLAC/MP3/
        # OGG/M4A) from the Song Audio, else the Drum Audio, else the full mix
        # located from the MIDI name, center-crops to 512×512, saves to a temp
        # PNG, and points cover_var at it. The build pipeline at _convert() then
        # copies that temp file into the .rlrr output folder as album.png,
        # exactly like a manually-chosen cover image — no build-side changes.
        self.use_metadata_art_var = tk.BooleanVar(
            value=load_config().get("use_metadata_art", False))
        self._metadata_art_temp_path = None
        meta_art_row = ttk.Frame(files_frame)
        meta_art_row.grid(row=4, column=0, columnspan=4, sticky="ew", pady=(2, 0))
        ttk.Checkbutton(
            meta_art_row,
            text="🎨  Use album art from audio file metadata (auto-cropped 512×512)",
            variable=self.use_metadata_art_var,
            command=self._on_metadata_art_toggle).pack(anchor="w")
        # Status sits BELOW the checkbox (was squeezed beside it and clipped in
        # the narrow card) so it wraps cleanly across the card's full width.
        self.metadata_art_status_var = tk.StringVar(value="")
        ttk.Label(meta_art_row, textvariable=self.metadata_art_status_var,
                  style="Sub.TLabel", foreground="#888888",
                  wraplength=380, justify=tk.LEFT).pack(anchor="w", pady=(1, 0))
        self.use_metadata_art_var.trace_add(
            "write",
            lambda *_: save_config({"use_metadata_art": self.use_metadata_art_var.get()}))
        # Re-extract whenever the user changes Song Audio, Drum Audio, or the
        # MIDI File while the toggle is on — the Drum Audio and MIDI feed the
        # fallback (Drum Audio as a source, the MIDI name to locate the full mix),
        # so a change to any of them can newly satisfy "use art from metadata".
        self.audio_var.trace_add(
            "write",
            lambda *_: self._refresh_metadata_art_if_active())
        self.drum_audio_var.trace_add(
            "write",
            lambda *_: self._refresh_metadata_art_if_active())
        self.midi_var.trace_add(
            "write",
            lambda *_: self._refresh_metadata_art_if_active())
        # Apply initial lock state (deferred — audio_var is empty at construction)
        self.root.after(50, self._on_metadata_art_toggle)

        # Auto Fetch Audio (2026-06-25, owner) — placed BETWEEN the Cover Image and
        # Preview Clip rows. The same button the MIDI Editor has: from the MIDI File's
        # name, fills Song Audio + Drum Audio. Purple button + cyan border + 🎵 icon.
        _sc_af_outer = ttk.Frame(files_frame)
        _sc_af_outer.grid(row=7, column=0, columnspan=4, sticky="w", pady=(4, 4))
        _sc_af_border = tk.Frame(_sc_af_outer, bg="#00d4d4")
        _sc_af_border.pack(side=tk.LEFT)
        _sc_af_btn = ttk.Button(_sc_af_border, text="🎵  Auto Fetch Audio",
                                command=self._creator_auto_fetch_audio, width=21)
        _sc_af_btn.pack(padx=2, pady=2)
        self._add_tooltip(
            _sc_af_btn,
            "From the MIDI File's name, finds the matching Drum Audio + Song Audio\n"
            "(from your Stem Splitter / YouTube output folders and next to the MIDI)\n"
            "and fills those two fields. Same as the MIDI Editor's Auto Fetch Audio.")
        ttk.Label(_sc_af_outer,
                  text="  Fills Song Audio + Drum Audio from the MIDI file's name",
                  style="Sub.TLabel", foreground="#888888").pack(side=tk.LEFT, padx=(8, 0))

        # Preview audio — 15s clip for song selection menu
        self.preview_audio_var = tk.StringVar()
        self._preview_clip_widgets = self._file_row(
            files_frame, "Preview Clip", self.preview_audio_var, 8,
            [("Audio files", "*.ogg *.mp3 *.wav *.flac"), ("All files", "*.*")],
            config_key="recent_preview_audio", entry_width=22)

        preview_note = ttk.Label(
            files_frame,
            text="Tip: make Preview Clips from the full mix in Asset Manager, then use "
                 "'Send clip to Song Creator'. Song Audio is often the backing track "
                 "with no drums, so auto-clipping it can sound wrong.",
            style="Sub.TLabel", foreground="#58a6ff",
            wraplength=400, justify=tk.LEFT)
        preview_note.grid(row=9, column=1, columnspan=3, sticky="w", pady=(0, 4))

        # ── Song Info (band col 1) ────────────────────────────────────────────
        info_frame = ttk.LabelFrame(sc_top_band, text=" Song Info ", padding=10)

        self.title_var   = tk.StringVar(value="Untitled")
        self.artist_var  = tk.StringVar(value="Unknown")
        self.creator_var = tk.StringVar(value="ParaKit")

        self._text_row(info_frame, "Title *",  self.title_var,  0, entry_width=22)
        self._text_row(info_frame, "Artist *", self.artist_var, 1, entry_width=22)
        self._text_row(info_frame, "Creator",  self.creator_var, 2, entry_width=22)

        # v4.5.6.2 — Description embedded into the .rlrr's recordingMetadata.
        # ParaDB reads the description straight from the uploaded .rlrr (there is
        # no website form for it) and renders it as HTML, so on save each newline
        # is written as a <br>. Optional; blank keeps the old empty-description.
        ttk.Label(info_frame, text="Description:").grid(
            row=3, column=0, sticky="nw", padx=(0, 5), pady=2)
        self.description_text = tk.Text(info_frame, height=3, width=22, wrap="word",
                                        bg="#0d1117", fg="#e0e0e0",
                                        insertbackground="#e0e0e0",
                                        selectbackground="#2a1235",
                                        relief="flat", bd=1, padx=6, pady=4)
        self.description_text.grid(row=3, column=1, columnspan=2, sticky="ew", pady=2)
        # Prefill the default description (stays until the user edits it).
        self.description_text.insert("1.0", self.DEFAULT_SONG_DESCRIPTION)
        self._add_tooltip(self.description_text,
                          "Optional. Shown on the song's ParaDB page — it is embedded\n"
                          "in the .rlrr file itself, not added on the website. Line breaks\n"
                          "are saved as <br> for ParaDB's HTML rendering.")

        opts_row = ttk.Frame(info_frame)
        opts_row.grid(row=4, column=0, columnspan=3, sticky="w", pady=2)

        ttk.Label(opts_row, text="Difficulty:").pack(side=tk.LEFT, padx=(0, 5))
        self.difficulty_var = tk.StringVar(value="Expert")
        diff_combo = ttk.Combobox(opts_row, textvariable=self.difficulty_var, width=10,
                                  values=["Easy", "Medium", "Hard", "Expert"], state="readonly")
        diff_combo.pack(side=tk.LEFT, padx=(0, 20))

        ttk.Label(opts_row, text="Complexity:").pack(side=tk.LEFT, padx=(0, 5))
        self.complexity_var = tk.IntVar(value=3)
