        ttk.Label(bpm_frame, text="Manual BPM:").grid(row=2, column=0, sticky="w", padx=(0, 5))
        self.bpm_var   = tk.StringVar()
        self.bpm_entry = ttk.Entry(bpm_frame, textvariable=self.bpm_var, width=10, state="disabled")
        self.bpm_entry.grid(row=2, column=1, sticky="w")
        self._add_tooltip(self.bpm_entry,
            "The tempo of the song in beats per minute.\n"
            "Use this when auto-detect gives the wrong BPM.\n"
            "Tip: the Song Tester tab can suggest the correct value.")

        # ÷2 / ×2 buttons for quick BPM correction
        bpm_btn_frame = ttk.Frame(bpm_frame)
        bpm_btn_frame.grid(row=2, column=2, sticky="w", padx=(6, 0))
        def _bpm_halve():
            try:
                val = float(self.bpm_var.get())
                self.bpm_var.set(f"{val / 2:.2f}")
            except ValueError:
                pass
        def _bpm_double():
            try:
                val = float(self.bpm_var.get())
                self.bpm_var.set(f"{val * 2:.2f}")
            except ValueError:
                pass
        self.bpm_half_btn   = ttk.Button(bpm_btn_frame, text="÷2", width=3, command=_bpm_halve)
        self.bpm_double_btn = ttk.Button(bpm_btn_frame, text="×2", width=3, command=_bpm_double)
        self.bpm_half_btn.pack(side=tk.LEFT, padx=(0, 2))
        self.bpm_double_btn.pack(side=tk.LEFT, padx=(0, 8))
        self._add_tooltip(self.bpm_half_btn,
            "Halve the BPM — use if notes fall at double speed.")
        self._add_tooltip(self.bpm_double_btn,
            "Double the BPM — use if notes fall at half speed.")

        # Offset now sits DIRECTLY UNDER Manual BPM (own row) instead of beside
