        # DrumSep output folder
        ds_out_row = ttk.Frame(self.stem_drumsep_inner)
        ds_out_row.pack(fill=tk.X, pady=(4, 0))
        ttk.Label(ds_out_row, text="Output Folder:", style="Sub.TLabel", width=14).pack(side=tk.LEFT)
        self.stem_drumsep_output_var = tk.StringVar()
