    # ── Lane definitions ──────────────────────────────────────────────────────
    # Order matches in-game left-to-right layout.
    # shape: 'circle' for cymbals, 'bar' for drums, 'kick' for kick line
    MIDI_EDITOR_LANES = [
        {"name": "Hi-Hat",    "midi": [42, 44, 46, 26, 21, 22, 23], "color": "#00e5ff", "shape": "circle"},
        {"name": "Crash",     "midi": [49, 55, 57], "color": "#ff8c00", "shape": "circle"},
        {"name": "Snare",     "midi": [37, 38, 40], "color": "#e63946", "shape": "bar"},
        {"name": "Tom 1",     "midi": [48, 50],     "color": "#1a3a8f", "shape": "bar"},
        {"name": "Tom 2",     "midi": [45, 47],     "color": "#2e8b57", "shape": "bar"},
        {"name": "Tom 3",     "midi": [41, 43],     "color": "#7b2d8b", "shape": "bar"},
        {"name": "Ride",      "midi": [51, 53, 59], "color": "#ffd700", "shape": "circle"},
        {"name": "Kick",      "midi": [35, 36],     "color": "#ff69b4", "shape": "kick"},
    ]

    # GM percussion the lanes can't represent, FOLDED to the closest lane on
    # load (owner 2026-07-11, R2-5 amendment: fold only the common ones —
    # clap/china/tambourine/cowbell; bongos/congas/claves/etc. stay on the
    # tally+warn path and are preserved by the .parakit_bak). Values are lane
    # NAMES; the note is stored as that lane's default (midi[0]). This dict
    # is the single place to extend later.
    _ME_FOLD_TO_LANE = {39: "Snare", 52: "Ride", 54: "Hi-Hat", 56: "Ride"}

    # Manual MIDI Note Manager (owner 2026-07-09): per-lane output-note variations,
    # restricted to notes valid in BOTH Paradiddle (MIDI_MAP) and Clone Hero
    # (_CH_NOTE_MAP). First entry per lane = the current default. Descriptions are
    # the verified General MIDI Level-1 percussion meanings. Hi-Hat is special:
    # the Manager sets the DEFAULT, but individual hats are set per-note in the
    # editor (Closed/Open/Pedal), so the remap EXEMPTS the Hi-Hat lane.
    MANUAL_NOTE_OPTIONS = {
        "Kick":   [(35, "Acoustic Bass Drum (deep / boomy)"), (36, "Bass Drum 1 (tight / punchy)")],
        "Snare":  [(38, "Acoustic Snare"), (40, "Electric Snare (tighter / higher)"),
                   (37, "Side Stick (cross-stick click)")],
        "Hi-Hat": [(42, "Closed"), (46, "Open (washy)"), (44, "Pedal (foot chick)")],
        "Crash":  [(49, 'Crash 15"'), (57, 'Crash 17"'), (55, "Splash")],
        "Ride":   [(51, 'Ride 17"'), (59, 'Ride 20"'), (53, "Ride Bell")],
        "Tom 1":  [(48, "Hi-Mid Tom"), (50, "High Tom (higher)")],
        "Tom 2":  [(45, "Low Tom"), (47, "Low-Mid Tom (higher)")],
        "Tom 3":  [(41, "Low Floor Tom (deepest)"), (43, "High Floor Tom (higher)")],
    }
    MANUAL_NOTE_HHAT_EXEMPT = "Hi-Hat"   # per-note in the editor, not lane-wide

    # Compact per-note labels for the editor lane-strip readout (feature: show
    # each lane's current output note at a glance). Keyed by MIDI note number.
    _MANUAL_NOTE_SHORT = {
        35: "Deep",  36: "Tight",
        38: "Snare", 40: "E.Snr", 37: "Stick",
        42: "Closed", 46: "Open", 44: "Pedal",
        49: 'Cr15"', 57: 'Cr17"', 55: "Splash",
        51: 'Rd17"', 59: 'Rd20"', 53: "Bell",
        48: "Hi-Mid", 50: "High",
        45: "Low",   47: "Lo-Mid",
        41: "Floor", 43: "Hi-Flr",
    }

    # Per-CHART override store (owner 2026-07-10): the Manual Note Manager's
    # choices are tied to the SPECIFIC source MIDI, not global. Loading a fresh
    # MIDI (or one with no saved choices) shows defaults; re-loading a MIDI
    # restores its saved choices. Config key holds {norm_path: {lane: note}}.
    # The editor keeps the ACTIVE chart's choices in memory (_me_note_overrides)
    # so the lane strip + Manager read them without re-hitting disk; export
    # paths look up the store by the file being converted. The old global
    # `manual_note_overrides` key is retired (silently ignored henceforth).
    _MANUAL_NOTE_STORE_KEY = "manual_note_overrides_by_chart"

    @staticmethod
    def _norm_chart_key(path):
        """Canonical dict key for a source MIDI path (case/slash-insensitive on
        Windows). None for an empty path."""
        if not path:
            return None
        try:
            return os.path.normcase(os.path.abspath(str(path)))
        except Exception:
            return str(path)

    def _manual_note_defaults(self):
        """{lane: default note} — the first option of every lane."""
        return {lane: opts[0][0]
                for lane, opts in self.MANUAL_NOTE_OPTIONS.items()}

    def _manual_note_store(self):
        """The full per-chart override store from config (never None)."""
        try:
            s = load_config().get(self._MANUAL_NOTE_STORE_KEY, {}) or {}
            return s if isinstance(s, dict) else {}
        except Exception:
            return {}

    def _get_manual_note_overrides(self, midi_path=None):
        """Resolved per-lane output notes. With ``midi_path`` given, reads THAT
        chart's saved choices from the per-chart store (lane defaults if it has
        none). Without it, reads the editor's ACTIVE in-memory choices
        (``_me_note_overrides``). Missing/invalid lanes fall back to the lane
        default. Always returns a full lane->note dict."""
        if midi_path is not None:
            key = self._norm_chart_key(midi_path)
            raw = self._manual_note_store().get(key, {}) if key else {}
        else:
            raw = getattr(self, "_me_note_overrides", {}) or {}
        if not isinstance(raw, dict):
            raw = {}
        ov = {}
        for lane, opts in self.MANUAL_NOTE_OPTIONS.items():
            valid = [n for n, _ in opts]
            v = raw.get(lane)
            ov[lane] = v if v in valid else opts[0][0]
        return ov

    def _set_active_chart_overrides(self, midi_path):
        """Point the editor's ACTIVE override set at ``midi_path``'s saved
        choices (or defaults if it has none). Called whenever a MIDI is loaded
        into the editor so the Manager + lane strip reflect that chart, and a
        fresh/untouched MIDI shows defaults."""
        key = self._norm_chart_key(midi_path)
        self._manual_note_active_key = key
        raw = self._manual_note_store().get(key, {}) if key else {}
        clean = {}
        for lane, opts in self.MANUAL_NOTE_OPTIONS.items():
            # Hi-Hat is INCLUDED here (it has a persisted lane note too, used as
            # the default for new hats + the strip readout); it's only exempt
            # from the export flatten so mixed open/closed hats survive.
            valid = [n for n, _ in opts]
            if isinstance(raw, dict) and raw.get(lane) in valid:
                clean[lane] = raw[lane]
        self._me_note_overrides = clean
        # Refresh an open Manager + the lane-strip readout for the new chart.
        refresh = getattr(self, "_me_note_mgr_refresh", None)
        if callable(refresh):
            try:
                refresh()
            except Exception:
                pass

    def _apply_manual_note_overrides(self, notes, midi_path=None):
        """Remap each hit to its lane's chosen output note before export. The
        Hi-Hat lane is EXEMPT — its notes keep their individual 42/44/46 values
        (set per-note in the editor) so mixed open/closed charts survive. With
        ``midi_path`` the choices come from that chart's saved entry; without it
        from the editor's active in-memory set. Returns a NEW list of same-shape
        tuples; the input is not mutated. Non-protected; run just before
        build_rlrr / midi_notes_to_ch / MIDI save."""
        ov = self._get_manual_note_overrides(midi_path)
        note_to_lane = {}
        for lane in self.MIDI_EDITOR_LANES:
            for n in lane["midi"]:
                note_to_lane.setdefault(n, lane["name"])
        out = []
        for nd in (notes or []):
            lane = note_to_lane.get(nd[1] if len(nd) > 1 else None)
            if lane and lane != self.MANUAL_NOTE_HHAT_EXEMPT:
                chosen = ov.get(lane)
                if chosen is not None and chosen != nd[1]:
                    t = list(nd); t[1] = chosen; out.append(tuple(t)); continue
            out.append(tuple(nd) if not isinstance(nd, tuple) else nd)
        return out

    def _me_default_place_note(self, lane_idx):
        """MIDI note for a NEWLY placed note in a lane. Non-Hi-Hat lanes use the
        lane's canonical note; the Hi-Hat lane uses the Manager's current
        Closed/Open/Pedal choice so 'selecting the note' works like the other
        lanes — while existing hats keep their own individual values."""
        lane = self.MIDI_EDITOR_LANES[lane_idx]
        if lane["name"] == self.MANUAL_NOTE_HHAT_EXEMPT:
            valid = [n for n, _ in
                     self.MANUAL_NOTE_OPTIONS[self.MANUAL_NOTE_HHAT_EXEMPT]]
            v = self._get_manual_note_overrides().get(
                self.MANUAL_NOTE_HHAT_EXEMPT)
            return v if v in valid else lane["midi"][0]
        return lane["midi"][0]

    def _me_set_hihat_notes(self, indices, new_note, label):
        """Set the per-note MIDI value (42 Closed / 46 Open / 44 Pedal) on the
        given hi-hat note indices in the loaded chart. Undo-able; only notes in
        the Hi-Hat lane are touched, so a mixed selection is safe."""
        if new_note not in (42, 44, 46):
            return
        targets = [i for i in indices
                   if 0 <= i < len(self.me_notes)
                   and self.MIDI_EDITOR_LANES[
                       self.me_notes[i]["lane_idx"]]["name"]
                   == self.MANUAL_NOTE_HHAT_EXEMPT]
        if not targets:
            return
        self._me_push_undo()
        for i in targets:
            self.me_notes[i]["note"] = new_note
        self._me_redraw()
        self.me_note_info_var.set(
            f"🎩  {len(targets)} hi-hat note(s) → {label} ({new_note})")
        self._me_update_info()

    def _me_open_manual_note_manager(self):
        """Floating 'Manual MIDI Note Manager' — pick which MIDI note each drum
        lane writes on export (variations within the same drum piece, verified
        GM percussion meanings). Persisted via config `manual_note_overrides`
        and applied by _apply_manual_note_overrides just before every export.
        Hi-Hat is PER-NOTE (right-click hats in the editor); its row here is a
        one-time bulk setter for the currently loaded chart only."""
        existing = getattr(self, "_me_note_mgr_popup", None)
        if existing is not None:
            try:
                existing.deiconify(); existing.lift(); return
            except Exception:
                self._me_note_mgr_popup = None
        pop = tk.Toplevel(self.root)
        self._me_note_mgr_popup = pop
        pop.title("🥁  Manual MIDI Note Manager")
        pop.configure(bg=APP_BG)
        pop.transient(self.root)
        pop.resizable(False, False)
        try:
            pw, ph = 640, 580
            px = self.root.winfo_x() + (self.root.winfo_width() - pw) // 2
            py = self.root.winfo_y() + (self.root.winfo_height() - ph) // 2
            pop.geometry(f"{pw}x{ph}+{px}+{py}")
        except Exception:
            pass

        def _close():
            self._me_note_mgr_popup = None
            self._me_note_mgr_refresh = None
            try:
                pop.destroy()
            except Exception:
                pass
        pop.protocol("WM_DELETE_WINDOW", _close)

        frame = ttk.Frame(pop, padding=14)
        frame.pack(fill=tk.BOTH, expand=True)
        ttk.Label(frame, text="🥁  Manual MIDI Note Manager",
                  font=("Segoe UI", 12, "bold"),
                  foreground="#b388ff").pack(anchor="w")
        ttk.Label(frame,
                  text=("Choose which MIDI note each lane writes on export "
                        "(.mid / .rlrr / .chart).\n"
                        "Crash & Ride switch the actual drum piece in Paradiddle. "
                        "The other lanes keep their\n"
                        "single Paradiddle pad — their choice sets the note "
                        "e-kits / DAWs receive from the\n"
                        "exported MIDI. Choices are tied to the loaded MIDI: a "
                        "fresh MIDI starts at defaults,\n"
                        "and re-loading a MIDI restores the choices you saved "
                        "for it."),
                  style="Sub.TLabel", justify=tk.LEFT).pack(anchor="w", pady=(2, 10))

        ov = self._get_manual_note_overrides()
        status_var = tk.StringVar(value="")
        combos = {}

        def _save_lane(lane_name):
            def _cb(_e=None):
                sel = combos[lane_name].get()
                try:
                    chosen = int(sel.split("—")[0].strip())
                except Exception:
                    return
                # Update the ACTIVE (in-memory) choices for the loaded chart…
                cur = dict(getattr(self, "_me_note_overrides", {}) or {})
                cur[lane_name] = chosen
                cur.pop(self.MANUAL_NOTE_HHAT_EXEMPT, None)  # hats = per-note
                self._me_note_overrides = cur
                # …and persist under the loaded MIDI's key (per-chart). With no
                # MIDI loaded the choice applies this session only.
                key = getattr(self, "_manual_note_active_key", None)
                if key:
                    store = self._manual_note_store()
                    store[key] = dict(cur)
                    try:
                        save_config({self._MANUAL_NOTE_STORE_KEY: store})
                    except Exception:
                        pass
                    where = "saved to this chart"
                else:
                    where = "this session only — no MIDI loaded"
                try:
                    self._me_redraw()   # refresh the lane-strip readout
                except Exception:
                    pass
                status_var.set(f"✓  {lane_name}  →  {sel}    "
                               f"({where}; applies on the next export)")
            return _cb

        rows = ttk.Frame(frame)
        rows.pack(fill=tk.X)
        for lane in self.MIDI_EDITOR_LANES:
            lname = lane["name"]
            opts = self.MANUAL_NOTE_OPTIONS.get(lname)
            if not opts:
                continue
            row = ttk.Frame(rows)
            row.pack(fill=tk.X, pady=3)
            # Colour swatch — a filled Canvas rectangle, NOT a tk.Frame(bg=…):
            # under the ttkbootstrap 'darkly' theme a bare Frame's bg is forced
            # to the theme default (#222222), which swallowed every lane colour
            # so all eight swatches rendered as identical empty boxes. A Canvas
            # fill is immune to the theme override (verified 2026-07-10) — same
            # pattern the MIDI-editor lane strip already uses.
            sw = tk.Canvas(row, width=15, height=15, highlightthickness=1,
                           highlightbackground="#000000", bd=0)
            sw.create_rectangle(0, 0, 15, 15, fill=lane["color"],
                                outline=lane["color"])
            sw.pack(side=tk.LEFT, padx=(0, 8))
            ttk.Label(row, text=lname, width=8,
                      font=("Segoe UI", 10, "bold")).pack(side=tk.LEFT)
            values = [f"{n} — {d}" for n, d in opts]
            cb = ttk.Combobox(row, state="readonly", width=36, values=values)
            combos[lname] = cb
            if lname == self.MANUAL_NOTE_HHAT_EXEMPT:
                cur_hh = ov.get(lname, opts[0][0])
                cb.set(next((v for v in values
                             if v.startswith(f"{cur_hh} ")), values[0]))
                cb.pack(side=tk.LEFT, padx=(4, 6))

                def _hh_save(cb=cb):    # persist the lane default (per-chart),
                                        # like the other lanes; existing hats keep
                                        # their own per-note values
                    sel = cb.get()
                    try:
                        chosen = int(sel.split("—")[0].strip())
                    except Exception:
                        return
                    cur = dict(getattr(self, "_me_note_overrides", {}) or {})
                    cur[self.MANUAL_NOTE_HHAT_EXEMPT] = chosen
                    self._me_note_overrides = cur
                    key = getattr(self, "_manual_note_active_key", None)
                    if key:
                        store = self._manual_note_store()
                        store[key] = dict(cur)
                        try:
                            save_config({self._MANUAL_NOTE_STORE_KEY: store})
                        except Exception:
                            pass
                        where = "saved to this chart"
                    else:
                        where = "this session only — no MIDI loaded"
                    try:
                        self._me_redraw()
                    except Exception:
                        pass
                    status_var.set(
                        f"✓  Hi-Hat default  →  {sel}    ({where}; new hats use "
                        f"it — existing hats keep their own value)")
                cb.bind("<<ComboboxSelected>>", lambda e, f=_hh_save: f())

                def _hh_apply(cb=cb):   # bind NOW — `cb` rebinds next loop pass
                    sel = cb.get()
                    try:
                        chosen = int(sel.split("—")[0].strip())
                    except Exception:
                        return
                    lbl = sel.split("—", 1)[1].strip()
                    n_before = len(self.me_notes)
                    if not n_before:
                        status_var.set("ℹ  No chart loaded — nothing to set.")
                        return
                    self._me_set_hihat_notes(range(n_before), chosen, lbl)
                    status_var.set(f"✓  ALL loaded hi-hats → {sel}    "
                                   f"(one-time on this chart; Ctrl+Z undoes)")
                ttk.Button(row, text="Set all hats now",
                           command=_hh_apply).pack(side=tk.LEFT)
            else:
                cur_note = ov.get(lname, opts[0][0])
                cur_val = next((v for v in values
                                if v.startswith(f"{cur_note} ")), values[0])
                cb.set(cur_val)
                cb.bind("<<ComboboxSelected>>", _save_lane(lname))
                cb.pack(side=tk.LEFT, padx=(4, 0))

        ttk.Label(frame,
                  text=("Hi-Hat is PER-NOTE: right-click any hi-hat note in the "
                        "editor to set it Closed (42) /\nOpen (46) / Pedal (44) — "
                        "mixed open/closed charts are preserved on export. Open "
                        "hats\nshow up hollow with a yellow outline in the editor "
                        "so you can spot them\nat a glance. The row above only "
                        "bulk-sets the currently loaded chart (not a saved "
                        "default)."),
                  style="Sub.TLabel", foreground="#00d4d4",
                  justify=tk.LEFT).pack(anchor="w", pady=(10, 0))

        # Refresh combos to the ACTIVE chart's choices — called when a new MIDI
        # is loaded while the Manager is open (see _set_active_chart_overrides).
        def _refresh_combos():
            ov2 = self._get_manual_note_overrides()
            for lname2, cb2 in combos.items():
                opts2 = self.MANUAL_NOTE_OPTIONS[lname2]
                vals2 = [f"{n} — {d}" for n, d in opts2]
                cur2 = ov2.get(lname2, opts2[0][0])
                cb2.set(next((v for v in vals2
                              if v.startswith(f"{cur2} ")), vals2[0]))
        self._me_note_mgr_refresh = _refresh_combos

        btns = ttk.Frame(frame)
        btns.pack(fill=tk.X, pady=(12, 0))

        def _reset():
            # Clear this CHART's saved choices (or the transient set if no MIDI
            # is loaded) — back to per-lane defaults.
            self._me_note_overrides = {}
            key = getattr(self, "_manual_note_active_key", None)
            if key:
                store = self._manual_note_store()
                if key in store:
                    store.pop(key, None)
                    try:
                        save_config({self._MANUAL_NOTE_STORE_KEY: store})
                    except Exception:
                        pass
            for lname2, cb2 in combos.items():
                opts2 = self.MANUAL_NOTE_OPTIONS[lname2]
                cb2.set(f"{opts2[0][0]} — {opts2[0][1]}")
            try:
                self._me_redraw()
            except Exception:
                pass
            status_var.set("✓  All lanes reset to defaults for this chart")
        ttk.Button(btns, text="↺  Reset to defaults",
                   command=_reset).pack(side=tk.LEFT)
        ttk.Button(btns, text="Close", command=_close).pack(side=tk.RIGHT)
        ttk.Label(frame, textvariable=status_var, style="Sub.TLabel",
                  foreground="#00c853", wraplength=600,
                  justify=tk.LEFT).pack(anchor="w", pady=(8, 0))

    def _make_stepper_control(self, parent, label_text, var, minimum, maximum,
                              step, fmt, command=None, label_width=14):
        """Small label + -/+ control for precise numeric UI values."""
        frame = ttk.Frame(parent)
        value_lbl = ttk.Label(frame, width=label_width)
        value_lbl.pack(side=tk.LEFT, padx=(0, 4))

        def _refresh(*_):
            try:
                value_lbl.configure(text=f"{label_text}: {fmt(var.get())}")
            except Exception:
                pass

        def _step(delta):
            try:
                new_val = max(minimum, min(maximum, var.get() + delta))
                var.set(round(new_val, 2))
                if command:
                    command()
            except Exception:
                pass

        var.trace_add("write", _refresh)
        _refresh()
        ttk.Button(frame, text="−", width=2,
                   command=lambda: _step(-step)).pack(side=tk.LEFT, padx=(0, 2))
        ttk.Button(frame, text="+", width=2,
                   command=lambda: _step(step)).pack(side=tk.LEFT)
        return frame

    def _build_midi_editor_tab(self, parent):
        """MIDI piano-roll editor tab — visualize and edit drum MIDI files."""
        compact = getattr(self, "_compact_layout", False)
        main = ttk.Frame(parent, padding=(4 if compact else 10))
        main.pack(fill=tk.BOTH, expand=True)

        # ── Top section: controls + right sidebar ────────────────────────────
        # top_section does NOT expand vertically, so roll_outer below it gets
        # full width and height.  right_col claims the right edge; lc fills the rest.
        top_section = ttk.Frame(main)
        top_section.pack(fill=tk.X)
        right_col = ttk.Frame(top_section)
        right_col.pack(side=tk.RIGHT, fill=tk.Y,
                       padx=(3 if compact else 6, 0))
        lc = ttk.Frame(top_section)
        lc.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)

        # Song Creator + Preview/Practice Track buttons — created here so they can be
        # placed at the top of right_col after all right_col widgets are built.
        _me_rc_sc_btn = ttk.Button(right_col, text="📋  Song Creator",
                                    style="Convert.TButton",
                                    command=self._me_send_to_creator)
        _me_rc_tp_btn = ttk.Button(right_col, text="📺  Preview/Practice Track",
                                    command=self._me_send_to_visualizer)

        # ── Header ────────────────────────────────────────────────────────────
        if compact:
            ttk.Label(
                lc,
                text="🎼  MIDI Editor — left-click empty space to place notes. Ghosts are hollow; accents use hot-pink outlines; open hi-hats are hollow with a yellow outline.",
                style="Sub.TLabel", foreground="#b388ff").pack(anchor="w", pady=(0, 2))
        else:
            ttk.Label(lc, text="🎼  MIDI Editor",
                      style="Header.TLabel").pack(anchor="w")
            ttk.Label(lc,
                      text="Visualize and edit your drum MIDI file before converting."
                           "  —  Left-click anywhere in the empty window below to start placing notes.",
                      style="Sub.TLabel").pack(anchor="w", pady=(2, 2))
            ttk.Label(lc,
                      text="👻 Ghost notes (vel < 40) = hollow   ⚡ Accent notes (vel ≥ 115) = hot pink outline   "
                           "🔓 Open hi-hats (note 46) = hollow + yellow outline   "
                           "🔍 Flag outlines: orange = Troubleshooter · white/lime/magenta = Sync Analyzer   Velocity Lane (in Tempo Map section) to edit",
                      style="Sub.TLabel", foreground="#888").pack(anchor="w", pady=(0, 6))

        # ── Top controls ─────────────────────────────────────────────────────
        ctrl_frame = ttk.Frame(lc)
        ctrl_frame.pack(fill=tk.X, pady=(0, 3 if compact else 6))

        # Load MIDI
        self.me_midi_var = tk.StringVar()
        ttk.Label(ctrl_frame, text="MIDI File:").pack(side=tk.LEFT, padx=(0, 5))
        me_entry = ttk.Entry(ctrl_frame, textvariable=self.me_midi_var,
                             width=(28 if compact else 40))
        me_entry.pack(side=tk.LEFT, padx=(0, 5))
        self._enable_drop(me_entry, self.me_midi_var)
        me_browse_frame = ttk.Frame(ctrl_frame)
        me_browse_frame.pack(side=tk.LEFT, padx=(0, 4))
        ttk.Button(me_browse_frame, text="Browse...",
                   command=self._me_browse).pack(side=tk.LEFT)
        self._make_recent_btn(me_browse_frame, "recent_midi_editor",
                              self.me_midi_var,
                              [("MIDI", "*.mid *.midi"), ("All", "*.*")]
                              ).pack(side=tk.LEFT, padx=(2, 0))
        ttk.Button(me_browse_frame, text="✕", width=2,
                   command=lambda: self.me_midi_var.set("")).pack(side=tk.LEFT, padx=(4, 0))

        # v4.4.57.5-6 — Optional .rlrr override (Option C). Lets the user
        # point at a Paradiddle .rlrr file for authoritative timing when
        # the loaded MIDI was extracted with the buggy pre-v4.2.13 extractor.
        # Empty by default; Option B (sibling autodetect) handles the common
        # case automatically. See _me_load for the priority logic.
        self.me_rlrr_override_var = tk.StringVar()
        ttk.Label(ctrl_frame, text="Source .rlrr:").pack(side=tk.LEFT, padx=(8, 3))
        me_rlrr_entry = ttk.Entry(ctrl_frame,
                                  textvariable=self.me_rlrr_override_var,
                                  width=(20 if compact else 28))
        me_rlrr_entry.pack(side=tk.LEFT, padx=(0, 5))
        self._enable_drop(me_rlrr_entry, self.me_rlrr_override_var)
        me_rlrr_browse_frame = ttk.Frame(ctrl_frame)
        me_rlrr_browse_frame.pack(side=tk.LEFT, padx=(0, 4))
        ttk.Button(me_rlrr_browse_frame, text="Browse...",
                   command=self._me_browse_rlrr).pack(side=tk.LEFT)
        self._make_recent_btn(me_rlrr_browse_frame, "recent_me_rlrr",
                              self.me_rlrr_override_var,
                              [(".rlrr", "*.rlrr"), ("All", "*.*")]
                              ).pack(side=tk.LEFT, padx=(2, 0))
        ttk.Button(me_rlrr_browse_frame, text="✕", width=2,
                   command=lambda: self.me_rlrr_override_var.set("")
                   ).pack(side=tk.LEFT, padx=(4, 0))

        ttk.Button(ctrl_frame, text="Load MIDI",
                   style="Convert.TButton",
                   command=self._me_load).pack(side=tk.LEFT, padx=(0, 16))

        # Save MIDI
        ttk.Button(ctrl_frame, text="💾  Save MIDI",
                   command=self._me_save).pack(side=tk.LEFT, padx=(0, 4))
        ttk.Button(ctrl_frame, text="🔄  Reload",
                   command=lambda: self._me_load(self._me_last_midi)
                   ).pack(side=tk.LEFT, padx=(0, 4))
        ttk.Button(ctrl_frame, text="✕  Clear",
                   command=self._me_clear).pack(side=tk.LEFT, padx=(0, 8))

        # Info labels
        self.me_info_var = tk.StringVar(value="No MIDI loaded")
        ttk.Label(ctrl_frame, textvariable=self.me_info_var,
                  style="Sub.TLabel").pack(side=tk.LEFT, padx=(10, 0))

        # Edit mode toggles — inline, no separate frame needed
        self.me_edit_mode_var = tk.StringVar(value="copy")
        self.me_edit_started  = False

        def _me_set_inplace():
            self.me_edit_mode_var.set("inplace")
            self.me_copy_cb.configure(style="TCheckbutton")
        def _me_set_copy():
            self.me_edit_mode_var.set("copy")

        self.me_inplace_var = tk.BooleanVar(value=False)
        self.me_copy_var    = tk.BooleanVar(value=True)

        def _me_inplace_toggled():
            if self.me_inplace_var.get():
                self.me_edit_mode_var.set("inplace")
                self.me_copy_var.set(False)
            else:
                self.me_edit_mode_var.set("copy")
                self.me_copy_var.set(True)

        def _me_copy_toggled():
            if self.me_copy_var.get():
                self.me_edit_mode_var.set("copy")
                self.me_inplace_var.set(False)
            else:
                self.me_edit_mode_var.set("inplace")
                self.me_inplace_var.set(True)

        self.me_mode_inplace_rb = ttk.Checkbutton(
            ctrl_frame, text="Modify original",
            variable=self.me_inplace_var, command=_me_inplace_toggled)
        self.me_mode_inplace_rb.pack(side=tk.LEFT, padx=(16, 4))

        self.me_mode_copy_rb = ttk.Checkbutton(
            ctrl_frame, text="Save as copy",
            variable=self.me_copy_var, command=_me_copy_toggled)
        self.me_mode_copy_rb.pack(side=tk.LEFT, padx=(0, 8))

        self.me_mode_lock_lbl = ttk.Label(
            ctrl_frame,
            text="⚠ Locked",
            style="Sub.TLabel", foreground="#e09a3a")
        # Not packed until mode is locked


        # ── Display option variables (UI built in options_col below) ──────────
        # Variables defined here (not in ctrl2 anymore) so the options panel —
        # which lives next to the playback rows further down — can reference
        # them. UI itself is constructed inside `options_col` in the playback
        # split section below.
        self.me_snap_var               = tk.BooleanVar(value=False)  # v4.4.53.9 — default OFF per owner direction 2026-05-16
        self.me_kick_line_var          = tk.BooleanVar(value=False)
        self.me_uniform_note_color_var = tk.BooleanVar(value=False)
        self.me_reclassify_var         = tk.BooleanVar(value=False)
        self.me_auto_zoom_var          = tk.BooleanVar(value=True)
        self.me_zoom_var               = tk.DoubleVar(value=1.0)
        self.me_note_size_var          = tk.DoubleVar(value=0.3)

        # Dedicated edit toolbar. Keep ctrl2 options-only so the piano roll does not
        # get horizontally crushed on smaller screens.
        edit_col = ttk.Frame(lc)
        edit_col.pack(fill=tk.X, pady=(0, 1 if compact else 3))

        edit_frame = ttk.Frame(edit_col)
        edit_frame.pack(anchor="w")

        def _tool_button(parent, text, command, tip, padx=(0, 2)):
            btn = ttk.Button(parent, text=text, command=command)
            btn.pack(side=tk.LEFT, padx=padx)
            self._add_tooltip(btn, tip)
            return btn

        _tool_button(edit_frame, "↩ Undo", self._me_undo,
                     "Undo the last MIDI Editor change. Shortcut: Ctrl+Z.")
        _tool_button(edit_frame, "↪ Redo", self._me_redo,
                     "Redo the last undone MIDI Editor change. Shortcut: Ctrl+Y.", padx=(0, 12))
        ttk.Separator(edit_frame, orient="vertical").pack(side=tk.LEFT, fill=tk.Y, padx=(0, 8))
        _tool_button(edit_frame, "⊞ Quantize", self._me_quantize,
                     "Snap selected notes to the beat grid. If nothing is selected, applies to all notes.")
        _tool_button(edit_frame, "⧉ Copy", self._me_copy,
                     "Copy the currently selected notes for paste/repeat edits.")
        _tool_button(edit_frame, "⧈ Paste", self._me_paste,
                     "Paste copied notes at the current playhead or last clicked time.")
        _tool_button(edit_frame, "× Dedup", self._me_dedup,
                     "Remove duplicate or near-duplicate notes. Use this after Audio to MIDI if doubles appear.")
        _tool_button(edit_frame, "↻ Repeat", self._me_repeat_pattern,
                     "Repeat the selected note pattern forward in time.")
        _tool_button(edit_frame, "🥁 Flam", self._me_insert_flam,
                     "Add a quiet grace note just before selected notes to create a flam effect.")
        _tool_button(edit_frame, "⊞~ Soft Quantize", self._me_soft_quantize,
                     "Gently pull selected notes toward the grid without fully snapping their timing.")
        _tool_button(edit_frame, "⚡ Re-run ML", self._me_rerun_ml,
                     "Re-run Audio→MIDI detection with current settings. "
                     "Use the Help tab → Detection Troubleshooter first to diagnose and tune settings.")
        _tool_button(edit_frame, "🔍 Review Issues", self._me_cleanup_wizard,
                     "After conversion, scan for duplicates, low-confidence hits, and cymbal mix-ups. "
                     "To fix the detection itself (too many/few hits), use Help tab → Detection Troubleshooter instead.")
        _tool_button(edit_frame, "✂ Vel Filter", self._me_filter_velocity,
                     "Remove notes below a velocity threshold. Uses selection when notes are selected.")
        _tool_button(edit_frame, "⏭ Next Flag", self._me_jump_next_flag,
                     "Jump to the next flagged note (orange / yellow / lime / white / magenta outlines). "
                     "Right-click any flagged note to clear its flag individually.")
        _tool_button(edit_frame, "🏳 Clear Flags", self._me_clear_all_flags,
                     "Remove all flag highlights from every note. Flags are visual only — no notes are changed.")

        ttk.Label(edit_col,
                  text=("Ctrl+scroll=zoom  Ctrl+C/V=copy/paste  Ctrl+Q=quantize"
                        if compact else
                        "Ctrl+scroll=zoom  Ctrl+C/V=copy/paste  Ctrl+Q=quantize  |"
                        "  Reclassify: click=picker, drag=lane change  |"
                        "  Vel Filter removes quiet notes"),
                  style="Sub.TLabel", foreground="#555").pack(anchor="w", pady=(0 if compact else 1, 0))

        self.me_flag_count_var = tk.StringVar(value="")
        ttk.Label(edit_col, textvariable=self.me_flag_count_var,
                  style="Sub.TLabel", foreground="#ff8c00").pack(anchor="w", pady=(0, 0))

        # ── Playback split: left column = playback/loop/offset/latency rows,
        #    right column = display-options panel (formerly the top ctrl2 row).
        #    Filling the previously-empty space to the right of the playback
        #    controls with the moved options.
        playback_split = ttk.Frame(lc)
        playback_split.pack(fill=tk.X, pady=(0, 1 if compact else 4))
        playback_col   = ttk.Frame(playback_split)
        playback_col.pack(side=tk.LEFT, fill=tk.X, expand=True)
        # Batch M (owner-requested): expose the shared MIDI-input settings
        # dialog on the editor tab, ABOVE the Display Options box — the
        # Practice tab's connection carries over (app-level queue + poll),
        # this is just the missing entry point.
        options_side = ttk.Frame(playback_split)
        options_side.pack(side=tk.LEFT, fill=tk.Y,
                          padx=(8 if compact else 12, 0))
        self.me_midi_input_btn = ttk.Button(
            options_side, text="🎹  MIDI Input (BETA)",
            command=self._midi_show_settings_dialog)
        self.me_midi_input_btn.pack(anchor="w", pady=(0, 2 if compact else 4))
        options_col    = ttk.LabelFrame(options_side, text=" Display Options ", padding=(4 if compact else 6))
        options_col.pack(fill=tk.Y)

        # ── Display Options panel (vertical layout, lives next to playback) ──
        # Snap to grid uses tk.Checkbutton with explicit dark-theme styling
        # because ttk.Checkbutton without a command= parameter renders with
        # invisible foreground under some ttkbootstrap themes (v4.3.29 fix).
        _me_snap_cb = tk.Checkbutton(options_col, text="Snap to grid",
                       variable=self.me_snap_var,
                       fg="#e6edf3", selectcolor="#0d1117",
                       activeforeground="#ffffff",
                       bg=APP_BG, activebackground=APP_BG,
                       font=("Segoe UI", 8 if compact else 9))
        _me_snap_cb.pack(anchor="w")
        _me_snap_cb.after(50, lambda: _me_snap_cb.configure(
            fg="#e6edf3", activeforeground="#ffffff"))
        ttk.Checkbutton(options_col, text="Kick - Notes/Lines",
                        variable=self.me_kick_line_var,
                        command=self._me_redraw
                        ).pack(anchor="w")
        ttk.Checkbutton(options_col, text="Uniform Colored Notes",
                        variable=self.me_uniform_note_color_var,
                        command=self._me_redraw
                        ).pack(anchor="w")
        _me_reclassify_cb = tk.Checkbutton(options_col, text="Reclassify mode",
                       variable=self.me_reclassify_var,
                       fg="#00d4d4", selectcolor="#0d1117",
                       activeforeground="#00ffe0",
                       bg=APP_BG, activebackground=APP_BG,
                       font=("Segoe UI", 8 if compact else 9, "bold"))
        _me_reclassify_cb.pack(anchor="w")
        _me_reclassify_cb.after(50, lambda: _me_reclassify_cb.configure(
            fg="#00d4d4", activeforeground="#00ffe0"))
        self._add_tooltip(
            _me_reclassify_cb,
            "When ON, clicking or dragging a note lets you change its instrument lane.\n\n"
            "Click a note  →  opens a picker menu to choose the lane.\n"
            "Drag a note up/down  →  moves it to the lane under the cursor in real time.\n\n"
            "Turn OFF when you're done reclassifying to return to normal edit mode."
        )
        ttk.Checkbutton(options_col, text="Auto zoom",
                        variable=self.me_auto_zoom_var,
                        command=lambda: self._me_apply_auto_zoom() if self.me_auto_zoom_var.get() else None
                        ).pack(anchor="w", pady=(4, 0))
        _zoom_row = ttk.Frame(options_col)
        _zoom_row.pack(anchor="w", fill=tk.X)
        self._make_stepper_control(
            _zoom_row, "Zoom", self.me_zoom_var, 0.3, 4.0, 0.2,
            lambda v: f"{v:.1f}×",
            command=lambda: [self.me_auto_zoom_var.set(False),
                             self._me_schedule_redraw()],
            label_width=10).pack(side=tk.LEFT)
        _ns_row = ttk.Frame(options_col)
        _ns_row.pack(anchor="w", fill=tk.X, pady=(2, 0))
        self._make_stepper_control(
            _ns_row, "Note size", self.me_note_size_var, 0.3, 1.0, 0.1,
            lambda v: f"{v:.1f}×",
            command=self._me_schedule_redraw,
            label_width=14).pack(side=tk.LEFT)

        # v4.4.62-1 — "Auto Fetch Audio" (purple button + cyan border, owner QoL): sits ABOVE Play/Stop
        # and spans their combined width. From the loaded MIDI's song name it
        # finds the Drums stem + Full Mix from the configured Stem/YouTube output
        # folders (and next to the MIDI) and fills ONLY the Drums + Full Mix
        # fields — never Stem 3/4.
        af_row = ttk.Frame(playback_col)
        af_row.pack(fill=tk.X, pady=(0, 3))
        # v4.4.62 follow-up — Owner spec: keep the button PURPLE (matching the
        # Play/Stop buttons) but wrap it in a CYAN BORDER so it still stands out.
        # The border is a 2px cyan tk.Frame around a default-purple ttk.Button;
        # this renders reliably, whereas a cyan ttk style / tk.Button bg did not.
        af_border = tk.Frame(af_row, bg="#00d4d4")
        af_border.pack(side=tk.LEFT)
        self.me_auto_fetch_btn = ttk.Button(
            af_border, text="🎵  Auto Fetch Audio",
            command=self._me_auto_fetch_audio, width=21)
        self.me_auto_fetch_btn.pack(padx=2, pady=2)
        self._add_tooltip(
            self.me_auto_fetch_btn,
            "Finds the Drums stem + Full Mix audio for the loaded MIDI's song\n"
            "(from your Stem Splitter / YouTube output folders and next to the\n"
            "MIDI) and fills the Drums and Full Mix fields. Never touches Stem 3/4.")

        # v4.5.2-1 — Song-title readout. Lives in af_row's EXISTING empty space to
        # the right of Auto Fetch. LAYOUT-SAFE BY CONSTRUCTION: af_row is a single
        # row whose height is the button's, and the much wider playback row
        # (pb_frame, below) already fixes playback_col's width — so this label can
        # never grow the column or add a row, i.e. it cannot reflow / smush the
        # editor canvas or velocity lane. Shows the loaded song's title/artist (from
        # the Full Mix tags, then Drums tags, then a cleaned file name); kept short
        # in _me_update_song_title(). Updated by traces on the MIDI + audio vars.
        self.me_song_title_var = tk.StringVar(value="")
        self.me_song_title_lbl = ttk.Label(
            af_row, textvariable=self.me_song_title_var,
            font=("Segoe UI", 11, "bold"), foreground="#b388ff", anchor="w")
        self.me_song_title_lbl.pack(side=tk.LEFT, padx=(14, 0))
        self._add_tooltip(
            self.me_song_title_lbl,
            "The song you're working on — read from the Full Mix audio's title /\n"
            "artist tags (or the Drums stem, or the file name). Updates when you\n"
            "load a MIDI or fill the audio fields (e.g. via Auto Fetch Audio).")
        try:
            self.me_midi_var.trace_add(
                "write", lambda *_: self._me_update_song_title())
        except Exception:
            pass

        # ── Playback controls ─────────────────────────────────────────────────
        pb_frame = ttk.Frame(playback_col)
        pb_frame.pack(fill=tk.X, pady=(0, 2))

        self.me_play_btn = ttk.Button(pb_frame, text="▶  Play",
                                      command=self._me_play)
        self.me_play_btn.pack(side=tk.LEFT, padx=(0, 4))

        ttk.Button(pb_frame, text="⏹  Stop",
                   command=self._me_stop).pack(side=tk.LEFT, padx=(0, 6))

        # v4.4.57.4-6 — Toolbar order swapped per owner request 2026-05-17:
        # Playback-position info (time + seek hint + Review Speed) now sits
        # immediately after Play / Stop, and the Recording cluster (Record /
        # Count-in / Metronome / Test) moves to the right end. Same widgets,
        # same callbacks — only `.pack()` call order changed.

        # ── Playback-position group (was after Test, now after Stop) ────────
        self.me_playhead_var = tk.StringVar(value="▶  00:00.0")
        ttk.Label(pb_frame, textvariable=self.me_playhead_var,
                  foreground="#00d4d4",
                  font=("Consolas", 9)).pack(side=tk.LEFT, padx=(0, 12))

        ttk.Label(pb_frame,
                  text="Click or drag the beat ruler to seek",
                  style="Sub.TLabel").pack(side=tk.LEFT, padx=(0, 16))

        # Speed controls
        self._me_speed = 1.0
        self.me_speed_lbl = ttk.Label(pb_frame, text="Review Speed: 1.0x",
                                       font=("Segoe UI", 10, "bold"), foreground="#ffd700")
        self.me_speed_lbl.pack(side=tk.LEFT, padx=(0, 6))

        ttk.Button(pb_frame, text="-0.1x", width=6,
                   command=self._me_speed_down).pack(side=tk.LEFT, padx=(0, 2))
        ttk.Button(pb_frame, text="+0.1x", width=6,
                   command=self._me_speed_up).pack(side=tk.LEFT, padx=(0, 2))
        # Bumped right padding from 2 -> 12 to give a visual section break
        # before the Recording cluster.
        ttk.Button(pb_frame, text="↺  Reset", width=8,
                   command=self._me_speed_reset).pack(side=tk.LEFT, padx=(0, 12))

        # ── Recording cluster (was right after Stop, now after Reset) ──────
        self.me_record_btn = ttk.Button(pb_frame, text="● Record",
                                        command=self._midi_record_toggle)
        self.me_record_btn.pack(side=tk.LEFT, padx=(0, 4))
        self._add_tooltip(
            self.me_record_btn,
            "Start a live MIDI recording. Count-in plays first if enabled, "
            "then audio plays while your drum hits get recorded as notes.")

        countin_cb = ttk.Checkbutton(pb_frame, text="Count-in (1 bar)",
                                     variable=self._midi_count_in_enabled)
        countin_cb.pack(side=tk.LEFT, padx=(0, 6))
        self._add_tooltip(
            countin_cb,
            "Play 1 bar (4 clicks) of metronome before recording starts. "
            "Turn off to start recording immediately on Record.")

        ttk.Label(pb_frame, text="Metronome:").pack(side=tk.LEFT, padx=(0, 3))
        self.me_metronome_combo = ttk.Combobox(
            pb_frame, textvariable=self._midi_metronome_sound,
            values=list(self.MIDI_METRONOME_SOUNDS),
            state="readonly", width=14)
        self.me_metronome_combo.pack(side=tk.LEFT, padx=(0, 4))
        self._add_tooltip(
            self.me_metronome_combo,
            "Pick the count-in click sound. Click Test to preview.")

        test_btn = ttk.Button(pb_frame, text="▶ Test", width=7,
                              command=self._metronome_test_play)
        test_btn.pack(side=tk.LEFT, padx=(0, 4))
        self._add_tooltip(
            test_btn,
            "Play the selected metronome sound once at normal volume.")

        # Loop controls row
        loop_frame = ttk.Frame(playback_col)
        loop_frame.pack(fill=tk.X, pady=(0, 2))
        self._me_loop_on   = tk.BooleanVar(value=False)
        self._me_loop_in   = 0.0
        self._me_loop_out  = 0.0
        self.me_loop_in_lbl  = ttk.Label(loop_frame, text="Start: --:--",
                                          font=("Consolas", 9), foreground="#ffd700")
        self.me_loop_out_lbl = ttk.Label(loop_frame, text="End: --:--",
                                          font=("Consolas", 9), foreground="#ffd700")
        ttk.Checkbutton(loop_frame, text="🔁  Loop",
                        variable=self._me_loop_on).pack(side=tk.LEFT, padx=(0, 8))
        self.me_loop_in_lbl.pack(side=tk.LEFT, padx=(0, 4))
        ttk.Button(loop_frame, text="Set Start", width=9,
                   command=self._me_loop_set_in).pack(side=tk.LEFT, padx=(0, 6))
        self.me_loop_out_lbl.pack(side=tk.LEFT, padx=(0, 4))
        ttk.Button(loop_frame, text="Set End", width=8,
                   command=self._me_loop_set_out).pack(side=tk.LEFT, padx=(0, 6))
        ttk.Button(loop_frame, text="✕  Clear Loop", width=14,
                   command=self._me_loop_clear).pack(side=tk.LEFT)
        ttk.Label(loop_frame,
                  text="  Right-click the beat ruler to set loop start/end points",
                  style="Sub.TLabel").pack(side=tk.LEFT, padx=(8, 0))

        # ── Offset row ────────────────────────────────────────────────────────
        offset_row = ttk.Frame(playback_col)
        offset_row.pack(fill=tk.X, pady=(0, 2))

        ttk.Label(offset_row, text="Note offset:").pack(side=tk.LEFT, padx=(0, 6))
        self.me_offset_var = tk.StringVar(value="0.000")
        ttk.Entry(offset_row, textvariable=self.me_offset_var, width=8).pack(side=tk.LEFT)
        ttk.Label(offset_row, text="seconds", style="Sub.TLabel").pack(side=tk.LEFT, padx=(4, 12))

        def _me_nudge_offset(delta):
            try:
                cur = float(self.me_offset_var.get().strip() or "0")
            except ValueError:
                cur = 0.0
            self.me_offset_var.set(f"{cur + delta:.3f}")

        ttk.Button(offset_row, text="-100ms", width=7,
                   command=lambda: _me_nudge_offset(-0.100)).pack(side=tk.LEFT, padx=(0, 2))
        ttk.Button(offset_row, text="-10ms", width=6,
                   command=lambda: _me_nudge_offset(-0.010)).pack(side=tk.LEFT, padx=(0, 2))
        ttk.Button(offset_row, text="+10ms", width=6,
                   command=lambda: _me_nudge_offset(0.010)).pack(side=tk.LEFT, padx=(0, 2))
        ttk.Button(offset_row, text="+100ms", width=7,
                   command=lambda: _me_nudge_offset(0.100)).pack(side=tk.LEFT, padx=(0, 12))

        def _me_apply_offset():
            try:
                shift = float(self.me_offset_var.get().strip() or "0")
            except ValueError:
                shift = 0.0
            if shift == 0.0:
                return
            self._me_push_undo()
            moves = [(n["time"], max(0.0, n["time"] + shift))
                     for n in self.me_notes]
            self.me_notes = [
                dict(n, time=max(0.0, n["time"] + shift))
                for n in self.me_notes
            ]
            # Flags follow their notes (audit-A2 class, R2 addendum), and the
            # canvas stays long enough after a positive shift.
            self._me_transfer_flags(moves)
            if self.me_notes:
                self.me_duration = max(self.me_duration,
                                       self.me_notes[-1]["time"] + 1.0)
            self.me_offset_var.set("0.000")
            self._me_redraw()
            self._me_update_info()
            self.me_status_var.set(
                f"✓  Offset {shift:+.3f}s applied to all notes  —  Ctrl+Z to undo")
            self.root.after(4000, lambda: self.me_status_var.set(
                self.ME_DEFAULT_STATUS))

        ttk.Button(offset_row, text="⟳  Apply Offset to All Notes",
                   command=_me_apply_offset,
                   style="Convert.TButton").pack(side=tk.LEFT)
        ttk.Label(offset_row,
                  text="  Shifts every note by this amount. Use T key while playing to tap the offset.",
                  style="Sub.TLabel", foreground="#888").pack(side=tk.LEFT, padx=(8, 0))

        # ── Audio output latency row ─────────────────────────────────────────
        # Compensates for the gap between when pygame.mixer.music.play() returns
        # and when audio actually reaches the speakers (output buffer + OS audio
        # path + user's hardware chain). Without this, the playhead runs ~30-80ms
        # ahead of the audio you hear, which makes the editor feel misaligned.
        # Initial value is auto-estimated per OS in _me_estimate_audio_latency();
        # users can fine-tune this slider for their specific hardware.
        latency_row = ttk.Frame(playback_col)
        latency_row.pack(fill=tk.X, pady=(0, 2))
        ttk.Label(latency_row, text="Audio output latency:").pack(side=tk.LEFT, padx=(0, 6))
        self.me_audio_latency_ms = tk.DoubleVar(value=self._me_estimate_audio_latency())
        self._me_latency_value_lbl = ttk.Label(
            latency_row, text=f"{self.me_audio_latency_ms.get():.0f} ms",
            width=7, style="Sub.TLabel")
        def _me_latency_changed(*_):
            try:
                v = float(self.me_audio_latency_ms.get())
                self._me_latency_value_lbl.configure(text=f"{v:.0f} ms")
            except Exception:
                pass
        _lat_sf = ttk.Frame(latency_row)
        ttk.Scale(_lat_sf, from_=0.0, to=200.0, length=180,
                  variable=self.me_audio_latency_ms,
                  command=_me_latency_changed).pack(side=tk.TOP, anchor="w")
        _tick_strip(_lat_sf, 180)
        _lat_sf.pack(side=tk.LEFT, padx=(0, 6))
        self._me_latency_value_lbl.pack(side=tk.LEFT, padx=(0, 12))
        ttk.Label(latency_row,
                  text=("Compensates for audio output delay (buffer + OS + hardware). "
                        "Auto-estimated per system; adjust if playhead drifts from what you hear."),
                  style="Sub.TLabel", foreground="#888").pack(side=tk.LEFT, padx=(0, 0))

        # ── Markers popup button (content for right_col sidebar) ─────────────
        self._me_marker_popup = None

        def _me_open_marker_popup():
            if self._me_marker_popup and self._me_marker_popup.winfo_exists():
                self._me_marker_popup.destroy()
                self._me_marker_popup = None
                return
            btn = marker_btn
            popup = tk.Toplevel(self.root)
            popup.overrideredirect(True)
            popup.attributes("-topmost", True)
            popup.configure(bg=APP_BG)
            self._me_marker_popup = popup
            popup.bind("<MouseWheel>", lambda e: "break")
            popup.bind("<Button-4>", lambda e: "break")
            popup.bind("<Button-5>", lambda e: "break")

            # Delay binding the close-on-outside so the opening click
            # doesn't immediately trigger it
            def _bind_close():
                def _close_on_outside(e):
                    if not popup.winfo_exists():
                        return
                    wx, wy = popup.winfo_rootx(), popup.winfo_rooty()
                    ww, wh = popup.winfo_width(), popup.winfo_height()
                    bx2, by2 = btn.winfo_rootx(), btn.winfo_rooty()
                    bw, bh   = btn.winfo_width(), btn.winfo_height()
                    # Ignore clicks on the button itself (toggle handled by command)
                    if bx2 <= e.x_root <= bx2 + bw and by2 <= e.y_root <= by2 + bh:
                        return
                    if not (wx <= e.x_root <= wx + ww and wy <= e.y_root <= wy + wh):
                        popup.destroy()
                        self._me_marker_popup = None
                self.root.bind("<Button-1>", _close_on_outside, add=True)
                popup.bind("<Destroy>", lambda e: self.root.unbind("<Button-1>"))
            self.root.after(50, _bind_close)

            # Use plain tk.Frame so tk.Button bg colors aren't overridden
            inner = tk.Frame(popup, bg=APP_BG, padx=8, pady=8)
            inner.pack(fill=tk.BOTH, expand=True)

            fg = "#e0e0e0"
            bg = APP_BG

            # Apply mode
            self.me_marker_apply_all_var = tk.BooleanVar(value=getattr(self, 'me_marker_apply_all_var', tk.BooleanVar(value=True)).get() if hasattr(self, 'me_marker_apply_all_var') else True)
            ar = tk.Frame(inner, bg=bg); ar.pack(fill=tk.X, pady=(0, 4))
            tk.Radiobutton(ar, text="All", variable=self.me_marker_apply_all_var,
                           value=True, bg=bg, fg=fg, selectcolor="#333",
                           activebackground=bg).pack(side=tk.LEFT, padx=(0, 4))
            tk.Radiobutton(ar, text="Selected", variable=self.me_marker_apply_all_var,
                           value=False, bg=bg, fg=fg, selectcolor="#333",
                           activebackground=bg).pack(side=tk.LEFT, padx=(0, 8))
            tk.Label(ar, text="← apply to", bg=bg,
                     fg="#555", font=("Segoe UI", 8)).pack(side=tk.LEFT)

            # Color swatches — tk.Button inside tk.Frame works
            cr = tk.Frame(inner, bg=bg); cr.pack(fill=tk.X, pady=(0, 4))
            tk.Label(cr, text="Color:", bg=bg, fg=fg,
                     font=("Segoe UI", 9), width=5).pack(side=tk.LEFT)
            if not hasattr(self, 'me_marker_color_var'):
                self.me_marker_color_var = tk.StringVar(value="#00ff88")
            MARKER_COLORS = [
                ("#00ff88","G"),("#ff4444","R"),("#ffff00","Y"),
                ("#00cfff","B"),("#ff8800","O"),("#cc88ff","P"),
            ]
            self._me_marker_color_btns = []

            def _me_update_marker_color_btns():
                cur = self.me_marker_color_var.get()
                for b, col in self._me_marker_color_btns:
                    b.configure(relief="sunken" if col == cur else "raised",
                                bd=3 if col == cur else 1)
            self._me_update_marker_color_btns = _me_update_marker_color_btns

            for col, letter in MARKER_COLORS:
                b = tk.Button(cr, text=letter, bg=col, fg="#000000",
                              activebackground=col, activeforeground="#000",
                              width=2, relief="raised", bd=1,
                              font=("Segoe UI", 8, "bold"), cursor="hand2")
                b.pack(side=tk.LEFT, padx=(0, 2))
                def _click(e=None, c=col, btn=b):
                    self.me_marker_color_var.set(c)
                    self._me_apply_marker_prop("color", c)
                    _me_update_marker_color_btns()
                b.configure(command=_click)
                self._me_marker_color_btns.append((b, col))
            _me_update_marker_color_btns()

            # Label entry
            if not hasattr(self, 'me_marker_label_var'):
                self.me_marker_label_var = tk.StringVar(value="")
            lr = tk.Frame(inner, bg=bg); lr.pack(fill=tk.X, pady=(0, 2))
            tk.Label(lr, text="Label:", bg=bg, fg=fg,
                     font=("Segoe UI", 9), width=5).pack(side=tk.LEFT)
            tk.Entry(lr, textvariable=self.me_marker_label_var, width=12,
                     bg="#2a2a4a", fg=fg, insertbackground=fg).pack(side=tk.LEFT, padx=(0, 3))
            tk.Button(lr, text="Set", width=4, bg="#333", fg=fg,
                      activebackground="#555", activeforeground=fg,
                      command=lambda: self._me_apply_marker_prop(
                          "label", self.me_marker_label_var.get())
                      ).pack(side=tk.LEFT)
            tk.Label(inner, text="Color + label = category (e.g. R+'Snare', G+'Roll', Y+'1:14')",
                     bg=bg, fg="#666", font=("Segoe UI", 8),
                     wraplength=240, justify=tk.LEFT).pack(anchor="w", pady=(1, 4))

            # Options
            if not hasattr(self, 'me_marker_rubber_band_var'):
                self.me_marker_rubber_band_var = tk.BooleanVar(value=True)
            tk.Checkbutton(inner, text="Select with rubber band",
                           variable=self.me_marker_rubber_band_var,
                           bg=bg, fg=fg, selectcolor="#333",
                           activebackground=bg).pack(anchor="w")
            tk.Button(inner, text="Clear All Markers", bg="#333", fg=fg,
                      activebackground="#555", activeforeground=fg,
                      command=lambda: (self._me_push_undo(),
                                       setattr(self, 'me_markers', []),
                                       setattr(self, '_me_selected_markers', set()),
                                       self._me_redraw())
                      ).pack(anchor="w", pady=(6, 0))

            def _position_popup():
                popup.update_idletasks()
                bx = btn.winfo_rootx()
                by = btn.winfo_rooty() + btn.winfo_height()
                # Guard against unmapped widget returning 0,0
                if bx == 0 and by == btn.winfo_height():
                    popup.after(50, _position_popup)
                    return
                pw = popup.winfo_reqwidth()
                sx = self.root.winfo_rootx() + self.root.winfo_width()
                if bx + pw > sx:
                    bx = sx - pw - 4
                popup.geometry(f"+{bx}+{by}")
                popup.deiconify()
            popup.withdraw()
            popup.after(10, _position_popup)

        marker_btn = ttk.Button(right_col, text="📍  Markers",
                                command=_me_open_marker_popup)
        marker_btn.pack(fill=tk.X, pady=(0, 4))

        # ── Display & Snap ────────────────────────────────────────────────────
        snap_outer = ttk.LabelFrame(right_col, text=" 🔲  Display & Snap ", padding=5)
        snap_outer.pack(fill=tk.X)

        # Grid resolution selector
        grid_res_row = ttk.Frame(snap_outer)
        grid_res_row.pack(fill=tk.X, pady=(0, 4))
        ttk.Label(grid_res_row, text="Grid:", style="Sub.TLabel").pack(side=tk.LEFT, padx=(0, 4))
        self.me_grid_res_var = tk.StringVar(value="1/16")
        for _res in ("1/4", "1/8", "1/16", "1/32"):
            ttk.Radiobutton(grid_res_row, text=_res, variable=self.me_grid_res_var,
                            value=_res, command=self._me_redraw).pack(side=tk.LEFT, padx=(0, 6))

        self.me_grid_over_notes_var = tk.BooleanVar(value=False)
        ttk.Checkbutton(snap_outer, text="Grid lines over notes",
                        variable=self.me_grid_over_notes_var,
                        command=self._me_redraw).pack(anchor="w")
        self.me_all_squares_var = tk.BooleanVar(value=False)
        ttk.Checkbutton(snap_outer, text="All notes as squares",
                        variable=self.me_all_squares_var,
                        command=self._me_redraw).pack(anchor="w")
        self.me_full_height_var = tk.BooleanVar(value=False)
        ttk.Checkbutton(snap_outer, text="Show notes as in-game icons",
                        variable=self.me_full_height_var,
                        command=self._me_redraw).pack(anchor="w", pady=(0, 3))

        # Low-confidence shade toggle (hot pink — for ML/Hybrid results)
        self.me_conf_shade_var = tk.BooleanVar(value=False)
        ttk.Checkbutton(snap_outer,
                        text="🎯  Stripe low-confidence ML notes  (hot pink)",
                        variable=self.me_conf_shade_var,
                        command=self._me_redraw).pack(anchor="w", pady=(0, 3))

        # Reactive notes toggle — notes flash white as playhead passes over them
        self.me_reactive_notes_var = tk.BooleanVar(value=True)
        _react_cb = ttk.Checkbutton(snap_outer,
                        text="⚡  Reactive notes  (flash white on playhead)",
                        variable=self.me_reactive_notes_var,
                        command=self._me_redraw)
        _react_cb.pack(anchor="w", pady=(0, 3))
        self._add_tooltip(
            _react_cb,
            "When on, notes turn solid white as the playhead passes over them.\n"
            "Works during playback, scrubbing, and while paused.\n\n"
            "Useful for checking whether notes land exactly where you expect\n"
            "them in a tricky section — watch for the white flash at the beat.")

        # v4.4.28 / v4.4.29 — Waveform display style selector. (v4.5.2-1 added a
        # 4th mode, "stereo_color", and made it the default — see below.)
        #   "bars": per-pixel vertical-line rendering with
        #     intensity-graded color (existing pre-toggle behavior).
        #   "filled_jagged": peak-traced polygon in ParaKit purple, one
        #     vertex per amps[] point in the visible region (jagged top
        #     edge with more amplitude detail at wide zoom).
        #   "jagged_detailed" [v4.4.29]: stem-compare-style thin vertical
        #     lines, uniform ParaKit purple, skip-if-silent. Modeled on
        #     `tools/dev/stem_compare/stem_compare_app.py` `_draw_waveform`
        #     line ~1601. Replaces the v4.4.28 smooth "filled" mode owner
        #     reported as visually indistinguishable from Bars.
        # Both non-default modes use ParaKit purple (#b388ff). Preference
        # persists across sessions via trace_add → save_config. NOTE: this
        # is a one-off persistence pattern in the Display & Snap panel —
        # the other me_*_var settings here currently don't persist. See
        # FOLLOWUPS_PARKED.md F-UX-007 for the parked backfill task.
        wave_row = ttk.Frame(snap_outer)
        wave_row.pack(fill=tk.X, pady=(0, 4))
        ttk.Label(wave_row, text="Waveform:",
                  style="Sub.TLabel").pack(side=tk.LEFT, padx=(0, 4))
        # v4.5.2-1 — the two-tone "Stereo" style is now the DEFAULT for users who
        # have not picked a waveform style (anyone with a saved preference keeps it).
        # v4.4.29 config migration still stands: the removed v4.4.28 "filled" smooth
        # mode maps to the safe "bars" style on load.
        _loaded_wave_style = load_config().get("me_waveform_style", "stereo_color")
        if _loaded_wave_style == "filled":
            _loaded_wave_style = "bars"
        # Any unknown / empty / missing value -> Stereo (the intended default since
        # v4.5.2-1); only a VALID saved choice keeps a non-Stereo style. This makes
        # the Stereo default robust against a blank/garbled config (owner 2026-06-30).
        if _loaded_wave_style not in ("bars", "filled_jagged",
                                      "jagged_detailed", "stereo_color"):
            _loaded_wave_style = "stereo_color"
        self.me_waveform_style_var = tk.StringVar(value=_loaded_wave_style)
        # Order: Stereo FIRST (it's the default), Bars LAST (owner 2026-06-30).
        for _wave_label, _wave_val in (("Stereo", "stereo_color"),
                                       ("Filled (Jagged)", "filled_jagged"),
                                       ("Jagged Hollow", "jagged_detailed"),
                                       ("Bars", "bars")):
            _wave_rb = ttk.Radiobutton(
                wave_row, text=_wave_label,
                variable=self.me_waveform_style_var,
                value=_wave_val,
                command=self._me_waveform_draw)
            _wave_rb.pack(side=tk.LEFT, padx=(0, 6))
        # Persist this preference across sessions even though the rest of
        # the Display & Snap panel does not (other me_*_var settings here
        # reset to defaults each launch — see F-UX-007 in FOLLOWUPS_PARKED.md
        # for the backfill plan).
        self.me_waveform_style_var.trace_add(
            "write",
            lambda *_: save_config(
                {"me_waveform_style": self.me_waveform_style_var.get()}))
        self._add_tooltip(
            _wave_rb.master,
            "Stereo: two-tone filled waveform in ParaKit's theme colors\n"
            "  (default) — the left channel in magenta above the midline,\n"
            "  the right channel in cyan below (mono audio splits the same\n"
            "  envelope top/bottom). The Paradiddle-style look.\n"
            "Filled (Jagged): continuous purple polygon with the top edge\n"
            "  tracing every amplitude sample — spikier silhouette, more\n"
            "  amplitude detail on dense passages.\n"
            "Jagged Hollow: thin purple vertical lines, one per pixel,\n"
            "  uniform color. Quiet sections render as a flat midline\n"
            "  (silence skipped) so hits read as crisp peaks against empty\n"
            "  space — the same rendering style as the developer Stem\n"
            "  Compare tool.\n"
            "Bars: per-pixel vertical lines with intensity-graded color.\n"
            "  Forces a 1-pixel line on every column so quiet sections\n"
            "  still show a faint stripe.\n\n"
            "Switch any time; the change applies immediately and your\n"
            "preference is remembered across app restarts.")

        snap_row = ttk.Frame(snap_outer)
        snap_row.pack(fill=tk.X, pady=(0, 2))
        self.me_note_snap_var = tk.BooleanVar(value=False)
        ttk.Checkbutton(snap_row, text="Snap to notes",
                        variable=self.me_note_snap_var).pack(side=tk.LEFT, padx=(0, 4))
        self.me_snap_thresh_var = tk.IntVar(value=10)
        self.me_snap_thresh_lbl = ttk.Label(snap_row, text="10px", width=4,
                                             style="Sub.TLabel")
        _sn_sf = ttk.Frame(snap_row)
        ttk.Scale(_sn_sf, from_=3, to=30, orient="horizontal", length=70,
                  variable=self.me_snap_thresh_var,
                  command=lambda v: self.me_snap_thresh_lbl.configure(
                      text=f"{int(float(v))}px")).pack(side=tk.TOP, anchor="w")
        _tick_strip(_sn_sf, 70)
        _sn_sf.pack(side=tk.LEFT)
        self.me_snap_thresh_lbl.pack(side=tk.LEFT, padx=(2, 0))

        guide_row = ttk.Frame(snap_outer)
        guide_row.pack(anchor="w")
        ttk.Label(guide_row, text="Guides:", style="Sub.TLabel").pack(side=tk.LEFT, padx=(0, 4))
        self.me_snap_guides_var = tk.StringVar(value="snap")
        ttk.Radiobutton(guide_row, text="On snap",
                        variable=self.me_snap_guides_var,
                        value="snap").pack(side=tk.LEFT, padx=(0, 6))
        ttk.Radiobutton(guide_row, text="Always",
                        variable=self.me_snap_guides_var,
                        value="always").pack(side=tk.LEFT, padx=(0, 10))
        # Force-on toggle: show guide line at the cursor while dragging,
        # even when "Snap to notes" is OFF.
        self.me_guides_force_var = tk.BooleanVar(value=False)
        guides_force_cb = ttk.Checkbutton(
            guide_row, text="Show even when snap off",
            variable=self.me_guides_force_var)
        guides_force_cb.pack(side=tk.LEFT)
        self._add_tooltip(
            guides_force_cb,
            "When on, the yellow guide line follows the cursor during a drag\n"
            "even if 'Snap to notes' is unchecked.\n\n"
            "Useful when you want a vertical reference while moving notes\n"
            "without engaging the snap behavior itself.")

        # ── Ghost Overlay — popup button (saves right column vertical space) ──
        self._me_ghost_popup = None

        def _me_open_ghost_popup():
            if self._me_ghost_popup and self._me_ghost_popup.winfo_exists():
                self._me_ghost_popup.destroy()
                self._me_ghost_popup = None
                return
            popup = tk.Toplevel(self.root)
            popup.title("👻  Ghost Overlay")
            popup.resizable(False, False)
            popup.configure(bg=APP_BG)
            popup.transient(self.root)
            self._me_ghost_popup = popup
            popup.bind("<MouseWheel>", lambda e: "break")
            popup.bind("<Button-4>", lambda e: "break")
            popup.bind("<Button-5>", lambda e: "break")
            popup.protocol("WM_DELETE_WINDOW",
                           lambda: (popup.destroy(),
                                    setattr(self, '_me_ghost_popup', None)))
            inner = tk.Frame(popup, bg=APP_BG, padx=10, pady=10)
            inner.pack(fill=tk.BOTH, expand=True)
            fg, bg = "#e0e0e0", APP_BG
            tk.Label(inner, text="👻  Ghost Overlay", bg=bg, fg="#b388ff",
                     font=("Segoe UI", 10, "bold")).pack(anchor="w", pady=(0, 4))
            tk.Label(inner,
                     text="Load a reference MIDI to show as faded background notes.\n"
                          "Useful for tracing Expert charts when making lower difficulties.",
                     bg=bg, fg="#888", font=("Segoe UI", 8),
                     justify=tk.LEFT).pack(anchor="w", pady=(0, 8))
            self.me_ghost_var = tk.StringVar(value=self.me_ghost_var.get()) \
                                  if hasattr(self, 'me_ghost_var') else tk.StringVar()
            er = tk.Frame(inner, bg=bg); er.pack(fill=tk.X, pady=(0, 6))
            tk.Entry(er, textvariable=self.me_ghost_var, width=28,
                     bg="#2a2a4a", fg=fg, insertbackground=fg).pack(side=tk.LEFT, padx=(0, 4))
            tk.Button(er, text="...", width=3, bg="#333", fg=fg,
                      activebackground="#555", activeforeground=fg,
                      command=lambda: (self.me_ghost_var.set(
                          filedialog.askopenfilename(
                              title="Select reference MIDI",
                              filetypes=[("MIDI", "*.mid *.midi"), ("All", "*.*")])
                          or self.me_ghost_var.get()),
                          self._me_load_ghost())).pack(side=tk.LEFT, padx=(0, 4))
            tk.Button(er, text="✕", width=2, bg="#333", fg=fg,
                      activebackground="#555", activeforeground=fg,
                      command=lambda: (self.me_ghost_var.set(""),
                                       setattr(self, 'me_ghost_notes', []),
                                       self._me_redraw())).pack(side=tk.LEFT)
            op_row = tk.Frame(inner, bg=bg); op_row.pack(anchor="w")
            tk.Label(op_row, text="Opacity:", bg=bg, fg=fg,
                     font=("Segoe UI", 9)).pack(side=tk.LEFT, padx=(0, 6))
            self.me_ghost_op_lbl = tk.Label(op_row,
                                             text=f"{self.me_ghost_opacity_var.get()}%",
                                             bg=bg, fg=fg, font=("Segoe UI", 9), width=4)
            def _op_change(delta):
                cur = self.me_ghost_opacity_var.get()
                new = max(10, min(60, cur + delta))
                self.me_ghost_opacity_var.set(new)
                self.me_ghost_op_lbl.configure(text=f"{new}%")
                self._me_redraw()
            tk.Button(op_row, text="−", width=2, bg="#333", fg=fg,
                      activebackground="#555", activeforeground=fg,
                      relief="flat", font=("Segoe UI", 10),
                      command=lambda: _op_change(-10)).pack(side=tk.LEFT)
            self.me_ghost_op_lbl.pack(side=tk.LEFT, padx=4)
            tk.Button(op_row, text="+", width=2, bg="#333", fg=fg,
                      activebackground="#555", activeforeground=fg,
                      relief="flat", font=("Segoe UI", 10),
                      command=lambda: _op_change(10)).pack(side=tk.LEFT)

            def _pos():
                popup.update_idletasks()
                bx = ghost_btn.winfo_rootx()
                by = ghost_btn.winfo_rooty() + ghost_btn.winfo_height()
                if bx == 0 and by == ghost_btn.winfo_height():
                    popup.after(50, _pos); return
                popup.geometry(f"+{bx}+{by}")
                popup.deiconify()
            popup.withdraw()
            popup.after(10, _pos)

        ghost_btn = ttk.Button(right_col, text="👻  Ghost Overlay",
                               command=_me_open_ghost_popup)
        # Pack right_col widgets from the BOTTOM so the group sits flush with the
        # bottom of the Playback Audio box; any empty space rises to the top.
        # Pack order is reverse of visual top-to-bottom order.
        for _w in (marker_btn, snap_outer, ghost_btn, _me_rc_sc_btn, _me_rc_tp_btn):
            _w.pack_forget()
        marker_btn.pack(side=tk.BOTTOM, fill=tk.X)
        ghost_btn.pack(side=tk.BOTTOM, fill=tk.X, pady=(4, 4))
        snap_outer.pack(side=tk.BOTTOM, fill=tk.X)
        _me_rc_tp_btn.pack(side=tk.BOTTOM, fill=tk.X, pady=(0, 6))
        _me_rc_sc_btn.pack(side=tk.BOTTOM, fill=tk.X, pady=(0, 2))

        # ── Playback Audio ────────────────────────────────────────────────────
        audio_frame = ttk.LabelFrame(lc, text=" 🎧  Playback Audio ", padding=6)
        audio_frame.pack(fill=tk.X, pady=(0, 1 if compact else 2))

        audio_left = ttk.Frame(audio_frame)
        audio_left.pack(fill=tk.BOTH, expand=True)

        # Stems area: two columns (stems 1&2 left, stems 3&4 right) + hint panel
        stems_area = ttk.Frame(audio_left)
        stems_area.pack(fill=tk.BOTH, expand=True)

        stems_left  = ttk.Frame(stems_area)
        stems_left.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        stems_right = ttk.Frame(stems_area)
        stems_right.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)

        STEM_DEFS = [
            ("Drums",    "recent_me_drums",  stems_left),
            ("Full Mix", "recent_me_mix",    stems_left),
            ("Stem 3",   "recent_me_stem3",  stems_right),
            ("Stem 4",   "recent_me_stem4",  stems_right),
        ]
        self.me_stem_vars    = []
        self.me_stem_vol_vars = []
        self.me_stem_indicators = []   # tk.Label dots per stem
        self.me_audio_track_var = tk.StringVar(value="0")
        self.me_layered_var  = tk.BooleanVar(value=False)

        def _me_update_stem_indicators(*_):
            """Update the active stem dot indicators."""
            layered = self.me_layered_var.get()
            try: active = int(self.me_audio_track_var.get())
            except ValueError: active = 0
            for idx, dot in enumerate(self.me_stem_indicators):
                if layered:
                    # In layered mode all loaded stems active — show blue
                    col = "#00aaff" if self.me_stem_vars[idx].get().strip() else "#333"
                elif idx == active:
                    col = "#00ff88"   # active stem — green
                else:
                    col = "#333"      # inactive — dark
                dot.configure(bg=col)

        # Cycle active stem — defined before loop so it can be referenced inline
        def _me_cycle_stem():
            """Switch to the next loaded stem."""
            try:
                cur = int(self.me_audio_track_var.get())
            except ValueError:
                cur = 0
            for offset in range(1, len(self.me_stem_vars)):
                nxt = (cur + offset) % len(self.me_stem_vars)
                if self.me_stem_vars[nxt].get().strip():
                    self.me_audio_track_var.set(str(nxt))
                    STEM_LABELS = ["Drums", "Full Mix", "Stem 3", "Stem 4"]
                    self.me_status_var.set(
                        f"🎵  Now playing: {STEM_LABELS[nxt]} — click ▶ to hear it")
                    self.root.after(2500, lambda: self.me_status_var.set(self.ME_DEFAULT_STATUS))
                    return

        # Mixer popup — defined before loop; mixer_btn assigned in loop (closure ref OK)
        self._me_mixer_popup = None

        def _me_open_mixer_popup():
            if self._me_mixer_popup and self._me_mixer_popup.winfo_exists():
                self._me_mixer_popup.destroy()
                self._me_mixer_popup = None
                return
            popup = tk.Toplevel(self.root)
            popup.title("🎚  Stem Mixer")
            popup.resizable(False, False)
            popup.configure(bg=APP_BG)
            popup.transient(self.root)
            self._me_mixer_popup = popup
            popup.bind("<MouseWheel>", lambda e: "break")
            popup.bind("<Button-4>", lambda e: "break")
            popup.bind("<Button-5>", lambda e: "break")
            popup.protocol("WM_DELETE_WINDOW", lambda: (popup.destroy(),
                                                         setattr(self, '_me_mixer_popup', None)))

            inner = tk.Frame(popup, bg=APP_BG, padx=10, pady=10)
            inner.pack(fill=tk.BOTH, expand=True)
            fg, bg = "#e0e0e0", APP_BG

            tk.Label(inner, text="🎚  Stem Volume Mixer", bg=bg, fg="#b388ff",
                     font=("Segoe UI", 10, "bold")).pack(anchor="w", pady=(0, 6))
            tk.Label(inner,
                     text="Sliders control volume per stem in both Single and Layered mode.\n"
                          "In Single mode, only the active stem plays.\n"
                          "In Layered mode, all loaded stems play simultaneously.",
                     bg=bg, fg="#888", font=("Segoe UI", 8),
                     justify=tk.LEFT).pack(anchor="w", pady=(0, 8))

            STEM_LABELS = ["Drums", "Full Mix", "Stem 3", "Stem 4"]
            for i2, (slabel, vol_var) in enumerate(zip(STEM_LABELS, self.me_stem_vol_vars)):
                r = tk.Frame(inner, bg=bg); r.pack(fill=tk.X, pady=(0, 6))
                tk.Label(r, text=f"{slabel}:", bg=bg, fg=fg,
                         font=("Segoe UI", 9), width=9, anchor="w").pack(side=tk.LEFT)
                lbl = tk.Label(r, text=f"{int(vol_var.get()*100)}%", bg=bg, fg=fg,
                               font=("Segoe UI", 8), width=5)
                def _update_lbl(_, __, ___, l=lbl, v=vol_var):
                    try: l.configure(text=f"{int(v.get()*100)}%")
                    except: pass
                vol_var.trace_add("write", _update_lbl)
                _vol_sf = tk.Frame(r, bg=bg)
                tk.Scale(_vol_sf, from_=0.0, to=1.0, resolution=0.01,
                         orient="horizontal", length=160,
                         variable=vol_var,
                         bg=bg, fg=fg, troughcolor="#333",
                         highlightthickness=0).pack(side=tk.TOP, anchor="w")
                _tick_strip(_vol_sf, 160, bg=bg)
                _vol_sf.pack(side=tk.LEFT, padx=(0, 4))
                lbl.pack(side=tk.LEFT)

            tk.Label(inner,
                     text="⚠  Layered mode + slow playback speed is CPU-intensive.\n"
                          "   Use 1.0x speed when layering multiple stems.",
                     bg=bg, fg="#e09a3a", font=("Segoe UI", 8),
                     justify=tk.LEFT).pack(anchor="w", pady=(8, 0))

            def _position():
                popup.update_idletasks()
                bx = mixer_btn.winfo_rootx()
                by = mixer_btn.winfo_rooty() + mixer_btn.winfo_height()
                if bx == 0 and by == mixer_btn.winfo_height():
                    popup.after(50, _position); return
                pw = popup.winfo_reqwidth()
                sx = self.root.winfo_rootx() + self.root.winfo_width()
                if bx + pw > sx: bx = sx - pw - 4
                popup.geometry(f"+{bx}+{by}")
                popup.deiconify()
            popup.withdraw()
            popup.after(10, _position)

        for i, (label, cfg_key, parent) in enumerate(STEM_DEFS):
            row = ttk.Frame(parent)
            row.pack(fill=tk.X, pady=(0, 2))
            # Active indicator dot
            dot = tk.Label(row, bg="#333", width=1, relief="flat")
            dot.pack(side=tk.LEFT, padx=(0, 3), fill=tk.Y)
            self.me_stem_indicators.append(dot)
            ttk.Radiobutton(row, variable=self.me_audio_track_var,
                            value=str(i)).pack(side=tk.LEFT, padx=(0, 2))
            ttk.Label(row, text=f"{label}:", width=9).pack(side=tk.LEFT, padx=(0, 2))
            v = tk.StringVar()
            self.me_stem_vars.append(v)
            self.me_stem_vol_vars.append(tk.DoubleVar(value=1.0))
            ent = ttk.Entry(row, textvariable=v, width=(24 if compact else 30))
            ent.pack(side=tk.LEFT, padx=(0, 3))
            self._enable_drop(ent, v, config_key=cfg_key)
            btn_f = ttk.Frame(row)
            btn_f.pack(side=tk.LEFT)
            ttk.Button(btn_f, text="Browse...",
                       command=lambda _v=v, _k=cfg_key: self._me_browse_stem(_v, _k)
                       ).pack(side=tk.LEFT)
            self._make_recent_btn(btn_f, cfg_key, v,
                                   [("Audio", "*.ogg *.wav *.flac *.mp3"), ("All", "*.*")]
                                   ).pack(side=tk.LEFT, padx=(2, 0))
            ttk.Button(btn_f, text="✕", width=2,
                       command=lambda _v=v: _v.set("")).pack(side=tk.LEFT, padx=(2, 0))
            # Inline playback controls — tucked after the X button for specific rows
            if i == 0:   # Drums: Single track / Layered radio toggles
                _mode_f = ttk.Frame(row)
                _mode_f.pack(side=tk.LEFT, padx=(8, 0))
                ttk.Radiobutton(_mode_f, text="Single track",
                                variable=self.me_layered_var, value=False).pack(anchor="w")
                ttk.Radiobutton(_mode_f, text="Layered",
                                variable=self.me_layered_var, value=True).pack(anchor="w")
            elif i == 2:  # Stem 3: Switch Stem button
                ttk.Button(row, text="⇄  Switch Stem",
                           command=_me_cycle_stem).pack(side=tk.LEFT, padx=(8, 0))
            elif i == 3:  # Stem 4: Mixer button
                mixer_btn = ttk.Button(row, text="🎚  Mixer",
                                       command=_me_open_mixer_popup)
                mixer_btn.pack(side=tk.LEFT, padx=(8, 0))

        # Wire volume traces — fire on every DoubleVar change (more reliable
        # than Scale command= which can miss events in transient windows)
        def _make_vol_trace(idx):
            def _trace(*_):
                if not self._me_playing:
                    return
                try:
                    vol = float(self.me_stem_vol_vars[idx].get())
                except Exception:
                    return
                try:
                    import pygame
                    if self.me_layered_var.get():
                        # Use Sound.set_volume — more reliable than Channel.set_volume
                        # because the channel may have been reassigned by pygame
                        snd = self._me_stem_sounds.get(idx)
                        if snd:
                            snd.set_volume(vol)
                        # Also set on channel as fallback
                        ch = self._me_stem_channels.get(idx)
                        if ch and ch.get_busy():
                            ch.set_volume(vol)
                    else:
                        try: active = int(self.me_audio_track_var.get())
                        except: active = 0
                        if idx == active:
                            ch = getattr(self, '_me_sound_channel', None)
                            if ch:
                                ch.set_volume(vol)
                            else:
                                pygame.mixer.music.set_volume(vol)
                except Exception:
                    pass
            return _trace

        for _idx, _vv in enumerate(self.me_stem_vol_vars):
            _vv.trace_add("write", _make_vol_trace(_idx))

        # Wire indicator updates to track and layered vars
        self.me_audio_track_var.trace_add("write", _me_update_stem_indicators)
        self.me_layered_var.trace_add("write", _me_update_stem_indicators)
        self.root.after(100, _me_update_stem_indicators)  # set initial state

        # Keep backward compat aliases
        self.me_audio_var     = self.me_stem_vars[0]
        self.me_audio_mix_var = self.me_stem_vars[1]
        # v4.5.2-1 — refresh the toolbar song-title readout whenever the Drums /
        # Full Mix paths change (Auto Fetch, manual Browse, or typing a path).
        for _sv in (self.me_audio_var, self.me_audio_mix_var):
            try:
                _sv.trace_add("write", lambda *_: self._me_update_song_title())
            except Exception:
                pass
        # Initial sync: reflect any MIDI / audio path already prefilled from recent
        # files / config before these traces existed (the method is fully guarded).
        try:
            self._me_update_song_title()
        except Exception:
            pass

        def _me_preserve_active_cache():
            """Keep cached prepared audio for unchanged stems/speeds."""
            active_path = self._me_active_audio()
            cache = getattr(self, '_me_sound_cache', {})
            if isinstance(cache, dict) and all(k in cache for k in ('path', 'speed', 'sound')):
                if cache.get('path') != active_path:
                    self._me_sound_cache = {}
                return
            if not isinstance(cache, dict):
                self._me_sound_cache = {}
                self._me_sound_cache_order = []
                return
            live_paths = {v.get().strip() for v in self.me_stem_vars if v.get().strip()}
            self._me_sound_cache = {
                k: v for k, v in cache.items()
                if isinstance(k, tuple) and len(k) == 3 and k[0] in live_paths
            }
            self._me_sound_cache_order = [
                k for k in getattr(self, '_me_sound_cache_order', [])
                if k in self._me_sound_cache
            ]

        def _me_audio_var_changed(*_):
            path = self._me_active_audio()
            if path and os.path.isfile(path):
                _me_preserve_active_cache()
                self.root.after(100, lambda p=path: self._me_waveform_load(p))
            if not self._me_playing:
                return
            layered = self.me_layered_var.get()
            if layered:
                # In layered mode, restart so new/removed stems take effect
                try:
                    import pygame
                    saved = self._me_actual_play_pos()
                    for ch in self._me_stem_channels.values():
                        try: ch.stop()
                        except: pass
                    self._me_stem_channels = {}
                    self._me_stem_sounds   = {}
                except Exception:
                    saved = self._me_play_offset
                self._me_play_offset = saved
                self._me_playing = False
                self.root.after_idle(self._me_play)
            else:
                # Single track — switch audio from current position
                try:
                    import pygame
                    ch = getattr(self, '_me_sound_channel', None)
                    if ch:
                        saved = self._me_actual_play_pos()
                        ch.stop()
                        self._me_sound_channel = None
                    else:
                        pos_ms = pygame.mixer.music.get_pos()
                        saved = self._me_actual_play_pos(elapsed=max(0, pos_ms) / 1000.0)
                        pygame.mixer.music.stop()
                except Exception:
                    saved = self._me_play_offset
                self._me_play_offset = saved
                self._me_playing = False
                self.root.after_idle(self._me_play)

        for v in self.me_stem_vars:
            v.trace_add("write", _me_audio_var_changed)
        self.me_audio_track_var.trace_add("write", _me_audio_var_changed)

        def _me_layered_changed(*_):
            """Restart playback when switching between single/layered mode."""
            if not self._me_playing:
                return
            try:
                import pygame
                saved = self._me_actual_play_pos()
                pygame.mixer.music.stop()
                for ch in self._me_stem_channels.values():
                    try: ch.stop()
                    except: pass
                self._me_stem_channels = {}
                self._me_stem_sounds   = {}
                ch = getattr(self, '_me_sound_channel', None)
                if ch:
                    try: ch.stop()
                    except: pass
                    self._me_sound_channel = None
            except Exception:
                saved = self._me_play_offset
            self._me_play_offset = saved
            self._me_playing = False
            self.root.after_idle(self._me_play)

        self.me_layered_var.trace_add("write", _me_layered_changed)

