        # Layout constants — must be defined before vel canvas uses ME_LABEL_W
        self.ME_LANE_H   = 52
        self.ME_HEADER_H = 28
        self.ME_LABEL_W  = 90

        vel_canvas_frame = ttk.Frame(vel_lane_frame)
