        # Playback state
        self._me_playing       = False
        self._me_play_start_t  = 0.0
        self._me_play_offset   = 0.0
        self._me_playhead_id   = None
        self._me_tick_id       = None
        self._me_ruler_dragging = False
        self._me_speed         = 1.0
        self._me_speed_audio   = None
        self._me_sound_cache        = {}
        self._me_sound_cache_order  = []
        self._me_sound_cache_limit  = 6
        self._me_sound_channel      = None
        self._me_stem_channels      = {}
        self._me_stem_sounds        = {}   # Sound refs for layered mode (prevent GC)
        self._me_waveform_data      = None
        self._me_audio_start_offset = 0.0
