        self.me_ghost_opacity_var = tk.IntVar(value=30)
        self._me_selected_markers = set() # indices of selected markers
        self._me_drag_marker = None       # index of marker being dragged
        self._me_reclassify_pre_snap   = None   # snapshot saved before reclassify drag
        self._me_reclassify_drag_start_y = 0    # canvas-y at drag start in reclassify mode
        self._me_last_canvas_t = 0.0     # last time position clicked on canvas
        self.me_bpm         = 120.0
        self.me_duration    = 0.0
        self.me_tpb         = 480
        self.me_undo_stack  = []
        self.me_redo_stack  = []
        self.me_drag_note   = None
        self.me_drag_start  = None
        self._me_last_midi  = None
        self.me_flagged     = {}   # time -> flag type for highlighting
        self._me_configure_pending = False
        self.me_note_info_var = tk.StringVar(value="")  # timestamp display

        # ── Status bar — packed BEFORE roll_outer so it gets space first ──────
        self.me_status_var = tk.StringVar(value=self.ME_DEFAULT_STATUS)
        status_bar = ttk.Frame(main)
        status_bar.pack(fill=tk.X, pady=(2, 0), side=tk.BOTTOM)
        # Note info (top row) — shows selected note details
        ttk.Label(status_bar, textvariable=self.me_note_info_var,
                  style="Sub.TLabel", foreground="#00e5ff").pack(anchor="w", padx=2)
        # Keyboard shortcut hint (bottom row) — always visible
        ttk.Label(status_bar, textvariable=self.me_status_var,
                  style="Sub.TLabel").pack(anchor="w", padx=2)

        # ── Piano roll canvas ─────────────────────────────────────────────────
        roll_outer = ttk.Frame(main)
        roll_outer.pack(fill=tk.BOTH, expand=True)

