    def _settings_path(self):
        return os.path.join(os.path.expanduser("~"), ".parakit", "settings.json")

    def _settings_load(self):
        """Load primary settings.json, falling back to sibling .bak.

        Mirrors save_config discipline: a corrupt/locked primary must not wipe
        known-good keys. If neither primary nor backup yields a dict, keep an
        empty cache and set `_settings_load_error` so `_settings_save` will not
        overwrite the unreadable file without first preserving a copy.
        """
        path = self._settings_path()
        bak = path + ".bak"
        self._settings_load_error = None
        primary_exists = os.path.isfile(path)
        bak_exists = os.path.isfile(bak)
        for p in (path, bak):
            try:
                with open(p, "r", encoding="utf-8") as f:
                    data = json.load(f)
                if isinstance(data, dict):
                    self._settings_cache = data
                    return
            except Exception:
                continue
        self._settings_cache = {}
        # Distinct load-error only when a file existed but was unusable —
        # missing both files is a normal first-run empty state.
        if primary_exists or bak_exists:
            self._settings_load_error = True

    def _settings_save(self):
        """Atomic settings write: sibling .tmp + fsync + os.replace + .bak mirror.

        Returns True on success, False on failure (prior primary left intact when
        replace never ran). On a prior load-error, preserves the unreadable
        primary as `.corrupt` before writing so recovery is never silent loss.
        """
        path = self._settings_path()
        tmp = path + ".tmp"
        try:
            os.makedirs(os.path.dirname(path), exist_ok=True)
            if getattr(self, "_settings_load_error", None):
                if os.path.isfile(path):
                    preserved = path + ".corrupt"
                    try:
                        if not os.path.exists(preserved):
                            shutil.copyfile(path, preserved)
                        else:
                            import time as _stime
                            shutil.copyfile(
                                path,
                                path + ".corrupt." + str(int(_stime.time())))
                    except Exception as exc:
                        print(
                            f"[settings] refuse overwrite; could not preserve "
                            f"unreadable primary: {exc}")
                        return False
                self._settings_load_error = None
            with open(tmp, "w", encoding="utf-8") as f:
                # ensure_ascii stays default-True — see save_config: unpaired
                # surrogates in path values would brick every future save.
                json.dump(self._settings_cache, f, indent=2)
                try:
                    f.flush()
                    os.fsync(f.fileno())
                except Exception:
                    pass
            os.replace(tmp, path)
            try:
                shutil.copyfile(path, path + ".bak")
            except Exception:
                pass
            return True
        except Exception as exc:
            try:
                if os.path.isfile(tmp):
                    os.remove(tmp)
            except Exception:
                pass
            print(f"[settings] save error: {exc}")
            return False

    def _settings_get(self, key, default=None):
        if not hasattr(self, "_settings_cache"):
            self._settings_load()
        cur = self._settings_cache
        for part in key.split("."):
            if isinstance(cur, dict) and part in cur:
                cur = cur[part]
            else:
                return default
        return cur

    def _settings_set(self, key, value):
        if not hasattr(self, "_settings_cache"):
            self._settings_load()
        cur = self._settings_cache
        parts = key.split(".")
        for part in parts[:-1]:
            cur = cur.setdefault(part, {})
        cur[parts[-1]] = value
        return self._settings_save()

    def _open_hihat_lane_entry(self):
        return {"name": "Open Hi-Hat", "midi": [46],
                "color": "#00b4d8", "shape": "ring"}

    def _active_lanes(self):
        lanes = list(self.VIZ_LANES)
        if self._settings_get("midi_input.editor_open_hihat_lane", False):
            # Append rather than insert so the eight legacy lane indexes stay
            # stable for existing charts and Practice keybindings.
            lanes.append(self._open_hihat_lane_entry())
        return lanes

    def _viz_ensure_lane_visibility_vars(self):
        if not hasattr(self, "viz_lane_visible"):
            return
        needed = len(self._active_lanes())
        while len(self.viz_lane_visible) < needed:
            self.viz_lane_visible.append(tk.BooleanVar(value=True))

    def _lane_index_by_name(self, name):
        for i, lane in enumerate(self._active_lanes()):
            if lane["name"] == name:
                return i
        return None

    def _midi_hh_mode_effective(self):
        if self._midi_hh_mode == "auto":
            if self._midi_first_cc4_seen_at is not None:
                return "cc4"
            return "note"
        return self._midi_hh_mode

    def _midi_note_to_lane(self, note, velocity):
        open_lane_enabled = self._settings_get(
            "midi_input.editor_open_hihat_lane", False)
        # v4.4.53.6 — user lane overrides win over the class-default
        # VIZ_LANES_MIDI_IN mapping. Lets the user remap any lane via the
        # Controls & Learn Mode dialog (e.g., when a kit sends note 49 for
        # what the user calls "Crash" but their physical pad is actually
        # the hi-hat). Special-case Hi-Hat / Open Hi-Hat preserved because
        # of the open/closed-state pedal logic which is non-trivial.
        overrides = getattr(self, "_midi_user_lane_overrides", {}) or {}
        # Check overrides for non-hi-hat lanes first
        for lane_name, override_notes in overrides.items():
            if lane_name in ("Hi-Hat", "Open Hi-Hat"):
                continue
            try:
                if note in override_notes:
                    return self._lane_index_by_name(lane_name)
            except Exception:
                continue
        hihat_open_notes = {46, 26, 21}
        hihat_close_notes = {42, 22, 23, 44}
        # Allow user overrides for the Hi-Hat lanes too (replaces both sets
        # if the override exists, treating all override notes as close-hits
        # — open-hat detection still uses the CC4 pedal mode when active).
        hihat_override = overrides.get("Hi-Hat")
        open_hihat_override = overrides.get("Open Hi-Hat")
        if hihat_override:
            try:
                hihat_close_notes = set(hihat_override)
            except Exception:
                pass
        if open_hihat_override:
            try:
                hihat_open_notes = set(open_hihat_override)
            except Exception:
                pass
        is_hihat = note in (hihat_open_notes | hihat_close_notes)
        if is_hihat:
            if self._midi_hh_mode_effective() == "cc4":
                is_open = self._midi_hh_pedal_pos < 64
            else:
                is_open = note in hihat_open_notes
            if open_lane_enabled and is_open:
                open_idx = self._lane_index_by_name("Open Hi-Hat")
                if open_idx is not None:
                    return open_idx
            return self._lane_index_by_name("Hi-Hat")

        for lane_name, notes in self.VIZ_LANES_MIDI_IN.items():
            if lane_name in ("Hi-Hat", "Open Hi-Hat"):
                continue
            # Skip any lane that has a user override — already checked above
            if lane_name in overrides:
                continue
            if note in notes:
                return self._lane_index_by_name(lane_name)
        return None

    def _midi_save_lane_overrides(self):
        """Persist `_midi_user_lane_overrides` to config so they survive
        across sessions. Called by the Controls & Learn Mode dialog whenever
        a learn-capture or reset happens."""
        try:
            overrides = getattr(self, "_midi_user_lane_overrides", {}) or {}
            # Serializable form — JSON wants lists, not sets
            clean = {k: list(v) for k, v in overrides.items() if v}
            save_config({"midi_input.lane_overrides": clean})
        except Exception as exc:
            print(f"[MIDI] failed to save lane overrides: {exc}")

    def _midi_get_lane_notes(self, lane_name):
        """Return the effective MIDI-note list for a lane: user override if
        present, otherwise the `VIZ_LANES_MIDI_IN` default. Used by the
        Controls dialog to display what each lane is currently mapped to."""
        overrides = getattr(self, "_midi_user_lane_overrides", {}) or {}
        if lane_name in overrides and overrides[lane_name]:
            return list(overrides[lane_name])
        return list(self.VIZ_LANES_MIDI_IN.get(lane_name, []))

    def _collapse_open_hihat_for_export(self, notes):
        if not self._settings_get("midi_input.editor_open_hihat_lane", False):
            return list(notes)
        open_idx = self._lane_index_by_name("Open Hi-Hat")
        hihat_idx = self._lane_index_by_name("Hi-Hat")
        if open_idx is None or hihat_idx is None:
            return list(notes)
        out = []
        for note in notes:
            if note.get("lane") == open_idx:
                n2 = dict(note)
                n2["lane"] = hihat_idx
                n2["velocity"] = 30
                out.append(n2)
            else:
                out.append(note)
        return out

    def _match_device_profile(self, port_name):
        if not port_name:
            return None
        name_lower = port_name.lower()
        for key, profile in self.MIDI_DEVICE_PROFILES.items():
            if key.startswith("_"):
                continue
            if key in name_lower:
                return profile
        return self.MIDI_DEVICE_PROFILES.get("_gm_fallback")

    def _midi_profile_status(self, port_name):
        if not port_name:
            return ("#888888", "No device selected")
        name_lower = port_name.lower()
        for key, profile in self.MIDI_DEVICE_PROFILES.items():
            if key.startswith("_"):
                continue
            if key in name_lower:
                return ("#00d4d4",
                        f"Recognized: {profile['display_name']} - auto-configured")
        return ("#ffd166",
                "Unknown device - using GM defaults. Custom mappings arrive in Phase 3.")

    def _midi_apply_profile(self, profile):
        if not profile:
            return
        self._midi_hh_mode = profile.get("hihat_mode", "auto")
        self._midi_active_profile = profile
        if hasattr(self, "_midi_input_offset_ms"):
            try:
                self._midi_input_offset_ms.set(float(
                    profile.get("midi_input_offset_ms", 0)))
            except Exception:
                pass

    def _midi_open(self, port_name):
        if not _MIDI_INPUT_AVAILABLE or mido is None:
            return False
        if self._midi_port is not None:
            self._midi_close()
        try:
            self._midi_port = mido.open_input(
                port_name, callback=self._midi_callback)
            self._midi_device_name = port_name
            self._midi_first_cc4_seen_at = None
            profile = self._match_device_profile(port_name)
            if profile:
                self._midi_apply_profile(profile)
            self._settings_set("midi_input.device_name", port_name)
            self._midi_open_disk_log(port_name)
            return True
        except Exception as exc:
            messagebox.showerror(
                "MIDI Error",
                f"Could not open MIDI device:\n{port_name}\n\n{exc}")
            self._midi_port = None
            return False

    def _midi_close(self):
        if self._midi_port is not None:
            try:
                self._midi_port.close()
            except Exception:
                pass
            self._midi_port = None
        self._midi_close_disk_log()

    def _midi_disk_log_path(self):
        try:
            base_dir = os.path.dirname(
                sys.executable if getattr(sys, 'frozen', False)
                else os.path.abspath(__file__))
            return os.path.join(base_dir, "midi_input_test_log.txt")
        except Exception:
            return None

    def _midi_open_disk_log(self, port_name):
        # Persistent on-disk log of MIDI input events (Phase 1 hardware test prep).
        # Append-mode so multiple sessions accumulate; user can clear by deleting file.
        try:
            path = self._midi_disk_log_path()
            if path is None:
                return
            import datetime as _dt
            self._midi_disk_log = open(path, "a", encoding="utf-8")
            self._midi_disk_log.write(
                f"\n=== MIDI session started "
                f"{_dt.datetime.now().strftime('%Y-%m-%d %H:%M:%S')} "
                f"port={port_name} ===\n")
            self._midi_disk_log.flush()
        except Exception as exc:
            print(f"[MIDI] disk-log open failed: {exc}")
            self._midi_disk_log = None

    def _midi_close_disk_log(self):
        log = getattr(self, "_midi_disk_log", None)
        if log is None:
            return
        try:
            import datetime as _dt
            log.write(
                f"=== MIDI session ended "
                f"{_dt.datetime.now().strftime('%Y-%m-%d %H:%M:%S')} ===\n")
            log.flush()
            log.close()
        except Exception:
            pass
        self._midi_disk_log = None

    def _midi_metronome_asset_path(self, sound_name):
        filename = self.MIDI_METRONOME_FILES.get(sound_name)
        if not filename:
            return None
        try:
            base_dir = os.path.join(os.path.expanduser("~"), ".parakit")
            os.makedirs(base_dir, exist_ok=True)
            return os.path.join(base_dir, filename)
        except Exception:
            return None

    def _midi_procedural_click_sound(self, sound_name="Procedural sine",
                                     accent=False):
        try:
            import array
            import math
            import pygame

            if not pygame.mixer.get_init():
                pygame.mixer.init(frequency=44100, size=-16, channels=2,
                                  buffer=PARAKIT_MIXER_BUFFER)
            mixer = pygame.mixer.get_init()
            sample_rate = mixer[0] if mixer else 44100
            channels = mixer[2] if len(mixer) >= 3 else 2
            profile = {
                "Wood block": {
                    "duration_s": 0.075, "attack_s": 0.003,
                    "decay_power": 2.8, "noise": 0.04,
                    "partials": ((1520.0, 0.80, "square"),
                                 (820.0, 0.25, "sine")),
                },
                "Cowbell": {
                    "duration_s": 0.130, "attack_s": 0.004,
                    "decay_power": 1.5, "noise": 0.00,
                    "partials": ((760.0, 0.58, "square"),
                                 (1125.0, 0.42, "square")),
                },
                "Rim shot": {
                    "duration_s": 0.060, "attack_s": 0.0015,
                    "decay_power": 3.2, "noise": 0.34,
                    "partials": ((2300.0, 0.48, "triangle"),
                                 (3200.0, 0.30, "sine")),
                },
                "High blip": {
                    "duration_s": 0.085, "attack_s": 0.003,
                    "decay_power": 2.0, "noise": 0.00,
                    "partials": ((1760.0, 0.82, "sine"),
                                 (2640.0, 0.18, "sine")),
                },
                "Procedural sine": {
                    "duration_s": 0.100, "attack_s": 0.005,
                    "decay_power": 1.0, "noise": 0.00,
                    "partials": ((880.0, 1.00, "sine"),),
                },
            }.get(sound_name, {
                "duration_s": 0.100, "attack_s": 0.005,
                "decay_power": 1.0, "noise": 0.00,
                "partials": ((880.0, 1.00, "sine"),),
            })
            pitch_mult = 1.25 if accent else 1.0
            duration_s = profile["duration_s"]
            attack_s = profile["attack_s"]
            frames = max(1, int(sample_rate * duration_s))
            attack_frames = max(1, int(sample_rate * attack_s))
            samples = array.array("h")
            for i in range(frames):
                if i < attack_frames:
                    env = i / attack_frames
                else:
                    tail = 1.0 - ((i - attack_frames) /
                                  max(1, frames - attack_frames))
                    env = max(0.0, tail) ** profile["decay_power"]
                mixed = 0.0
                weight_total = profile["noise"]
                for freq, weight, shape in profile["partials"]:
                    phase = 2.0 * math.pi * (freq * pitch_mult) * (
                        i / sample_rate)
                    sine = math.sin(phase)
                    if shape == "square":
                        wave = 1.0 if sine >= 0.0 else -1.0
                    elif shape == "triangle":
                        wave = (2.0 / math.pi) * math.asin(sine)
                    else:
                        wave = sine
                    mixed += weight * wave
                    weight_total += abs(weight)
                if profile["noise"]:
                    # Deterministic noise keeps rim-shot/wood transients stable
                    # across runs while still sounding less like a pure tone.
                    n = ((i * 1103515245 + 12345) >> 16) & 0x7fff
                    mixed += profile["noise"] * ((n / 16383.5) - 1.0)
                mixed /= max(0.01, weight_total)
                value = int(17000 * env * mixed)
                value = max(-32767, min(32767, value))
                for _ in range(max(1, channels)):
                    samples.append(value)
            return pygame.mixer.Sound(buffer=samples.tobytes())
        except Exception:
            return None

    def _midi_get_metronome_sound(self, sound_name, accent=False):
        sound_name = sound_name if sound_name in self.MIDI_METRONOME_SOUNDS \
            else "Wood block"
        # Key includes the live mixer rate/channels (R2-7): a Sound built
        # under an old mixer config plays at the wrong pitch after a rate
        # re-init (e.g. 44.1k stem -> 48k mix), so stale entries must miss.
        try:
            import pygame as _pg
            _mi = _pg.mixer.get_init() or (44100, -16, 2)
        except Exception:
            _mi = (44100, -16, 2)
        key = (sound_name, bool(accent), _mi[0], _mi[2])
        if key in self._midi_metronome_cache:
            return self._midi_metronome_cache[key]

        sound = None
        try:
            import pygame
            if not pygame.mixer.get_init():
                pygame.mixer.init(frequency=44100, size=-16, channels=2,
                                  buffer=PARAKIT_MIXER_BUFFER)
            path = self._midi_metronome_asset_path(sound_name)
            if path and os.path.exists(path):
                sound = pygame.mixer.Sound(path)
        except Exception:
            sound = None

        if sound is None:
            sound = self._midi_procedural_click_sound(
                sound_name, accent=accent)
        self._midi_metronome_cache[key] = sound
        return sound

    def _metronome_play(self, sound_name=None, accent=False):
        sound_name = sound_name or self._midi_metronome_sound.get()
        sound = self._midi_get_metronome_sound(sound_name, accent=accent)
        if sound is not None:
            try:
                sound.play()
                return
            except Exception:
                pass
        try:
            import winsound
            winsound.Beep(1200 if accent else 880, 70)
        except Exception:
            pass

    def _metronome_test_play(self):
        self._metronome_play(self._midi_metronome_sound.get(), accent=False)

    def _midi_record_has_playback_audio(self):
        layered = bool(getattr(self, 'me_layered_var', None) and
                       self.me_layered_var.get())
        if layered:
            try:
                return any(v.get().strip() and os.path.isfile(v.get().strip())
                           for v in self.me_stem_vars)
            except Exception:
                return False
        audio_path = self._me_active_audio() if hasattr(self, "_me_active_audio") else ""
        return bool(audio_path and os.path.isfile(audio_path))

    def _midi_record_set_button_state(self):
        btn = getattr(self, "me_record_btn", None)
        if not btn:
            return
        state = getattr(self, "_midi_record_state", "IDLE")
        try:
            btn.configure(text="■ Stop" if state in ("COUNTIN", "RECORDING")
                          else "● Record")
        except Exception:
            pass

    def _midi_record_status(self, text, timeout_ms=0):
        try:
            self.me_status_var.set(text)
            if timeout_ms:
                self.root.after(timeout_ms, lambda: self.me_status_var.set(
                    self.ME_DEFAULT_STATUS))
        except Exception:
            pass

    def _midi_record_toggle(self):
        state = getattr(self, "_midi_record_state", "IDLE")
        if state == "IDLE":
            self._midi_record_start()
        else:
            self._me_stop()

    def _midi_record_start(self):
        if getattr(self, "_midi_record_state", "IDLE") != "IDLE":
            return
        if not self._midi_record_has_playback_audio():
            messagebox.showwarning(
                "No Audio",
                "Load an audio file in the Playback Audio section before "
                "recording. ParaKit records your drum hits while the song plays.")
            return
        if getattr(self, "_me_playing", False):
            self._me_pause()

        self._midi_record_buffer = []
        self._midi_record_song_start = max(
            0.0, float(getattr(self, "_me_play_offset", 0.0) or 0.0))
        self._midi_record_start_time = None

        if self._midi_count_in_enabled.get():
            self._midi_record_state = "COUNTIN"
            self._midi_record_countin_bpm = float(self.me_bpm)
            self._midi_count_in_clicks_remaining = 4
            self._midi_record_set_button_state()
            self._midi_record_status(
                "Recording starts after the 1-bar count-in. Press Stop to cancel.")
            self._midi_record_count_in_tick(4)
        else:
            self._midi_record_begin_playback()

    def _midi_record_count_in_ms(self):
        try:
            bpm = float(getattr(self, "_midi_record_countin_bpm", 120.0) or 120.0)
        except Exception:
            bpm = 120.0
        bpm = max(1.0, bpm)
        return max(1, int((60.0 / bpm) * 1000))

    def _midi_record_clear_count_in(self):
        for aid in getattr(self, "_midi_record_countin_after_ids", []) or []:
            try:
                self.root.after_cancel(aid)
            except Exception:
                pass
        self._midi_record_countin_after_ids = []
        try:
            self.me_canvas.delete("midi_record_countin")
        except Exception:
            pass

    def _midi_record_draw_count_in_overlay(self, text):
        try:
            c = self.me_canvas
            c.delete("midi_record_countin")
            cx = c.canvasx(max(1, c.winfo_width()) / 2)
            cy = c.canvasy(max(1, c.winfo_height()) / 2)
            c.create_text(cx + 3, cy + 3, text=text,
                          fill="#111111", font=("Segoe UI", 54, "bold"),
                          tags="midi_record_countin")
            c.create_text(cx, cy, text=text,
                          fill="#ff5555", font=("Segoe UI", 54, "bold"),
                          tags="midi_record_countin")
        except Exception:
            pass

    def _midi_record_count_in_tick(self, count):
        if getattr(self, "_midi_record_state", "IDLE") != "COUNTIN":
            return
        self._midi_count_in_clicks_remaining = count
        self._metronome_play(self._midi_metronome_sound.get(),
                             accent=(count == 4))
        self._midi_record_draw_count_in_overlay(str(count))
        wait_ms = self._midi_record_count_in_ms()
        if count <= 1:
            aid = self.root.after(wait_ms, self._midi_record_begin_playback)
        else:
            aid = self.root.after(
                wait_ms, lambda c=count - 1: self._midi_record_count_in_tick(c))
        self._midi_record_countin_after_ids.append(aid)

    def _midi_record_begin_playback(self):
        state = getattr(self, "_midi_record_state", "IDLE")
        if state not in ("IDLE", "COUNTIN"):
            return
        self._midi_record_clear_count_in()
        self._midi_record_state = "RECORDING"
        self._midi_record_set_button_state()
        self._me_play_offset = max(0.0, float(
            self._midi_record_song_start or 0.0))
        self._me_play()
        if not getattr(self, "_me_playing", False):
            self._midi_record_reset_state()
            return
        import time as _mtime
        self._midi_record_start_time = getattr(
            self, "_me_play_start_t", _mtime.time())
        self._midi_record_song_start = getattr(
            self, "_me_audio_start_offset", self._me_play_offset)
        self._midi_record_status(
            "Recording... Play your drum kit, then press Stop when finished.")

    def _midi_record_reset_state(self):
        self._midi_record_clear_count_in()
        self._midi_record_state = "IDLE"
        self._midi_record_buffer = []
        self._midi_record_start_time = None
        self._midi_record_song_start = None
        self._midi_count_in_clicks_remaining = 0
        self._midi_record_set_button_state()

    def _midi_record_stop(self):
        state = getattr(self, "_midi_record_state", "IDLE")
        if state == "COUNTIN":
            self._midi_record_reset_state()
            self._midi_record_status("Recording canceled before the song started.",
                                     timeout_ms=3000)
            return
        if state != "RECORDING":
            return
        self._midi_record_state = "STOPPING"
        self._midi_record_commit_buffer()

    def _midi_record_time_now(self):
        import time as _mtime
        now = _mtime.time()
        start = self._midi_record_start_time or now
        song_start = float(self._midi_record_song_start or 0.0)
        try:
            audio_latency = float(self.me_audio_latency_ms.get()) / 1000.0
        except Exception:
            audio_latency = 0.0
        try:
            input_offset = float(self._midi_input_offset_ms.get()) / 1000.0
        except Exception:
            input_offset = 0.0
        elapsed = now - start
        return max(0.0, song_start + elapsed * self._me_speed -
                   audio_latency + input_offset)

    def _midi_record_editor_lane_for_input(self, lane_idx, velocity):
        try:
            active_lanes = self._active_lanes()
            lane_name = active_lanes[lane_idx]["name"]
        except Exception:
            return None, None
        try:
            velocity = max(1, min(127, int(velocity)))
        except Exception:
            velocity = 100
        if lane_name == "Open Hi-Hat":
            lane_name = "Hi-Hat"
            velocity = min(velocity, 30)
        for editor_idx, lane in enumerate(self.MIDI_EDITOR_LANES):
            if lane["name"] == lane_name:
                return editor_idx, velocity
        return None, None

    def _midi_record_capture_midi_hit(self, msg, lane_idx):
        if getattr(self, "_midi_record_state", "IDLE") != "RECORDING":
            return
        editor_lane, velocity = self._midi_record_editor_lane_for_input(
            lane_idx, getattr(msg, "velocity", 100))
        if editor_lane is None:
            return
        self._midi_record_buffer.append(
            (self._midi_record_time_now(), editor_lane, velocity))

    def _midi_record_capture_editor_lane(self, lane_idx, velocity=100):
        if getattr(self, "_midi_record_state", "IDLE") != "RECORDING":
            return False
        if lane_idx < 0 or lane_idx >= len(self.MIDI_EDITOR_LANES):
            return False
        try:
            velocity = max(1, min(127, int(velocity)))
        except Exception:
            velocity = 100
        self._midi_record_buffer.append(
            (self._midi_record_time_now(), lane_idx, velocity))
        return True

    def _midi_record_commit_buffer(self):
        raw = list(getattr(self, "_midi_record_buffer", []) or [])
        new_notes = []
        for time_s, lane_idx, velocity in raw:
            if lane_idx < 0 or lane_idx >= len(self.MIDI_EDITOR_LANES):
                continue
            t = max(0.0, float(time_s))
            if getattr(self, "me_snap_var", None) and self.me_snap_var.get():
                t = self._me_snap_time(t)
            lane = self.MIDI_EDITOR_LANES[lane_idx]
            new_notes.append({
                "time": t,
                "note": lane["midi"][0],
                "lane_idx": lane_idx,
                "vel": velocity,
            })

        if new_notes:
            self._me_push_undo()
            self.me_notes.extend(new_notes)
            self.me_notes.sort(key=lambda n: n["time"])
            last_t = max(n["time"] for n in new_notes)
            if last_t > getattr(self, "me_duration", 0.0):
                self.me_duration = last_t + 1.0
            self._me_selected_notes = set()
            # The sort above shifted indices — a stale last-clicked index
            # would make Delete-with-no-selection remove the WRONG note
            # (Batch-M QA).
            self._me_last_clicked_note = -1
            self._me_redraw()
            self._me_update_info()
            self._midi_record_status(
                f"Recorded {len(new_notes)} drum hit(s). Press Ctrl+Z to undo the take.",
                timeout_ms=5000)
        else:
            self._midi_record_status("No drum hits were recorded.",
                                     timeout_ms=3000)
        self._midi_record_reset_state()

    def _midi_callback(self, msg):
        if msg.type == "note_on" and msg.velocity > 0:
            self.midi_queue.put(msg)
        elif msg.type == "note_off" or (
                msg.type == "note_on" and msg.velocity == 0):
            return
        elif msg.type == "control_change" and msg.control == 4:
            self.midi_queue.put(msg)

    def _poll_midi_queue(self):
        while True:
            try:
                msg = self.midi_queue.get(block=False)
            except queue.Empty:
                break
            try:
                self._handle_midi_message(msg)
            except Exception as exc:
                print(f"[MIDI] handler error: {exc}")
        try:
            self.root.after(5, self._poll_midi_queue)
        except Exception:
            pass

    def _handle_midi_message(self, msg):
        import time as _mtime
        if msg.type == "control_change" and msg.control == 4:
            self._midi_hh_pedal_pos = msg.value
            if self._midi_hh_mode == "auto":
                if self._midi_first_cc4_seen_at is None:
                    self._midi_first_cc4_seen_at = _mtime.time()
            self._midi_log_message(msg, None)
            return

        if msg.type != "note_on" or msg.velocity == 0:
            return

        # v4.4.53.6 — Learn-mode capture. If the user clicked a lane's
        # "Learn" button in the new MIDI Controls dialog, the next note_on
        # gets assigned to that lane via `_midi_user_lane_overrides`. Skip
        # normal routing so the captured hit doesn't double-fire as a
        # Practice hit during capture.
        target_lane = getattr(self, "_midi_learn_target_lane", None)
        if target_lane is not None:
            try:
                self._midi_apply_learn_capture(target_lane, msg.note)
                self._midi_log_message(msg, None)
            except Exception as exc:
                print(f"[MIDI] learn-capture error: {exc}")
            return

        lane_idx = self._midi_note_to_lane(msg.note, msg.velocity)
        self._midi_log_message(msg, lane_idx)

        # v4.4.53.6 — Pulse the per-lane hit indicator in the Controls
        # dialog if it's open. Independent of in-game Practice routing
        # so users can verify their MIDI mapping outside Practice mode.
        try:
            self._midi_pulse_dialog_indicator(lane_idx)
        except Exception:
            pass

        if lane_idx is None:
            return
        if getattr(self, "_midi_record_state", "IDLE") == "RECORDING":
            self._midi_record_capture_midi_hit(msg, lane_idx)
        if self._viz_practice_active():
            self._viz_practice_register_hit(lane_idx)

    def _midi_apply_learn_capture(self, lane_name, note):
        """Record `note` as the new mapping for `lane_name` in the user
        overrides dict, persist to config, refresh dialog UI. Called from
        `_handle_midi_message` while learn-mode is armed for that lane."""
        if not lane_name:
            return
        try:
            note_int = int(note)
        except Exception:
            return
        overrides = getattr(self, "_midi_user_lane_overrides", None)
        if overrides is None:
            overrides = {}
            self._midi_user_lane_overrides = overrides
        # Single-note replacement on capture (simple owner-direction —
        # the dialog can offer "add another note" / "reset to default"
        # as separate controls if the user wants multi-note mappings).
        overrides[lane_name] = [note_int]
        self._midi_save_lane_overrides()
        # Clear the learn target so subsequent hits route normally
        self._midi_learn_target_lane = None
        # Refresh dialog UI if open
        status_vars = getattr(self, "_midi_dialog_learn_status_vars", None)
        if status_vars and lane_name in status_vars:
            try:
                status_vars[lane_name].set(f"note {note_int}")
            except Exception:
                pass

    def _midi_pulse_dialog_indicator(self, lane_idx):
        """Briefly flash the lane's hit indicator in the Controls dialog
        (called from `_handle_midi_message` when a note routes to a lane).
        No-op when dialog isn't open."""
        indicators = getattr(self, "_midi_dialog_lane_indicators", None)
        if not indicators or lane_idx is None:
            return
        try:
            lanes = self._active_lanes()
            if not (0 <= lane_idx < len(lanes)):
                return
            lane = lanes[lane_idx]
            lane_name = lane["name"]
            canvas = indicators.get(lane_name)
            if canvas is None:
                return
            color = lane.get("color", "#00ff88")
            canvas.itemconfigure("hit_bg", fill=color, outline=color)
            # Fade back to dim after 200ms — matches the in-game flash
            # duration so the dialog and the playfield feel consistent.
            self.root.after(200, lambda c=canvas, lc=color:
                            self._midi_pulse_indicator_fade(c, lc))
        except Exception:
            pass

    def _midi_pulse_indicator_fade(self, canvas, lane_color):
        """Restore dialog indicator to its dim resting state (called 200ms
        after `_midi_pulse_dialog_indicator`)."""
        try:
            canvas.itemconfigure("hit_bg", fill="#1a1a2e",
                                 outline=lane_color)
        except Exception:
            pass

    def _midi_log_message(self, msg, lane_idx):
        if msg.type == "control_change":
            text = f"CC#{msg.control} value {msg.value}"
        elif msg.type == "note_on":
            lane_name = "ignored"
            lanes = self._active_lanes()
            if lane_idx is not None and 0 <= lane_idx < len(lanes):
                lane_name = lanes[lane_idx]["name"]
            text = f"note {msg.note} vel {msg.velocity} -> {lane_name}"
        else:
            text = str(msg)
        self._midi_last_messages.append(text)
        self._midi_last_messages = self._midi_last_messages[-5:]
        # Persistent on-disk log (Phase 1 hardware-test prep). Timestamped so
        # post-test verification can confirm timing and lane-mapping without
        # requiring a live screen view.
        log = getattr(self, "_midi_disk_log", None)
        if log is not None:
            try:
                import datetime as _dt
                stamp = _dt.datetime.now().strftime('%H:%M:%S.%f')[:-3]
                prefix = "[IGNORED] " if (
                    msg.type == "note_on" and lane_idx is None) else ""
                log.write(f"{stamp}  {prefix}{text}\n")
                log.flush()
            except Exception:
                pass
        widget = getattr(self, "_midi_test_text", None)
        if widget is not None:
            try:
                widget.configure(state="normal")
                widget.delete("1.0", tk.END)
                widget.insert(tk.END, "\n".join(self._midi_last_messages))
                widget.configure(state="disabled")
                widget.see(tk.END)
            except Exception:
                pass

    def _midi_refresh_input_names(self):
        if not _MIDI_INPUT_AVAILABLE or mido is None:
            return []
        try:
            return list(mido.get_input_names())
        except Exception:
            return []

    def _midi_on_open_hihat_toggle(self, enabled):
        self._settings_set("midi_input.editor_open_hihat_lane", bool(enabled))
        self._viz_ensure_lane_visibility_vars()
        try:
            if getattr(self, "viz_midi_var", None) and self.viz_midi_var.get().strip():
                self._viz_load_notes()
            self._viz_redraw_static()
            self._viz_draw_legend()
            self._viz_draw_practice_legend()
        except Exception:
            pass

    def _midi_show_settings_dialog(self):
        """v4.4.53.6 — kept as a thin alias for backward compatibility.
        Forwards to the new combined Controls + Learn Mode dialog."""
        return self._midi_show_controls_learn_dialog()

    def _midi_show_controls_learn_dialog(self):
        """v4.4.53.6 — MIDI Controls & Learn Mode dialog (BETA).

        Combines:
          - Device selector + refresh + recognized-profile status
          - Per-lane row showing lane color swatch + name + current MIDI
            note(s) + live hit indicator + "Learn" button + "Reset"
          - Hi-hat / multi-source toggles
          - Live "last 5 messages" test area
          - Bottom action buttons (Reset All / Close)

        Opens whether or not a MIDI device is connected (per owner direction
        2026-05-16 for testing). When `mido` itself is missing the dialog
        shows a clear banner explaining that learn-mode capture won't fire
        until the library is available, but everything else stays visible.

        ⚠ TEMPORARY: the no-device gate-bypass for testing is owner-
        requested. Once owner approves the layout, revert the
        `_build_visualizer_tab`'s `if not _MIDI_INPUT_AVAILABLE` gate so
        the button greys out again when no device is connected.
        """
        dlg = tk.Toplevel(self.root)
        dlg.title("🎹  MIDI Controls & Learn Mode  (BETA)")
        dlg.resizable(False, False)
        try:
            dlg.configure(bg=APP_BG)
        except Exception:
            pass
        dlg.grab_set()

        outer = ttk.Frame(dlg, padding=14)
        outer.pack(fill=tk.BOTH, expand=True)

        ttk.Label(outer, text="🎹  MIDI Controls & Learn Mode",
                  style="Header.TLabel").grid(
                      row=0, column=0, columnspan=4, sticky="w")
        ttk.Label(outer,
                  text="BETA — MIDI drum-kit input for Practice mode. "
                       "If a pad triggers the wrong lane, use Learn to remap it.",
                  style="Sub.TLabel", foreground="#ffd166",
                  wraplength=600, justify=tk.LEFT).grid(
                      row=1, column=0, columnspan=4, sticky="w",
                      pady=(2, 10))

        # ── mido availability banner ──────────────────────────────────────
        if not _MIDI_INPUT_AVAILABLE or mido is None:
            ttk.Label(
                outer,
                text="⚠  MIDI library not loaded. You can preview the "
                     "controls layout, but Learn capture and live hit "
                     "indicators will only work once the library is "
                     "available (reinstall ParaKit to restore).",
                style="Sub.TLabel", foreground="#e09a3a",
                wraplength=600, justify=tk.LEFT).grid(
                    row=2, column=0, columnspan=4, sticky="w", pady=(0, 10))
            _row_offset = 3
        else:
            _row_offset = 2

        # ── Device selector + refresh ─────────────────────────────────────
        dev_frame = ttk.LabelFrame(outer, text=" Device ", padding=8)
        dev_frame.grid(row=_row_offset, column=0, columnspan=4,
                       sticky="ew", pady=(0, 10))
        dev_frame.columnconfigure(1, weight=1)

        none_label = "(None / Keyboard only)"
        device_var = tk.StringVar()
        last_device = self._settings_get("midi_input.device_name", "")
        try:
            ports = self._midi_refresh_input_names() if _MIDI_INPUT_AVAILABLE else []
        except Exception:
            ports = []
        values = [none_label] + ports
        device_var.set(last_device if last_device in ports else none_label)

        status_var = tk.StringVar()
        status_lbl = ttk.Label(dev_frame, textvariable=status_var,
                               style="Sub.TLabel")

        def _set_status_for(name):
            if name == none_label:
                color, text = self._midi_profile_status("")
            else:
                color, text = self._midi_profile_status(name)
            status_var.set(text)
            try:
                status_lbl.configure(foreground=color)
            except Exception:
                pass

        ttk.Label(dev_frame, text="Device:").grid(
            row=0, column=0, sticky="w", padx=(0, 8), pady=3)
        combo = ttk.Combobox(dev_frame, textvariable=device_var,
                             values=values, state="readonly", width=42)
        combo.grid(row=0, column=1, sticky="ew", pady=3)

        def _refresh():
            if not _MIDI_INPUT_AVAILABLE:
                return
            new_ports = self._midi_refresh_input_names()
            combo.configure(values=[none_label] + new_ports)
            if device_var.get() not in ([none_label] + new_ports):
                device_var.set(none_label)
                self._midi_close()
                self._settings_set("midi_input.device_name", "")
                _set_status_for(none_label)

        ttk.Button(dev_frame, text="🔄  Refresh",
                   command=_refresh).grid(
                       row=0, column=2, sticky="e", padx=(8, 0), pady=3)
        status_lbl.grid(row=1, column=0, columnspan=3, sticky="w",
                        pady=(4, 0))
        _set_status_for(device_var.get())

        # ── Per-lane visualization + Learn rows ───────────────────────────
        lanes_frame = ttk.LabelFrame(
            outer, text=" Per-Lane Hit Indicator + Learn Mode ", padding=8)
        lanes_frame.grid(row=_row_offset + 1, column=0, columnspan=4,
                         sticky="ew", pady=(0, 10))
        lanes_frame.columnconfigure(2, weight=1)

        ttk.Label(lanes_frame,
                  text="Each indicator flashes when its MIDI note arrives. "
                       "If the wrong lane flashes (e.g. you hit hi-hat but "
                       "Crash lights up), click that lane's Learn button, "
                       "then hit the pad on your kit — ParaKit captures "
                       "that note as the new mapping for that lane.",
                  style="Sub.TLabel", foreground="#888888",
                  wraplength=620, justify=tk.LEFT).grid(
                      row=0, column=0, columnspan=5, sticky="w",
                      pady=(0, 8))

        # Header row
        ttk.Label(lanes_frame, text="Lane",
                  style="Sub.TLabel", foreground="#b388ff",
                  font=("Segoe UI", 9, "bold")).grid(
                      row=1, column=0, sticky="w", padx=(0, 8))
        ttk.Label(lanes_frame, text="Hit",
                  style="Sub.TLabel", foreground="#b388ff",
                  font=("Segoe UI", 9, "bold")).grid(
                      row=1, column=1, sticky="w", padx=(0, 8))
        ttk.Label(lanes_frame, text="MIDI Note(s)",
                  style="Sub.TLabel", foreground="#b388ff",
                  font=("Segoe UI", 9, "bold")).grid(
                      row=1, column=2, sticky="w", padx=(0, 8))
        ttk.Label(lanes_frame, text="",
                  style="Sub.TLabel").grid(row=1, column=3, padx=(0, 4))
        ttk.Label(lanes_frame, text="",
                  style="Sub.TLabel").grid(row=1, column=4, padx=(0, 4))

        # One row per non-Open-Hi-Hat lane (Open Hi-Hat is a virtual variant
        # that piggy-backs on Hi-Hat's mapping with pedal state — owner can
        # toggle the open-hat lane below, but it's not directly learnable
        # as a separate physical pad here.)
        lane_names_for_dialog = [
            "Hi-Hat", "Crash", "Snare",
            "Tom 1", "Tom 2", "Tom 3", "Ride", "Kick"]

        indicator_canvases = {}
        status_vars_per_lane = {}

        for i, lane_name in enumerate(lane_names_for_dialog):
            row_i = 2 + i
            lane_entry = next(
                (l for l in self.VIZ_LANES if l["name"] == lane_name), None)
            lane_color = lane_entry["color"] if lane_entry else "#888"

            # Lane name + small color swatch
            name_row = ttk.Frame(lanes_frame)
            name_row.grid(row=row_i, column=0, sticky="w", padx=(0, 8),
                          pady=2)
            sw = tk.Canvas(name_row, width=14, height=14,
                           bg=APP_BG, highlightthickness=0)
            sw.create_rectangle(2, 2, 12, 12, fill=lane_color,
                                outline=lane_color)
            sw.pack(side=tk.LEFT, padx=(0, 6))
            ttk.Label(name_row, text=lane_name,
                      font=("Segoe UI", 9, "bold"),
                      foreground="#e0e0e0").pack(side=tk.LEFT)

            # Live hit indicator canvas (pulses on matching note_on)
            hit_canvas = tk.Canvas(lanes_frame, width=40, height=20,
                                   bg=APP_BG, highlightthickness=0)
            hit_canvas.create_rectangle(
                2, 2, 38, 18, fill="#1a1a2e",
                outline=lane_color, width=1, tags="hit_bg")
            hit_canvas.grid(row=row_i, column=1, sticky="w",
                            padx=(0, 8), pady=2)
            indicator_canvases[lane_name] = hit_canvas

            # Current mapping (effective: override OR default)
            current_notes = self._midi_get_lane_notes(lane_name)
            notes_var = tk.StringVar(
                value=", ".join(str(n) for n in current_notes)
                if current_notes else "(unmapped)")
            ttk.Label(lanes_frame, textvariable=notes_var,
                      style="Sub.TLabel", foreground="#c0c0d0",
                      font=("Consolas", 9)).grid(
                          row=row_i, column=2, sticky="w",
                          padx=(0, 8), pady=2)
            status_vars_per_lane[lane_name] = notes_var

            def _arm_learn(target=lane_name, var=notes_var):
                self._midi_learn_target_lane = target
                var.set("Hit a pad on your kit...")

            def _reset_lane(target=lane_name, var=notes_var):
                overrides = getattr(self, "_midi_user_lane_overrides", None)
                if overrides and target in overrides:
                    overrides.pop(target, None)
                    self._midi_save_lane_overrides()
                # Refresh display from defaults
                defaults = list(
                    self.VIZ_LANES_MIDI_IN.get(target, []))
                var.set(", ".join(str(n) for n in defaults)
                        if defaults else "(unmapped)")
                # If this lane was the learn target, clear it
                if self._midi_learn_target_lane == target:
                    self._midi_learn_target_lane = None

            ttk.Button(lanes_frame, text="🎯  Learn",
                       width=10,
                       command=_arm_learn).grid(
                           row=row_i, column=3, padx=(0, 4), pady=2)
            ttk.Button(lanes_frame, text="↺",
                       width=3,
                       command=_reset_lane).grid(
                           row=row_i, column=4, padx=(0, 0), pady=2)

        # Register the indicator canvases + status vars on self so
        # `_handle_midi_message` can pulse them and `_midi_apply_learn_capture`
        # can refresh the displayed note text.
        self._midi_dialog_lane_indicators = indicator_canvases
        self._midi_dialog_learn_status_vars = status_vars_per_lane

        # ── Toggles ───────────────────────────────────────────────────────
        toggles_frame = ttk.LabelFrame(outer, text=" Options ", padding=8)
        toggles_frame.grid(row=_row_offset + 2, column=0, columnspan=4,
                           sticky="ew", pady=(0, 10))

        open_var = tk.BooleanVar(value=self._settings_get(
            "midi_input.editor_open_hihat_lane", False))
        multi_var = tk.BooleanVar(value=self._settings_get(
            "midi_input.multi_source", True))

        ttk.Checkbutton(
            toggles_frame,
            text="Show Open Hi-Hat as a separate lane (uses pedal state if available)",
            variable=open_var,
            command=lambda: self._midi_on_open_hihat_toggle(open_var.get())
        ).pack(anchor="w", pady=(0, 4))
        ttk.Checkbutton(
            toggles_frame,
            text="Keep keyboard hotkeys active alongside MIDI device",
            variable=multi_var,
            command=lambda: self._settings_set(
                "midi_input.multi_source", bool(multi_var.get()))
        ).pack(anchor="w")

        # ── Test area (last 5 MIDI messages) ──────────────────────────────
        offset_row = ttk.Frame(toggles_frame)
        offset_row.pack(anchor="w", fill=tk.X, pady=(8, 0))
        ttk.Label(offset_row, text="MIDI input offset (-50ms to +50ms):").pack(
            side=tk.LEFT, padx=(0, 6))
        offset_value_var = tk.StringVar(
            value=f"{float(self._midi_input_offset_ms.get()):+.0f} ms")

        def _offset_changed(_value=None):
            try:
                v = float(self._midi_input_offset_ms.get())
            except Exception:
                v = 0.0
            offset_value_var.set(f"{v:+.0f} ms")

        ttk.Scale(offset_row, from_=-50.0, to=50.0, length=180,
                  variable=self._midi_input_offset_ms,
                  command=_offset_changed).pack(side=tk.LEFT, padx=(0, 6))
        ttk.Label(offset_row, textvariable=offset_value_var,
                  width=8, style="Sub.TLabel").pack(side=tk.LEFT)
        ttk.Label(
            toggles_frame,
            text=("If recorded hits land late, move this left. If they land "
                  "early, move this right."),
            style="Sub.TLabel", foreground="#888888",
            wraplength=600, justify=tk.LEFT).pack(anchor="w", pady=(2, 0))

        ttk.Label(outer, text="Live MIDI Test Log (last 5 messages):",
                  style="Sub.TLabel").grid(
                      row=_row_offset + 3, column=0, columnspan=4,
                      sticky="w", pady=(4, 2))
        test = scrolledtext.ScrolledText(outer, height=6, width=68,
                                         bg=LOG_BG, fg="#d7e7ff",
                                         insertbackground="#d7e7ff",
                                         font=("Consolas", 9))
        test.grid(row=_row_offset + 4, column=0, columnspan=4, sticky="ew")
        try:
            test.insert(tk.END, "\n".join(self._midi_last_messages))
        except Exception:
            pass
        test.configure(state="disabled")
        self._midi_test_text = test

        # ── Device-select handler ─────────────────────────────────────────
        def _select_device(_event=None):
            if not _MIDI_INPUT_AVAILABLE:
                return
            name = device_var.get()
            if name == none_label:
                self._midi_close()
                self._midi_device_name = None
                self._settings_set("midi_input.device_name", "")
                _set_status_for(none_label)
                return
            if self._midi_open(name):
                _set_status_for(name)

        combo.bind("<<ComboboxSelected>>", _select_device)

        # ── Bottom action row ─────────────────────────────────────────────
        btn_row = ttk.Frame(outer)
        btn_row.grid(row=_row_offset + 5, column=0, columnspan=4,
                     sticky="ew", pady=(10, 0))

        def _reset_all_overrides():
            confirmed = messagebox.askyesno(
                "Reset All Mappings",
                "Reset every lane back to its default MIDI mapping?\n\n"
                "This clears all Learn-mode customizations.",
                parent=dlg)
            if not confirmed:
                return
            self._midi_user_lane_overrides = {}
            self._midi_save_lane_overrides()
            self._midi_learn_target_lane = None
            # Refresh every lane's display
            for ln_name, var in status_vars_per_lane.items():
                defaults = list(self.VIZ_LANES_MIDI_IN.get(ln_name, []))
                var.set(", ".join(str(n) for n in defaults)
                        if defaults else "(unmapped)")

        ttk.Button(btn_row, text="↺  Reset All Mappings",
                   command=_reset_all_overrides).pack(side=tk.LEFT)

        def _close():
            # Clear dialog-only references so the indicator-pulse code in
            # _handle_midi_message stops trying to update destroyed widgets.
            if self._midi_test_text is test:
                self._midi_test_text = None
            self._midi_dialog_lane_indicators = None
            self._midi_dialog_learn_status_vars = None
            self._midi_learn_target_lane = None
            dlg.destroy()

        ttk.Button(btn_row, text="Close",
                   command=_close).pack(side=tk.RIGHT)
        dlg.protocol("WM_DELETE_WINDOW", _close)

    def _build_visualizer_tab(self, parent):
        """Tab 9 — falling notes track preview, matching Paradiddle in-game appearance."""
        main = ttk.Frame(parent, padding=10)
        main.pack(fill=tk.BOTH, expand=True)
        main.rowconfigure(3, weight=1)  # canvas row expands
        main.columnconfigure(0, weight=1)

        # ── Header ────────────────────────────────────────────────────────────
        hdr = ttk.Frame(main)
        hdr.grid(row=0, column=0, sticky="ew", pady=(0, 6))
        ttk.Label(hdr, text="🥁  Preview/Practice Track",
                  style="Header.TLabel").pack(anchor="w")
        ttk.Label(hdr,
                  text="Watch your chart and practice hitting notes in time — "
                       "notes fall vertically into their lanes in real time with your audio.",
                  style="Sub.TLabel").pack(anchor="w")

        # ── File / settings panel ─────────────────────────────────────────────
        top_frame = ttk.Frame(main)
        top_frame.grid(row=1, column=0, sticky="ew", pady=(0, 4))
        top_frame.columnconfigure(1, weight=1)

        def frow(label, var, row, filetypes, config_key=None):
            """Build one file-picker row. Returns (entry, browse_btn,
            recent_btn, clear_btn, label_widget) so callers that need to
            disable/enable a row in response to other state changes (e.g.
            v4.4.57.6-6 .rlrr-overrides-MIDI lock) can do so.
            """
            row_label = ttk.Label(top_frame, text=label, width=16)
            row_label.grid(row=row, column=0, sticky="w", padx=(0, 8), pady=2)
            ent = ttk.Entry(top_frame, textvariable=var)
            ent.grid(row=row, column=1, sticky="ew", padx=(0, 4), pady=2)
            self._enable_drop(ent, var, config_key=config_key)
            btn_f = ttk.Frame(top_frame)
            btn_f.grid(row=row, column=2, pady=2)
            browse_btn = ttk.Button(btn_f, text="Browse...",
                       command=lambda v=var, ft=filetypes, ck=config_key:
                               self._viz_browse(v, ft, ck))
            browse_btn.pack(side=tk.LEFT)
            recent_btn = None
            if config_key:
                recent_btn = self._make_recent_btn(btn_f, config_key, var, filetypes)
                recent_btn.pack(side=tk.LEFT, padx=(2, 0))
            clear_btn = ttk.Button(btn_f, text="✕",
                       command=lambda v=var: v.set(""),
                       width=2)
            clear_btn.pack(side=tk.LEFT, padx=(4, 0))
            return (ent, browse_btn, recent_btn, clear_btn, row_label)

        self.viz_midi_var      = tk.StringVar()
        self.viz_audio_var     = tk.StringVar()
        self.viz_drum_var      = tk.StringVar()
        self.viz_offset_var    = tk.StringVar(value="0.000")
        # v4.4.57.3-6 — Optional .rlrr override (Option C). Lets the user
        # point at a Paradiddle .rlrr file for authoritative timing when the
        # loaded MIDI was extracted with the buggy pre-v4.2.13 extractor.
        # Empty by default; Option B (sibling autodetect) handles the
        # common case automatically. See _viz_load_notes for the priority
        # logic (override > sibling > MIDI fallback).
        self.viz_rlrr_override_var = tk.StringVar()

        # v4.4.57.6-6 — Capture MIDI row widgets so we can gray them out
        # when an .rlrr override is active. .rlrr ALWAYS wins for downloaded
        # / third-party charts because the MIDI's tick positions can't
        # reliably represent the song's actual tempo map; the .rlrr stores
        # authoritative times in seconds. Disabling the MIDI field while a
        # .rlrr is loaded makes that priority explicit in the UI.
        self._viz_midi_row_widgets = frow(
            "MIDI File:", self.viz_midi_var, 0,
            [("MIDI","*.mid *.midi"),("All","*.*")], "recent_viz_midi")
        frow("Full Mix Audio:",  self.viz_audio_var, 1,
             [("Audio","*.ogg *.wav *.flac *.mp3"),("All","*.*")], "recent_viz_audio")
        frow("Drum Audio:",      self.viz_drum_var,  2,
             [("Audio","*.ogg *.wav *.flac *.mp3"),("All","*.*")], "recent_viz_drum")
        frow("Source .rlrr:",  self.viz_rlrr_override_var,  3,
             [(".rlrr","*.rlrr"),("All","*.*")], "recent_viz_rlrr")

        # Inline lock note next to MIDI row (hidden until .rlrr is active)
        self._viz_midi_lock_note = ttk.Label(
            top_frame,
            text=".rlrr selected — clear .rlrr file to change to a different MIDI",
            style="Sub.TLabel", foreground="#e09a3a",
            wraplength=420, justify=tk.LEFT)
        self._viz_midi_lock_note.grid(
            row=0, column=3, sticky="w", padx=(8, 0))
        self._viz_midi_lock_note.grid_remove()  # hidden by default

        def _update_midi_lock_state(*_args):
            """Gray out the MIDI row when an .rlrr override is loaded.
            Re-enables when the .rlrr field is cleared.
            """
            rlrr_path = ""
            try:
                rlrr_path = self.viz_rlrr_override_var.get().strip()
            except Exception:
                pass
            rlrr_active = bool(rlrr_path) and os.path.exists(rlrr_path)
            new_state = "disabled" if rlrr_active else "normal"
            for w in self._viz_midi_row_widgets:
                if w is None:
                    continue
                try:
                    # ttk widgets use state() method; tk widgets use configure
                    if hasattr(w, "state") and isinstance(w, ttk.Widget):
                        w.state(["disabled"] if rlrr_active else ["!disabled"])
                    else:
                        w.configure(state=new_state)
                except Exception:
                    pass
            if rlrr_active:
                self._viz_midi_lock_note.grid()
            else:
                self._viz_midi_lock_note.grid_remove()

        self.viz_rlrr_override_var.trace_add("write", _update_midi_lock_state)

        # Auto-load notes whenever MIDI path changes
        def _on_source_change(*args):
            midi = self.viz_midi_var.get().strip()
            if midi and os.path.exists(midi):
                self._viz_notes = []
                self._viz_load_notes()
                self._viz_redraw_static()

        self.viz_midi_var.trace_add("write", _on_source_change)

        def _viz_clear_all():
            self.viz_midi_var.set("")
            self.viz_audio_var.set("")
            self.viz_drum_var.set("")
            self.viz_offset_var.set("0.000")
            self._viz_notes = []
            self._viz_stop()

        clear_row = ttk.Frame(top_frame)
        clear_row.grid(row=4, column=0, columnspan=3, sticky="w", pady=(2, 0))
        ttk.Button(clear_row, text="🗑  Clear All Fields",
                   command=_viz_clear_all).pack(side=tk.LEFT)
        ttk.Button(clear_row, text="↺  Reload Notes",
                   command=lambda: [self._viz_load_notes(),
                                    self._viz_redraw_static()]
                   ).pack(side=tk.LEFT, padx=(8, 0))
        # Auto Fetch Audio (2026-06-25, owner) — between Reload Notes and Apply Offset;
        # plain button (matches its row neighbors) with the 🎵 now-playing icon.
        _viz_af_btn = ttk.Button(clear_row, text="🎵  Auto Fetch Audio",
                                 command=self._viz_auto_fetch_audio)
        _viz_af_btn.pack(side=tk.LEFT, padx=(8, 0))
        self._add_tooltip(
            _viz_af_btn,
            "From the MIDI File's name (or the .rlrr), finds the matching Full Mix +\n"
            "Drum Audio (from your Stem Splitter / YouTube output folders and next to\n"
            "the MIDI) and fills those fields. Same as the MIDI Editor's Auto Fetch.")
        ttk.Button(clear_row, text="✓  Apply Offset",
                   command=self._viz_redraw_static
                   ).pack(side=tk.LEFT, padx=(8, 0))
        ttk.Label(clear_row,
                  text="  ← after manually editing offset or using ↺ Reload",
                  style="Sub.TLabel").pack(side=tk.LEFT, padx=(4, 0))

        ttk.Label(top_frame,
                  text="ℹ  Button guide:  "
                       "↺ Reload Notes — re-reads the MIDI and refreshes the canvas.  "
                       "✓ Apply Offset — redraws the canvas using your current offset value "
                       "without reloading the file.",
                  style="Sub.TLabel", foreground="#888888",
                  wraplength=900, justify=tk.LEFT).grid(
                  row=5, column=0, columnspan=3, sticky="w", pady=(4, 2))

        ttk.Label(top_frame,
                  text="💡  Load a MIDI file to preview your chart. "
                       "Load Drum Audio and/or Full Mix Audio to enable playback and toggling between tracks.",
                  style="Sub.TLabel", foreground="#b388ff",
                  wraplength=800, justify=tk.LEFT).grid(
                  row=6, column=0, columnspan=3, sticky="w", pady=(2, 2))

        ttk.Label(top_frame,
                  text="ℹ  If your song has a drum-free intro, the canvas will be empty for those "
                       "first few seconds while the audio plays — this is normal and correct. "
                       "The preview is synced to the full audio from the start, just like in game. "
                       "In Paradiddle itself the song starts from the beginning of the audio as usual.",
                  style="Sub.TLabel", foreground="#888",
                  wraplength=900, justify=tk.LEFT).grid(
                  row=7, column=0, columnspan=3, sticky="w", pady=(0, 4))

        # Offset / speed row — visual settings moved to right panel
        bpm_row = ttk.Frame(top_frame)
        bpm_row.grid(row=8, column=0, columnspan=3, sticky="w", pady=(4, 2))
        ttk.Label(bpm_row, text="Offset (s):").pack(side=tk.LEFT, padx=(0, 4))
        ttk.Entry(bpm_row, textvariable=self.viz_offset_var, width=10).pack(
            side=tk.LEFT, padx=(0, 8))
        ttk.Label(bpm_row,
                  text="Use offset if notes appear consistently early or late against the audio.",
                  style="Sub.TLabel").pack(side=tk.LEFT, padx=(0, 16))
        # Variable defs needed before right panel is built
        self.viz_kick_line_var  = tk.BooleanVar(value=True)
        self.viz_square_notes_var = tk.BooleanVar(value=False)
        self.viz_note_size_var  = tk.DoubleVar(value=0.8)
        self.viz_grid_var       = tk.BooleanVar(value=True)
        # v4.4.18 — Speed slider removed per owner request 2026-05-10. The
        # slider's time-stretch path was causing timing issues in the
        # Preview/Practice playback. Zoom + note-fall-time controls cover
        # the practice-pacing use case the speed slider was added for in
        # v4.3.5. Backend time-stretch plumbing (`_viz_prepare_stretched_audio`,
        # `_viz_speed`, etc.) left intact and defensive — downstream
        # `getattr(self, "viz_speed_var", default)` calls fall back to 1.0
        # so the time-stretch code path becomes a no-op. Dead-code cleanup of
        # the now-orphan time-stretch helpers deferred to a future polish ship.

        # Playback controls row
        ctrl_row = ttk.Frame(top_frame)
        ctrl_row.grid(row=9, column=0, columnspan=3, sticky="w", pady=(4, 2))

        self.viz_play_btn = ttk.Button(ctrl_row, text="▶  Play",
                                       command=self._viz_play)
        self.viz_play_btn.pack(side=tk.LEFT, padx=(0, 4))
        ttk.Button(ctrl_row, text="⏹  Stop",
                   command=self._viz_stop).pack(side=tk.LEFT, padx=(0, 12))

        self.viz_pos_var = tk.StringVar(value="00:00.0")
        ttk.Label(ctrl_row, textvariable=self.viz_pos_var,
                  foreground="#00d4d4",
                  font=("Consolas", 9)).pack(side=tk.LEFT, padx=(0, 12))

        # Audio track toggle
        self.viz_audio_track_var = tk.StringVar(value="mix")
        self.viz_toggle_btn = ttk.Button(
            ctrl_row,
            text="🎵  Now playing: Full Mix  →  switch to Drums",
            command=self._viz_toggle_audio)
        self.viz_toggle_btn.pack(side=tk.LEFT, padx=(0, 12))

        self.viz_flash_var = tk.BooleanVar(value=True)  # widget in right panel

        # Zoom row
        zoom_row = ttk.Frame(top_frame)
        zoom_row.grid(row=10, column=0, columnspan=3, sticky="w", pady=(2, 4))
        ttk.Label(zoom_row, text="Zoom (note fall time):").pack(side=tk.LEFT, padx=(0, 4))
        # v4.4.25 — default note fall time 8.0s → 2.5s per owner ask. Slider
        # range stays 0.5-15.0s; users can dial back up if they prefer.
        self.viz_fall_var = tk.DoubleVar(value=2.5)
        _vzf_sf = ttk.Frame(zoom_row)
        ttk.Scale(_vzf_sf, from_=0.5, to=15.0, variable=self.viz_fall_var,
                  orient="horizontal", length=200).pack(side=tk.TOP, anchor="w")
        _tick_strip(_vzf_sf, 200)
        _vzf_sf.pack(side=tk.LEFT, padx=(0, 4))
        self.viz_fall_lbl = ttk.Label(zoom_row, text="8.0s", width=5)
        self.viz_fall_lbl.pack(side=tk.LEFT)
        self.viz_fall_var.trace_add("write",
            lambda *a: self.viz_fall_lbl.configure(
                text=f"{self.viz_fall_var.get():.1f}s"))
        ttk.Label(zoom_row,
                  text="  Higher = more notes visible (zoomed out).  Lower = fewer notes, larger (zoomed in).",
                  style="Sub.TLabel").pack(side=tk.LEFT)

        # Loop row
        loop_row = ttk.Frame(top_frame)
        loop_row.grid(row=11, column=0, columnspan=3, sticky="w", pady=(0, 2))
        self._viz_loop_on  = tk.BooleanVar(value=False)
        self._viz_loop_in  = 0.0
        self._viz_loop_out = 0.0
        ttk.Checkbutton(loop_row, text="🔁  Loop",
                        variable=self._viz_loop_on).pack(side=tk.LEFT, padx=(0, 8))
        self.viz_loop_in_lbl = ttk.Label(loop_row, text="Start: --:--",
                                          font=("Consolas", 9), foreground="#ffd700")
        self.viz_loop_in_lbl.pack(side=tk.LEFT, padx=(0, 4))
        ttk.Button(loop_row, text="Set Start", width=9,
                   command=self._viz_loop_set_in).pack(side=tk.LEFT, padx=(0, 6))
        self.viz_loop_out_lbl = ttk.Label(loop_row, text="End: --:--",
                                           font=("Consolas", 9), foreground="#ffd700")
        self.viz_loop_out_lbl.pack(side=tk.LEFT, padx=(0, 4))
        ttk.Button(loop_row, text="Set End", width=8,
                   command=self._viz_loop_set_out).pack(side=tk.LEFT, padx=(0, 6))
        ttk.Button(loop_row, text="✕  Clear Loop", width=14,
                   command=self._viz_loop_clear).pack(side=tk.LEFT)
        ttk.Label(loop_row,
                  text="  Set start/end points then enable Loop to repeat a section",
                  style="Sub.TLabel").pack(side=tk.LEFT, padx=(8, 0))

        # Scrubber row
        scrub_row = ttk.Frame(top_frame)
        scrub_row.grid(row=12, column=0, columnspan=3, sticky="ew", pady=(0, 4))
        scrub_row.columnconfigure(1, weight=1)
        ttk.Label(scrub_row, text="00:00", font=("Consolas", 8),
                  foreground="#888").pack(side=tk.LEFT, padx=(0, 4))
        self.viz_scrub_var = tk.DoubleVar(value=0.0)
        self._viz_scrub_dragging = False

        self.viz_scrubber = ttk.Scale(scrub_row, from_=0.0, to=300.0,
                                      variable=self.viz_scrub_var,
                                      orient="horizontal")
        self.viz_scrubber.pack(side=tk.LEFT, fill=tk.X, expand=True, padx=(0, 4))

        self.viz_scrub_end_lbl = ttk.Label(scrub_row, text="00:00",
                                            font=("Consolas", 8), foreground="#888")
        self.viz_scrub_end_lbl.pack(side=tk.LEFT)

        def _fmt_scrub(secs):
            m = int(secs // 60)
            s = int(secs % 60)
            return f"{m:02d}:{s:02d}"

        def _on_scrub_press(e):
            self._viz_scrub_dragging = True

        def _on_scrub_release(e):
            self._viz_scrub_dragging = False
            pos = self.viz_scrub_var.get()
            self._viz_seek(pos)

        self.viz_scrubber.bind("<ButtonPress-1>",   _on_scrub_press)
        self.viz_scrubber.bind("<ButtonRelease-1>", _on_scrub_release)

        # Update scrubber position during playback (called from _viz_tick)
        self._viz_scrub_fmt = _fmt_scrub

