        def _refresh_midi_status():
            try:
                if not _MIDI_INPUT_AVAILABLE or mido is None:
                    self.viz_midi_status_var.set(
                        "⚠  MIDI library not loaded")
                    try:
                        _status_lbl.configure(foreground="#e09a3a")
                    except Exception:
                        pass
                elif self._midi_port is None:
                    self.viz_midi_status_var.set(
                        "No device connected.\n"
                        "Plug in a USB MIDI drum kit and open\n"
                        "MIDI Controls below to select it.")
                    try:
                        _status_lbl.configure(foreground="#888888")
                    except Exception:
                        pass
                else:
                    dev = self._midi_device_name or "(unknown)"
                    prof = getattr(self, "_midi_active_profile", None)
                    prof_name = (prof.get("display_name")
                                  if isinstance(prof, dict) else None)
                    if prof_name:
                        self.viz_midi_status_var.set(
                            f"✓  Connected: {dev}\nProfile: {prof_name}")
                    else:
                        self.viz_midi_status_var.set(
                            f"✓  Connected: {dev}\nGM defaults in use")
                    try:
                        _status_lbl.configure(foreground="#00d4d4")
                    except Exception:
                        pass
            except Exception:
                pass
            # Re-schedule
            try:
                self.root.after(1500, _refresh_midi_status)
            except Exception:
                pass

