    def _build_batch_tab(self, parent):
        """Batch conversion UI — 3 independent song slots."""
        canvas = tk.Canvas(parent, bg=APP_BG, highlightthickness=0)
        self._tab3_canvas = canvas
        sb = ttk.Scrollbar(parent, orient="vertical", command=canvas.yview)
        canvas.configure(yscrollcommand=sb.set)
        sb.pack(side=tk.RIGHT, fill=tk.Y)
        canvas.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        main = ttk.Frame(canvas, padding=20)
        win = canvas.create_window((0, 0), window=main, anchor="nw")
        main.bind("<Configure>",   lambda e: canvas.configure(
            scrollregion=(0, 0, *(canvas.bbox("all")[2:] or [800, 600]))))
        canvas.bind("<Configure>", lambda e: canvas.itemconfig(win, width=e.width))

        ttk.Label(main, text="\U0001f3b6  Create Multiple Songs", style="Header.TLabel").pack(anchor="w")
        ttk.Label(main, text="Fill up to 3 song slots and convert them all at once.",
                  style="Sub.TLabel").pack(anchor="w", pady=(2, 2))

        ttk.Label(main,
                  text="ℹ  Each song folder the program creates will have its slot number (1, 2, or 3)\n"
                       "   added to the end of its name (e.g. 'MySong1', 'MySong2', 'MySong3').\n"
                       "   Your chosen output folder is NOT renamed — only the folders created inside it.\n"
                       "   You can safely rename those created folders and remove the number before\n"
                       "   transferring to Paradiddle — it won't cause any issues.\n\n"
                       "\U0001f4a1  You can use all 3 slots for the same song at different difficulties\n"
                       "   to generate Easy, Medium, and Hard versions all in one go.",
                  style="Sub.TLabel", foreground="#b388ff",
                  justify=tk.LEFT).pack(anchor="w", pady=(0, 10))

        shared_frame = ttk.LabelFrame(main, text=" Shared Settings ", padding=10)
        shared_frame.pack(fill=tk.X, pady=(0, 10))
        ttk.Label(shared_frame, text="Creator:").grid(row=0, column=0, sticky="w", padx=(0,5))
        self.batch_creator_var = tk.StringVar(value="ParaKit")
        ttk.Entry(shared_frame, textvariable=self.batch_creator_var, width=35
                  ).grid(row=0, column=1, sticky="w")
        ttk.Label(shared_frame, text="Output Folder:").grid(row=1, column=0, sticky="w",
                                                             padx=(0,5), pady=(6,0))
        self.batch_output_var = tk.StringVar()
        _cfg = load_config()
        if _cfg.get("output_folder_batch") and os.path.isdir(_cfg["output_folder_batch"]):
            self.batch_output_var.set(_cfg["output_folder_batch"])
        batch_out_ent = ttk.Entry(shared_frame, textvariable=self.batch_output_var, width=45)
        batch_out_ent.grid(row=1, column=1, sticky="ew", padx=(0,5), pady=(6,0))
        batch_out_btn = ttk.Button(shared_frame, text="Browse...", command=self._batch_browse_output)
        batch_out_btn.grid(row=1, column=2, pady=(6,0))
        ttk.Button(shared_frame, text="✕", width=2,
                   command=lambda: self.batch_output_var.set("")).grid(row=1, column=3, padx=(4,0), pady=(6,0))
        shared_frame.columnconfigure(1, weight=1)
        for w in (batch_out_ent, batch_out_btn):
            self._enable_folder_drop(w, self.batch_output_var)
        shared_frame.columnconfigure(1, weight=1)

        self._batch_slots = []
        for slot_num in range(1, 4):
            self._build_batch_slot(main, slot_num)

        # Pre-flight button (Phase 1 of v4.3.0). Auto-runs on Convert too.
        ttk.Button(main, text="🔍  Check for Issues (All Enabled Songs)",
                   command=self._pfv_run_batch_button
                   ).pack(fill=tk.X, pady=(10, 4), ipady=4)

        self.batch_convert_btn = ttk.Button(
            main, text="\U0001f3b6  Convert All Songs", style="Convert.TButton",
            command=self._batch_start_convert)
        self.batch_convert_btn.pack(fill=tk.X, pady=(0, 8), ipady=8)

        # Progress bar (v4.4.7) — indeterminate animation while batch runs.
        self.batch_progress = _G85AltSnareProgressBar(main, mode="indeterminate", width=400, height=30)
        self.batch_progress.pack(fill=tk.X, pady=(0, 2))

        blog_frame = ttk.LabelFrame(main, text=" Log ", padding=5)
        blog_frame.pack(fill=tk.BOTH, expand=True)
        blog_btn_row = ttk.Frame(blog_frame)
        blog_btn_row.pack(fill=tk.X, pady=(0,4))
        ttk.Button(blog_btn_row, text="📄  Export Log",
                   command=lambda: self._export_log(
                       self.batch_log_text, "batch_creator_log.txt", "Create Multiple Songs")
                   ).pack(side=tk.LEFT)
        ttk.Button(blog_btn_row, text="\U0001f4c2  Open Output Folder",
                   command=self._batch_open_output).pack(side=tk.RIGHT)
        self.batch_log_text = scrolledtext.ScrolledText(
            blog_frame, height=8, bg="#0d1117", fg="#58a6ff",
            font=("Consolas", 9), wrap=tk.WORD,
            insertbackground="#58a6ff", state="disabled")
        self.batch_log_text.pack(fill=tk.BOTH, expand=True)

        # ── Folder Batch section (Phase 2 of v4.3.0) ─────────────────────────
        ttk.Separator(main, orient="horizontal").pack(fill=tk.X, pady=(14, 0))
        self._build_batch_folder_section(main)

    def _build_batch_slot(self, parent, slot_num):
        """Build one song slot with all required fields."""
        slot = {
            "midi_var":     tk.StringVar(),
            "audio_var":    tk.StringVar(),
            "drum_var":     tk.StringVar(),
            "cover_var":    tk.StringVar(),
            "title_var":    tk.StringVar(value="Untitled"),
            "artist_var":   tk.StringVar(value="Unknown"),
            "diff_var":     tk.StringVar(value="Expert"),
            "comp_var":     tk.IntVar(value=3),
            "auto_bpm_var": tk.BooleanVar(value=True),
            "bpm_var":      tk.StringVar(),
            "offset_var":   tk.StringVar(),
            "reduce_var":   tk.BooleanVar(value=False),
            "enabled_var":  tk.BooleanVar(value=(slot_num == 1)),
            "use_metadata_art_var": tk.BooleanVar(value=False),
            "meta_art_status_var":  tk.StringVar(value=""),
            "_metadata_art_temp_path": None,
        }
        self._batch_slots.append(slot)

        frame = ttk.LabelFrame(parent, text=f" Song {slot_num} ", padding=10)
        frame.pack(fill=tk.X, pady=(0, 8))

        ttk.Checkbutton(frame, text=f"Enable Song {slot_num}",
                        variable=slot["enabled_var"]
                        ).grid(row=0, column=0, columnspan=3, sticky="w", pady=(0, 6))

        def frow(lbl, var, row, ft, ck=None, s=slot):
            ttk.Label(frame, text=f"{lbl}:").grid(row=row, column=0, sticky="w", padx=(0,5), pady=2)
            ent = ttk.Entry(frame, textvariable=var, width=42)
            ent.grid(row=row, column=1, sticky="ew", padx=(0,5), pady=2)
            btn_frame = ttk.Frame(frame)
            btn_frame.grid(row=row, column=2, pady=2, sticky="w")
            btn = ttk.Button(btn_frame, text="Browse...",
                             command=lambda v=var, f=ft, sl=s: self._batch_slot_browse(v, f, sl))
            btn.pack(side=tk.LEFT)
            if ck:
                self._make_recent_btn(btn_frame, ck, var, ft
                                      ).pack(side=tk.LEFT, padx=(2,0))
            for w in (ent, btn):
                self._enable_drop(w, var, config_key=ck)

        frow("MIDI File *",  slot["midi_var"],  1, [("MIDI","*.mid *.midi"),("All","*.*")],       ck="recent_midi")
        frow("Song Audio *", slot["audio_var"], 2, [("Audio","*.ogg *.mp3 *.wav *.flac"),("All","*.*")], ck="recent_audio")
        frow("Drum Audio",   slot["drum_var"],  3, [("Audio","*.ogg *.mp3 *.wav *.flac"),("All","*.*")], ck="recent_drum_audio")

        # ── Extra Stems ───────────────────────────────────────────────────────
        slot["extra_stems"] = []
        _bso = ttk.Frame(frame)
        _bso.grid(row=4, column=0, columnspan=3, sticky="ew", pady=(2, 2))
        _bso.columnconfigure(0, weight=1)

        def _bupd(s=slot, btn=None):
            if btn:
                btn.configure(state="normal" if len(s["extra_stems"]) < 4 else "disabled")

        def _badd(s=slot, container=_bso):
            if len(s["extra_stems"]) >= 4:
                return
            idx = len(s["extra_stems"]) + 1
            var = tk.StringVar()
            is_song_var = tk.BooleanVar(value=False)
            is_drum_var = tk.BooleanVar(value=True)
            row_f = ttk.Frame(container)
            row_f.pack(fill="x", pady=1)
            ttk.Label(row_f, text=f"Extra Stem {idx}:", width=14,
                      anchor="w").pack(side=tk.LEFT, padx=(0, 4))
            ent = ttk.Entry(row_f, textvariable=var, width=26)
            ent.pack(side=tk.LEFT, padx=(0, 4), fill="x", expand=True)
            ttk.Button(row_f, text="Browse…",
                       command=lambda v=var, sl=s: self._batch_slot_browse(
                           v, [("Audio files", "*.ogg *.mp3 *.wav *.flac"),
                               ("All files", "*.*")], sl)
                       ).pack(side=tk.LEFT, padx=(0, 4))
            ttk.Checkbutton(row_f, text="Drum audio", variable=is_drum_var,
                            command=lambda isd=is_drum_var, iss=is_song_var: (
                                isd.set(True), iss.set(False))
                            ).pack(side=tk.LEFT, padx=(0, 2))
            ttk.Checkbutton(row_f, text="Song audio", variable=is_song_var,
                            command=lambda isd=is_drum_var, iss=is_song_var: (
                                isd.set(False), iss.set(True))
                            ).pack(side=tk.LEFT, padx=(0, 4))
            sd = {"var": var, "is_song_var": is_song_var, "frame": row_f}
            s["extra_stems"].append(sd)

            def _brem(sdd=sd, sl=s):
                sdd["frame"].destroy()
                sl["extra_stems"].remove(sdd)
                _bupd(sl, _b_add_btn)

            ttk.Button(row_f, text="✕", width=2, command=_brem).pack(side=tk.LEFT)
            self._enable_drop(ent, var)
            _bupd(s, _b_add_btn)

        _b_add_btn = ttk.Button(_bso, text="➕  Add more stem options", command=_badd)
        _b_add_btn.pack(anchor="w", pady=(0, 2))

        frow("Cover Image",  slot["cover_var"], 5, [("Images","*.jpg *.jpeg *.png"),("All","*.*")],  ck="recent_cover")
        frame.columnconfigure(1, weight=1)

        ttk.Label(frame, text="Title *:").grid(row=6, column=0, sticky="w", padx=(0,5), pady=2)
        ttk.Entry(frame, textvariable=slot["title_var"], width=42
                  ).grid(row=6, column=1, columnspan=2, sticky="ew", pady=2)
        ttk.Label(frame, text="Artist *:").grid(row=7, column=0, sticky="w", padx=(0,5), pady=2)
        ttk.Entry(frame, textvariable=slot["artist_var"], width=42
                  ).grid(row=7, column=1, columnspan=2, sticky="ew", pady=2)

        dc_row = ttk.Frame(frame)
        dc_row.grid(row=8, column=0, columnspan=3, sticky="w", pady=4)
        ttk.Label(dc_row, text="Difficulty:").pack(side=tk.LEFT, padx=(0,5))
        ttk.Combobox(dc_row, textvariable=slot["diff_var"], width=10,
                     values=["Easy","Medium","Hard","Expert"],
                     state="readonly").pack(side=tk.LEFT, padx=(0,18))
        ttk.Label(dc_row, text="Complexity:").pack(side=tk.LEFT, padx=(0,5))
        ttk.Combobox(dc_row, textvariable=slot["comp_var"], width=5,
                     values=[1,2,3,4,5], state="readonly").pack(side=tk.LEFT, padx=(0,18))
        ttk.Checkbutton(dc_row, text="Enable note reduction",
                        variable=slot["reduce_var"]).pack(side=tk.LEFT)
        ttk.Label(dc_row,
                  text="(off = difficulty label only, no MIDI changes)",
                  style="Sub.TLabel").pack(side=tk.LEFT, padx=(6, 0))

        bpm_row = ttk.Frame(frame)
        bpm_row.grid(row=9, column=0, columnspan=3, sticky="w", pady=2)
        bpm_entry    = ttk.Entry(bpm_row, textvariable=slot["bpm_var"],    width=8, state="disabled")
        offset_entry = ttk.Entry(bpm_row, textvariable=slot["offset_var"], width=8, state="disabled")
        slot["bpm_entry"]    = bpm_entry
        slot["offset_entry"] = offset_entry

        def make_toggle(s=slot, be=bpm_entry, oe=offset_entry):
            def toggle():
                st = "disabled" if s["auto_bpm_var"].get() else "normal"
                be.configure(state=st)
                oe.configure(state=st)
            return toggle

        ttk.Checkbutton(bpm_row, text="Auto-detect BPM",
                        variable=slot["auto_bpm_var"],
                        command=make_toggle()).pack(side=tk.LEFT, padx=(0,14))
        ttk.Label(bpm_row, text="Manual BPM:").pack(side=tk.LEFT, padx=(0,5))
        bpm_entry.pack(side=tk.LEFT, padx=(0,14))
        ttk.Label(bpm_row, text="Offset (s):").pack(side=tk.LEFT, padx=(0,5))
        offset_entry.pack(side=tk.LEFT)

        # v4.5.6.2 — parity with the Single Song Creator: per-slot Auto Fetch
        # Audio + Album Art preview + Description. Appended at the bottom (rows
        # 10-11) so the existing slot grid above is untouched.
        extras = ttk.Frame(frame)
        extras.grid(row=10, column=0, columnspan=3, sticky="ew", pady=(6, 2))
        af_border = tk.Frame(extras, bg="#00e5ff", bd=0)   # cyan outline, app style
        af_border.pack(side=tk.LEFT, padx=(0, 12), anchor="n")
        ttk.Button(af_border, text="🎵  Auto Fetch Audio", width=21,
                   command=lambda s=slot: self._batch_auto_fetch_audio(s)
                   ).pack(padx=1, pady=1)

        art_box = tk.Frame(extras, width=80, height=80, bg="#17172d",
                           highlightthickness=1, highlightbackground="#2a2a44")
        art_box.pack_propagate(False)
        art_box.pack(side=tk.LEFT, padx=(0, 8))
        slot["cover_preview_label"] = tk.Label(art_box, bg="#17172d", fg="#555",
                                               text="No art")
        slot["cover_preview_label"].pack(expand=True)
        slot["cover_imgref"] = None
        slot["cover_caption_var"] = tk.StringVar(value="No art selected")
        ttk.Label(extras, textvariable=slot["cover_caption_var"],
                  style="Sub.TLabel").pack(side=tk.LEFT, anchor="s", pady=(0, 4))
        slot["cover_var"].trace_add(
            "write", lambda *_a, s=slot: self._batch_update_cover_preview(s))

        ttk.Label(frame, text="Description:").grid(
            row=11, column=0, sticky="nw", padx=(0, 5), pady=2)
        slot["desc_text"] = tk.Text(frame, height=2, width=42, wrap="word",
                                    bg="#0d1117", fg="#e0e0e0",
                                    insertbackground="#e0e0e0",
                                    selectbackground="#2a1235",
                                    relief="flat", bd=1, padx=6, pady=4)
        slot["desc_text"].grid(row=11, column=1, columnspan=2, sticky="ew", pady=2)
        self._add_tooltip(slot["desc_text"],
                          "Optional. Embedded in this song's .rlrr and shown on its\n"
                          "ParaDB page. Line breaks are saved as <br>.")

        # Per-slot "use album art from metadata" (parity with the Single Song
        # Creator). Uses the embedded art in Song Audio, else Drum Audio, else
        # the full mix located from this slot's MIDI name; writes album.png.
        ma_row = ttk.Frame(frame)
        ma_row.grid(row=12, column=0, columnspan=3, sticky="w", pady=(4, 0))
        ttk.Checkbutton(
            ma_row, text="🎨  Use album art from metadata",
            variable=slot["use_metadata_art_var"],
            command=lambda s=slot: self._batch_metadata_art_toggle(s)).pack(side=tk.LEFT)
        ttk.Label(ma_row, textvariable=slot["meta_art_status_var"],
                  style="Sub.TLabel", foreground="#888888",
                  wraplength=420).pack(side=tk.LEFT, padx=(8, 0))
        # Re-extract when this slot's audio/MIDI changes while the toggle is on.
        for _mk in ("audio_var", "drum_var", "midi_var"):
            slot[_mk].trace_add(
                "write",
                lambda *_a, s=slot: self._batch_refresh_metadata_art_if_active(s))

    # ── Batch helpers ─────────────────────────────────────────────────────────
    def _batch_auto_fetch_audio(self, slot):
        """Auto Fetch Audio for one batch slot — mirrors the Single Song Creator:
        from the slot's MIDI file name, fill Song Audio with the BACKING (no-drums)
        stem and Drum Audio with the drums stem, both preferring the .ogg copy (a
        full mix would double the drums in the compiled pack)."""
        midi_path = slot["midi_var"].get().strip()
        if not midi_path:
            messagebox.showinfo(
                "Auto Fetch Audio",
                "Pick this song's MIDI File first — Auto Fetch uses its file name "
                "to find the matching Song Audio and Drum Audio.")
            return
        drums, mix, used_recursive, song = self._find_song_audio_from_midi(
            midi_path, prefer_ogg=True, song_is_backing=True)
        if not song:
            messagebox.showinfo(
                "Auto Fetch Audio",
                "Couldn't read a song name from the MIDI file name.")
            return
        found = []
        if drums:
            slot["drum_var"].set(drums)
            self._add_recent_file("recent_drum_audio", drums)
            found.append("Drum Audio: " + os.path.basename(drums))
        if mix:
            slot["audio_var"].set(mix)
            self._add_recent_file("recent_audio", mix)
            found.append("Song Audio: " + os.path.basename(mix))
        self._auto_fetch_show_result(song, drums, mix, used_recursive, found,
                                     mix_label="Backing track",
                                     mix_pattern=f"{song}_backing.<ext>")

    # ── Per-slot "Use album art from metadata" (parity with the Single Song
    #    Creator; shares _pick_metadata_art_source + _save_metadata_art_png) ─────
    def _batch_metadata_art_toggle(self, slot):
        """Slot checkbox handler: extract on turn-ON; on turn-OFF blank the status
        and drop our temp cover if slot['cover_var'] still points at it."""
        v = slot.get("use_metadata_art_var")
        if v is None:
            return
        if v.get():
            self._batch_apply_metadata_art(slot)
        else:
            st = slot.get("meta_art_status_var")
            if st is not None:
                try: st.set("")
                except Exception: pass
            tmp = slot.get("_metadata_art_temp_path")
            if tmp and slot["cover_var"].get().strip() == tmp:
                slot["cover_var"].set("")
            if tmp and os.path.exists(tmp):
                try: os.unlink(tmp)
                except Exception: pass
            slot["_metadata_art_temp_path"] = None

    def _batch_refresh_metadata_art_if_active(self, slot):
        """Re-run a slot's extraction when its Song/Drum Audio or MIDI changes
        while that slot's metadata-art toggle is on (deferred so the var settles)."""
        v = slot.get("use_metadata_art_var")
        if v is not None and v.get():
            self.root.after(10, lambda s=slot: self._batch_apply_metadata_art(s))

    def _batch_apply_metadata_art(self, slot):
        """Create-Multiple-Songs equivalent of _apply_metadata_art, per slot:
        Song Audio → Drum Audio → the full mix located from the slot's MIDI name;
        crop to 512×512, save a temp PNG, point THIS slot's cover_var at it (which
        drives the slot's art preview + writes album.png in the export). The batch
        slot key for the drums field is 'drum_var'. Returns True/False."""
        def _v(key):
            try:
                return slot[key].get().strip()
            except Exception:
                return ""

        status = slot.get("meta_art_status_var")
        def _set(msg):
            if status is not None:
                try: status.set(msg)
                except Exception: pass

        song_audio = _v("audio_var")
        drum_audio = _v("drum_var")
        if not song_audio and not drum_audio:
            _set("⚠  Load a Song Audio or Drum Audio file first")
            return False

        _set("🔍  Extracting album art from audio metadata…")
        old_tmp = slot.get("_metadata_art_temp_path")

        img_bytes, src_label, src_path = self._pick_metadata_art_source(
            song_audio, drum_audio, _v("midi_var"))

        if not img_bytes:
            if old_tmp and slot["cover_var"].get().strip() == old_tmp:
                slot["cover_var"].set("")
            if old_tmp and os.path.exists(old_tmp):
                try: os.unlink(old_tmp)
                except Exception: pass
            slot["_metadata_art_temp_path"] = None
            _set("⚠  No album art in the Song Audio, Drum Audio, or the located full mix")
            return False

        try:
            tmp_path = self._save_metadata_art_png(img_bytes, src_path)
        except ImportError:
            _set("⚠  Pillow (PIL) is not installed — cannot crop album art")
            return False
        except Exception as exc:
            _set(f"⚠  Image error: {str(exc)[:60]}")
            return False

        if old_tmp and old_tmp != tmp_path and os.path.exists(old_tmp):
            try: os.unlink(old_tmp)
            except Exception: pass
        slot["_metadata_art_temp_path"] = tmp_path
        slot["cover_var"].set(tmp_path)
        _set(f"✓  Album art from {src_label} ({os.path.basename(src_path)})")
        return True

    def _batch_update_cover_preview(self, slot):
        """Per-slot album-art thumbnail (mirror of _update_cover_preview). Renders
        slot['cover_var'] into slot['cover_preview_label'] with a size caption."""
        label = slot.get("cover_preview_label")
        if label is None:
            return
        px = 80
        path = (slot["cover_var"].get() or "").strip()
        if path and os.path.isfile(path):
            try:
                from PIL import Image, ImageTk
                img = Image.open(path)
                w, h = img.size
                thumb = img.copy()
                if thumb.mode not in ("RGB", "RGBA"):
                    thumb = thumb.convert("RGB")
                thumb.thumbnail((px, px), Image.LANCZOS)
                photo = ImageTk.PhotoImage(thumb)
                label.configure(image=photo, text="")
                slot["cover_imgref"] = photo  # keep ref (Tk GC quirk)
                cap = f"{w}×{h}"
                if w != h:
                    cap += "  ·  not square"
                slot["cover_caption_var"].set(cap)
            except Exception:
                slot["cover_imgref"] = None
                label.configure(image="", text="(can't\npreview)")
                slot["cover_caption_var"].set(os.path.basename(path)[:24])
        else:
            slot["cover_imgref"] = None
            label.configure(image="", text="No art")
            slot["cover_caption_var"].set("No art selected")

    def _batch_slot_browse(self, var, filetypes, slot):
        path = filedialog.askopenfilename(filetypes=filetypes)
        if path:
            var.set(path)
            # Save to the shared recent list based on filetype
            ext = os.path.splitext(path)[1].lower()
            if ext in ('.mid', '.midi'):
                self._add_recent_file("recent_midi", path)
            elif ext in ('.ogg', '.mp3', '.wav', '.flac'):
                if var == slot["drum_var"]:
                    self._add_recent_file("recent_drum_audio", path)
                else:
                    self._add_recent_file("recent_audio", path)
            elif ext in ('.jpg', '.jpeg', '.png'):
                self._add_recent_file("recent_cover", path)
            if var == slot["midi_var"] and slot["title_var"].get() in ("Untitled",""):
                base = os.path.splitext(os.path.basename(path))[0]
                for sfx in ["_MIDI","_midi","_drums","_drum"," MIDI"," midi"]:
                    base = base.replace(sfx,"")
                slot["title_var"].set(base.strip())

    def _batch_browse_output(self):
        path = filedialog.askdirectory()
        if path:
            self.batch_output_var.set(path)
            save_config({"output_folder_batch": path})

    def _batch_open_output(self):
        folder = self.batch_output_var.get() or os.getcwd()
        import subprocess, platform
        try:
            if platform.system() == "Windows":
                os.startfile(folder)
            elif platform.system() == "Darwin":
                subprocess.Popen(["open", folder])
            else:
                subprocess.Popen(["xdg-open", folder])
        except Exception as e:
            messagebox.showerror("Error", f"Could not open folder:\n{e}")

    def _batch_log(self, msg):
        def _do():
            try:
                self.batch_log_text.configure(state="normal")
                self._pretty_log_insert(self.batch_log_text, msg + "\n")
                self.batch_log_text.see(tk.END)
                self.batch_log_text.configure(state="disabled")
            except Exception:
                pass   # widget may be gone during shutdown
        self.root.after(0, _do)

